        // unless I turn the bot off.
        fun isConfirmedManualStopSource(source: String, uiStopConfirmed: Boolean): Boolean {
            return (source == "ui_stop_button" && uiStopConfirmed) ||
                source == "halt_reset" ||
                source == "operator_manual_stop"
        }

