        /**
         * V5.9.614 вҖ” AntiChokeManager safety hook. When the choke goes RECOVERY
         * because the watchlist is choked with unpriced pump.fun firehose mints,
         * trigger a soft scanner reset so cooldown/saturation maps clear and
         * the discovery feed can re-prioritise. Soft only вҖ” never clears
         * seenMints/rejectedMints.
         */
        fun forceScannerSoftResetIfPossible() {
            try {
                val svc = instance ?: return
                val sc = svc.marketScanner ?: return
                sc.forceReset()
            } catch (_: Throwable) { /* never break */ }
        }


        /**
         * V5.9.362 вҖ” runtime re-apply of the Markets Trader switches. Called
         * from MainActivity right after the Settings sheet save, so toggling
         * Perps/Stocks/Commodities/Metals/Forex/Alts in the UI takes effect
         * without a service restart. The MARKET_TRADER_KILL_SWITCH constant
         * is honoured so dev builds can still globally suppress the stack.
         */
        fun reapplyMarketsTraderSwitches(ctx: android.content.Context) {
            val cfg = com.lifecyclebot.data.ConfigStore.load(ctx)
            val kill = MARKET_TRADER_KILL_SWITCH
            // V5.9.708 FIX: honour the marketsTraderEnabled master toggle.
            // If the master Markets toggle is off (or kill switch active), disable all
            // Markets sub-traders AND stop PerpsExecutionEngine immediately so the user
            // doesn't have to restart the bot manually.
            val marketsOn = !kill && isMarketsLaneEnabled(cfg)
            try { com.lifecyclebot.perps.PerpsTraderAI.setEnabled(marketsOn && cfg.perpsEnabled) } catch (_: Exception) {}
            try { com.lifecyclebot.perps.TokenizedStockTrader.setEnabled(marketsOn && cfg.stocksEnabled && !com.lifecyclebot.engine.EnabledTraderAuthority.MARKET_LANES_QUARANTINED) } catch (_: Exception) {}
            try { com.lifecyclebot.perps.CommoditiesTrader.setEnabled(marketsOn && cfg.commoditiesEnabled) } catch (_: Exception) {}
            try { com.lifecyclebot.perps.MetalsTrader.setEnabled(marketsOn && cfg.metalsEnabled) } catch (_: Exception) {}
            try { com.lifecyclebot.perps.ForexTrader.setEnabled(marketsOn && cfg.forexEnabled && !com.lifecyclebot.engine.EnabledTraderAuthority.MARKET_LANES_QUARANTINED) } catch (_: Exception) {}
            // Stop PerpsExecutionEngine immediately when Markets master toggle is turned off
            if (!marketsOn) {
                try {
                    if (com.lifecyclebot.perps.PerpsExecutionEngine.isRunning()) {
                        com.lifecyclebot.perps.PerpsExecutionEngine.stop()
                        ErrorLogger.info("BotService", "рҹ“ҙ reapply: Markets OFF вҖ” PerpsExecutionEngine stopped")
                        instance?.addLog("рҹ“ҙ Markets Trader toggled OFF вҖ” engine stopped")
                    }
                } catch (_: Exception) {}
            }
            // V5.9.1160 вҖ” Crypto Universe is part of the Markets lane. In MEME-only
            // mode (tradingMode=0 or markets master OFF) it must not scan, publish
            // DynSig/SIGNAL logs, write learning, or execute.
            // V5.0.3744 вҖ” operator explicit-enable escape hatch (crypto-isolated).
            // If cryptoAltsEnabled=true AND marketsTraderEnabled=true, keep crypto
            // running even when tradingMode==0. Operator intent ('explicitly
            // enabled') overrides the mode-based suppression.
            // V5.0.6015 вҖ” operator doctrine: Crypto Universe is an isolated
            // sidecar to the successful-lane feed, not part of stocks/forex/perps.
            // It must run with MEME when the bot is trading live so volume can come
            // from major/alt crypto setups without reopening MARKET_STOCKS.
            val cryptoUniverseDoctrine6015 = cfg.memeTraderEnabled
            val cryptoUniverseOn = cryptoUniverseDoctrine6015 || ((marketsOn ||
                (cfg.marketsTraderEnabled && cfg.cryptoAltsEnabled)) &&
                cfg.cryptoAltsEnabled)
            try { com.lifecyclebot.perps.CryptoAltTrader.setEnabled(cryptoUniverseOn) } catch (_: Exception) {}
            try {
                val cur = com.lifecyclebot.engine.EnabledTraderAuthority.snapshot().toMutableSet()
                if (cryptoUniverseOn) cur += com.lifecyclebot.engine.EnabledTraderAuthority.Trader.CRYPTO_ALT
                else cur -= com.lifecyclebot.engine.EnabledTraderAuthority.Trader.CRYPTO_ALT
                com.lifecyclebot.engine.EnabledTraderAuthority.publish(cur)
            } catch (_: Exception) {}
            if (!cryptoUniverseOn) {
                try {
                    com.lifecyclebot.perps.CryptoAltTrader.stop()
                    ErrorLogger.info("BotService", "CRYPTO_RUNTIME_DISABLED reason=MEME_ONLY_MODE_OR_MARKETS_OFF reapply marketsOn=$marketsOn cryptoToggle=${cfg.cryptoAltsEnabled}")
                    instance?.addLog("рҹ“ҙ Crypto Universe disabled вҖ” Meme-only/Markets-off isolation")
                } catch (_: Exception) {}
            }
            ErrorLogger.info("BotService", "рҹҺҡпёҸ Markets switches re-applied: " +
                "marketsOn=$marketsOn perps=${cfg.perpsEnabled} stocks=${cfg.stocksEnabled} " +
                "comm=${cfg.commoditiesEnabled} metals=${cfg.metalsEnabled} " +
                "forex=${cfg.forexEnabled} alts=${cfg.cryptoAltsEnabled}")
        }

        /**
         * V5.9.469 вҖ” single source of truth for "should the Markets lane run?".
         *
         * Operator-reported bug: Markets engine kept starting in live whether
         * the toggle was switched on or not. Root cause: the previous formula
         * was `marketsTraderEnabled || tradingMode==1 || tradingMode==2`. With
         * tradingMode defaulting to 2 (BOTH), the OR made the master toggle
         * silently ineffective вҖ” flipping marketsTraderEnabled=false had no
         * effect because the tradingMode==2 branch overrode it. Watchdog
         * loop kept restarting the engine on every 10th tick.
         *
         * Fix: AND semantics. The master toggle has authority; the trading
         * mode just decides whether the Markets lane is even applicable
         * (mode 0 = MEMES_ONLY вҶ’ markets off; modes 1/2 вҶ’ master toggle
         * decides).
         *
         * Safe at startup AND in the watchdog. Used in both places below.
         */
        fun isMarketsLaneEnabled(cfg: com.lifecyclebot.data.BotConfig): Boolean {
            // V5.0.6069 вҖ” PAPER MODE = LEARN EVERYTHING. In paper mode, enable
            // Markets lane universally (all trading modes) so the learning stack
            // gets samples across every lane surface. Kill switch still respected.
            if (cfg.paperMode && !MARKET_TRADER_KILL_SWITCH) return true
            return !MARKET_TRADER_KILL_SWITCH &&
                   cfg.marketsTraderEnabled &&
                   (cfg.tradingMode == 1 || cfg.tradingMode == 2)
        }

        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
