        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.7.8: WATCHLIST & ALERTS ENGINE
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        try {
            com.lifecyclebot.perps.WatchlistEngine.init(applicationContext)
            com.lifecyclebot.perps.WatchlistEngine.setAlertCallback { triggered ->
                addLog("рҹ”” ALERT: ${triggered.message}")
                try {
                    notifHistory.add(
                        "Price Alert: ${triggered.alert.symbol}",
                        triggered.message,
                        NotificationHistory.NotifEntry.NotifType.SAFETY_BLOCK
                    )
                } catch (_: Exception) {}
            }
            val wStats = com.lifecyclebot.perps.WatchlistEngine.getStats()
            addLog("рҹ”” Watchlist: ${wStats["watchlist_size"]} items, ${wStats["active_alerts"]} alerts")
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "Watchlist init failed (non-fatal): ${e.message}", e)
        }
        // Set up paper wallet balance tracking
        executor.onPaperBalanceChange = { delta ->
            // V5.9.21 FIX: previous guard (delta > currentBal*100) was silently
            // DROPPING real winning-sell credits, so trade journal showed +$10k
            // P&L while free cash stayed frozen at drawdown. The guard
            // self-reinforced because shrinking free cash shrank the threshold.
            //
            // New policy: only CLAMP absurd oracle spikes, never drop. A delta
            // is "insane" only if it's > 10,000x current balance AND > 500 SOL
            // absolute вҖ” otherwise credit exactly as-is. Even then we clamp
            // (don't drop) so the trade still moves the wallet in the right
            // direction, and we log loudly so the price-feed glitch is visible.
            val currentBal = status.paperWalletSol.coerceAtLeast(0.01)
            val ratio = if (currentBal > 0) delta / currentBal else 0.0
            val isInsane = delta > 500.0 && ratio > 10_000.0
            val applied = if (isInsane) {
                val capped = currentBal * 100.0
                ErrorLogger.warn("PaperWallet",
                    "INSANE DELTA CLAMPED: raw=${delta} (${ratio.toInt()}x bal=${currentBal}) вҖ” " +
                    "oracle/price glitch suspected вҖ” crediting capped=${capped} instead of dropping")
                capped
            } else {
                delta
            }

            status.paperWalletSol = (status.paperWalletSol + applied).coerceAtLeast(0.0)
            repairUnifiedPaperWalletIfImpossible("paper_delta")
            ErrorLogger.info("PaperWallet",
                "О”=${"%.4f".format(applied)} SOL вҶ’ balance=${"%.4f".format(status.paperWalletSol)}" +
                if (isInsane) " [CLAMPED from ${"%.4f".format(delta)}]" else "")

            // V5.9.8: Persist to SharedPrefs so balance survives app updates
            try {
                PaperWalletStore.persist(applicationContext, status.paperWalletSol)
            } catch (_: Exception) {}
        }
        
        // Persist running state so BootReceiver can restart after reboot
        getSharedPreferences(RUNTIME_PREFS, android.content.Context.MODE_PRIVATE)
            .edit()
            .putBoolean(KEY_WAS_RUNNING_BEFORE_SHUTDOWN, true)
            .putBoolean(KEY_MANUAL_STOP_REQUESTED, false)
            .apply()
        userStartQueuedDuringStop = false
        // Acquire/reassert partial wake lock вҖ” keeps CPU alive during transaction confirmation and screen-off live management.
        ensureRuntimeWakeLock6031("startBot")
        ensureRuntimeWifiLock6032("startBot")
        
        // Schedule a repeating keep-alive alarm every 60 seconds
        // This ensures the service restarts if Android kills it
        scheduleKeepAliveAlarm()
        
        // Schedule WorkManager watchdog (more reliable than AlarmManager on newer Android)
        ServiceWatchdog.schedule(applicationContext)
        // V5.9.707 вҖ” 5-min AlarmManager keep-alive (backup for OEMs that defer WorkManager)
        ServiceWatchdog.scheduleAlarm(applicationContext)
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V3.2 SHADOW LEARNING: Start BOTH shadow learning engines
        // - V1: Parameter variant testing
        // - V3: AI calibration shadow trades
        // Shadow learning is NEVER stopped - it's a constant learning state.
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        try {
            // Start V1 parameter variant engine
            ShadowLearningEngine.start()
            
            // Start V3 AI calibration engine (processes blocked trades)
            com.lifecyclebot.v3.learning.ShadowLearningEngine.start(scope)
            
            addLog("рҹ§  ShadowLearning: V1 + V3 engines started")
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "ShadowLearning start failed: ${e.message}", e)
        }
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.2 EMERGENT PATCH: Initialize RunTracker30D for proof tracking
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        try {
            RunTracker30D.init(applicationContext)
            
            // If run is active, apply guardrails
            if (RunTracker30D.isRunActive()) {
                // Lock config changes during proof run
                EmergentGuardrails.disableConfigChanges()
                
                addLog("рҹ“Ҡ RunTracker30D: Day ${RunTracker30D.getCurrentDay()} | " +
                    "Trades=${RunTracker30D.totalTrades} W=${RunTracker30D.wins} L=${RunTracker30D.losses}")
            } else {
                // No active run - prompt to start one for proof tracking
                addLog("рҹ“Ҡ RunTracker30D: No active run (use long-press to start 30-day proof)")
            }
            
            // Start a run automatically if not started and we have an initial balance
            val effectiveBalance = status.getEffectiveBalance(cfg.paperMode)
            if (!RunTracker30D.isRunActive() && effectiveBalance > 0) {
                RunTracker30D.startRun(effectiveBalance)
                EmergentGuardrails.disableConfigChanges()
                addLog("рҹҡҖ RunTracker30D: 30-Day Run STARTED | Balance=${effectiveBalance.toInt()} SOL")
            }
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "RunTracker30D init failed: ${e.message}", e)
        }
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.2.5: Initialize EducationSubLayerAI (Harvard Brain) with persistence
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        try {
            com.lifecyclebot.v3.scoring.EducationSubLayerAI.init(applicationContext)
            addLog("рҹҺ“ Harvard Brain initialized | Layers=${com.lifecyclebot.v3.scoring.EducationSubLayerAI.runDiagnostics().count { it.value }} active")
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "EducationSubLayerAI init failed: ${e.message}", e)
        }

        // V5.9.178 вҖ” LocalOrphanStore.reconcileAll is now DISABLED because the
        // new PerpsPositionStore rehydrates the actual positions at trader
        // init (AltPosition/MetalPosition/ForexPosition/CommodityPosition/
        // StockPosition). Refunding SOL on top of rehydration would
        // double-credit the paper balance. The orphan store still records
        // open positions for diagnostics but no longer mutates the wallet.
        try {
            com.lifecyclebot.collective.LocalOrphanStore.init(applicationContext)
            val snap = com.lifecyclebot.collective.LocalOrphanStore.snapshot()
            if (snap.isNotEmpty()) {
                addLog("рҹ“Ӯ ${snap.size} paper positions tracked by orphan store (diagnostics only; PerpsPositionStore is the source of truth)")
            }
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "LocalOrphanStore init failed: ${e.message}", e)
        }
        
        // V5.9.484 вҖ” wire 4 new push-data integrations (PumpPortal WS for new
        // pump.fun launches, Helius Enhanced WS for whale-wallet txs, Pyth
        // Hermes SSE for ~400ms pricing on SOL/BTC/ETH, and the LLM client
        // for trade-decision validation). Each one fails open: the bot
        // continues running on REST polling if any of these fail to start.
        try { wireExternalStreams(cfg) } catch (e: Exception) {
            ErrorLogger.warn("BotService", "wireExternalStreams error: ${e.message}")
        }

        addLog("Bot started вҖ” paper=${cfg.paperMode} auto=${cfg.autoTrade} sounds=${cfg.soundEnabled}")
        ErrorLogger.info("BotService", "Bot started successfully")
        
        // Log watchdog stats for debugging
        val watchdogStats = ServiceWatchdog.getStats(applicationContext)
        addLog("рҹҗ• Watchdog: ${watchdogStats.format()}")
        
        // Show Toast on UI thread for immediate feedback
        android.os.Handler(android.os.Looper.getMainLooper()).post {
            android.widget.Toast.makeText(
                applicationContext,
                "рҹҡҖ Bot Started\nPaper=${cfg.paperMode} | Learning applied",
                android.widget.Toast.LENGTH_LONG
            ).show()
        }
        
        // Send Telegram notification for bot start
        sendTradeNotif(
            "рҹҡҖ Bot Started",
            "Paper=${cfg.paperMode} | Auto=${cfg.autoTrade} | Sounds=${cfg.soundEnabled}",
            NotificationHistory.NotifEntry.NotifType.INFO
        )
        
        } catch (e: Exception) {
            // Catch any crash and log it with full stack trace to ErrorLogger
            ErrorLogger.crash("BotService", "startBot CRASH: ${e.javaClass.simpleName}: ${e.message}", e)
            addLog("вқҢ Bot start CRASH: ${e.javaClass.simpleName}: ${e.message}")
            android.util.Log.e("BotService", "startBot CRASH", e)
            e.printStackTrace()

            // V5.9.1072 вҖ” SOURCE FIX: post-runtime startup exceptions are NOT stops.
            // If loopJob is already active (or we passed the runtime commit point), the
            // service is running. Do not flip status.running=false, do not disarm
            // recovery, do not make Main show STOPPED. Keep alarms armed and surface
            // the failure as degraded optional init. This is the exact no-ACTION_STOP
            // false-stop class seen when returning from Journal/Pipeline.
            if (runtimeCommitted || loopJob?.isActive == true) {
                status.running = true
                stopInProgress = false
                userStartQueuedDuringStop = false
                try {
                    getSharedPreferences(RUNTIME_PREFS, android.content.Context.MODE_PRIVATE)
                        .edit()
                        .putBoolean(KEY_WAS_RUNNING_BEFORE_SHUTDOWN, true)
                        .putBoolean(KEY_MANUAL_STOP_REQUESTED, false)
                        .apply()
                } catch (_: Throwable) {}
                try {
                    ForensicLogger.lifecycle(
                        "STARTBOT_POST_COMMIT_EXCEPTION_KEPT_RUNNING",
                        "exception=${e.javaClass.simpleName} loopActive=${loopJob?.isActive == true} statusRunning=${status.running}",
                    )
                } catch (_: Throwable) {}
                try { scheduleKeepAliveAlarm() } catch (_: Throwable) {}
                try { scheduleLoopHeartbeatAlarm() } catch (_: Throwable) {}
                try { ServiceWatchdog.schedule(applicationContext) } catch (_: Throwable) {}
                ErrorLogger.warn(
                    "BotService",
                    "startBot post-commit exception kept runtime alive: ${e.javaClass.simpleName}: ${e.message}"
                )
                addLog("вҡ пёҸ Startup optional init failed after runtime commit вҖ” bot kept running (${e.javaClass.simpleName})")
                return
            }

            status.running = false

            // V5.9.913 вҖ” AUTO-RECOVERY REWRITE for "bot keeps stopping itself".
            //
            // Operator (2026-05-18): "the bot keeps stopping self completely.
            // you go back in everything is off. also randomly restarts to match.
            // this is a persisting issue. once started the bot should run
            // uninhibited unless stopped by user!!!"
            //
            // Root cause (pre-913): V5.9.495z11 disarmed the ENTIRE recovery
            // chain on ANY startBot crash:
            //   - was_running = false   вҶ’ watchdog skips
            //   - ServiceWatchdog.cancel вҶ’ 15-min worker gone
            //   - cancelKeepAliveAlarm   вҶ’ 60s alarm gone
            //   - stopForeground(REMOVE) вҶ’ notification gone, OS more
            //     aggressive about killing the process
            //
            // For DETERMINISTIC crashes (NPE on uninitialised lateinit, parse
            // error in saved state) this prevents a 15-min crash loop. Good.
            // For TRANSIENT crashes (network blip on wallet connect, scanner
            // JSONException on a malformed Birdeye response, RPC timeout,
            // OOM during init, race condition) this PERMANENTLY KILLS the
            // bot вҖ” the operator sees "everything off" with no path back
            // until they manually tap Start. The bot may then partially
            // come back via a stale alarm hours later, looking like a
            // "random restart" вҶ’ exactly the reported symptom pair.
            //
            // V5.9.913 fix: track crash count + last-crash-time. If we're in
            // a tight crash loop (3+ failures in 5 minutes), disarm to
            // protect operator from a runaway. Otherwise: KEEP was_running
            // alive, KEEP the watchdog, KEEP the keep-alive chain, and
            // schedule a FAST 60s ACTION_START retry alarm so transient
            // errors self-heal within a minute. The notification is
            // DETACHED (kept visible) rather than REMOVED вҖ” operator sees
            // "bot recovering" instead of "bot vanished", and the OS is
            // less aggressive about killing the process.
            val crashPrefs = try {
                getSharedPreferences("bot_runtime", android.content.Context.MODE_PRIVATE)
            } catch (_: Exception) { null }
            val now = System.currentTimeMillis()
            val lastCrashMs = crashPrefs?.getLong("last_startbot_crash_ms", 0L) ?: 0L
            val priorCount = crashPrefs?.getInt("startbot_crash_count_5min", 0) ?: 0
            // Reset crash counter if last crash was >5 min ago (fresh failure window).
            val crashCount = if (now - lastCrashMs > 5 * 60_000L) 1 else priorCount + 1
            try {
                crashPrefs?.edit()
                    ?.putLong("last_startbot_crash_ms", now)
                    ?.putInt("startbot_crash_count_5min", crashCount)
                    ?.apply()
            } catch (_: Exception) {}

            val runawayLoop = crashCount >= 3
            ForensicLogger.lifecycle(
                "STARTBOT_CRASH",
                "exception=${e.javaClass.simpleName} crashCount5min=$crashCount runawayLoop=$runawayLoop"
            )

            if (runawayLoop) {
                // Genuine crash loop вҖ” preserve V5.9.495z11 disarm behaviour.
                addLog("рҹӣ‘ Bot start crashed ${crashCount}x in 5 min вҖ” disarming auto-recovery to prevent loop. Tap Start to retry.")
                ErrorLogger.error(
                    "BotService",
                    "startBot crashed $crashCount times in 5min вҖ” disarming auto-recovery (V5.9.495z11)"
                )
                try {
                    crashPrefs?.edit()?.putBoolean("was_running_before_shutdown", false)?.apply()
                } catch (_: Exception) {}
                try { ServiceWatchdog.cancel(applicationContext) } catch (_: Exception) {}
                try { cancelKeepAliveAlarm() } catch (_: Exception) {}
                try { cancelLoopHeartbeatAlarm() } catch (_: Throwable) {}
                try { loopHeartbeatJob?.cancel() } catch (_: Throwable) {}
                loopHeartbeatJob = null
                try { stopForeground(STOP_FOREGROUND_REMOVE) } catch (_: Exception) {}
            } else {
                // Transient crash вҖ” KEEP recovery armed and schedule fast retry.
                addLog("вҡ пёҸ Bot start failed (${e.javaClass.simpleName}) вҖ” auto-retrying in 60s. Crash $crashCount/3 in 5min window.")
                ErrorLogger.warn(
                    "BotService",
                    "startBot transient crash ($crashCount/3 in 5min) вҖ” auto-retry in 60s"
                )
                // was_running stays TRUE so watchdog and resurrection paths see "should be running".
                // Schedule a single-shot ACTION_START alarm in 60s вҖ” fast self-heal.
                try {
                    val retryIntent = Intent(applicationContext, BotService::class.java).apply {
                        action = ACTION_START
                    }
                    val pi = android.app.PendingIntent.getService(
                        this, 9913, retryIntent,
                        android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
                    )
                    val am = getSystemService(android.app.AlarmManager::class.java)
                    am?.setExactAndAllowWhileIdle(
                        android.app.AlarmManager.RTC_WAKEUP,
                        System.currentTimeMillis() + 60_000L,
                        pi
                    )
                    ForensicLogger.lifecycle("STARTBOT_RETRY_SCHEDULED", "delayMs=60000 crashCount=$crashCount")
                } catch (ex: Exception) {
                    ErrorLogger.error("BotService", "Failed to schedule 60s retry alarm: ${ex.message}", ex)
                }
                // Keep loop heartbeat infrastructure ARMED for next attempt.
                try { cancelLoopHeartbeatAlarm() } catch (_: Throwable) {}
                try { loopHeartbeatJob?.cancel() } catch (_: Throwable) {}
                loopHeartbeatJob = null
                // STOP_FOREGROUND_DETACH keeps the notification visible so the OS knows
                // we're still a "user-facing" service вҶ’ less aggressive kill behaviour.
                // The notification text will be updated on next successful start.
                try { stopForeground(android.app.Service.STOP_FOREGROUND_DETACH) } catch (_: Exception) {
                    try { stopForeground(STOP_FOREGROUND_REMOVE) } catch (_: Exception) {}
                }
            }
        }
    }

    /**
     * V5.9.73: Kick off a wallet connect in the background so startBot()
     * / in-loop reconnect never blocks the IO thread for 30-90s of
     * sequential RPC timeouts. Cancels any previous in-flight attempt.
     *
     * @param runReconciliation fire StartupReconciler once connected вҖ”
     *        true for cold start, false for mid-loop reconnect where
     *        we only want the wallet back online.
     */
    private fun launchWalletConnect(
        privateKeyB58: String,
        rpcUrl: String,
        runReconciliation: Boolean,
    ) {
        walletConnectJob?.cancel()
        walletConnectJob = scope.launch {
            try {
                val connected = walletManager.connect(privateKeyB58, rpcUrl)
                val cfgNow = ConfigStore.load(applicationContext)
                if (!kotlinx.coroutines.currentCoroutineContext().isActive) return@launch

                if (connected && !cfgNow.paperMode) {
                    wallet = walletManager.getWallet()
                    addLog("вң“ Wallet connected: ${walletManager.state.value.shortKey}")
                    ErrorLogger.info("BotService", "вң“ Wallet connected in background")

                    // V5.9.105: live-safety circuit breaker вҖ” refuse live trades
                    // if the wallet starts below 0.1 SOL (dust bleeds fees on
                    // every Jupiter swap). Also seeds session-PnL halt.
                    try {
                        val liveSol = wallet?.getSolBalance() ?: 0.0
                        LiveSafetyCircuitBreaker.beginSession(liveSol)
                        if (LiveSafetyCircuitBreaker.isTripped()) {
                            addLog("рҹҡЁ LIVE HALT: ${LiveSafetyCircuitBreaker.trippedReason()}")
                            sendTradeNotif(
                                "рҹҡЁ Live Trading Disabled",
                                LiveSafetyCircuitBreaker.trippedReason(),
                                NotificationHistory.NotifEntry.NotifType.INFO,
                            )
                        }
                    } catch (e: Exception) {
                        addLog("вҡ пёҸ Could not seed live safety CB: ${e.message}")
                    }

                    if (runReconciliation) {
                        val liveWallet = wallet
                        if (liveWallet != null) {
                            try {
                                val reconciler = StartupReconciler(
                                    wallet  = liveWallet,
                                    status  = status,
                                    onLog   = { msg -> addLog(msg) },
                                    onAlert = { title, body ->
                                        sendTradeNotif(title, body,
                                            NotificationHistory.NotifEntry.NotifType.INFO)
                                    },
                                    executor = executor,
                                    autoSellOrphans = false,  // V5.9.102: prefer adoption over sell
                                )
                                reconciler.reconcile()
                            } catch (e: Exception) {
                                addLog("Reconciliation error: ${e.message}")
                            }
                        }
                    }
                } else if (!connected) {
                    val msg = walletManager.state.value.errorMessage.ifBlank { "unknown" }
                    addLog("вҡ пёҸ Wallet connect failed: $msg")
                    ErrorLogger.warn("BotService", "Wallet connect failed: $msg")
                }
            } catch (e: kotlinx.coroutines.CancellationException) {
                addLog("Wallet connect cancelled")
                throw e
            } catch (e: Exception) {
                addLog("вҡ пёҸ Wallet connect error: ${e.message}")
                ErrorLogger.warn("BotService", "Wallet connect exception: ${e.message}")
            }
        }
    }

    /**
     * V5.9.779 вҖ” EMERGENT MEME-ONLY: rehydrate a minimal TokenState for the
     * SellReconciler trigger when the mint isn't in status.tokens (e.g.
     * after a stopBot trim, a service kill, or a user-side restart). The
     * TokenState we synthesise is just enough for Executor.requestSell to
     * resolve quantity and broadcast a sell вҖ” the HostWalletTokenTracker
     * + Executor's RPC fallback paths fill in the rest. The synthesised
     * ts is also added back into status.tokens so the bot loop's exit
     * gate can pick it up on the next tick.
     */
    /**
     * V5.9.780a вҖ” extracted from botLoop to keep the suspend state machine
     * under the JVM 64 KB method-size limit. Identical semantics:
     *   PAPER mode вҶ’ tick if CYCLIC is enabled
     *   LIVE  mode вҶ’ tick only if CYCLIC enabled AND walletUsd >= $5000
     */
    private fun maybeTickCyclicTradeEngine(wallet: SolanaWallet?) {
        try {
            val isPaperRuntime = com.lifecyclebot.engine.RuntimeModeAuthority.isPaper()
            val solPrice = com.lifecyclebot.engine.WalletManager.lastKnownSolPrice
            val walletSolNow = walletManager.state.value.solBalance
            val walletUsdNow = walletSolNow * solPrice.coerceAtLeast(0.0)
            val cfgNow = ConfigStore.load(applicationContext)
            val cyclicEnabled = com.lifecyclebot.engine.EnabledTraderAuthority.isEnabled(
                com.lifecyclebot.engine.EnabledTraderAuthority.Trader.CYCLIC
            )
            val liveThreshold = 5000.0
            // V5.0.6069 вҖ” PAPER MODE = LEARN EVERYTHING. Force-enable cyclic
            // ring in paper regardless of user's cyclic toggle. Operator wants
            // every surface accumulating learning samples in paper.
            val cyclicPaperOverride6069 = isPaperRuntime
            val allowTick = when {
                cyclicPaperOverride6069 -> true  // V5.0.6069 вҖ” paper always runs cyclic for learning
                isPaperRuntime -> cyclicEnabled
                // V5.0.3959 вҖ” CYCLIC bankroll gate. CYCLIC is a separate
                // compounding ring and must NOT engage the live wallet until the
                // actual wallet balance exceeds $5000 USD. MEME lanes remain live.
                else -> cyclicEnabled && walletUsdNow >= liveThreshold
            }
            if (allowTick) {
                // V5.9.1238 вҖ” snapshot cheap state on the loop thread, then run the
                // (potentially blocking) tick OFF the bot-loop coroutine. Single-flight:
                // if a prior tick is still running, skip this one rather than queueing вҖ”
                // cyclic is a low-frequency lane and a backed-up tick means the executor
                // is busy, not that we lost a signal.
                if (!cyclicTickInFlight.compareAndSet(false, true)) {
                    try {
                        ForensicLogger.lifecycle(
                            "CYCLIC_TICK_SKIPPED",
                            "reason=in_flight (previous cyclic tick still running off-loop)",
                        )
                    } catch (_: Throwable) {}
                    return
                }
                val cyclicTokens = synchronized(status.tokens) { status.tokens.toMap() }
                val walletSnap = wallet
                scope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    try {
                        val completed = kotlinx.coroutines.withTimeoutOrNull(CYCLIC_TICK_TIMEOUT_MS) {
                            CyclicTradeEngine.tick(
                                context   = applicationContext,
                                tokens    = cyclicTokens,
                                executor  = executor,
                                wallet    = walletSnap,
                                walletSol = walletSolNow,
                            )
                            true
                        }
                        if (completed == null) {
                            try {
                                ForensicLogger.lifecycle(
                                    "CYCLIC_TICK_TIMEOUT",
                                    "budgetMs=$CYCLIC_TICK_TIMEOUT_MS вҖ” tick exceeded watchdog; loop unaffected",
                                )
                            } catch (_: Throwable) {}
                        }
                    } catch (e: Throwable) {
                        ErrorLogger.error("BotService", "CyclicTradeEngine async tick error: ${e.message}", e)
                    } finally {
                        cyclicTickInFlight.set(false)
                    }
                }
            } else {
                try {
                    ForensicLogger.lifecycle(
                        "CYCLIC_TICK_SKIPPED",
                        "mode=${if (isPaperRuntime) "PAPER" else "LIVE"} cyclicEnabled=$cyclicEnabled agenicAlwaysOn=true cfgEnabled=${cfgNow.cyclicTradeEnabled} liveOptIn=${cfgNow.cyclicTradeLiveEnabled} walletUsd=${"%.2f".format(walletUsdNow)} threshold=$liveThreshold reason=${if (!isPaperRuntime && walletUsdNow < liveThreshold) "CYCLIC_WALLET_USD_BELOW_5000_MEME_STILL_ACTIVE" else "disabled_or_in_flight"}",
                    )
                } catch (_: Throwable) {}
            }
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "CyclicTradeEngine tick error: ${e.message}", e)
        }
    }


    private fun rehydrateTokenStateFromTracker(
        mint: String,
        symbolHint: String,
        balanceHint: Double,
    ): com.lifecyclebot.data.TokenState? {
        try {
            val tracked = com.lifecyclebot.engine.HostWalletTokenTracker.getEntry(mint)
            val sym = (tracked?.symbol?.takeIf { it.isNotBlank() }) ?: symbolHint.takeIf { it.isNotBlank() } ?: "?"
            val qty = tracked?.uiAmount?.takeIf { it > 0.0 } ?: balanceHint
            if (qty <= 1.0) {
                try { ForensicLogger.lifecycle("TOKEN_STATE_REHYDRATE_SKIPPED_TERMINAL_DUST", "mint=${mint.take(12)} qty=$qty") } catch (_: Throwable) {}
                try { purgeGhostLivePosition(mint, "REHYDRATE_TERMINAL_TOKEN_DUST") } catch (_: Throwable) {}
                return null
            }
            // V5.9.1530 вҖ” REHYDRATION GUARD: a CLOSED+dust mint must NOT be resurrected.
            // Only a confirmed NON-dust on-chain balance overrides a close stamp.
            if (com.lifecyclebot.engine.PositionCloseLedger.isHardClosed(mint, qty)) {
                try { ForensicLogger.lifecycle("SELL_REHYDRATE_BLOCKED_CLOSED_LEDGER", "mint=${mint.take(12)} qty=$qty reason=closed_ledger_dust") } catch (_: Throwable) {}
                return null
            }
            val ts = com.lifecyclebot.data.TokenState(mint = mint, symbol = sym, name = sym)
            val meta = try { com.lifecyclebot.engine.TokenLifecycleTracker.getEntryMetadata(mint) } catch (_: Throwable) { null }
            val metaEntryUsd = meta?.entryPriceUsd?.takeIf { it.isFinite() && it > 0.0 } ?: 0.0
            val metaCostSol = meta?.entrySolSpent?.takeIf { it.isFinite() && it > 0.0 } ?: 0.0
            val trackerEntryUsd = tracked?.entryPriceUsd?.takeIf { it.isFinite() && it > 0.0 } ?: 0.0
            val trackerCostSol = tracked?.entrySol?.takeIf { it.isFinite() && it > 0.0 } ?: 0.0
            val currentUsd = tracked?.currentPriceUsd?.takeIf { it.isFinite() && it > 0.0 } ?: 0.0
            fun saneRecoveredBasis(entryUsd: Double): Boolean {
                if (entryUsd <= 0.0 || !entryUsd.isFinite()) return false
                if (currentUsd <= 0.0) return true
                val ratio = currentUsd / entryUsd
                return ratio.isFinite() && ratio in 0.0001..5_000.0
            }
            val useMetaBasis = metaEntryUsd > 0.0 && metaCostSol > 0.0 && saneRecoveredBasis(metaEntryUsd)
            val useTrackerBasis = !useMetaBasis && trackerEntryUsd > 0.0 && trackerCostSol > 0.0 && saneRecoveredBasis(trackerEntryUsd)
            val recoveredEntryUsd = when {
                useMetaBasis -> metaEntryUsd
                useTrackerBasis -> trackerEntryUsd
                else -> 0.0
            }
            val recoveredCostSol = when {
                useMetaBasis -> metaCostSol
                useTrackerBasis -> trackerCostSol
                else -> 0.0
            }
            val recoveredSource = when {
                useMetaBasis -> "LIVE_PROOF_COST_BASIS_REHYDRATED"
                useTrackerBasis -> "HOST_WALLET_TRACKER_REHYDRATED_SANITY_OK"
                else -> "HOST_WALLET_TRACKER_BASIS_UNKNOWN"
            }
            ts.position = com.lifecyclebot.data.Position(
                qtyToken = qty,
                entryPrice = recoveredEntryUsd,
                costSol = recoveredCostSol,
                entryTime = tracked?.buyTimeMs ?: System.currentTimeMillis(),
                isPaperPosition = false,
                entryPriceSource = recoveredSource,
                priceBasisRescaled = useMetaBasis || useTrackerBasis,
            )
            if (ts.position.entryPrice <= 0.0 || ts.position.costSol <= 0.0) {
                try { com.lifecyclebot.engine.sell.RecoveryLockTracker.lock(mint = mint, symbol = sym, reason = "HOST_WALLET_TRACKER_BASIS_UNKNOWN") } catch (_: Throwable) {}
                try { ForensicLogger.lifecycle("TOKEN_STATE_REHYDRATED_BASIS_LOCKED", "mint=${mint.take(10)} symbol=$sym trackerEntry=$trackerEntryUsd metaEntry=$metaEntryUsd current=$currentUsd qty=$qty source=$recoveredSource") } catch (_: Throwable) {}
            } else {
                try { ForensicLogger.lifecycle("TOKEN_STATE_REHYDRATED_BASIS_TRUSTED", "mint=${mint.take(10)} symbol=$sym source=$recoveredSource entry=$recoveredEntryUsd cost=$recoveredCostSol current=$currentUsd") } catch (_: Throwable) {}
            }
            ts.source = "WALLET_RESTORED_LIVE_POSITION"
            ts.addedToWatchlistAt = System.currentTimeMillis()
            synchronized(status.tokens) {
                status.tokens.putIfAbsent(mint, ts)
            }
            try {
                ForensicLogger.lifecycle(
                    "TOKEN_STATE_REHYDRATED_FROM_TRACKER",
                    "mint=${mint.take(10)} symbol=$sym qty=$qty",
                )
            } catch (_: Throwable) {}
            return ts
        } catch (e: Throwable) {
            ErrorLogger.warn("BotService", "rehydrateTokenStateFromTracker(${mint.take(10)}) failed: ${e.message?.take(80)}")
            return null
        }
    }

    // V5.9.1522 вҖ” POSITION AUTO-HEAL. Adopt any wallet-held mint that has no live
    // open position in the store so it gets an exit monitor. Cure for the operator
    // forensic: walletHeldMints>0 && liveOpenPositions==0 && orphanLivePositions=7.
    // Called from the SellReconciler live tick with the wallet-truth held set.
    @Volatile private var lastHealLogMs: Long = 0L
    private fun healWalletHeldIntoLiveStore(heldMints: Set<String>) {
        if (heldMints.isEmpty()) return
        // Mints already represented as a LIVE open position in the store.
        val liveOpen: Set<String> = try {
            synchronized(status.tokens) {
                status.tokens.values
                    .filter { it.position.isOpen && !it.position.isPaperPosition }
                    .map { it.mint }
                    .toSet()
            }
        } catch (_: Throwable) { emptySet() }
        val missing = heldMints.filter { it !in liveOpen }
        if (missing.isEmpty()) return
        var healed = 0
        for (mint in missing) {
            try {
                val tracked = HostWalletTokenTracker.getEntry(mint)
                val sym = tracked?.symbol?.takeIf { it.isNotBlank() } ?: mint.take(6)
                val bal = tracked?.uiAmount ?: 0.0
                if (bal <= 1.0) {
                    try { ForensicLogger.lifecycle("POSITION_AUTO_HEAL_SKIPPED_TERMINAL_DUST", "mint=${mint.take(12)} qty=$bal") } catch (_: Throwable) {}
                    try { purgeGhostLivePosition(mint, "AUTO_HEAL_TERMINAL_TOKEN_DUST") } catch (_: Throwable) {}
                    continue   // terminal token dust / not economically held
                }
                // V5.9.1530 вҖ” AUTOHEAL GUARD: never autoheal a CLOSED+dust mint back to OPEN.
                if (com.lifecyclebot.engine.PositionCloseLedger.isHardClosed(mint, bal)) {
                    try { ForensicLogger.lifecycle("SELL_REHYDRATE_BLOCKED_CLOSED_LEDGER", "mint=${mint.take(12)} qty=$bal source=autoheal") } catch (_: Throwable) {}
                    continue
                }
                val ts = rehydrateTokenStateFromTracker(mint, sym, bal)
                if (ts != null) {
                    // ensure flagged open + live so the exit monitor/hotExit picks it up
                    if (!ts.position.isOpen || ts.position.isPaperPosition) {
                        synchronized(ts) {
                            ts.position = ts.position.copy(isPaperPosition = false)
                        }
                    }
                    healed++
                }
            } catch (e: Throwable) {
                ErrorLogger.warn("BotService", "heal mint ${mint.take(10)} failed: ${e.message?.take(60)}")
            }
        }
        if (healed > 0) {
            val now = System.currentTimeMillis()
            if (now - lastHealLogMs > 5_000L) {
                lastHealLogMs = now
                try {
                    ForensicLogger.lifecycle(
                        "LIVE_POSITION_AUTOHEAL",
                        "walletHeld=${heldMints.size} liveOpenBefore=${liveOpen.size} missing=${missing.size} healed=$healed",
                    )
                } catch (_: Throwable) {}
                try { ErrorLogger.warn("BotService", "вҷ»пёҸ LIVE_POSITION_AUTOHEAL healed=$healed orphan wallet bags into live store") } catch (_: Throwable) {}
            }
        }
    }

    fun stopBot(source: String = "direct_call_unknown") {
        val liquidateOnStop = source == "ui_stop_button" || source == "halt_reset" || source == "operator_manual_stop"
        val stopAllowed = liquidateOnStop || source == "config_restart"
        if (!stopAllowed) {
            ErrorLogger.error("BotService", "рҹҡ« stopBot rejected: unapproved source=$source вҖ” runtime must stay running")
            try { ForensicLogger.lifecycle("STOPBOT_REJECTED", "source=$source reason=unapproved_stop_source") } catch (_: Throwable) {}
            try {
                getSharedPreferences(RUNTIME_PREFS, Context.MODE_PRIVATE)
                    .edit()
                    .putBoolean(KEY_WAS_RUNNING_BEFORE_SHUTDOWN, true)
                    .putBoolean(KEY_MANUAL_STOP_REQUESTED, false)
                    .apply()
            } catch (_: Throwable) {}
            scheduleKeepAliveAlarm()
            try { ServiceWatchdog.scheduleAlarm(applicationContext) } catch (_: Throwable) {}
            return
        }
        val softStopPreservePositions = !liquidateOnStop
        isShuttingDown = liquidateOnStop  // V5.9.1078: only liquidation stops use fast-close shutdown paths
        // V5.9.1016 вҖ” forensic stop source marker. Report/navigation bugs must
        // never be allowed to hide behind a generic BOT_STOP_REQUESTED again.
        val stopGeneration = BotRuntimeController.beginStopping(source)
        ForensicLogger.lifecycle("BOT_STOP_REQUESTED", "gen=$stopGeneration source=$source liquidate=$liquidateOnStop softPreserve=$softStopPreservePositions loopActive=${loopJob?.isActive == true} statusRunning=${status.running} openPositions=${status.tokens.values.count { it.position.isOpen }}")
        // V5.9.148 вҖ” gate so a concurrent ACTION_START queues instead of racing
        // the tail of this method. Cleared in the `finally` block below.
        stopInProgress = true
        status.running = false  // visible immediately; stopInProgress remains the cleanup truth

        // V5.9.1033 вҖ” HARD-CANCEL ESCAPE HATCH.
        //
        // Operator V5.9.1031 freeze: pressed Stop, bot didn't react for
        // 10+ minutes. Root cause: status.running=false only gets read
        // at the TOP of the next botLoop iteration. With supervisor
        // cycles taking 22-28s (95%+ chunks timing out at 4.8s each)
        // and 32 OkHttp workers per chunk blocked inside synchronous
        // .execute() that does NOT honour coroutine cancellation,
        // stopBot effectively has to wait for every socket to time out.
        //
        // 1. Cancel loopJob explicitly вҖ” any suspended state-machine
        //    branch wakes up at its next suspension point and exits.
        // 2. SharedHttpClient.cancelAllRequests() aborts every in-flight
        //    AND queued OkHttp call across the shared dispatcher. The
        //    supervisor's awaitAll() returns within ms with IOException
        //    instead of waiting 4.8s budget Г— 3 chunks = 14.4s drain.
        try {
            loopJob?.cancel(kotlinx.coroutines.CancellationException("stopBot:$source"))
            BotRuntimeController.registerJob(stopGeneration, "botLoop", loopJob)
            try { ForensicLogger.lifecycle("LIFECYCLE_RUNTIME_JOB_CANCELLED", "gen=$stopGeneration source=$source") } catch (_: Throwable) {}
        } catch (_: Throwable) {}
        try {
            com.lifecyclebot.network.SharedHttpClient.cancelAllRequests()
        } catch (_: Throwable) {}
        // V5.9.1310 вҖ” DISCONNECT INTAKE FIRST (unconditional, before the long
        // shutdown body). Previously orchestrator.stop() sat at the TAIL of
        // stopBot(), after position liquidation / watchlist clear / persistence
        // clear. If any of those threw, or the shutdown coroutine was cancelled
        // mid-body, the PumpPortal/Helius/Dex WebSockets were NEVER disconnected
        // and kept streaming new tokens into intake post-stop. Tear the data feeds
        // down immediately and unconditionally so no scanner/WS message can reach
        // intake during the rest of shutdown. The tail orchestrator=null cleanup
        // remains (idempotent: disconnect() is safe to call twice).
        try {
            marketScanner?.stop()
        } catch (_: Throwable) {}
        try {
            orchestrator?.stop()
            try { ForensicLogger.lifecycle("STOP_DATAFEEDS_DISCONNECTED", "gen=$stopGeneration source=$source early=true") } catch (_: Throwable) {}
        } catch (e: Throwable) {
            try { ForensicLogger.lifecycle("STOP_DATAFEEDS_DISCONNECT_ERR", "err=${e.message?.take(60)}") } catch (_: Throwable) {}
        }
        try {
            try {
                getSharedPreferences(RUNTIME_PREFS, android.content.Context.MODE_PRIVATE)
                    .edit()
                    .putBoolean(KEY_WAS_RUNNING_BEFORE_SHUTDOWN, softStopPreservePositions)
                    .putBoolean(KEY_MANUAL_STOP_REQUESTED, liquidateOnStop)
                    .apply()
            } catch (_: Exception) {}
        if (liquidateOnStop) {
            cancelAllRestartAlarms()
            try { ServiceWatchdog.cancel(applicationContext) } catch (_: Exception) {}
        }
        // V5.9.674 вҖ” stop the proactive loop heartbeat watchdog before the
        // loopJob it watches is cancelled; otherwise the watchdog could
        // observe sinceLastTickMs > 180s mid-shutdown and relaunch botLoop
        // exactly when we are trying to stop.
        // V5.9.675 вҖ” also cancel the AlarmManager-driven Doze-proof
        // heartbeat alarm; otherwise it would fire ACTION_LOOP_HEARTBEAT
        // post-stop, the handler would see status.running=false and skip
        // the rescue, but the alarm would keep re-arming itself (it only
        // self-cancels when running == true; absent that, we cancel it
        // explicitly here).
        try { cancelLoopHeartbeatAlarm() } catch (_: Throwable) {}
        try { loopHeartbeatJob?.cancel() } catch (_: Throwable) {}
        loopHeartbeatJob = null
        // V5.9.756 вҖ” Emergent ticket item #4: stop the periodic reconciler.
        try { reconcilerJob?.cancel() } catch (_: Throwable) {}
        reconcilerJob = null
        // V5.9.905 вҖ” stop the high-frequency exit manager loop.
        try { hotExitJob?.cancel() } catch (_: Throwable) {}
        hotExitJob = null
        // V5.9.1313 вҖ” reset hotExit liveness trackers so the next start has a
        // clean grace window and the loop doesn't false-trigger a resurrection.
        botLoopStartedAtMs = 0L
        lastTickExitSweepMs = 0L
        try { exitSweepCoordinatorJob?.cancel(kotlinx.coroutines.CancellationException("stopBot:$source")) } catch (_: Throwable) {}
        exitSweepCoordinatorJob = null
        fullExitSweepPending.set(false)
        universalSlSweepPending.set(false)
        addLog("Stopping bot...")

        // V5.9.73: kill any in-flight wallet connect so a 90-second RPC
        // timeout from the previous live-start doesn't leak past the stop
        // and block the next paper-mode start from going clean.
        walletConnectJob?.cancel()
        walletConnectJob = null

        // V5.9.495z20 вҖ” stop recovery loop on bot stop.
        try {
            com.lifecyclebot.engine.execution.RecoveryExecutionLoop.stop()
        } catch (_: Exception) {}

        // V5.9.495z22 вҖ” stop reconciler loop on bot stop.
        try {
            com.lifecyclebot.engine.execution.PositionWalletReconciler.stop()
        } catch (_: Exception) {}
        try {
            com.lifecyclebot.engine.sell.SellReconciler.stop()
            BotRuntimeController.markSellReconcilerStarted(stopGeneration, false)
        } catch (_: Exception) {}

        // V5.9.495z24 вҖ” stop background discovery loop.
        try {
            com.lifecyclebot.perps.DynamicAltTokenRegistry.stopBackgroundDiscovery()
        } catch (_: Exception) {}
        
        // V5.9.1063 вҖ” removed paper-purge block. The previous implementation
        // called clearAllTrades() on every stopBot() whenever ANY trade had
        // pnlPct < -100 (decimal rounding errors on BUY records triggered this).
        // Result: every bot restart (rescue cycle, app reopen, manual stop)
        // wiped the entire SQLite journal вҶ’ Journal always showed 0 trades.
        // The paper wallet inflation guard is also removed вҖ” the SmartSizer
        // already caps balance to a sane value each cycle.
        
        if (softStopPreservePositions) {
            val preservedOpenCount = try { status.tokens.values.count { it.position.isOpen } } catch (_: Throwable) { -1 }
            try {
                ForensicLogger.lifecycle(
                    "STOP_SOFT_PRESERVE_POSITIONS",
                    "source=$source openPositions=$preservedOpenCount mapSize=${status.tokens.size} action=no_liquidation_no_clear",
                )
            } catch (_: Throwable) {}
            addLog("вҶ» Soft stop/restart: preserving open positions (source=$source)")
        }

        if (liquidateOnStop) {
        // IMPORTANT: Close all open positions BEFORE stopping.
        // V5.9.1078 вҖ” liquidation is no longer unconditional. Only confirmed
        // operator STOP/halt reset may close positions with bot_shutdown.
        // Internal/config/lifecycle stops preserve positions and skip this block.
        // V5.9.661 вҖ” UNCONDITIONAL on every manual stop. Per operator mandate,
        // every stop MUST close all open positions and sweep the live
        // wallet, regardless of the legacy cfg.closePositionsOnStop
        // toggle. That flag is now ignored for safety: live tokens
        // stranded in the host wallet, and paper SOL never returning,
        // were both traced to this gate being false.
        try {
            val cfg = ConfigStore.load(applicationContext)

            run {
                val effectiveBalance = status.getEffectiveBalance(cfg.paperMode)

                // V5.9.454 вҖ” STOP-PATH WALLET RECOVERY.
                // On live stop, the local `wallet` var may have been
                // nulled by an earlier RPC hiccup (see WalletManager
                // preservation fix) or by the old launchWalletConnect
                // race. If it's null here, held tokens would stay
                // stranded in the host wallet because closeAllPositions
                // and liveSweepWalletTokens both need a live wallet.
                //
                // Do one synchronous attemptReconnect before giving up
                // so the user's positions actually liquidate.
                if (!cfg.paperMode && wallet == null) {
                    try {
                        ErrorLogger.warn("BotService",
                            "рҹҡЁ STOP: live wallet is null вҖ” attempting reconnect so held tokens can be swept")
                        addLog("рҹҡЁ STOP: reconnecting wallet to sell held tokensвҖҰ")
                        val recovered = com.lifecyclebot.engine.WalletManager.attemptReconnect()
                        if (recovered != null) {
                            wallet = recovered
                            addLog("вң… Wallet reconnected for shutdown sweep")
                            ErrorLogger.info("BotService", "вң… STOP: wallet recovered for shutdown sweep")
                        } else {
                            ErrorLogger.error("BotService",
                                "вқҢ STOP: wallet reconnect failed вҖ” held tokens will remain in host wallet")
                            addLog("вқҢ STOP: wallet reconnect failed вҖ” held tokens will NOT be sold")
                        }
                    } catch (e: Exception) {
                        ErrorLogger.error("BotService", "STOP reconnect threw: ${e.message}", e)
                    }
                }
                
                // Get a synchronized copy of tokens to avoid ConcurrentModificationException
                val tokensCopy = synchronized(status.tokens) {
                    status.tokens.toMap()
                }

                // V5.9.681 вҖ” AGGRESSIVE EARLY UI CLEAR (operator regression fix).
                //
                // Previous flow ran closeAllPositions() FIRST (which does
                // per-position paperSell() + heavy learning code, ~500ms each),
                // then 7 lane-trader clears, then trackers, THEN finally
                // status.tokens.clear() + PositionPersistence.clear().
                //
                // Operator screenshot V5.9.680: 10+ paper positions still on UI
                // after pressing Stop. Root cause: with 10 open positions, the
                // per-token paperSell learning loop takes 5+ seconds. The bot
                // loop may also be frozen mid-cycle (cycle 3 wedged at 170s+),
                // holding monitors that block stopBot's downstream work. So
                // status.tokens never reaches the late clear() call within the
                // window the user looks at the screen.
                //
                // Fix: clear status.tokens AND PositionPersistence RIGHT NOW,
                // before any heavy work. The tokensCopy snapshot already holds
                // the live TokenState references so closeAllPositions() and the
                // sub-trader close loops downstream still operate on real data
                // for learning purposes. UI sees a clean state immediately, and
                // even if the process is killed during the slow paperSell loop,
                // persistence is already wiped so the next start can't restore
                // ghosts.
                // V5.9.1003-FIX: Clear in-memory tokens early (UI fast-clear) but
                // do NOT clear PositionPersistence until AFTER closeAllPositions.
                // Treasury live positions: if PositionPersistence.clear() fires first
                // and the process is killed mid-close, the positions are orphaned on-chain
                // (persistence wiped вҶ’ next boot restorePositions finds nothing).
                // Keep positions in persistence until the sell loop completes so the
                // next-boot reconciler can adopt any that didn't close cleanly.
                run {
                    try {
                        synchronized(status.tokens) {
                            status.tokens.clear()
                        }
                        try { GlobalTradeRegistry.reset() } catch (_: Throwable) {}
                        ForensicLogger.lifecycle(
                            "STOP_EARLY_TOKENS_CLEARED",
                            "snapshotSize=${tokensCopy.size}"
                        )
                    } catch (e: Throwable) {
                        ErrorLogger.warn("BotService", "early tokens clear: ${e.message}")
                    }
                    // PositionPersistence.clear() intentionally moved AFTER closeAllPositions below.
                }

                val closedCount = executor.closeAllPositions(
                    tokens = tokensCopy,
                    wallet = wallet,
                    walletSol = effectiveBalance,
                    paperMode = cfg.paperMode,
                )
                
                if (closedCount > 0) {
                    addLog("вң… Closed $closedCount position(s) before shutdown")
                }

                // V5.9.1003-FIX: Clear persistence AFTER close loop so treasury/live
                // positions aren't orphaned if the process dies mid-sell.
                try {
                    PositionPersistence.clear()
                    ForensicLogger.lifecycle("STOP_PERSIST_CLEARED_POST_CLOSE", "closedCount=$closedCount")
                } catch (e: Throwable) {
                    ErrorLogger.warn("BotService", "post-close persist clear: ${e.message}")
                }

                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V5.9.261 вҖ” LIVE WALLET SWEEP (chronic 1-month sell bug fix)
                // Layer traders (ShitCoin/Moonshot/BlueChip/Manip/Express/Quality)
                // do only in-memory accounting in their closePosition() paths вҖ”
                // they never broadcast a Jupiter sell. Sweep the wallet now so
                // every meme/altcoin actually returns to SOL before shutdown.
                // Stablecoins + SOL are preserved.
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                if (!cfg.paperMode && wallet != null) {
                    try {
                        val swept = executor.liveSweepWalletTokens(wallet!!, effectiveBalance)
                        if (swept > 0) {
                            addLog("рҹ’° Wallet sweep: liquidated $swept on-chain holding(s) to SOL")
                        }
                    } catch (sweepEx: Exception) {
                        ErrorLogger.error("BotService", "Wallet sweep failed: ${sweepEx.message}", sweepEx)
                        addLog("вҡ пёҸ Wallet sweep error: ${sweepEx.message?.take(80)}")
                    }
                }
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V4.0 FIX: Also close Treasury Mode positions
                // Treasury tracks positions separately in CashGenerationAI
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                try {
                    val treasuryPositions = com.lifecyclebot.v3.scoring.CashGenerationAI.getActivePositions()
                    if (treasuryPositions.isNotEmpty()) {
                        addLog("рҹ’° Closing ${treasuryPositions.size} Treasury position(s)...")
                        for (tPos in treasuryPositions) {
                            try {
                                val ts = tokensCopy[tPos.mint]
                                val currentPrice = ts?.lastPrice ?: ts?.ref ?: tPos.entryPrice
                                
                                // Close the treasury position tracking
                                com.lifecyclebot.v3.scoring.CashGenerationAI.closePosition(
                                    mint = tPos.mint,
                                    exitPrice = currentPrice,
                                    exitReason = com.lifecyclebot.v3.scoring.CashGenerationAI.ExitSignal.TIME_EXIT
                                )
                                recentlyClosedMs[tPos.mint] = System.currentTimeMillis()
                                addLog("рҹ’° Closed Treasury position: ${tPos.symbol}", tPos.mint)
                            } catch (te: Exception) {
                                addLog("вҡ пёҸ Failed to close Treasury ${tPos.symbol}: ${te.message}", tPos.mint)
                            }
                        }
                    }
                } catch (treasuryEx: Exception) {
                    ErrorLogger.error("BotService", "Error closing Treasury positions: ${treasuryEx.message}", treasuryEx)
                }
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V4.0 FIX: Also close Blue Chip positions
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                try {
                    val blueChipPositions = com.lifecyclebot.v3.scoring.BlueChipTraderAI.getActivePositions()
                    if (blueChipPositions.isNotEmpty()) {
                        addLog("рҹ”ө Closing ${blueChipPositions.size} Blue Chip position(s)...")
                        for (bcPos in blueChipPositions) {
                            try {
                                val ts = tokensCopy[bcPos.mint]
                                val currentPrice = ts?.lastPrice ?: ts?.ref ?: bcPos.entryPrice
                                
                                com.lifecyclebot.v3.scoring.BlueChipTraderAI.closePosition(
                                    mint = bcPos.mint,
                                    exitPrice = currentPrice,
                                    exitReason = com.lifecyclebot.v3.scoring.BlueChipTraderAI.ExitSignal.TIME_EXIT
                                )
                                addLog("рҹ”ө Closed Blue Chip position: ${bcPos.symbol}", bcPos.mint)
                            } catch (bcEx: Exception) {
                                addLog("вҡ пёҸ Failed to close BlueChip ${bcPos.symbol}: ${bcEx.message}", bcPos.mint)
                            }
                        }
                    }
                } catch (bcEx: Exception) {
                    ErrorLogger.error("BotService", "Error closing BlueChip positions: ${bcEx.message}", bcEx)
                }
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V4.0 FIX: Also close ShitCoin positions
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                try {
                    val shitCoinPositions = com.lifecyclebot.v3.scoring.ShitCoinTraderAI.getActivePositions()
                    if (shitCoinPositions.isNotEmpty()) {
                        addLog("рҹ’© Closing ${shitCoinPositions.size} ShitCoin position(s)...")
                        for (scPos in shitCoinPositions) {
                            try {
                                val ts = tokensCopy[scPos.mint]
                                val currentPrice = ts?.lastPrice ?: ts?.ref ?: scPos.entryPrice
                                
                                com.lifecyclebot.v3.scoring.ShitCoinTraderAI.closePosition(
                                    mint = scPos.mint,
                                    exitPrice = currentPrice,
                                    exitReason = com.lifecyclebot.v3.scoring.ShitCoinTraderAI.ExitSignal.TIME_EXIT
                                )
                                addLog("рҹ’© Closed ShitCoin position: ${scPos.symbol}", scPos.mint)
                            } catch (scEx: Exception) {
                                addLog("вҡ пёҸ Failed to close ShitCoin ${scPos.symbol}: ${scEx.message}", scPos.mint)
                            }
                        }
                    }
                    // V5.2: Force clear all ShitCoin positions to ensure UI updates
                    com.lifecyclebot.v3.scoring.ShitCoinTraderAI.clearAllPositions()
                } catch (scEx: Exception) {
                    ErrorLogger.error("BotService", "Error closing ShitCoin positions: ${scEx.message}", scEx)
                }
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V5.2: Also close ShitCoinExpress positions
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                try {
                    com.lifecyclebot.v3.scoring.ShitCoinExpress.clearAllRides()
                    addLog("рҹ’©рҹҡӮ Cleared ShitCoin Express rides")
                } catch (scEx: Exception) {
                    ErrorLogger.error("BotService", "Error clearing ShitCoin Express: ${scEx.message}", scEx)
                }

                // вҳ пёҸ Clear Manipulated positions
                try {
                    com.lifecyclebot.v3.scoring.ManipulatedTraderAI.clearAll()
                    addLog("вҳ пёҸ Cleared Manipulated positions")
                } catch (mEx: Exception) {
                    ErrorLogger.error("BotService", "Error clearing Manipulated positions: ${mEx.message}", mEx)
                }
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V5.2.12: Also close Quality positions
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                try {
                    val qualityPositions = com.lifecyclebot.v3.scoring.QualityTraderAI.getActivePositions()
                    if (qualityPositions.isNotEmpty()) {
                        addLog("вӯҗ Closing ${qualityPositions.size} Quality position(s)...")
                        for (qPos in qualityPositions) {
                            try {
                                val ts = tokensCopy[qPos.mint]
                                val currentPrice = ts?.lastPrice ?: ts?.ref ?: qPos.entryPrice
                                
                                com.lifecyclebot.v3.scoring.QualityTraderAI.closePosition(
                                    mint = qPos.mint,
                                    exitPrice = currentPrice,
                                    exitSignal = com.lifecyclebot.v3.scoring.QualityTraderAI.ExitSignal.TIME_EXIT
                                )
                                addLog("вӯҗ Closed Quality position: ${qPos.symbol}", qPos.mint)
                            } catch (qEx: Exception) {
                                addLog("вҡ пёҸ Failed to close Quality ${qPos.symbol}: ${qEx.message}", qPos.mint)
                            }
                        }
                    }
                } catch (qEx: Exception) {
                    ErrorLogger.error("BotService", "Error closing Quality positions: ${qEx.message}", qEx)
                }
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V5.2.12: Also close Moonshot positions
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                try {
                    val moonshotPositions = com.lifecyclebot.v3.scoring.MoonshotTraderAI.getActivePositions()
                    if (moonshotPositions.isNotEmpty()) {
                        addLog("рҹҡҖ Closing ${moonshotPositions.size} Moonshot position(s)...")
                        for (mPos in moonshotPositions) {
                            try {
                                val ts = tokensCopy[mPos.mint]
                                val currentPrice = ts?.lastPrice ?: ts?.ref ?: mPos.entryPrice
                                
                                com.lifecyclebot.v3.scoring.MoonshotTraderAI.closePosition(
                                    mint = mPos.mint,
                                    exitPrice = currentPrice,
                                    exitReason = com.lifecyclebot.v3.scoring.MoonshotTraderAI.ExitSignal.TIMEOUT
                                )
                                addLog("рҹҡҖ Closed Moonshot position: ${mPos.symbol}", mPos.mint)
                            } catch (mEx: Exception) {
                                addLog("вҡ пёҸ Failed to close Moonshot ${mPos.symbol}: ${mEx.message}", mPos.mint)
                            }
                        }
                    }
                } catch (mEx: Exception) {
                    ErrorLogger.error("BotService", "Error closing Moonshot positions: ${mEx.message}", mEx)
                }
                
                // Also purge any orphaned tokens (live mode only)
                if (!cfg.paperMode && wallet != null) {
                    purgeOrphanedTokensOnStop(cfg)
                }
            }
        } catch (e: Exception) {
            addLog("вҡ пёҸ Error closing positions on shutdown: ${e.message}")
            ErrorLogger.error("BotService", "Error closing positions on shutdown: ${e.message}", e)
        }
        
        // V5.2 FIX: ALWAYS clear all layer positions when bot stops, regardless of closePositionsOnStop setting
        // This ensures the UI doesn't show stale positions after a bot stop/crash
        //
        // V5.9.679 вҖ” DEFENSIVE per-step clears (P0 bug fix).
        //
        // Operator screenshot: 6 paper positions persisted on the UI after
        // pressing Stop. Root cause: the previous single try-catch wrapped
        // SEVEN lane-trader clears + a LiveWalletReconciler pass + TWO
        // tracker clears in one block. If ANY of the lane traders threw
        // (a defensive throw inside CashGen/BlueChip/ShitCoin/etc), the
        // SHARED catch at the bottom skipped the trackers вҖ” and the UI's
        // open-counter does maxOf(tokens, hostTracker, lifecycleTracker)
        // so the tracker leak alone keeps the badge non-zero.
        //
        // Fix: each clear gets its own try-catch. Trackers ALWAYS run in a
        // dedicated final try regardless of upstream failures. Also emit
        // STOP_CLEAR_STEP forensic events so the next dump shows EXACTLY
        // which step failed if this regression ever recurs.
        try {
            try { com.lifecyclebot.v3.scoring.CashGenerationAI.clearAllPositions() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear CashGen: ${e.message}") }
            try { com.lifecyclebot.v3.scoring.BlueChipTraderAI.clearAllPositions() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear BlueChip: ${e.message}") }
            try { com.lifecyclebot.v3.scoring.ShitCoinTraderAI.clearAllPositions() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear ShitCoin: ${e.message}") }
            try { com.lifecyclebot.v3.scoring.ShitCoinExpress.clearAllRides() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear ShitCoinExpress: ${e.message}") }
            try { com.lifecyclebot.v3.scoring.ManipulatedTraderAI.clearAll() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear Manipulated: ${e.message}") }
            try { com.lifecyclebot.v3.scoring.QualityTraderAI.clearAllPositions() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear Quality: ${e.message}") }
            try { com.lifecyclebot.v3.scoring.MoonshotTraderAI.clearAllPositions() }
                catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear Moonshot: ${e.message}") }
            // V5.9.665 вҖ” operator regression fix.
            // Before wiping HostWalletTokenTracker / TokenLifecycleTracker,
            // give LiveWalletReconciler one synchronous pass so any swap
            // that landed on chain after the last verifyWalletDelta poll
            // (Jupiter ATA still settling) is captured into the position
            // store BEFORE the trackers get cleared. Without this, late-
            // landing swaps would be silently dropped on stop.
            try {
                val w = wallet
                if (w != null) {
                    com.lifecyclebot.engine.sell.LiveWalletReconciler.reconcileNow(w, "stop_pre_tracker_clear")
                }
            } catch (rcEx: Throwable) {
                ErrorLogger.debug("BotService", "pre-clear reconcile soft-failed: ${rcEx.message}")
            }
        } catch (clearEx: Exception) {
            ErrorLogger.error("BotService", "Error clearing layer positions: ${clearEx.message}", clearEx)
        }
        // V5.9.679 вҖ” trackers ALWAYS clear, even if every lane trader
        // above threw. This is the dedicated final guard for the UI
        // open-counter maxOf computation.
        // V5.9.661c вҖ” also wipe the lifecycle + host-wallet trackers
        // so the main UI "Open" counter (uses maxOf of all sources)
        // actually drops to 0. Operator: 'still showed 11 as per
        // screen shot with the bot off'. Root cause was these two
        // trackers retaining their counts past stop.
        // V5.9.777 вҖ” EMERGENT MEME-ONLY stop-bot live preservation.
        // Operator forensics: WC2026 / early / GOAT vanished from host
        // tracker after a stop/start cycle because clearAll() wiped
        // live OPEN_TRACKING positions. In LIVE mode we now call
        // clearPaperOnly() which preserves every live wallet-backed
        // position (BUY_CONFIRMED / HELD_IN_WALLET / OPEN_TRACKING /
        // EXIT_SIGNALLED / SELL_PENDING / SELL_VERIFYING). PAPER mode
        // still uses clearAll() because there's no on-chain truth to
        // preserve. The lifecycle tracker keeps its existing clearAll
        // behaviour вҖ” it's an ephemeral state machine, not wallet truth.
        val liveStop = try {
            !ConfigStore.load(applicationContext).paperMode
        } catch (_: Throwable) {
            false  // safe default вҖ” if config read fails, behave like PAPER (full clear)
        }
        try { com.lifecyclebot.engine.TokenLifecycleTracker.clearAll() }
            catch (e: Throwable) { ErrorLogger.warn("BotService", "stop-clear LifecycleTracker: ${e.message}") }
        try {
            if (liveStop) {
                com.lifecyclebot.engine.HostWalletTokenTracker.clearPaperOnly()
            } else {
                com.lifecyclebot.engine.HostWalletTokenTracker.clearAll()
            }
        } catch (e: Throwable) {
            ErrorLogger.warn("BotService", "stop-clear HostWalletTracker: ${e.message}")
        }
        try {
            ForensicLogger.lifecycle(
                "STOP_TRACKERS_CLEARED",
                "lifecycleCleared=true hostCleared=${if (liveStop) "PAPER_ONLY" else "ALL"} mode=${if (liveStop) "LIVE" else "PAPER"}"
            )
        } catch (_: Throwable) {}
        addLog("вң… Cleared trackers (host=${if (liveStop) "PAPER_ONLY В· live positions preserved" else "ALL"})")
        
        // V5.2.12 FIX: Also clear position.isOpen flags in status.tokens
        // This is what the UI reads - critical to prevent stale position display
        // Note: isOpen is a computed property (qtyToken > 0), so we replace with empty Position
        //
        // V5.9.777 вҖ” EMERGENT MEME-ONLY: in LIVE mode, do NOT clear live
        // position flags. The wallet still holds the tokens; clearing the
        // in-memory flag desyncs the UI from on-chain truth and causes
        // restart races where paper sells overwrite the live position.
        // Paper positions are still cleared because there's no on-chain
        // truth to preserve.
        try {
            synchronized(status.tokens) {
                status.tokens.values.forEach { ts ->
                    if (ts.position.isOpen) {
                        if (liveStop && !ts.position.isPaperPosition) {
                            // Preserve live wallet-backed position.
                            ErrorLogger.debug("BotService", "рҹ”’ Preserved LIVE position for ${ts.symbol} on stopBot")
                        } else {
                            ts.position = Position()
                            ErrorLogger.debug("BotService", "Cleared position for ${ts.symbol}")
                        }
                    }
                }
            }
            addLog("вң… Cleared token position flags (live positions preserved: $liveStop)")
        } catch (tokensEx: Exception) {
            ErrorLogger.error("BotService", "Error clearing token positions: ${tokensEx.message}", tokensEx)
        }

        // V5.6: Clear the watchlist so UI shows clean state after stop
        // Learning data is persisted in trade DB вҖ” status.tokens is just the live runtime cache
        //
        // V5.9.777 вҖ” EMERGENT MEME-ONLY: in LIVE mode, retain mints that
        // still have an open live position so restart can find them.
        try {
            val _preClearCount = status.tokens.values.count { it.position.isOpen }
            synchronized(status.tokens) {
                if (liveStop) {
                    // Retain only live open positions; drop the rest.
                    val keepKeys = status.tokens.entries.asSequence()
                        .filter { it.value.position.isOpen && !it.value.position.isPaperPosition }
                        .map { it.key }
                        .toSet()
                    val it = status.tokens.entries.iterator()
                    while (it.hasNext()) {
                        if (it.next().key !in keepKeys) it.remove()
                    }
                    ErrorLogger.info("BotService", "рҹ”’ stopBot LIVE: retained ${keepKeys.size} open mints in watchlist")
                } else {
                    status.tokens.clear()
                }
            }
            if (!liveStop) GlobalTradeRegistry.reset()
            try {
                ForensicLogger.lifecycle(
                    "STOP_TOKENS_CLEARED",
                    "preClearOpen=$_preClearCount mapSize=${status.tokens.size} liveStop=$liveStop"
                )
            } catch (_: Throwable) {}
            addLog("вң… Watchlist ${if (liveStop) "trimmed (live mints kept)" else "cleared"}")
        } catch (clearEx: Exception) {
            ErrorLogger.error("BotService", "Error clearing watchlist on stop: ${clearEx.message}", clearEx)
        }

        // V5.6.10 FIX: Also clear PositionPersistence so positions don't restore on restart
        // Without this, positions reappear after bot stop вҶ’ start cycle
        try {
            PositionPersistence.clear()
            persistenceFinalizedByStop = true
            try {
                ForensicLogger.lifecycle("STOP_PERSIST_CLEARED", "ok=true finalizedByStop=true")
            } catch (_: Throwable) {}
            addLog("вң… Cleared position persistence вҖ” positions won't restore on restart")
        } catch (persistEx: Exception) {
            ErrorLogger.error("BotService", "Error clearing position persistence: ${persistEx.message}", persistEx)
            try {
                ForensicLogger.lifecycle("STOP_PERSIST_CLEARED", "ok=false err=${persistEx.message?.take(60)}")
            } catch (_: Throwable) {}
        }

        }

        status.running = false
        loopJob?.cancel()
        orchestrator?.stop()
        orchestrator = null
        marketScanner?.stop(); marketScanner = null
        // V5.9.484 вҖ” disconnect external push streams + LLM client
        try { unwireExternalStreams() } catch (_: Exception) {}
        networkCallback?.let {
            (getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager)
                .unregisterNetworkCallback(it)
        }
        networkCallback = null
        TreasuryManager.save(applicationContext)
        botBrain?.stop(); botBrain = null
        tradeDb?.close(); tradeDb = null
        // Cancel keep-alive alarm only on explicit manual stop. Soft/restart
        // stops must keep resurrection available.
        if (liquidateOnStop) cancelKeepAliveAlarm()
        // Cancel watchdog only on explicit manual stop. Soft/restart stops must
        // remain resurrectable and must not arm the manual-stop dead latch.
        if (liquidateOnStop) ServiceWatchdog.cancel(applicationContext)
        // Stop self-healing diagnostics
        try {
            SelfHealingDiagnostics.stop()
        } catch (e: Exception) {
            ErrorLogger.debug("BotService", "SelfHealingDiagnostics stop error: ${e.message}")
        }
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // NOTE: ShadowLearningEngine is NOT stopped here!
        // Shadow learning should continue running persistently as a constant
        // state of learning, even when the bot is stopped or paper mode is off.
        // It will keep tracking market data and learning from opportunities.
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        
        // V5.9.40/42: Clear the "was running" flag FIRST (before stopForeground/stopSelf).
        // Previously this happened AFTER stopSelf() so a fast process-kill dropped
        // the write and AATEApp saw stale wasRunning=true on next launch вҶ’ silent
        // auto-restart.
        //
        // V5.9.42: Use .apply() (async) not .commit() вҖ” .commit() does sync disk IO
        // on the main thread and triggered an ANR on stop. Because the write is
        // queued BEFORE all the heavy shutdown work (TreasuryManager.save, trader
        // closeAll, stopForeground/stopSelf), SharedPreferences has plenty of time
        // to flush before the process dies.
        try {
            getSharedPreferences(RUNTIME_PREFS, android.content.Context.MODE_PRIVATE)
                .edit()
                .putBoolean(KEY_WAS_RUNNING_BEFORE_SHUTDOWN, softStopPreservePositions)
                .putBoolean(KEY_MANUAL_STOP_REQUESTED, liquidateOnStop && !userStartQueuedDuringStop)
                .apply()
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "Failed to clear was_running flag: ${e.message}", e)
        }

        // REMOVED: walletManager.disconnect() 
        // V5.9.157 вҖ” reorder teardown so every trader.stop() and
        // closeAllPositions() runs BEFORE stopForeground/stopSelf. Previously
        // stopSelf() fired first and the remaining coroutine kept running on
        // the BotService scope; Android then auto-recreated the service via
        // START_STICKY (user log 00:08:37 'onCreate starting'), and the OLD
        // coroutine's tail reached trader.stop() 24s later, stopping the
        // NEW service's traders (user log 00:08:50 'CryptoAltTrader STOPPED'
        // AFTER the new instance started at 00:08:37). Symptom: bot refused
        // to restart no matter how many times the user tapped Start.
        //
        // V5.9.5: Close all Markets positions then stop all traders when main bot stops
        try {
            com.lifecyclebot.perps.TokenizedStockTrader.closeAllPositions()
            com.lifecyclebot.perps.CommoditiesTrader.closeAllPositions()
            com.lifecyclebot.perps.MetalsTrader.closeAllPositions()
            com.lifecyclebot.perps.ForexTrader.closeAllPositions()
            com.lifecyclebot.perps.CryptoAltTrader.closeAllPositions()
            kotlinx.coroutines.runBlocking { com.lifecyclebot.perps.PerpsExecutionEngine.closeAllPositions() }
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "Error closing markets positions: ${e.message}", e)
        }
        try {
            com.lifecyclebot.perps.TokenizedStockTrader.stop()
            com.lifecyclebot.perps.CommoditiesTrader.stop()
            com.lifecyclebot.perps.MetalsTrader.stop()
            com.lifecyclebot.perps.ForexTrader.stop()
            com.lifecyclebot.perps.CryptoAltTrader.stop()
            com.lifecyclebot.perps.PerpsExecutionEngine.stop()
            ErrorLogger.info("BotService", "All Markets traders stopped + positions closed alongside main bot")
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "Error stopping markets traders: ${e.message}", e)
        }

        // V4.0: Reset initialization flags so services can reinit on next start
        tradingModesInitialized = false
        allTradingLayersReady = false

        // Wallet should ONLY disconnect when user explicitly requests it
        // This allows wallet to stay connected when:
        // - Bot is stopped
        // - App is minimized
        // - App crashes and restarts
        // V5.9.679 вҖ” emit STOP_COMPLETE BEFORE stopForeground/stopSelf so
        // the next dump shows the full clearing chain ran end-to-end.
        // Counters captured here let the operator verify in one look:
        // status.tokens.size MUST be 0, host/lifecycle trackers MUST be 0.
        try {
            // V5.9.764 вҖ” EMERGENT item C: tear down the SellReconciler so
            // it doesn't keep ticking after Stop and won't survive into
            // the next paper-mode start.
            com.lifecyclebot.engine.sell.SellReconciler.stop()
            // V5.9.777 вҖ” also stop the LiveWalletReconciler periodic tick
            // on bot stop so it doesn't keep hammering the wallet RPC.
            try { com.lifecyclebot.engine.sell.LiveWalletReconciler.stop() } catch (_: Throwable) {}
            // V5.9.779 вҖ” clear EnabledTraderAuthority so any post-stop
            // scanner/engine straggler immediately short-circuits.
            try { com.lifecyclebot.engine.EnabledTraderAuthority.clear() } catch (_: Throwable) {}
        } catch (_: Throwable) {}

        try {
            val _finalTokens = status.tokens.size
            val _finalHostOpen = try {
                com.lifecyclebot.engine.HostWalletTokenTracker.getOpenTrackedPositions().size
            } catch (_: Throwable) { -1 }
            val _finalLifeOpen = try {
                com.lifecyclebot.engine.TokenLifecycleTracker.openCount()
            } catch (_: Throwable) { -1 }
            ForensicLogger.lifecycle(
                "STOP_COMPLETE",
                "gen=$stopGeneration tokens=$_finalTokens host=$_finalHostOpen life=$_finalLifeOpen"
            )
            BotRuntimeController.publishStopped(stopGeneration, source)
        } catch (_: Throwable) {}
        stopForeground(STOP_FOREGROUND_REMOVE)
        stopSelf()
        wakeLock?.let { if (it.isHeld) it.release() }
        wakeLock = null
        try { wifiLock6032?.let { if (it.isHeld) it.release() } } catch (_: Throwable) {}
        wifiLock6032 = null
        
        addLog("Bot stopped. All positions closed. Wallet remains connected.")
        
        // Show Toast on UI thread for immediate feedback
        android.os.Handler(android.os.Looper.getMainLooper()).post {
            android.widget.Toast.makeText(
                applicationContext,
                "рҹӣ‘ Bot Stopped\nAll positions closed",
                android.widget.Toast.LENGTH_LONG
            ).show()
        }
        
        // Send Telegram notification for bot stop
        sendTradeNotif(
            "рҹӣ‘ Bot Stopped",
            "All positions closed. Wallet remains connected.",
            NotificationHistory.NotifEntry.NotifType.INFO
        )
        } finally {
            // V5.9.148 вҖ” always clear, even on early return/exception, so any
            // queued restart in onStartCommand can proceed.
            stopInProgress = false
            BotRuntimeController.publishStopped(stopGeneration, source)
            try { ForensicLogger.lifecycle("LIFECYCLE_STOP_COMPLETE", "source=$source liquidate=$liquidateOnStop softPreserve=$softStopPreservePositions") } catch (_: Throwable) {}
        }
    }
    
    // Keep-alive alarm to ensure service restarts if killed
    private fun scheduleKeepAliveAlarm() {
        val scheduleNowMs = System.currentTimeMillis()
        if (scheduleNowMs - lastKeepAliveAlarmScheduledMs < 45_000L) {
            try { ForensicLogger.lifecycle("KEEPALIVE_ALARM_THROTTLED", "ageMs=${scheduleNowMs - lastKeepAliveAlarmScheduledMs}") } catch (_: Throwable) {}
            return
        }
        lastKeepAliveAlarmScheduledMs = scheduleNowMs
        // V5.9.714 вҖ” Keep-alive alarm redesign.
        //
        // Previous design used setAlarmClock() as the primary, which:
        //   (a) Shows a clock icon in the status bar on every device вҖ” intrusive.
        //   (b) Requires SCHEDULE_EXACT_ALARM (Android 12+) which some OEMs
        //       silently deny without a user-visible prompt, causing the whole
        //       chain to fail with a SecurityException swallowed in the catch block.
        //
        // New design:
        //   вҖў PRIMARY  (rc=999): setExactAndAllowWhileIdle вҖ” no status-bar icon,
        //     no extra permission required, fires within ~10s when not in deep Doze.
        //   вҖў BACKUP   (rc=997): setExactAndAllowWhileIdle at +120s вҖ” belt-and-
        //     suspenders in case the 60s primary is briefly deferred.
        //   вҖў DOZE-BYPASS (rc=998): setAlarmClock at +70s вҖ” only scheduled if the
        //     device is confirmed to be in Doze (pm.isDeviceIdleMode()). Fires
        //     through Doze unconditionally but we only use it when we actually
        //     need it so the clock icon doesn't appear during normal operation.
        //
        // The ACTION_START handler in onStartCommand already reschedules the next
        // alarm on every keep-alive delivery, so this forms a self-healing chain.
        val restartIntent = Intent(applicationContext, BotService::class.java).apply {
            action = ACTION_START
        }
        val am = getSystemService(android.app.AlarmManager::class.java) ?: return
        val now = System.currentTimeMillis()

        // Primary: 60s
        try {
            val pi = android.app.PendingIntent.getService(
                this, 999, restartIntent,
                android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
            )
            am.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, now + 60_000L, pi)
            ErrorLogger.info("BotService", "Keep-alive alarm set (60s primary)")
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "Keep-alive primary alarm failed: ${e.message}")
        }

        // Backup: 120s
        try {
            val backupPi = android.app.PendingIntent.getService(
                this, 997, restartIntent,
                android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
            )
            am.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, now + 120_000L, backupPi)
        } catch (_: Exception) {}

        // V5.9.913 вҖ” FGS-BYPASS AlarmClock arm (UNCONDITIONAL).
        //
        // Previous logic only armed the setAlarmClock backup when
        // pm.isDeviceIdleMode() returned true. The operator reports
        // the bot self-stopping and the screenshots show no clock-icon
        // in the status bar, so the inDoze branch is mostly never
        // taking effect вҖ” meaning the only restart path is the 60s
        // setExactAndAllowWhileIdle primary, which DOES fire but
        // when delivered to a backgrounded app on Android 12+ throws
        // ForegroundServiceStartNotAllowedException (silently
        // swallowed in BotService.onStartCommand error paths).
        //
        // New behaviour: ALWAYS arm the setAlarmClock cousin at +75s.
        // setAlarmClock IS exempt from background-start FGS
        // restrictions because it's classified as a user-facing
        // alarm. The status-bar icon is a small cost to pay for
        // a bot that actually stays alive вҖ” and modern setAlarmClock
        // on most OEMs no longer shows the persistent clock icon
        // (only on the lockscreen at the wake time).
        //
        // This forms a triple-redundant keep-alive: primary (60s
        // setExactAndAllowWhileIdle), backup (120s setExactAndAllowWhileIdle),
        // FGS-safe (75s setAlarmClock). At least one of these
        // SHALL deliver an ACTION_START that successfully starts
        // the service.
        try {
            val showPi = android.app.PendingIntent.getActivity(
                this, 996,
                Intent(applicationContext, com.lifecyclebot.ui.MainActivity::class.java),
                android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
            )
            val safePi = android.app.PendingIntent.getService(
                this, 998, restartIntent,
                android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
            )
            am.setAlarmClock(
                android.app.AlarmManager.AlarmClockInfo(now + 75_000L, showPi),
                safePi
            )
            ErrorLogger.info("BotService", "FGS-bypass AlarmClock armed (75s вҖ” unconditional)")
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "FGS-bypass AlarmClock arm failed: ${e.message}")
        }

        // Start self-healing diagnostics (runs every 3 hours)
        try {
            SelfHealingDiagnostics.start(scope)
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "Failed to start SelfHealingDiagnostics: ${e.message}")
        }
    }
    
    // V5.9.1000 вҖ” cancelAllRestartAlarms() extracted to BotServiceLifecycleExt.kt

    private fun cancelKeepAliveAlarm() {
        cancelAllRestartAlarms()
        ErrorLogger.info("BotService", "Keep-alive alarms cancelled")
    }

    // V5.9.1000 вҖ” scheduleLoopHeartbeatAlarm() extracted to BotServiceLifecycleExt.kt

    // V5.9.1000 вҖ” cancelLoopHeartbeatAlarm() extracted to BotServiceLifecycleExt.kt

    // в”Җв”Җ V5.9.675 вҖ” BATTERY OPTIMISATION WHITELIST в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    //
    // Even with a foreground service + PARTIAL_WAKE_LOCK, Doze suspends
    // the entire process (and our coroutines) unless the user has
    // whitelisted the app under Settings вҶ’ Apps вҶ’ Battery вҶ’ Unrestricted.
    // We check on every bot start, log the result, and the first time we
    // find we're NOT whitelisted, we kick the system dialog so the user
    // can fix it in one tap. MainActivity also surfaces a banner via the
    // sticky RUNTIME_PREFS flag.
    private fun checkAndPromptBatteryOptimisation() {
        val pm = getSystemService(Context.POWER_SERVICE) as? PowerManager ?: return
        val whitelisted = pm.isIgnoringBatteryOptimizations(packageName)
        try {
            getSharedPreferences(RUNTIME_PREFS, Context.MODE_PRIVATE)
                .edit()
                .putBoolean("battery_opt_whitelisted", whitelisted)
                .apply()
        } catch (_: Throwable) {}
        ForensicLogger.lifecycle(
            "BATTERY_OPT_CHECK",
            "whitelisted=$whitelisted pkg=$packageName"
        )
        if (whitelisted) {
            ErrorLogger.info("BotService", "вң… Battery optimisation: app is WHITELISTED (Doze cannot suspend bot loop)")
            return
        }
        ErrorLogger.warn(
            "BotService",
            "вҡ пёҸ Battery optimisation NOT whitelisted вҖ” Doze will suspend bot loop on screen-off. Prompting user."
        )
        addLog("вҡ пёҸ Battery optimisation must be disabled for 24/7 trading. Tap the banner to fix.")
        // Fire the system dialog at most once per process start. The dialog
        // launches the per-app exemption screen; on Samsung this is a
        // confirmation popup with "Allow" / "Cancel".
        val prefs = getSharedPreferences(RUNTIME_PREFS, Context.MODE_PRIVATE)
        val alreadyPromptedThisSession = prefs.getBoolean("battery_opt_prompted_session", false)
        if (alreadyPromptedThisSession) return
        try {
            @android.annotation.SuppressLint("BatteryLife")
            val intent = Intent(android.provider.Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS)
                .setData(android.net.Uri.parse("package:$packageName"))
                .addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
            startActivity(intent)
            prefs.edit().putBoolean("battery_opt_prompted_session", true).apply()
        } catch (e: Throwable) {
            ErrorLogger.warn("BotService", "Battery-opt prompt failed: ${e.message}")
        }
    }

    /** V5.9.675 вҖ” read-only accessor used by MainActivity for the banner. */
    fun isBatteryOptWhitelisted(): Boolean {
        return try {
            val pm = getSystemService(Context.POWER_SERVICE) as? PowerManager
            pm?.isIgnoringBatteryOptimizations(packageName) ?: false
        } catch (_: Throwable) { false }
    }

    // в”Җв”Җ V5.9.484 вҖ” external push-data streams + LLM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Wire the four push integrations introduced in V5.9.484:
     *   вҖў PumpPortal WS  вҶ’ pump.fun new launches + migrations (5вҖ“30s before
     *                      DexScreener/Birdeye see them)
     *   вҖў Helius LaserStream вҶ’ push notifications for whale-wallet txs
     *                      (replaces InsiderWalletTracker REST polling)
     *   вҖў Pyth Hermes SSE вҶ’ ~400ms price updates for SOL/BTC/ETH (drives
     *                      faster trailing-stop and profit-lock triggers)
     *   вҖў EmergentLlmClient вҶ’ Claude-Sonnet-4.5 risk validator + exit
     *                      narrator (opt-in: requires a personal sk-ant-вҖҰ
     *                      key in cfg.geminiApiKey; the Emergent universal
     *                      key cannot be used directly from a native Kotlin
     *                      HTTP client because the proxy only ships in the
     *                      Python emergentintegrations SDK)
     *
     * Each stream fails open: if any one cannot start, the bot continues on
     * its existing REST-based pipelines. Safe to call multiple times вҖ” the
     * inner objects all guard against double-start.
     */
    private fun wireExternalStreams(cfg: com.lifecyclebot.data.BotConfig) {
        // V5.0.3684 вҖ” capture the runtime generation at WS-wire time so the
        // PumpPortal callback below can self-terminate if a STOP/START cycle
        // supersedes this wiring (V5.0.3682 doctrine parity вҖ” the scanner
        // callbacks already do this; PumpFunWS is the highest-volume meme
        // intake stream and was the gap).
        val streamGeneration = try {
            com.lifecyclebot.engine.BotRuntimeController.currentGeneration()
        } catch (_: Throwable) { 0L }
        // 1) PumpPortal WS вҖ” new pump.fun launches + migrations
        try {
            com.lifecyclebot.network.PumpFunWS.start(
                onNewToken = onNewToken@{ mint, symbol, name, mcapSol ->
                    try {
                        // V5.0.3684 вҖ” generation + state guard at the source.
                        // Drop emissions when the WS outlived its runtime
                        // generation OR the runtime is no longer admitting.
                        val curGen = try {
                            com.lifecyclebot.engine.BotRuntimeController.currentGeneration()
                        } catch (_: Throwable) { 0L }
                        val rtState = try {
                            com.lifecyclebot.engine.BotRuntimeController.snapshot().state
                        } catch (_: Throwable) { com.lifecyclebot.engine.BotRuntimeController.RuntimeState.STOPPED }
                        val admitting = rtState == com.lifecyclebot.engine.BotRuntimeController.RuntimeState.RUNNING ||
                                        rtState == com.lifecyclebot.engine.BotRuntimeController.RuntimeState.STARTING
                        if (streamGeneration != 0L && (streamGeneration != curGen || !admitting || isShuttingDown)) {
                            return@onNewToken
                        }
                        // V5.9.629 вҖ” PumpPortal is the high-throughput Meme launch feed
                        // that made builds 2489/2490 ramp to ~40 open positions. It must
                        // follow the same Meme-enabled semantics as the scanner and main
                        // loop, not stale auto-add/V3/autoTrade toggles. If Meme Trader is
                        // enabled or tradingMode is Meme/Both, admit fresh pump.fun launches.
                        // V5.9.632 вҖ” keep parity with startBot scanner gate + botLoop meme gate
                        // (V5.9.631 added `|| status.running` in those two but missed THIS feed,
                        // which is the highest-volume Meme intake stream). Scanner-gate parity:
                        // if the bot is up, PumpPortal feeds the protected intake.
                        val liveCfg = ConfigStore.load(applicationContext)
                        val shouldAdmit = liveCfg.memeTraderEnabled ||
                            liveCfg.tradingMode == 0 ||
                            liveCfg.tradingMode == 2 ||
                            liveCfg.autoAddNewTokens ||
                            liveCfg.v3EngineEnabled ||
                            liveCfg.autoTrade ||
                            status.running
                        if (shouldAdmit) {
                            lastScannerDiscoveryMs = System.currentTimeMillis()
                            try { marketScanner?.recordNewTokenFound() } catch (_: Throwable) {}
                            // V5.0.3730 вҖ” scanner-active source truth (PumpPortal WS sibling).
                            try { com.lifecyclebot.engine.BotRuntimeController.markScannerActive(com.lifecyclebot.engine.BotRuntimeController.currentGeneration(), true) } catch (_: Throwable) {}
                            val solUsd = com.lifecyclebot.engine.WalletManager.lastKnownSolPrice
                                .takeIf { it > 0.0 } ?: 150.0
                            val mcapUsd = mcapSol * solUsd
                            // pump.fun bonding-curve liquidity вүҲ mcap pre-graduation.
                            val estLiq = (mcapUsd * 0.85).coerceAtLeast(0.0)
                            // V5.9.1463 вҖ” DERIVED intake confidence (was hardcoded 80 for
                            // EVERY WS token). That constant lie was the root of the 6.3% WR:
                            // a brand-new bonding-curve launch with vol1h=$0 and ~$1.5k liq is
                            // NOT an 80-confidence candidate вҖ” it's a discovery-tier probe. The
                            // downstream score-band gates read this confidence; stamping 80 made
                            // them treat every dead-on-arrival pump.fun mint as high-conviction,
                            // so the bot kept buying zero-volume rugs into -15% stops. We only
                            // truly know liquidity at WS time (volume is unmeasured = 0), so
                            // derive a HONEST discovery-band confidence from the liquidity tier.
                            // Real conviction must be EARNED later when live volume/microstructure
                            // confirms (the additive-confidence model upgrades from here). This
                            // keeps throughput (still admits, protected-pool intact) but stops
                            // feeding fake high-confidence into the entry gates.
                            val wsConfidence = when {
                                estLiq >= 8000.0 -> 45   // deepest fresh pool we see вҖ” still only "investigate"
                                estLiq >= 4000.0 -> 38
                                estLiq >= 2000.0 -> 30
                                else             -> 22   // sub-$2k fresh rug-zone вҖ” discovery probe only
                            }
                            admitProtectedMemeIntake(
                                mint = mint,
                                symbol = symbol,
                                name = name.ifBlank { symbol },
                                source = "PUMP_PORTAL_WS",
                                marketCapUsd = mcapUsd,
                                liquidityUsd = estLiq,
                                volumeH1 = 0.0,
                                confidence = wsConfidence,
                                allSources = setOf("PUMP_PORTAL_WS", "PUMP_PORTAL"),
                                playSound = true,
                                operatorLog = true,
                                expectedRuntimeGeneration = streamGeneration,
                            )
                            ErrorLogger.info(
                                "BotService",
                                "рҹҶ• PumpPortal protected intake: $symbol ($name) mcap=${mcapSol.toInt()}SOL liqEst=\$${estLiq.toInt()}"
                            )
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "PumpPortal protected intake error: ${e.message}")
                    }
                },
                onMigration = { mint ->
                    ErrorLogger.info("BotService", "рҹҡҖ PumpPortal migration: ${mint.take(8)}вҖҰ")
                },
            )
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "PumpFunWS start failed: ${e.message}")
        }

        // 2) Helius Enhanced WS вҖ” push whale-wallet activity
        try {
            if (cfg.heliusApiKey.isNotBlank()) {
                val whaleAddrs = try {
                    com.lifecyclebot.perps.InsiderWalletTracker.getTrackedWallets()
                        .map { it.address }
                        .filter { it.isNotBlank() }
                } catch (_: Exception) { emptyList() }
                if (whaleAddrs.isNotEmpty()) {
                    com.lifecyclebot.network.HeliusEnhancedWS.start(
                        heliusApiKey = cfg.heliusApiKey,
                        watchAccounts = whaleAddrs,
                    ) { sig, accounts, _ ->
                        // V5.9.1022 вҖ” CRITICAL COST FIX.
                        // Operator V5.9.1021 snapshot showed 200+ "рҹҗі PUSH: whale tx XвҖҰ (0 accounts)"
                        // events in 4 seconds. Every event was logged AND triggered a
                        // scanForSignals() call вҖ” even with ZERO matching whale accounts.
                        // The Helius subscription is firing on ALL mainnet txns (filter
                        // probably mis-attached at WS layer or the parser stopped finding
                        // accountKeys after key rotation). Each spurious scanForSignals()
                        // call hits Birdeye+DexScreener+Helius вҶ’ direct paid-tier credit
                        // burn (operator just lost $300 AUD this way).
                        //
                        // Fix: early-return on empty accounts. The scan ONLY fires when
                        // at least one of our tracked whale wallets is actually in the
                        // tx payload. Log is silenced too so logcat is readable.
                        if (accounts.isEmpty()) return@start
                        try {
                            ErrorLogger.info("BotService",
                                "рҹҗі PUSH: whale tx ${sig.take(10)}вҖҰ (${accounts.size} accounts)")
                            scope.launch {
                                try { com.lifecyclebot.perps.InsiderWalletTracker.scanForSignals() }
                                catch (_: Exception) {}
                            }
                        } catch (_: Exception) {}
                    }
                } else {
                    ErrorLogger.info("BotService",
                        "HeliusEnhancedWS skipped вҖ” no tracked whale wallets to subscribe to")
                }
            }
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "HeliusEnhancedWS start failed: ${e.message}")
        }

        // 3) Pyth Hermes SSE вҖ” ~400ms SOL/BTC/ETH price stream
        try {
            val solFeed = "ef0d8b6fda2ceba41da15d4095d1da392a0d2f8ed0c6c7bc0f4cfac8c280b56d"
            val btcFeed = "e62df6c8b4a85fe1a67db44dc12de5db330f7ac66b72dc658afedf0f4a415b43"
            val ethFeed = "ff61491a931112ddf1bd8147cd1b641375f79f5825126d665480874634fd0ace"
            com.lifecyclebot.network.PythHermesStream.subscribe(
                feedHexIds = listOf(solFeed, btcFeed, ethFeed),
            ) { feedId, priceUsd, _, _ ->
                try {
                    when (feedId) {
                        solFeed -> com.lifecyclebot.engine.WalletManager.lastKnownSolPrice = priceUsd
                    }
                } catch (_: Exception) {}
            }
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "PythHermesStream start failed: ${e.message}")
        }

        // 4) EmergentLlmClient вҖ” Claude Sonnet 4.5 (opt-in, personal key only)
        try {
            val key = cfg.geminiApiKey.trim()
            if (key.startsWith("sk-ant-")) {
                com.lifecyclebot.network.EmergentLlmClient.configure(apiKey = key)
            } else {
                ErrorLogger.info("BotService",
                    "EmergentLlmClient disabled вҖ” paste a personal Anthropic key (sk-ant-вҖҰ) into " +
                    "BotConfig.geminiApiKey to enable Claude trade-risk validation. The Emergent " +
                    "universal sk-emergent-вҖҰ key cannot be used from native Kotlin (proxy is " +
                    "Python-SDK only).")
            }
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "EmergentLlmClient configure failed: ${e.message}")
        }
    }

    private fun unwireExternalStreams() {
        try { com.lifecyclebot.network.PumpFunWS.stop() } catch (_: Exception) {}
        try { com.lifecyclebot.network.HeliusEnhancedWS.stop() } catch (_: Exception) {}
        try { com.lifecyclebot.network.PythHermesStream.unsubscribeAll() } catch (_: Exception) {}
        // EmergentLlmClient is request-scoped вҖ” nothing to disconnect.
    }

    // в”Җв”Җ main loop в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * RAPID STOP-LOSS MONITOR
     * Runs every 500ms to check ALL open positions against hard floor stop loss.
     * This catches catastrophic losses that the main loop (5-10sec cycle) might miss.
     */
    // V5.9.1277 вҖ” fallback-price oracle chain for stale-feed positions. The full
    // 4-oracle stack (Switchboard/Jupiter/Birdeye/DexScreener) lived in perps/ and
    // was ONLY used by the perps trader; the meme trader force-dumped on a dead WS.
    // Free sources first (DexScreener, no key, multi-DEX), then the budget-gated
    // Birdeye boost. Throttled per-mint so a genuinely-dead token can't spam the APIs.
    private val staleFallbackLastTryMs = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private suspend fun resolveStaleFallbackPrice(mint: String): Double? {
        val now = System.currentTimeMillis()
        val last = staleFallbackLastTryMs[mint] ?: 0L
        if (now - last < 8_000L) return null   // at most one oracle sweep per 8s per mint
        staleFallbackLastTryMs[mint] = now
        // 1) DexScreener вҖ” free, no key, aggregates all DEX pools.
        try {
            val p = com.lifecyclebot.perps.DexScreenerOracle.getPriceByAddress(mint)
            if (p != null && p > 0.0) return p
        } catch (_: Exception) {}
        // 2) Birdeye вҖ” the "boost" (keyed, budget-gated inside the oracle itself).
        try {
            val p = com.lifecyclebot.perps.BirdeyeOracle.getPriceByAddress(mint)
            if (p != null && p > 0.0) return p
        } catch (_: Exception) {}
        return null
    }

    private suspend fun rapidStopLossMonitor() {
        ErrorLogger.info("BotService", "рҹӣЎпёҸ Rapid Stop-Loss Monitor STARTED (adaptive 500ms / 5s cycle)")
        
        val HARD_FLOOR_STOP_PCT = 15.0  // ABSOLUTE MAX LOSS - NEVER EXCEEDED
        val CHECK_INTERVAL_MS = 500L      // Check every 500ms when positions are open
        // V5.9.484 вҖ” BATTERY: when zero positions are open, sleep 5s instead
        // of busy-looping at 500ms. Catastrophe protection only matters when
        // there is actually capital at risk; before any BUY the rapid-stop
        // monitor was burning ~7,200 tight cycles/hour for nothing.
        val IDLE_INTERVAL_MS = 5_000L
        
        while (status.running) {
            try {
                val cfg = ConfigStore.load(applicationContext)
                val effectiveBalance = status.getEffectiveBalance(cfg.paperMode)
                
                // Get all open positions
                val openPositions = synchronized(status.tokens) {
                    status.tokens.values.filter { it.position.isOpen }.toList()
                }
                // V5.9.484 вҖ” adaptive idle sleep when no positions are open
                if (openPositions.isEmpty()) {
                    kotlinx.coroutines.delay(IDLE_INTERVAL_MS)
                    continue
                }
                
                for (ts in openPositions) {
                    try {
                        // Get current price - use the most recent available
                        // V5.9.684 вҖ” STALE-PRICE RUG ESCAPE: restructured to avoid
                        // continue inside run{} lambda (Kotlin experimental feature).
                        val rawPrice = ts.lastPrice.takeIf { it > 0 }
                            ?: ts.history.lastOrNull()?.priceUsd
                        if (rawPrice == null || rawPrice <= 0.0) {
                            // V5.9.698 вҖ” Tightened stale-price-rug-escape: 5 min вҶ’ 90s.
                            // Flash rugs complete in <90s and immediately go price-dark.
                            // The previous 5-min threshold meant the rapid monitor couldn't
                            // fire (price stale = pnl вүҲ 0%), and by the time the main
                            // polling cycle got a real price the loss was already -54%/-77%.
                            // 90s is safe: a legitimately trading token will always have at
                            // least one WS tick (PumpPortal fires every trade) inside 90s.
                            // V5.9.703 вҖ” same entry-anchor fix: use max(lastPriceUpdate, entryTime)
                            // so a position that opened before the most recent price tick is never
                            // immediately considered stale. posAgeMs anchors correctly already but
                            // lastPriceAgeMs was using lastPriceUpdate which pre-dates the buy.
                            val posAgeMs = System.currentTimeMillis() - ts.position.entryTime
                            val priceRefMs = if (ts.lastPriceUpdate > 0)
                                maxOf(ts.lastPriceUpdate, ts.position.entryTime)
                                else ts.position.entryTime
                            val lastPriceAgeMs = System.currentTimeMillis() - priceRefMs
                            val staleThresholdMs = if (posAgeMs > 60_000L) 90_000L else 120_000L
                            if (lastPriceAgeMs > staleThresholdMs && ts.position.isOpen && ts.position.entryPrice > 0) {
                                // V5.9.1277 вҖ” FALLBACK-PRICE BEFORE FORCED DUMP. The WS feed
                                // dying does NOT mean the token rugged вҖ” it usually means our
                                // primary feed (Helius/PumpPortal) flaked. Before we assume rug
                                // and eat a forced loss, ask the FREE off-chain oracles that are
                                // already built but were only wired into the perps trader:
                                // DexScreener (free, multi-DEX) вҶ’ Birdeye (budget-gated). If ANY
                                // returns a live price, treat the position as healthy, refresh
                                // ts.lastPrice, and let normal PnL/exit logic run this cycle.
                                val fbPrice = resolveStaleFallbackPrice(ts.mint)
                                if (fbPrice != null && fbPrice > 0.0) {
                                    ts.lastPrice = fbPrice
                                    ts.lastPriceUpdate = System.currentTimeMillis()
                                    ts.lastPriceSource = "ORACLE_FALLBACK"
                                    try { com.lifecyclebot.engine.sell.StalePriceExitGuard.clearStale(ts.mint) } catch (_: Throwable) {}  // V5.9.1533
                                    ErrorLogger.info("BotService",
                                        "рҹӣҹ STALE_FALLBACK_RECOVERED: ${ts.symbol} primary feed dark ${lastPriceAgeMs/1000}s вҶ’ oracle price \$$fbPrice (NO forced dump)")
                                    addLog("рҹӣҹ PRICE RECOVERED via oracle: ${ts.symbol} = \$$fbPrice вҖ” skipping rug-escape", ts.mint)
                                    continue  // re-evaluate with real price next monitor pass
                                }
                                ErrorLogger.warn("BotService",
                                    "рҹ’Җ STALE_PRICE_RUG_ESCAPE: ${ts.symbol} вҖ” no price for ${lastPriceAgeMs/1000}s (pos age ${posAgeMs/1000}s), all oracles dark, force-exit")
                                addLog("рҹ’Җ STALE PRICE EXIT: ${ts.symbol} | no price ${lastPriceAgeMs/1000}s вҖ” oracles dark, assume rug", ts.mint)
                                executor.requestSell(ts = ts, reason = "STALE_PRICE_RUG_ESCAPE",
                                    wallet = wallet, walletSol = effectiveBalance)
                                // V5.9.715-FIX: stale-price exits in paper mode are price-feed
                                // noise, not real rugs. Catastrophe cooldown punished the same
                                // mint for 30min, starving V3 via the loss_streak guard and
                                // collapsing trading to near-zero. Only fire in live mode.
                                if (!cfg.paperMode) TradeStateMachine.startCatastropheCooldown(ts.mint, -100.0)
                            }
                            continue  // can't do pnl math without price
                        }
                        val currentPrice = rawPrice

                        // V5.9.698 вҖ” STALE LIVE PRICE GUARD: rawPrice is non-null but may be
                        // a cached value that hasn't moved since before the rug. If lastPriceUpdate
                        // is >90s old (position >60s) treat it the same as null-price rug escape.
                        // This catches -54%/-77% RAPID_CATASTROPHE_STOP cases where the WS died
                        // before the dump, ts.lastPrice stayed at entry, pnl showed 0%, and the
                        // rapid monitor held until the polling cycle fetched the real rug price.
                        // V5.9.703 вҖ” FIX: stale-live-price guard now anchors to
                        // max(ts.lastPriceUpdate, ts.position.entryTime) so a freshly
                        // opened position always has вүҘ90s from entry before the guard
                        // can fire. The V5.9.698 bug: ts.lastPriceUpdate was set at
                        // SCAN time (not buy time), so a token scanned 2+ min before
                        // its paper buy looked "stale" the moment the position opened вҖ”
                        // causing 100% of paper trades to exit STALE_LIVE_PRICE_RUG_ESCAPE
                        // at 0min hold time, collapsing WR to 8%.
                        //
                        // Correct semantics: "has a LIVE price tick arrived since entry?"
                        // Use max so that if a new price arrives after entry it still works,
                        // and if no post-entry tick has arrived, entryTime is the baseline.
                        if (ts.lastPriceUpdate > 0) {
                            val priceRefMs = maxOf(ts.lastPriceUpdate, ts.position.entryTime)
                            val livePriceAgeMs = System.currentTimeMillis() - priceRefMs
                            val posAgeForStale = System.currentTimeMillis() - ts.position.entryTime
                            // V5.9.922 вҖ” TIGHTEN PAPER STALE THRESHOLD.
                            // V5.9.788's 7.5min/10min paper window was meant to stop noise-
                            // eviction, but operator V5.9.921 dump shows it lets REAL rugs
                            // run free: UNPC -90.8%, Thumas -75.8%, COMPASS -70.6% вҖ” all
                            // bled past every floor while ts.lastPrice stayed frozen because
                            // DexScreener dropped the rugged tokens from its batch endpoint.
                            //
                            // Paper trains live (memory #87 doctrine). When paper holds a
                            // rugged position 7.5min before exit, the brain learns a -90%
                            // loss it would never have taken in live (live's 90s window
                            // would have escaped at -30%).
                            //
                            // V5.9.1121 вҖ” paper stale-price is now an intelligent gate,
                            // not a hair-trigger. Journal export showed 14 stale-live exits
                            // averaging -14.4%, including -5.4%/-10.1% cuts. In paper,
                            // feed darkness alone should not teach the bot fake rug losses.
                            // Live remains aggressive; paper requires hard-floor-level
                            // last-known damage before stale feed may force a sell.
                            val staleLivePriceThreshMs = if (cfg.paperMode) {
                                if (posAgeForStale > 60_000L) 120_000L else 180_000L      // 2min / 3min in paper
                            } else {
                                if (posAgeForStale > 60_000L) 90_000L else 120_000L       // 90s / 120s in LIVE (real money)
                            }
                            if (livePriceAgeMs > staleLivePriceThreshMs && ts.position.isOpen) {
                                // V5.9.1023 вҖ” PNL CORROBORATION GATE.
                                //
                                // Operator V5.9.1022 snapshot: "first 60 trades are instant
                                // death" вҖ” bot was force-exiting tokens at phantom -24% to
                                // -74% losses purely because DexScreener/Birdeye/Helius hit
                                // rate limits and the price feed went dark for 90-180s. A
                                // dark feed alone is NOT a rug. The comment block at L5971
                                // documented the intended TWO-condition rule but the
                                // implementation only ever checked condition (a).
                                //
                                // Required gates:
                                //   (a) livePriceAgeMs > staleLivePriceThreshMs  (already)
                                //   (b) last-known PnL is NOT in profit  (NEW)
                                //
                                // Reasoning: a real rug happens AFTER the last price tick,
                                // so lastKnown PnL is ~entry-flat or slightly negative when
                                // the feed dies вҖ” that's still allowed to fire. But if we
                                // were already up +20% before the feed went dark, the rug
                                // hypothesis is much weaker than the "API rate-limited"
                                // hypothesis and we should ride out the dark period rather
                                // than nuke a winner. Operator words: "stale-feed AND
                                // last-known PnL is already in the red".
                                val lastKnownPnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                                    entryPrice = ts.position.entryPrice,
                                    currentPrice = ts.lastPrice,
                                    entrySource = ts.position.entryPriceSource,
                                    currentSource = ts.lastPriceSource,
                                    entryPool = ts.position.entryPoolAddress,
                                    currentPool = ts.lastPricePoolAddr,
                                    priceBasisRescaled = ts.position.priceBasisRescaled,
                                    context = "BotService.staleLiveLastKnown/${ts.symbol}/${ts.mint.take(8)}",
                                )
                                val lastKnownPnlPct = if (lastKnownPnlVerdict.ok) lastKnownPnlVerdict.pnlPct else 0.0
                                val stalePnlFloor = if (cfg.paperMode) -HARD_FLOOR_STOP_PCT else 0.0
                                val pnlCorroborates = lastKnownPnlPct <= stalePnlFloor
                                if (!pnlCorroborates) {
                                    // V5.9.1352 troubleshoot вҖ” ZOMBIE FIX. Previously this
                                    // branch logged and `continue`d, freezing the position
                                    // at its last mark for the entire dark-feed window
                                    // (9304 STALE_HOLD events/session, positions stuck
                                    // 400-650s = undead capital + poisoned WR average).
                                    // Before giving up, try the oracle for a REAL mark so
                                    // the position resolves through normal exit logic
                                    // instead of zombie-ing. Still NEVER fake-rugs: if the
                                    // oracle is also dark we hold (unchanged behaviour).
                                    val zombieFb = try { resolveStaleFallbackPrice(ts.mint) } catch (_: Throwable) { null }
                                    if (zombieFb != null && zombieFb > 0.0) {
                                        ts.lastPrice = zombieFb
                                        ts.lastPriceUpdate = System.currentTimeMillis()
                                        ts.lastPriceSource = "ORACLE_ZOMBIE_REFRESH"
                                        try { com.lifecyclebot.engine.sell.StalePriceExitGuard.clearStale(ts.mint) } catch (_: Throwable) {}  // V5.9.1533
                                        val zPnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                                            entryPrice = ts.position.entryPrice,
                                            currentPrice = zombieFb,
                                            entrySource = ts.position.entryPriceSource,
                                            currentSource = "ORACLE_ZOMBIE_REFRESH",
                                            entryPool = ts.position.entryPoolAddress,
                                            currentPool = ts.lastPricePoolAddr,
                                            priceBasisRescaled = ts.position.priceBasisRescaled,
                                            context = "BotService.zombieOracle/${ts.symbol}/${ts.mint.take(8)}",
                                        )
                                        val zPnl = if (zPnlVerdict.ok) zPnlVerdict.pnlPct else 0.0
                                        try {
                                            ForensicLogger.lifecycle(
                                                "STALE_ZOMBIE_REFRESHED_ORACLE",
                                                "symbol=${ts.symbol} oraclePnl=${"%.1f".format(zPnl)}% wasStale=${livePriceAgeMs/1000}s вҖ” real mark restored, defer to exit logic"
                                            )
                                        } catch (_: Throwable) {}
                                        // real price set; do NOT continue вҖ” let this tick's
                                        // hard-floor / exit / pivot logic act on the true mark.
                                    } else {
                                        // V5.0.3739 вҖ” PAPER stale-zombie source fix.
                                        // In PAPER there is no wallet capital to protect from a
                                        // blind stale-feed dump. Holding forever here turns a dark
                                        // Dex/GT/API window into forcedOpen debt + thousands of
                                        // EXIT evaluations (`STALE_LIVE_PRICE_HOLD...`) and poisons
                                        // rolling WR with undead positions. Live keeps the existing
                                        // conservative hold. Paper gets a bounded scratch/timeout
                                        // close after one extra stale grace window so training churn
                                        // keeps moving without inventing a rug loss.
                                        val paperStaleTimeoutMs = staleLivePriceThreshMs + 60_000L
                                        if (cfg.paperMode && livePriceAgeMs > paperStaleTimeoutMs) {
                                            try {
                                                ForensicLogger.lifecycle(
                                                    "PAPER_STALE_ZOMBIE_SCRATCH_EXIT",
                                                    "symbol=${ts.symbol} lastPnlPct=${"%.1f".format(lastKnownPnlPct)} floor=${"%.1f".format(stalePnlFloor)} ageS=${livePriceAgeMs/1000} timeoutS=${paperStaleTimeoutMs/1000} вҖ” feed+oracle dark, closing scratch to prevent forcedOpen/WR poison"
                                                )
                                            } catch (_: Throwable) {}
                                            executor.requestSell(
                                                ts = ts,
                                                reason = "PAPER_STALE_PRICE_TIMEOUT_SCRATCH",
                                                wallet = wallet,
                                                walletSol = effectiveBalance,
                                            )
                                            continue
                                        }
                                        try {
                                            ForensicLogger.lifecycle(
                                                if (cfg.paperMode) "STALE_LIVE_PRICE_HOLD_PAPER_NOT_HARDFLOOR" else "STALE_LIVE_PRICE_HOLD_WINNER",
                                                "symbol=${ts.symbol} lastPnlPct=${"%.1f".format(lastKnownPnlPct)} floor=${"%.1f".format(stalePnlFloor)} ageS=${livePriceAgeMs/1000} вҖ” feed+oracle dark, hold (no blind dump)"
                                            )
                                        } catch (_: Throwable) {}
                                        continue
                                    }
                                }
                                // V5.9.1277 вҖ” one real-price check before dumping a
                                // corroborated-stale position. A live oracle price either
                                // confirms the rug (refresh вҶ’ normal floor logic dumps it at
                                // the true price, not a guess) or proves it's a feed glitch.
                                val fbLivePrice = resolveStaleFallbackPrice(ts.mint)
                                if (fbLivePrice != null && fbLivePrice > 0.0) {
                                    ts.lastPrice = fbLivePrice
                                    ts.lastPriceUpdate = System.currentTimeMillis()
                                    ts.lastPriceSource = "ORACLE_FALLBACK"
                                    try { com.lifecyclebot.engine.sell.StalePriceExitGuard.clearStale(ts.mint) } catch (_: Throwable) {}  // V5.9.1533
                                    val fbPnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                                        entryPrice = ts.position.entryPrice,
                                        currentPrice = fbLivePrice,
                                        entrySource = ts.position.entryPriceSource,
                                        currentSource = "ORACLE_FALLBACK",
                                        entryPool = ts.position.entryPoolAddress,
                                        currentPool = ts.lastPricePoolAddr,
                                        priceBasisRescaled = ts.position.priceBasisRescaled,
                                        context = "BotService.liveFallback/${ts.symbol}/${ts.mint.take(8)}",
                                    )
                                    val fbPnl = if (fbPnlVerdict.ok) fbPnlVerdict.pnlPct else 0.0
                                    ErrorLogger.info("BotService",
                                        "рҹӣҹ STALE_LIVE_FALLBACK: ${ts.symbol} feed frozen ${livePriceAgeMs/1000}s вҶ’ oracle \$$fbLivePrice (pnl ${"%.1f".format(fbPnl)}%) вҖ” defer to floor logic")
                                    addLog("рҹӣҹ LIVE PRICE RECOVERED via oracle: ${ts.symbol} @ ${"%.1f".format(fbPnl)}% вҖ” no blind dump", ts.mint)
                                    continue  // real price now set; hard-floor/exit logic handles it correctly
                                }
                                // V5.9.1533 вҖ” spec item 4: emit EXACTLY ONE exit intent per
                                // mint. Previously this fired every tick (stampede) and fed a
                                // FAKE -100% into catastrophe cooldown + learning from a dark
                                // price. Now: arm once; on later ticks skip cheaply. Never feed
                                // catastrophe cooldown / learning from a stale/dark price вҖ” only
                                // a confirmed on-chain zero or a verified fresh price may do that.
                                val armedOnce = com.lifecyclebot.engine.sell.StalePriceExitGuard
                                    .armOnceRugEscape(ts.mint, ts.symbol ?: "?")
                                if (!armedOnce) {
                                    // already armed within the window вҖ” do NOT re-fire / re-feed.
                                    continue
                                }
                                ErrorLogger.warn("BotService",
                                    "рҹ’Җ STALE_LIVE_PRICE_RUG_ESCAPE: ${ts.symbol} вҖ” lastPrice stale ${livePriceAgeMs/1000}s (since max(priceUpd,entry)), lastPnl=${"%.1f".format(lastKnownPnlPct)}%, oracles dark, force-exit (ONE intent)")
                                addLog("рҹ’Җ STALE LIVE PRICE EXIT: ${ts.symbol} | price frozen ${livePriceAgeMs/1000}s @ ${"%.1f".format(lastKnownPnlPct)}% вҖ” oracles dark, one exit intent", ts.mint)
                                executor.requestSell(ts = ts, reason = "STALE_LIVE_PRICE_RUG_ESCAPE",
                                    wallet = wallet, walletSol = effectiveBalance)
                                // V5.9.1533 вҖ” do NOT seed catastrophe cooldown from a stale/dark
                                // price (it is not a confirmed -100% loss). The controlled sell
                                // drain + on-chain balance read will confirm the real outcome;
                                // catastrophe cooldown is seeded only on a verified close.
                                continue
                            }
                        }

                        val entryPrice = ts.position.entryPrice
                        if (entryPrice <= 0) continue

                        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                        // V5.9.1489 вҖ” DANGER-ZONE FRESH-QUOTE (source fix for the
                        // -8%вҶ’-31% / -53% STOP_LOSS overshoot).
                        //
                        // ROOT CAUSE: stops are SET tight (SHITCOIN -8%, lanes -15%
                        // floor) but REALIZE deep (SHITCOIN avg -31.6%, MANIPULATED
                        // -53.5% in snapshot 5.0.3494). The stop check below evaluates
                        // against `currentPrice` = ts.lastPrice, which only refreshes on
                        // the 6-9s scan cycle. On illiquid memes the price gaps between
                        // polls, so by the time pnlPct is recomputed the position is
                        // already -31%. The loss is booked far past where the stop sits.
                        //
                        // This is NOT the time-staleness path above (that fires at
                        // 90-180s feed-dark). This is a fresh-but-one-cycle-old mark on a
                        // position that has ENTERED the danger zone. The fix: the moment a
                        // held position's last-known PnL is within striking distance of
                        // its stop, pull a real oracle mark THIS tick (respecting the
                        // oracle's own 8s/mint throttle) so the stop chain acts on the
                        // true price and books nearer the intended level. Shrinks avg_loss
                        // on EVERY lane вҖ” the doctrine pf lever (avg_win*WR vs avg_loss).
                        //
                        // Bounded + safe: only when held past warmup (>8s, avoids
                        // entry-tick noise) AND last-known pnl <= -5% (approaching the
                        // tightest -8% lane stop) AND not already fresh this tick. Oracle
                        // self-throttles to вүӨ1 call/8s/mint, so worst case is one extra
                        // DEX read per danger-zone position per 8s. Never blocks, never
                        // fakes a price; if the oracle is dark we fall through to the
                        // existing stale/floor logic unchanged.
                        // dzEffectivePrice starts at the loop's currentPrice and is
                        // replaced by a fresh oracle mark if the danger-zone refresh
                        // fires. Kept as a separate val-after-block (not a reassigned
                        // currentPrice) so downstream smart-casts on currentPrice stay
                        // valid (currentPrice remains immutable / non-null).
                        val dzEffectivePrice: Double = run {
                            val preEntry = ts.position.entryPrice
                            if (preEntry <= 0.0 || !ts.position.isOpen) return@run currentPrice
                            val premarkVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                                entryPrice = preEntry,
                                currentPrice = currentPrice,
                                entrySource = ts.position.entryPriceSource,
                                currentSource = ts.lastPriceSource,
                                entryPool = ts.position.entryPoolAddress,
                                currentPool = ts.lastPricePoolAddr,
                                priceBasisRescaled = ts.position.priceBasisRescaled,
                                context = "BotService.dangerZonePremark/${ts.symbol}/${ts.mint.take(8)}",
                            )
                            if (!premarkVerdict.ok) return@run currentPrice
                            val premarkPnl = premarkVerdict.pnlPct
                            val posAgeMsDz = System.currentTimeMillis() - ts.position.entryTime
                            val markAgeMsDz = if (ts.lastPriceUpdate > 0)
                                System.currentTimeMillis() - ts.lastPriceUpdate else Long.MAX_VALUE
                            // In the danger zone, held past warmup, and the mark is at
                            // least ~1 scan cycle old вҶ’ force a real quote now.
                            if (premarkPnl > -5.0 || posAgeMsDz <= 8_000L || markAgeMsDz <= 4_000L) return@run currentPrice
                            val freshDz = try { resolveStaleFallbackPrice(ts.mint) } catch (_: Throwable) { null }
                            if (freshDz == null || freshDz <= 0.0) return@run currentPrice
                            ts.lastPrice = freshDz
                            ts.lastPriceUpdate = System.currentTimeMillis()
                            ts.lastPriceSource = "DANGER_ZONE_FRESH"
                            try {
                                val dzPnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                                    entryPrice = preEntry,
                                    currentPrice = freshDz,
                                    entrySource = ts.position.entryPriceSource,
                                    currentSource = "DANGER_ZONE_FRESH",
                                    entryPool = ts.position.entryPoolAddress,
                                    currentPool = ts.lastPricePoolAddr,
                                    priceBasisRescaled = ts.position.priceBasisRescaled,
                                    context = "BotService.dangerZoneFresh/${ts.symbol}/${ts.mint.take(8)}",
                                )
                                val dzPnl = if (dzPnlVerdict.ok) dzPnlVerdict.pnlPct else premarkPnl
                                ForensicLogger.lifecycle(
                                    "DANGER_ZONE_FRESH_QUOTE",
                                    "symbol=${ts.symbol} staleMarkPnl=${"%.1f".format(premarkPnl)}% freshPnl=${"%.1f".format(dzPnl)}% markAgeS=${markAgeMsDz/1000} вҖ” refreshed before stop eval"
                                )
                                com.lifecyclebot.engine.PipelineHealthCollector.labelInc("DANGER_ZONE_FRESH_QUOTE")
                            } catch (_: Throwable) {}
                            freshDz
                        }

                        // Calculate PnL вҖ” uses the danger-zone-refreshed mark when it fired,
                        // otherwise the loop's currentPrice (unchanged behaviour).
                        val rapidExitPrice4481 = walletCorrespondentOpenPrice4481(ts, dzEffectivePrice, "RAPID_MONITOR")
                        val pnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                            entryPrice = entryPrice,
                            currentPrice = rapidExitPrice4481,
                            entrySource = ts.position.entryPriceSource,
                            currentSource = ts.lastPriceSource,
                            entryPool = ts.position.entryPoolAddress,
                            currentPool = ts.lastPricePoolAddr,
                            priceBasisRescaled = ts.position.priceBasisRescaled,
                            context = "BotService.rapidStop/${ts.symbol}/${ts.mint.take(8)}",
                        )
                        if (!pnlVerdict.ok) continue
                        val pnlPct = pnlVerdict.pnlPct

                        // V5.9.922 вҖ” BELT-AND-BRACES HARD CATASTROPHE NET.
                        // Operator V5.9.921 dump: UNPC -90.8%, Thumas -75.8%, COMPASS -70.6%
                        // bled invisibly while normal catastrophe (-14%) never fired because
                        // ts.lastPrice was frozen for several minutes.
                        //
                        // If the position has been open >60s AND pnlPct is past -30% on ANY
                        // price reading (even one a couple minutes stale), force-exit. This
                        // is BEYOND the standard -14% catastrophe вҖ” a sanity net for cases
                        // where the standard exit chain didn't fire (sell-lock contention,
                        // executor stall, or anything else).
                        //
                        // Memory rule #23: -15% floor is unconditional. -30% deep-net
                        // is unambiguously rugged for any token where we have ANY price.
                        // (V5.9.924: inlined вҖ” `continue` inside `run{}` was illegal Kotlin
                        // and broke V5.9.922 compile. The conditional is identical in effect.)
                        val posAgeForNet = System.currentTimeMillis() - ts.position.entryTime
                        // V5.9.1541 вҖ” ZOMBIE ESCAPE HATCH (operator regression: 0 execs/5h).
                        // MARS sat at -37% for 16.5h (age=59437s) re-firing DEEP_CATASTROPHE_NET
                        // every tick. Its sell could NEVER land (helius_sender sr=0%, 21x 503)
                        // and it could NEVER reconcile-close (wallet RPC THREW вҖ” not empty-map вҖ”
                        // so RECONCILE_ABORT_RPC_UNTRUSTED + my 1540 empty-map reaper both missed
                        // it). The undying position kept pendingSellQueue/activeJobs/
                        // workerTimeoutStorm > 0, holding SellOnlySafeMode ACTIVE, which blocked
                        // 100% of live buys at LiveBuyAdmissionGate (EXEC_LIVE_ATTEMPT=0).
                        // FIX: when a catastrophe position is absurdly old (sell route is
                        // provably dead) AND has racked up many failed close attempts, stop
                        // re-requesting a doomed sell. Force the LOCAL close: flip isOpen=false
                        // so this loop stops re-entering, release the CloseLease + sell job, and
                        // hard-close the tracker so SafeMode signals drain and buys reopen. NO
                        // wallet read required (the wallet RPC is the thing that's broken).
                        val zombieAttempts = try { com.lifecyclebot.engine.sell.CloseLease.attemptCount(ts.mint) } catch (_: Throwable) { 0 }
                        if (posAgeForNet > 30 * 60_000L && pnlPct <= -30.0 && ts.position.isOpen) {
                            // V5.0.3985 вҖ” FINALITY DOCTRINE FIX.
                            // This used to force a LOCAL close (zero qty, release CloseLease,
                            // mark SellJob landed, confirm tracker zero) when an old catastrophe
                            // position had repeated sell trouble. That unblocked buys, but it also
                            // created fake terminal state without chain proof вҖ” exactly the
                            // LIVE_SELL_NO_FINALITY/accounting corruption class. Never locally
                            // close a live bag from stale UI/wallet state. Keep it open, mark the
                            // close lease retryable/non-terminal, and wake the reconciler/sell path.
                            ErrorLogger.warn("BotService",
                                "вҸі ZOMBIE_CATASTROPHE_PENDING_RETRY: ${ts.symbol} pnl=${pnlPct.toInt()}% age=${posAgeForNet/1000}s attempts=$zombieAttempts вҖ” no local close without sell finality proof")
                            try { com.lifecyclebot.engine.sell.CloseLease.recordRetry(ts.mint, "ZOMBIE_CATASTROPHE_PENDING_RETRY") } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.sell.SellReconciler.requestUrgentTick("ZOMBIE_CATASTROPHE_PENDING_RETRY") } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("ZOMBIE_CATASTROPHE_PENDING_RETRY") } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.ForensicLogger.lifecycle("ZOMBIE_CATASTROPHE_PENDING_RETRY", "mint=${ts.mint.take(10)} symbol=${ts.symbol} ageMs=$posAgeForNet pnl=${pnlPct.toInt()} attempts=$zombieAttempts action=no_local_close_no_slot_release") } catch (_: Throwable) {}
                            try {
                                executor.requestSell(ts = ts, reason = "ZOMBIE_CATASTROPHE_PENDING_RETRY", wallet = wallet, walletSol = effectiveBalance)
                            } catch (e: Throwable) {
                                ErrorLogger.warn("BotService", "ZOMBIE_CATASTROPHE_PENDING_RETRY sell retry error: ${e.message?.take(50)}")
                            }
                            continue
                        }
                        if (posAgeForNet > 60_000L && pnlPct <= -30.0 && ts.position.isOpen) {
                            ErrorLogger.warn("BotService",
                                "рҹҡЁ DEEP_CATASTROPHE_NET: ${ts.symbol} pnl=${pnlPct.toInt()}% age=${posAgeForNet/1000}s вҖ” bypassed all other floors, force-exit")
                            addLog("рҹӣ‘ DEEP CATASTROPHE NET: ${ts.symbol} ${pnlPct.toInt()}% (>${(posAgeForNet/1000).toInt()}s) вҖ” emergency exit", ts.mint)
                            try {
                                executor.requestSell(ts = ts, reason = "DEEP_CATASTROPHE_NET",
                                    wallet = wallet, walletSol = effectiveBalance)
                                TradeStateMachine.startCatastropheCooldown(ts.mint, pnlPct)
                            } catch (e: Throwable) {
                                ErrorLogger.warn("BotService", "DEEP_CATASTROPHE_NET sell error: ${e.message?.take(50)}")
                            }
                            continue  // skip rest of per-position loop, position closed
                        }

                        // V5.9.363 вҖ” TIGHTENED HARD FLOOR.
                        // Old rapid-stop fired at -15% but real positions kept
                        // hitting -69% because price feeds dropped during fast
                        // rugs and `currentPrice` went stale. We now also fire
                        // a CATASTROPHE COOLDOWN whenever we observe pnl вүӨ -25%
                        // вҖ” even though the hard floor sell is already in flight,
                        // the 30-min cooldown prevents the bot from instantly
                        // re-buying the same rug as soon as the price oracle
                        // catches up.
                        //
                        // V5.9.495z27 вҖ” REWRITE of z23 peak-protect.
                        // Operator screenshot evidence: TWIG peaked +45% вҶ’ fell
                        // to -94%, USDS at -99%, HARRY at -95%, MOONCLUB at -73%,
                        // Winston at -24% вҖ” all way past their displayed -20%
                        // SL with no exit fired. Two compounding bugs:
                        //
                        //   1. DEAD ZONE between -15% and -25%: the dynamic
                        //      stop block below this guard had `pnlPct >
                        //      -HARD_FLOOR_STOP_PCT` so it never ran for
                        //      positions deeper than -15%. With z23 also
                        //      blocking the hard floor for peaked positions,
                        //      any peaked position falling -15% to -25% had
                        //      ZERO exit firing.
                        //
                        //   2. PEAK-PROTECT had no give-back ceiling: a
                        //      position that peaked +45% could give back
                        //      139 points before catastrophe (-25%) caught
                        //      it вҖ” by which time the LP was usually pulled
                        //      and the catastrophe sell failed.
                        //
                        // New logic вҖ” single linear if/else chain:
                        //   a. CATASTROPHE (вүӨ -25%) always fires.
                        //   b. DRAWDOWN_FROM_PEAK fires when peak вүҘ +20% AND
                        //      (peak - pnl) вүҘ 25 points. So a position that
                        //      peaked +45% exits no later than +20% pnl
                        //      (locking in +20% instead of becoming -94%).
                        //   c. HARD_FLOOR fires for never-winners (peak < +20%)
                        //      that hit -15%.
                        // The dynamic/trailing stop block below remains but
                        // its condition is fixed in the same change to allow
                        // it to run regardless of how deep the loss is.
                        // V5.9.791 вҖ” operator audit Item 7: catastrophe stop tightened from
                        // -25% to -14%. Previously the rapid catastrophe band (вүӨ -25%)
                        // let positions bleed past the operator's mandated meme hard floor.
                        // Combined with the new PositionExitArbiter, an early hard exit at
                        // -14% means one terminal SELL per position with a tighter loss cap
                        // вҖ” duplicate cascades that used to fire CASHGEN+STRICT_SL+CATASTROPHE
                        // on the same position now collide at the arbiter and only the first
                        // (typically -9% to -14% range) wins.
                        //
                        // V5.9.1022 вҖ” PAPER-MODE CATASTROPHE THRESHOLD WIDENED.
                        // Operator V5.9.1021 snapshot showed RAPID_CATASTROPHE_STOP firing
                        // at 30-53 s after BUY on fresh pump.fun launches вҖ” these tokens
                        // have wild price quantization (8.3E-5 вҶ’ 1E-4 = +20% instant) and
                        // paper-mode adds ~18% simulated slippage on top. The -14% trigger
                        // catches NORMAL noise, not catastrophes. 30-loss streak + 6.3% WR
                        // is the symptom: bot buys вҶ’ noise dump вҶ’ -14% вҶ’ SL вҶ’ re-buy вҶ’ repeat.
                        // Paper threshold widened to -25% (the pre-V5.9.791 value) to give
                        // mean-reversion room. Live mode keeps the -14% tight stop because
                        // live slippage is real money, not simulated.
                        // V5.9.1031 вҖ” Rapid monitor extracted into evaluateRapidMonitorExit
                        // to shrink botLoop bytecode under the JVM 64KB cap on Debug compile.
                        // The when-block held 4 suspending executor.requestSell call sites;
                        // moving them into a helper collapses 4 state-machine slots into 1.
                        if (evaluateRapidMonitorExit(ts, pnlPct, cfg, wallet, effectiveBalance)) {
                            continue
                        }
                        
                        // V3.3: DYNAMIC FLUID STOP CHECK (moves with position)
                        val holdTimeMs = System.currentTimeMillis() - ts.position.entryTime
                        val holdTimeSecs = holdTimeMs / 1000.0
                        // V5.9.1427 вҖ” RATCHET THE HIGH-WATER MARK IN THE FAST LOOP.
                        // ROOT CAUSE of "fluid stops / sliding profit-locks not working":
                        // this 500ms rapid monitor is the ONLY loop fast enough to catch
                        // pumps the 10s main loop misses вҖ” yet it READ peakGainPct without
                        // ever UPDATING it. The high-water mark was only ratcheted by the
                        // slower MainActivity UI tick / lifecycle loop, so a token that
                        // pumped +60% and gave back to +20% BETWEEN slow ticks never had
                        // its peak recorded here. getDynamicFluidStop's profit-trail branch
                        // (peakPnlPct > 3.0) therefore never engaged in the fast path, and
                        // the sliding lock silently did nothing. Ratchet from the freshly
                        // computed pnlPct (HWM only ever climbs) BEFORE reading it.
                        if (pnlPct > ts.position.peakGainPct) ts.position.peakGainPct = pnlPct
                        val peakPnlPct = ts.position.peakGainPct
                        val volatility = ts.volatility ?: 50.0

                        // V5.9.1404 вҖ” RAPID ENTRY CHURN SOURCE FIX.
                        // evaluateRapidMonitorExit() already applies hard-floor /
                        // catastrophe protection first. If it returns false during the
                        // first seconds of a PAPER position, the trade is still in price
                        // settlement / spread-discovery. Pre-1404 we immediately fell
                        // through into the dynamic-stop block below and sold as
                        // RAPID_ENTRY_PROTECT_STOP within ~5s, turning scanner volume
                        // into buyвҶ’sell churn and making those micro-holds dominate the
                        // loss book. Do not let adaptive/fluid ENTRY_PROTECT act during
                        // the initial warmup; the unconditional -15% hard floor and true
                        // catastrophe exits above remain active.
                        // V5.9.1418 вҖ” EXTEND PAPER WARMUP HOLD 15s вҶ’ 60s.
                        // Operator forensics (build 5.0.3417): canonical outcomes
                        // dominated by RAPID_ENTRY_PROTECT_STOP at a near-constant
                        // -8.5% (paper clamp band -13..-8 in Executor.parsePaperExitClamp).
                        // Root cause: the warmup only suppressed the adaptive ENTRY_PROTECT
                        // stop for the first 15s, but FluidLearningAI.getDynamicFluidStop's
                        // OWN entry-protection phase runs to 60s (returns -12%..-15%). So a
                        // fresh meme token that wicked -8..-13% on entry spread/slippage
                        // between 15s and 60s got stopped as RAPID_ENTRY_PROTECT_STOP before
                        // it could settle вҖ” buyвҶ’noise-dumpвҶ’stopвҶ’re-buy churn, the exact
                        // "buys then instantly loses" the operator reported. An 8-13% wick is
                        // NOISE for a just-launched token, not signal. Hold the adaptive stop
                        // for the full 60s entry-protection window so settlement can happen.
                        // The unconditional -15% hard floor (pnlPct > -HARD_FLOOR_STOP_PCT)
                        // and the true catastrophe exits handled ABOVE this block remain
                        // active вҖ” a token genuinely crashing past -15% still exits now.
                        if (cfg.paperMode && holdTimeMs in 0L until 40_000L && pnlPct > -HARD_FLOOR_STOP_PCT) {  // V5.9.1429 60s->40s warmup
                            val nowWarmup = System.currentTimeMillis()
                            val holdUntil = rapidEntryWarmupHoldUntilMs[ts.mint] ?: 0L
                            if (nowWarmup >= holdUntil) {
                                rapidEntryWarmupHoldUntilMs[ts.mint] = nowWarmup + 30_000L
                                try {
                                    ForensicLogger.lifecycle(
                                        "RAPID_ENTRY_WARMUP_HOLD",
                                        "symbol=${ts.symbol} pnl=${"%.1f".format(pnlPct)}% ageMs=$holdTimeMs floor=-${HARD_FLOOR_STOP_PCT.toInt()} window=40s ttl=30s once_per_mint"
                                    )
                                } catch (_: Throwable) {}
                                continue
                            }
                            // Already held recently; do not loop-hold forever. Fall through
                            // to dynamic stop/normal management so stale fresh launches clear.
                        }
                        
                        val dynamicStopPct = try {
                            val modeDefault = cfg.stopLossPct
                            com.lifecyclebot.v3.scoring.FluidLearningAI.getDynamicFluidStop(
                                modeDefaultStop = modeDefault,
                                currentPnlPct = pnlPct,
                                peakPnlPct = peakPnlPct,
                                holdTimeSeconds = holdTimeSecs,
                                volatility = volatility
                            )
                        } catch (_: Exception) {
                            // Fallback to static fluid stop
                            try {
                                -com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidStopLoss(cfg.stopLossPct)
                            } catch (_: Exception) { -cfg.stopLossPct }
                        }

                        // V5.0.4301 вҖ” explicit peak-lock breach sell.
                        // A basic bot must not watch a live runner print a huge
                        // peak, show a lock, then sit open after the price falls
                        // below that lock. This guard is independent of generic
                        // dynamic-stop semantics and fires even if current PnL
                        // already gapped below zero between 500ms ticks.
                        val explicitPeakLockFloor4301 = when {
                            peakPnlPct >= 100.0 -> peakPnlPct - 12.0
                            peakPnlPct >= 20.0 -> try {
                                com.lifecyclebot.v3.scoring.FluidLearningAI.fluidProfitFloor(peakPnlPct, volatility, holdTimeSecs)
                            } catch (_: Throwable) { peakPnlPct - 8.0 }
                            else -> Double.NEGATIVE_INFINITY
                        }
                        if (explicitPeakLockFloor4301.isFinite() && pnlPct <= explicitPeakLockFloor4301) {
                            ErrorLogger.warn("BotService", "рҹҡЁ RAPID_PEAK_LOCK_BREACH_4301: ${ts.symbol} peak=${peakPnlPct.toInt()}% lock=${explicitPeakLockFloor4301.toInt()}% now=${pnlPct.toInt()}% вҖ” force sell")
                            addLog("рҹӣ‘ PEAK LOCK BREACH: ${ts.symbol} peak +${peakPnlPct.toInt()}% вҶ’ now ${pnlPct.toInt()}%", ts.mint)
                            try { PipelineHealthCollector.labelInc("RAPID_PEAK_LOCK_BREACH_4301") } catch (_: Throwable) {}
                            try { ForensicLogger.lifecycle("RAPID_PEAK_LOCK_BREACH_4301", "mint=${ts.mint.take(10)} symbol=${ts.symbol} peak=${"%.1f".format(peakPnlPct)} lock=${"%.1f".format(explicitPeakLockFloor4301)} now=${"%.1f".format(pnlPct)} action=force_sell_before_generic_dynamic_stop") } catch (_: Throwable) {}
                            executor.requestSell(
                                ts = ts,
                                reason = "RAPID_PEAK_LOCK_BREACH_4301_peak${peakPnlPct.toInt()}_now${pnlPct.toInt()}",
                                wallet = wallet,
                                walletSol = effectiveBalance
                            )
                            TradeStateMachine.startCooldown(ts.mint)
                            continue
                        }
                        
                        // Dynamic stop is already negative
                        // V5.9.495z27 вҖ” was `pnlPct > -HARD_FLOOR_STOP_PCT`,
                        // which created a DEAD ZONE between -15% and -25% where
                        // neither the hard-floor block above nor this trailing
                        // block fired. Removed the condition so the dynamic
                        // stop runs at every pnl depth. The when-block above
                        // already handles -25% catastrophe and -15% hard-floor
                        // exits with appropriate reason codes; this trailing
                        // path only matters for non-catastrophe / non-floor
                        // exits driven by FluidLearningAI's adaptive stop.
                        if (pnlPct <= dynamicStopPct) {
                            // V5.9.1431 вҖ” RAPID ENTRY PROTECT REMOVED (operator
                            // directive). No more ENTRY_PROTECT stop label/behaviour.
                            // The 40s warmup HOLD above already prevents the dynamic
                            // stop from firing on a fresh token; everything that
                            // reaches here post-warmup is a normal trailing/fluid
                            // stop. Hard -15% floor (handled above) is untouched.
                            val stopType = if (peakPnlPct > 5.0) "TRAILING" else "FLUID"
                            ErrorLogger.warn("BotService", "вҡ пёҸ RAPID $stopType STOP: ${ts.symbol} at ${pnlPct.toInt()}% (limit=${dynamicStopPct.toInt()}%)")
                            addLog("рҹӣ‘ RAPID $stopType STOP: ${ts.symbol} ${pnlPct.toInt()}%")
                            
                            executor.requestSell(
                                ts = ts,
                                reason = "RAPID_${stopType}_STOP",
                                wallet = wallet,
                                walletSol = effectiveBalance
                            )
                            
                            TradeStateMachine.startCooldown(ts.mint)
                            continue
                        }

                        // V5.9.684 вҖ” RAPID TAKE-PROFIT.
                        // Monitor runs every 500ms so it can catch pumps the
                        // main loop (10s cycle) misses. Resolve TP target from
                        // sub-trader fields; fall back to fluid TP.
                        if (ts.position.isOpen) {
                            val tpPct = when {
                                ts.position.isShitCoinPosition && ts.position.shitCoinTakeProfit > 0.0 ->
                                    ts.position.shitCoinTakeProfit
                                ts.position.isBlueChipPosition && ts.position.blueChipTakeProfit > 0.0 ->
                                    ts.position.blueChipTakeProfit
                                ts.position.isTreasuryPosition && ts.position.treasuryTakeProfit > 0.0 ->
                                    ts.position.treasuryTakeProfit
                                else -> try {
                                    com.lifecyclebot.v3.scoring.FluidLearningAI
                                        .getFluidTakeProfit(cfg.exitScoreThreshold.coerceAtLeast(20.0))
                                } catch (_: Throwable) { 20.0 }
                            }
                            if (pnlPct >= tpPct) {
                                // V5.0.4182 вҖ” REAL PRICE LOCK on rapid TP delegate.
                                // Operator V5.0.4181 dump: `рҹҺҜ RAPID TAKE_PROFIT_DELEGATE: piss pnl=98181004%`.
                                // Meme moonshots CAN legitimately do 10,000x+ вҖ” we
                                // want to bank those profits. The phantom risk is
                                // when ts.lastPrice came from a stale oracle blip
                                // that won't survive a real swap. For any high-PnL
                                // trigger, force a Jupiter route verification of
                                // ts.lastPrice BEFORE delegating to runManageOnly.
                                // If Jupiter confirms the price within tolerance,
                                // the gain is REAL вҖ” bank it. If Jupiter disagrees,
                                // refresh ts.lastPrice from Jupiter and re-evaluate
                                // next tick. NEVER cap or block on PnL magnitude.
                                val priceReal = if (pnlPct >= 500.0) {
                                    try {
                                        com.lifecyclebot.engine.RealPriceLock.verifyTakeProfitPrice(
                                            ts, pnlPct, tpPct,
                                        )
                                    } catch (_: Throwable) { true }  // never block on verifier failure
                                } else true
                                if (priceReal) {
                                    if (!ts.position.isPaperPosition) {
                                        // V5.0.4301 вҖ” live rapid profit capture must ACT, not
                                        // delegate and wait. Paper learning looked good because it
                                        // captured/managed many runners; live missed Pride-style
                                        // instant peaks while the rapid monitor only delegated to
                                        // manage-only. On live fast pumps, send a sell/partial
                                        // request immediately from the 500ms monitor.
                                        val capturePct4301 = when {
                                            pnlPct >= 500.0 -> 1.0
                                            pnlPct >= 200.0 -> 0.75
                                            pnlPct >= 50.0  -> 0.50
                                            else            -> 0.25
                                        }
                                        ErrorLogger.warn("BotService", "вҡЎ RAPID_INSTANT_PROFIT_CAPTURE_4301: ${ts.symbol} pnl=${pnlPct.toInt()}% tp=${tpPct.toInt()}% capture=${(capturePct4301*100).toInt()}%")
                                        addLog("вҡЎ RAPID PROFIT CAPTURE: ${ts.symbol} +${pnlPct.toInt()}% sell ${(capturePct4301*100).toInt()}%", ts.mint)
                                        try { PipelineHealthCollector.labelInc("RAPID_INSTANT_PROFIT_CAPTURE_4301") } catch (_: Throwable) {}
                                        try { ForensicLogger.lifecycle("RAPID_INSTANT_PROFIT_CAPTURE_4301", "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnl=${"%.1f".format(pnlPct)} peak=${"%.1f".format(peakPnlPct)} tp=${"%.1f".format(tpPct)} capturePct=${"%.2f".format(capturePct4301)} action=immediate_live_sell_or_partial") } catch (_: Throwable) {}
                                        if (capturePct4301 >= 0.999) {
                                            executor.requestSell(
                                                ts = ts,
                                                reason = "RAPID_INSTANT_PROFIT_CAPTURE_4301_${pnlPct.toInt()}PCT",
                                                wallet = wallet,
                                                walletSol = effectiveBalance
                                            )
                                        } else {
                                            executor.requestPartialSell(
                                                ts = ts,
                                                sellPercentage = capturePct4301,
                                                reason = "RAPID_INSTANT_PROFIT_CAPTURE_4301_${(capturePct4301*100).toInt()}PCT_${pnlPct.toInt()}PCT",
                                                wallet = wallet,
                                                walletBalance = effectiveBalance
                                            )
                                        }
                                        TradeStateMachine.startCooldown(ts.mint)
                                        continue
                                    } else {
                                        ErrorLogger.info("BotService",
                                            "рҹҺҜ RAPID TAKE_PROFIT_DELEGATE: ${ts.symbol} pnl=${pnlPct.toInt()}% вүҘ tp=${tpPct.toInt()}% вҖ” manage-only partial/profit-lock first")
                                        addLog("рҹҺҜ RAPID TP: ${ts.symbol} +${pnlPct.toInt()}% вҖ” checking dynamic partial/profit-lock first", ts.mint)
                                        executor.runManageOnly(ts, wallet, effectiveBalance)
                                    }
                                }
                            }
                        }
                        
                    } catch (e: Exception) {
                        // Log but don't crash the monitor
                        ErrorLogger.debug("BotService", "Rapid stop check error for ${ts.symbol}: ${e.message}")
                    }
                }
                
                // V5.9.721 вҖ” SUB-TRADER EMERGENCY SL SWEEP.
                // ShitCoin / Moonshot / Quality / BlueChip positions live in their
                // own private maps вҖ” NOT in status.tokens. When botLoop is dead
                // (rescue / relaunch cycle) these positions receive zero exit checks.
                // This sweep catches the -97% positions the rapid monitor previously missed.
                // Runs every other tick (~1s cadence) to limit overhead.
                if (System.currentTimeMillis() % 1000L < 550L) {
                    try {
                        val subFloor = -15.0  // unconditional -15% hard floor
                        // List of (mint, entryPrice, closeFn) triples built from each sub-trader
                        val subPositions = mutableListOf<Triple<String, Double, (Double) -> Unit>>()

                        try {
                            com.lifecyclebot.v3.scoring.ShitCoinTraderAI.getActivePositions().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.ShitCoinTraderAI.closePosition(
                                        p.mint, price,
                                        com.lifecyclebot.v3.scoring.ShitCoinTraderAI.ExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}

                        try {
                            com.lifecyclebot.v3.scoring.MoonshotTraderAI.getActivePositions().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.MoonshotTraderAI.closePosition(
                                        p.mint, price,
                                        com.lifecyclebot.v3.scoring.MoonshotTraderAI.ExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}

                        try {
                            com.lifecyclebot.v3.scoring.QualityTraderAI.getActivePositions().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.QualityTraderAI.closePosition(
                                        p.mint, price, com.lifecyclebot.v3.scoring.QualityTraderAI.ExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}

                        try {
                            com.lifecyclebot.v3.scoring.BlueChipTraderAI.getActivePositions().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.BlueChipTraderAI.closePosition(
                                        p.mint, price, com.lifecyclebot.v3.scoring.BlueChipTraderAI.ExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}

                        // V5.9.963 вҖ” EXTEND SWEEP TO ALL 9 SUB-TRADERS.
                        // Pre-fix only 4 of 9 sub-traders were swept. The other 5
                        // (Moonshot, Quality, Manipulated, DipHunter, ProjectSniper,
                        // ShitCoinExpress) could leak zombies that paperSell missed.
                        // With the V5.9.963 universal close in Executor.kt this is
                        // belt-and-braces, but it also guarantees that ANY future
                        // entry path that bypasses paperSell's close block still
                        // gets cleaned up.
                        try {
                            com.lifecyclebot.v3.scoring.ManipulatedTraderAI.getActivePositions().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.ManipulatedTraderAI.closePosition(
                                        p.mint, price,
                                        com.lifecyclebot.v3.scoring.ManipulatedTraderAI.ManipExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}
                        try {
                            com.lifecyclebot.v3.scoring.DipHunterAI.getActiveDips().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.DipHunterAI.closeDip(
                                        p.mint, price,
                                        com.lifecyclebot.v3.scoring.DipHunterAI.DipExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}
                        try {
                            com.lifecyclebot.v3.scoring.ProjectSniperAI.getActiveMissions().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    val snEx = com.lifecyclebot.v3.scoring.ProjectSniperAI.ExitSignal(
                                        shouldExit = true,
                                        exitPct = 100,
                                        reason = "STOP_LOSS",
                                        rank = com.lifecyclebot.v3.scoring.ProjectSniperAI.SniperRank.PENDING,
                                    )
                                    com.lifecyclebot.v3.scoring.ProjectSniperAI.completeMission(p.mint, price, snEx)
                                })
                            }
                        } catch (_: Throwable) {}
                        try {
                            com.lifecyclebot.v3.scoring.ShitCoinExpress.getActiveRides().forEach { p ->
                                subPositions.add(Triple(p.mint, p.entryPrice) { price ->
                                    com.lifecyclebot.v3.scoring.ShitCoinExpress.exitRide(
                                        p.mint, price,
                                        com.lifecyclebot.v3.scoring.ShitCoinExpress.ExitSignal.STOP_LOSS)
                                })
                            }
                        } catch (_: Throwable) {}

                        for ((mint, entryPrice, closeFn) in subPositions) {
                            if (entryPrice <= 0.0) continue
                            // V5.9.963 вҖ” SELF-CLEANING ZOMBIE PURGE.
                            // If the main status.tokens position is already closed
                            // (qtyToken=0 / pendingVerify) the sub-trader's private
                            // map is stale -- the bleed source for V5.9.962's
                            // SELL_LOCK churn (417 sets / 3 real sells). Purge
                            // the sub-trader entry silently so the next sweep
                            // tick is a no-op for this mint.
                            val tsPurge = synchronized(status.tokens) { status.tokens[mint] }
                            if (tsPurge != null && !tsPurge.position.isOpen) {
                                try { closeFn(tsPurge.lastPrice.coerceAtLeast(entryPrice)) }
                                catch (_: Throwable) {}
                                ForensicLogger.lifecycle(
                                    "SUB_TRADER_ZOMBIE_PURGE",
                                    "mint=${mint.take(10)} entryPrice=$entryPrice вҖ” main pos closed, purging sub-trader map"
                                )
                                continue
                            }
                            // Cheapest price source: status.tokens (no RPC hit)
                            val ts = synchronized(status.tokens) { status.tokens[mint] }
                            val currentPrice = ts?.lastPrice?.takeIf { it > 0.0 } ?: continue
                            val subPnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(
                                entryPrice = entryPrice,
                                currentPrice = currentPrice,
                                entrySource = ts.position.entryPriceSource,
                                currentSource = ts.lastPriceSource,
                                entryPool = ts.position.entryPoolAddress,
                                currentPool = ts.lastPricePoolAddr,
                                priceBasisRescaled = ts.position.priceBasisRescaled,
                                context = "BotService.rapidSubTraderFloor/${ts.symbol}/${mint.take(8)}",
                            )
                            if (!subPnlVerdict.ok) continue
                            val pnlPct = subPnlVerdict.pnlPct
                            if (pnlPct <= subFloor) {
                                ErrorLogger.warn("BotService",
                                    "рҹҡЁ RAPID_SUB_TRADER_HARD_FLOOR: $mint pnl=${pnlPct.toInt()}% вҖ” force-closing")
                                addLog("рҹӣ‘ SUB-TRADER RAPID STOP: $mint ${pnlPct.toInt()}%")
                                try { closeFn(currentPrice) } catch (e2: Exception) {
                                    ErrorLogger.warn("BotService", "Sub-trader closeFn failed $mint: ${e2.message}")
                                }
                                // Belt-and-suspenders: also fire executor path if we have a TokenState
                                if (ts != null) {
                                    try {
                                        executor.requestSell(
                                            ts = ts,
                                            reason = "RAPID_SUB_TRADER_HARD_FLOOR",
                                            wallet = wallet,
                                            walletSol = effectiveBalance)
                                    } catch (_: Throwable) {}
                                }
                            }
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "Sub-trader rapid SL sweep error: ${e.message}")
                    }
                }

                kotlinx.coroutines.delay(CHECK_INTERVAL_MS)
                
            } catch (e: Exception) {
                ErrorLogger.error("BotService", "Rapid stop-loss monitor error: ${e.message}")
                kotlinx.coroutines.delay(1000L)  // Wait longer on error
            }
        }
        
        ErrorLogger.info("BotService", "рҹӣЎпёҸ Rapid Stop-Loss Monitor STOPPED")
    }

    /**
     * V5.9.730 вҖ” OPEN-POSITION 1Hz PRICE TICK LOOP.
     *
     * Operator demand: "live paper and live position price ticks should be
     * every second!" Previously the only path that refreshed ts.lastPrice
     * for an open position was the main bot loop (pollSeconds=8s default)
     * + tryFallbackPriceData calls fired ad-hoc by the scanner. That meant
     * a paper position could go 8+ seconds without a fresh tick, causing
     * three operator-visible symptoms:
     *   1. UI %PnL frozen between cycles вҶ’ looked like the bot was idle
     *   2. STALE_LIVE_PRICE_RUG_ESCAPE firing on healthy pools every time
     *      pump.fun WS dropped or DS pair-cache went cold (90s threshold
     *      hit easily when the scanner skipped the mint for two cycles)
     *   3. Rapid-stop monitor (500ms) reading the same stale lastPrice
     *      over and over вҶ’ its tight cadence was wasted
     *
     * Architecture:
     *   - Runs only while >=1 position is open (idle-sleep otherwise)
     *   - Pulls all open-position mints in a single DS batch call (up to
     *     30 mints; we never have >25 open positions in practice)
     *   - Bypasses the 45s pair cache because the whole point is freshness
     *   - Tick cadence 1000ms вҖ” matches operator spec, well within DS limits
     *     (RateLimiter holds dexscreener at 1-2 req/sec which is fine since
     *     we batch up to 30 mints per request)
     *   - On rate-limit denial: keep lastPrice as-is, do NOT bump
     *     lastPriceUpdate (so a true stale feed still triggers rug-escape)
     *   - On success: update ts.lastPrice + ts.lastPriceUpdate, append a
     *     synthetic candle so trailing-stop / pattern detectors see motion
     */
    // V5.9.924 вҖ” per-mint cooldown for Birdeye fallback in openPositionTickLoop.
    // Prevents hammering /defi/price for permanently-rugged mints.
    private val openPosFallbackLastAttempt = java.util.concurrent.ConcurrentHashMap<String, Long>()
    // V5.9.946 вҖ” track first-miss timestamp per mint so chronic DS-misses (>60s) get a 60s backoff
    private val openPosFallbackFirstMiss = java.util.concurrent.ConcurrentHashMap<String, Long>()

        private suspend fun openPositionTickLoop() {
        ErrorLogger.info("BotService", "рҹ“Ў Open-Position Tick Loop STARTED (1Hz when positions open)")
        val TICK_MS = 1_000L
        val IDLE_MS = 5_000L
        var consecutiveEmpty = 0

        while (status.running) {
            try {
                val openMints = synchronized(status.tokens) {
                    status.tokens.values
                        .filter { it.position.isOpen && it.mint.isNotBlank() }
                        .map { it.mint }
                }

                if (openMints.isEmpty()) {
                    kotlinx.coroutines.delay(IDLE_MS)
                    consecutiveEmpty = 0
                    continue
                }

                // DS batch endpoint caps at 30 mints; split if we ever exceed it
                val chunks = openMints.chunked(30)
                val priceMap = HashMap<String, Double>(openMints.size)
                for (chunk in chunks) {
                    val part = try { dex.batchPriceFetch(chunk) } catch (_: Throwable) { emptyMap() }
                    priceMap.putAll(part)
                }

                // V5.9.924 вҖ” MULTI-SOURCE FALLBACK for mints DS dropped.
                // Operator V5.9.922 screenshots showed positions bleeding past
                // every floor while ts.lastPrice was frozen вҖ” DexScreener had
                // dropped rugged tokens from its index, so the batch call
                // returned no entry for those mints. Previously the tick loop
                // silently moved on, leaving ts.lastPrice at the entry value
                // and pnlPct=0% so catastrophe never fired.
                //
                // Memory rules #87 (paper trains live, dropped signal hurts the
                // brain) and #23 (-15% floor unconditional): if DS won't tell
                // us the rugged price, ask Birdeye. /defi/price is the cheapest
                // tier-unrestricted endpoint (memory #143). For an 8-position
                // open set with 3-4 DS misses, this adds вүӨ4 HTTP calls/sec вҖ”
                // well inside our rate budget. We rate-limit to 1 fallback
                // attempt per mint per 5s so a permanently-rugged mint can't
                // hammer the API every tick.
                val missing = openMints.filter { it !in priceMap }
                if (missing.isNotEmpty()) {
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    // V5.9.946 вҖ” BIRDEYE FALLBACK BUDGET DISCIPLINE.
                    //
                    // Operator V5.9.945 dump revealed THIS loop was the dominant
                    // CU burn source вҖ” not the V5.9.937-942 prefetch. With 55
                    // open positions and ~30 DS-missing mints per tick (mostly
                    // fresh PUMP_FUN_NEW with liq=$0.0 that DS hasn't indexed),
                    // this loop was firing ~30 Birdeye calls every 5s = ~360/min
                    // Г— 60min Г— 5CU = ~108K CU/hour, ~2.6M CU/day. Combined
                    // with prefetch = 75% monthly burn in 10 hours.
                    //
                    // The V5.9.924 cost-comment ("8 positions, 3-4 DS misses,
                    // вүӨ4 calls/sec") rotted as position cap grew and PUMP_FUN
                    // intake exploded. Same anti-pattern as V5.9.945 #87.23.
                    //
                    // Three discipline knobs:
                    //   1. BUDGET GATE вҖ” respect BirdeyeBudgetGate. If we're
                    //      at the daily cap, fall back to last known price
                    //      (will trip a hard SL eventually).
                    //   2. CHRONIC-MISS BACKOFF вҖ” if a mint has been DS-missing
                    //      for >60s, it's almost certainly rugged or DS-unindexed.
                    //      Slow retry to once every 60s instead of 5s. Saves
                    //      ~10Г— on the chronic offenders.
                    //   3. PER-TICK CAP вҖ” never burn more than 5 Birdeye calls
                    //      from a single tick. If 30 mints are missing, we'll
                    //      cycle through them across multiple ticks.
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    val cfg2 = try { ConfigStore.load(applicationContext) } catch (_: Throwable) { null }
                    val key = cfg2?.birdeyeApiKey
                    if (!key.isNullOrBlank()) {
                        val birdeye = try { com.lifecyclebot.network.BirdeyeApi(key) } catch (_: Throwable) { null }
                        if (birdeye != null) {
                            val nowMs = System.currentTimeMillis()
                            var burnedThisTick = 0
                            // V5.9.1123 вҖ” Birdeye emergency conservation: provider
                            // account is ~300% over monthly. Use at most one fallback
                            // price per tick and only through the emergency gate.
                            val perTickCap = 1
                            for (mint in missing) {
                                if (burnedThisTick >= perTickCap) break
                                val lastFb = openPosFallbackLastAttempt[mint] ?: 0L
                                val firstMiss = openPosFallbackFirstMiss.getOrPut(mint) { nowMs }
                                val chronicMs = nowMs - firstMiss
                                // Cooldown: 5s normally, 60s for chronic (>60s missing)
                                val cooldownMs = if (chronicMs > 60_000L) 60_000L else 5_000L
                                if (nowMs - lastFb < cooldownMs) continue
                                // Budget gate вҖ” if we're at cap, skip. Open-position
                                // safety still has hard-SL via the position's last
                                // known price (price will go stale вҶ’ SL trips later).
                                if (!com.lifecyclebot.engine.BirdeyeBudgetGate.canAffordOpenPositionEmergency(1)) {
                                    com.lifecyclebot.engine.BirdeyeBudgetGate.logThrottleIfDue()
                                    break
                                }
                                openPosFallbackLastAttempt[mint] = nowMs
                                burnedThisTick++
                                val price = try { birdeye.getTokenPriceEmergency(mint) } catch (_: Throwable) { null }
                                if (price != null && price > 0.0) {
                                    priceMap[mint] = price
                                    // Reset chronic counter on success
                                    openPosFallbackFirstMiss.remove(mint)
                                    val tsRef = status.tokens[mint]
                                    if (tsRef != null) {
                                        synchronized(tsRef) {
                                            tsRef.lastPriceSource = "BIRDEYE_PRICE_FALLBACK"
                                        }
                                    }
                                    ErrorLogger.info("BotService",
                                        "рҹ“Ў BIRDEYE_FALLBACK: ${mint.take(8)} DS missing вҶ’ birdeye price=$price")
                                }
                            }
                        }
                    }
                    // Clean up tracking for mints no longer in our open set
                    openPosFallbackFirstMiss.keys.retainAll(openMints.toSet())
                }

                if (priceMap.isEmpty()) {
                    // Rate-limited or DS down. Don't bump lastPriceUpdate.
                    // After ~30s of empty results, log once for forensics.
                    consecutiveEmpty++
                    if (consecutiveEmpty == 30) {
                        ErrorLogger.warn("BotService",
                            "рҹ“Ў OpenPositionTick: 30 consecutive empty batches (${openMints.size} mints) вҖ” DS rate-limited or feed-dark")
                    }
                    kotlinx.coroutines.delay(TICK_MS)
                    continue
                }
                consecutiveEmpty = 0

                val now = System.currentTimeMillis()
                var updated = 0
                for ((mint, priceUsd) in priceMap) {
                    val ts = status.tokens[mint] ?: continue
                    if (!ts.position.isOpen) continue
                    if (priceUsd <= 0.0) continue

                    // V5.9.734 вҖ” WS TICK-FILTER for OPEN positions.
                    // The pair-poll ingest path at line ~8500 already
                    // applies a 100x tick-filter (decimal-shift artifact
                    // rejection) before persisting. The WebSocket open-
                    // position update path had no such guard вҖ” any glitch
                    // quote on a thin Pump.fun pool wrote straight to
                    // ts.lastPrice AND appended a fake candle, which then
                    // tripped trailing-stop / RAPID_TAKE_PROFIT_30 on a
                    // ghost move. Result: the +9,398% / +12,675% wins in
                    // the operator's journal вҖ” all real-Executor exits
                    // firing on bad ticks, not the Lab.
                    //
                    // Per operator policy (V5.9.734): NO PRICE SIMULATION,
                    // NO PnL CAPS. The right answer is to REJECT the bad
                    // tick at ingest and keep the last real price. If the
                    // move is genuine the next clean quote will confirm
                    // it. If it was a feed glitch we never acted on it.
                    // V5.9.953 вҖ” bounded reject streak. If 50+ consecutive
                    // ticks fail the filter at the same anchor, the ANCHOR is
                    // the glitch (basis-switch, stale BC quote), not the
                    // incoming data. Accept and reset; otherwise the position
                    // is frozen forever at a fake price. Operator dump showed
                    // GOOOOAL stuck at prev=6.169E-4 while every Pump.fun WS
                    // tick at ~2E-6 got rejected вҖ” that's a real basis switch
                    // (BC вҶ’ graduated) that the filter mistakenly treats as a
                    // glitch indefinitely.
                    val prev = ts.lastPrice
                    if (prev > 0.0) {
                        val jumpMult = priceUsd / prev
                        if (jumpMult > 100.0 || jumpMult < 0.01) {
                            ts.wsTickRejectStreak += 1
                            if (ts.wsTickRejectStreak >= 50) {
                                ErrorLogger.warn("BotService",
                                    "рҹҹў WS_TICK_FILTER recovery for ${ts.symbol}: " +
                                    "${ts.wsTickRejectStreak} consecutive rejects at prev=$prev вҖ” " +
                                    "anchor is the glitch, accepting new=$priceUsd as truth")
                                ts.wsTickRejectStreak = 0
                                // fall through to accept the new price
                            } else {
                                val liveOpenCrashTick = ts.position.isOpen && !ts.position.isPaperPosition && jumpMult < 0.01
                                if (liveOpenCrashTick) {
                                    ErrorLogger.warn("BotService",
                                        "рҹҡЁ WS_TICK_FILTER_CRASH_PROOF ${ts.symbol}: prev=$prev вҶ’ new=$priceUsd " +
                                        "(jump=${"%.4f".format(jumpMult)}x streak=${ts.wsTickRejectStreak}) вҖ” rejected tick is NOT safe; forcing emergency sell proof route")
                                    try {
                                        ForensicLogger.lifecycle(
                                            "WS_TICK_FILTER_CRASH_PROOF_ROUTE",
                                            "mint=${ts.mint.take(10)} symbol=${ts.symbol} prev=$prev new=$priceUsd jump=${"%.6f".format(jumpMult)} streak=${ts.wsTickRejectStreak} action=request_sell_no_ui_settlement",
                                        )
                                    } catch (_: Throwable) {}
                                    try { com.lifecyclebot.engine.sell.SellReconciler.requestUrgentTick("WS_TICK_FILTER_CRASH_PROOF_ROUTE") } catch (_: Throwable) {}
                                    try {
                                        val cfgTick = ConfigStore.load(applicationContext)
                                        val walletTick = walletManager.getWallet()
                                        val balTick = status.getEffectiveBalance(cfgTick.paperMode)
                                        executor.requestSell(
                                            ts,
                                            "WS_TICK_FILTER_CRASH_PROOF_${(jumpMult * 10000.0).toInt()}BPS",
                                            walletTick,
                                            balTick,
                                        )
                                    } catch (e: Throwable) {
                                        try { com.lifecyclebot.engine.sell.CloseLease.recordRetry(ts.mint, "WS_TICK_FILTER_CRASH_PROOF_ROUTE_SUBMIT_FAILED") } catch (_: Throwable) {}
                                        ErrorLogger.warn("BotService", "WS_TICK_FILTER_CRASH_PROOF sell route failed to submit: ${e.message}")
                                    }
                                } else {
                                    ErrorLogger.warn("BotService",
                                        "рҹҡ« WS_TICK_FILTER rejected ${ts.symbol} OPEN: prev=$prev вҶ’ new=$priceUsd " +
                                        "(jump=${"%.1f".format(jumpMult)}x streak=${ts.wsTickRejectStreak}) вҖ” feed glitch, position holds")
                                }
                                continue
                            }
                        } else {
                            ts.wsTickRejectStreak = 0  // healthy tick вҖ” reset
                        }
                    }

                    synchronized(ts) {
                        ts.lastPrice = priceUsd
                        ts.lastPriceUpdate = now
                        ts.lastPriceSource = "DEXSCREENER_WS"  // V5.9.744
                        // Append a tick candle so trailing-stop + pattern AIs see motion.
                        // Keep history bounded вҖ” same 300-candle cap used elsewhere.
                        val candle = com.lifecyclebot.data.Candle(
                            ts = now,
                            priceUsd = priceUsd,
                            marketCap = ts.lastMcap,
                            volumeH1 = 0.0,
                            volume24h = 0.0,
                            buysH1 = 0,
                            sellsH1 = 0,
                            highUsd = priceUsd,
                            lowUsd = priceUsd,
                            openUsd = priceUsd,
                        )
                        synchronized(ts.history) {
                            ts.history.addLast(candle)
                            if (ts.history.size > 300) ts.history.removeFirst()
                        }
                    }
                    // V5.9.924 вҖ” BROADCAST FRESH TICK TO LANE-PRIVATE STORES.
                    // Operator reported "data mismatches between token display
                    // panels". Root cause: openPositionTickLoop updated only
                    // ts.lastPrice. The Treasury card reads CashGenerationAI's
                    // trackedPrices map; ShitCoin/Moonshot/BlueChip/Quality
                    // cards each read their own private currentPrice fields.
                    // None of those stores were ever updated by the 1Hz tick
                    // loop вҖ” they only got fresh prices from the slow scanner
                    // cycle in processTokenCycle. So the meme card showed a
                    // live PnL while the Treasury card for the same mint sat
                    // at +0.0% (or stale numbers from minutes ago). Broadcast
                    // each fresh tick to every lane-private store so all cards
                    // read the same number. Each lane updateLivePrice is a
                    // fast no-op if the lane doesn't hold this mint.
                    try {
                        com.lifecyclebot.v3.scoring.CashGenerationAI.updatePrice(mint, priceUsd)
                    } catch (_: Throwable) {}
                    try {
                        com.lifecyclebot.v3.scoring.ShitCoinTraderAI.updateLivePrice(mint, priceUsd)
                    } catch (_: Throwable) {}
                    try {
                        com.lifecyclebot.v3.scoring.MoonshotTraderAI.updateLivePrice(mint, priceUsd)
                    } catch (_: Throwable) {}
                    try {
                        com.lifecyclebot.v3.scoring.BlueChipTraderAI.updateLivePrice(mint, priceUsd)
                    } catch (_: Throwable) {}
                    try {
                        com.lifecyclebot.v3.scoring.QualityTraderAI.updateLivePrice(mint, priceUsd)
                    } catch (_: Throwable) {}
                    // V5.9.965 вҖ” FEED THE DORMANT SCORERS (audit V5.9.962 Tier 1).
                    // OrderFlowImbalanceAI / SmartMoneyDivergenceAI /
                    // VolatilityRegimeAI all had .score() wired into
                    // UnifiedScorer but .analyze() had ZERO callers вҖ” so
                    // their internal state never updated and they reported
                    // neutral votes forever, diluting genuine layer signals.
                    // We have fresh ts.history here; pull the last ~30
                    // candles and feed each feeder. Each analyze() call is
                    // cheap (math on вүӨ30 doubles) and fail-open.
                    try {
                        val hist = synchronized(ts.history) { ts.history.toList() }
                        if (hist.size >= 5) {
                            val recent = hist.takeLast(30)
                            val highs   = recent.map { it.highUsd }
                            val lows    = recent.map { it.lowUsd }
                            val closes  = recent.map { it.priceUsd }
                            val buys    = recent.map { it.buysH1.toDouble() }
                            val sells   = recent.map { it.sellsH1.toDouble() }
                            try {
                                com.lifecyclebot.v3.scoring.VolatilityRegimeAI.analyze(
                                    mint, ts.symbol, highs, lows, closes
                                )
                            } catch (_: Throwable) {}
                            try {
                                com.lifecyclebot.v3.scoring.OrderFlowImbalanceAI.analyze(
                                    mint, ts.symbol, buys, sells, closes
                                )
                            } catch (_: Throwable) {}
                            try {
                                com.lifecyclebot.v3.scoring.SmartMoneyDivergenceAI.analyze(
                                    mint, ts.symbol, closes
                                )
                            } catch (_: Throwable) {}
                        }
                    } catch (_: Throwable) { /* never break the tick loop */ }

                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    // V5.9.1455 вҖ” TICK-TIME HARD-FLOOR + PROFIT-LOCK (sub-second exit)
                    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                    // Problem (operator V5.9.1454 dump): -15% HARD_FLOOR filled at
                    // -29.4% on a real-money sell because the actual stop check
                    // lived in hotExit's 2s cadence вҶ’ up to 2s of slippage on a
                    // fast rug, AND a +1000% peak gave back to ~+4% because the
                    // give-back trailing only fired in the slow path. Both bleed
                    // real $$$.
                    //
                    // Fix: evaluate two tick-time guards the instant a fresh price
                    // arrives. Gated to MEME lane (Moonshot + ShitCoin) per
                    // operator directive вҖ” that's where the bleeds happened.
                    // BlueChip/Treasury keep their own lane-specific tighter SLs.
                    //
                    //   1) TICK_HARD_FLOOR_PCT (-10): unconditional kill-switch.
                    //   2) TICK_PROFIT_LOCK: progressive trailing give-back вҖ”
                    //      once a position has peaked past +30%, we never let
                    //      give-back exceed a peak-tier-specific share. Lets
                    //      runners run but never gives back a 1000% ride.
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    try {
                        val pos = ts.position
                        val entryPx = pos.entryPrice
                        if (pos.isOpen && entryPx > 0.0) {
                            // V5.0.6083 вҖ” TICK-TIME EXIT PARITY FOR EVERY OPEN POSITION.
                            // Runtime 6081 report showed BLUE_CHIP/PRESALE/LONG_HOLD paper
                            // positions repeatedly logging TICK_PROFIT_LOCK_SKIPPED_LANE while
                            // open winners/losers waited for slower lane exits. The 1Hz tick path
                            // has the freshest price and must provide the universal hard-floor +
                            // peak/giveback shell for ALL open positions. Lane-specific exits can
                            // still add smarter behavior; they cannot be the only runner safety net.
                            val tickProfitLockEligible = true
                            if (tickProfitLockEligible) {
                                val rawTickPnlPctNow = (priceUsd - entryPx) / entryPx * 100.0
                                // V5.0.4152 вҖ” UI/EXEC HIGH-LOCK PARITY.
                                // Operator screenshot: TARGET Peak +2600% / lock +2600%,
                                // but position stayed open. Root cause: the UI displayed
                                // FluidLearningAI.getDynamicFluidStop() while this hot exit
                                // path used an older loose peak-ratio floor and raw tick PnL.
                                // Resolve through Executor's executable price normalizer, then
                                // compare against the SAME fluid lock floor the UI shows.
                                val execPxForTickLock = try {
                                    executor.getActualPricePublic(ts).takeIf { it.isFinite() && it > 0.0 }
                                } catch (_: Throwable) { null }
                                val entryPxForTickLock = pos.entryPrice.takeIf { it.isFinite() && it > 0.0 } ?: entryPx
                                val safeExecPxForTickLock4481 = walletCorrespondentOpenPrice4481(ts, execPxForTickLock ?: priceUsd, "TICK_PROFIT_LOCK")
                                val execPnlPctNow = if (safeExecPxForTickLock4481 > 0.0 && entryPxForTickLock > 0.0)
                                    ((safeExecPxForTickLock4481 - entryPxForTickLock) / entryPxForTickLock) * 100.0
                                else rawTickPnlPctNow
                                val pnlPctNow = execPnlPctNow
                                if (kotlin.math.abs(execPnlPctNow - rawTickPnlPctNow) >= 5.0) {
                                    try { PipelineHealthCollector.labelInc("TICK_PROFIT_LOCK_EXEC_PRICE_REBASE") } catch (_: Throwable) {}
                                    try { ForensicLogger.lifecycle("TICK_PROFIT_LOCK_EXEC_PRICE_REBASE", "mint=${ts.mint.take(10)} symbol=${ts.symbol} raw=${"%.1f".format(rawTickPnlPctNow)} exec=${"%.1f".format(execPnlPctNow)} peak=${"%.1f".format(pos.peakGainPct)} src=${ts.lastPriceSource}") } catch (_: Throwable) {}
                                }
                                // V5.9.1562 вҖ” RATCHET peakGainPct BEFORE the lock check.
                                // Operator MFE forensic 5.0.3659 (MOONSHOT avgPeak +630% but
                                // avgRealized -1.4% вҖ” runner cut catastrophically): root
                                // cause was reading a stale ts.position.peakGainPct that
                                // only got bumped by rapidStopLossMonitor's separate pnl
                                // calc. The 1Hz openPositionTickLoop has the FRESHEST price
                                // in the entire bot вҖ” if we don't ratchet here, the meme
                                // peak runs ahead of the host peak by seconds-to-minutes
                                // and the TICK_PROFIT_LOCK reads a near-zero high-water
                                // mark, never firing while the runner gives it all back.
                                if (pnlPctNow > pos.peakGainPct) {
                                    pos.peakGainPct = pnlPctNow
                                }
                                val peakPct = pos.peakGainPct

                                // в”Җв”Җв”Җ Guard 1: TICK_HARD_FLOOR @ -10% в”Җв”Җв”Җ
                                // V5.9.1564 вҖ” SANITY: a single tick can read a stale entry
                                // price right after a basis switch (PumpFun BC вҶ’ Raydium)
                                // and report pnlвүҲ-96% on a token actually up +100%. Operator
                                // dump 5.0.3671: 3osrzz BUY 0.014 вҶ’ SELL 0.030 pnl=+0.016
                                // reason=TICK_HARD_FLOOR_-96PCT (sold a winner because the
                                // tick read a phantom -96%). Two-line guard:
                                //   1) cap floor sensitivity вҖ” anything below -50% is past
                                //      the real -10% floor anyway and almost certainly a
                                //      bad read. Defer to the slow-path sweep / sub-trader.
                                //   2) require two consecutive sub-floor reads before firing
                                //      (lastTickPnlBelowFloor must already be true).
                                val execVsRawDelta4485 = kotlin.math.abs(execPnlPctNow - rawTickPnlPctNow)
                                val catastrophicConfirmed4485 = pnlPctNow <= -50.0 && execPxForTickLock != null && execVsRawDelta4485 <= 20.0
                                val phantomRead = pnlPctNow < -50.0 && !catastrophicConfirmed4485
                                val twoStrike = pos.lastTickFloorBreach
                                // V5.0.4588 вҖ” CATASTROPHIC-LANE ONE-STRIKE (operator P0 task d).
                                // Operator report: -95%/-99% closes still landing on
                                // MANIPULATED/SHITCOIN/EXPRESS because the two-strike
                                // requirement means the rug happens BETWEEN two ticks.
                                // For known-catastrophic lanes, honour the -10% tick
                                // floor on the FIRST breach вҖ” no two-strike grace. Rule
                                // 2's -15% lane hard-SL in Executor.kt still fires as
                                // the last-mile backstop, but this closes the gap
                                // between ticks where rugs slip through.
                                val laneName4588 = try { pos.tradingMode.uppercase() } catch (_: Throwable) { "" }
                                val catastrophicLane4588 =
                                    laneName4588 == "MANIPULATED" ||
                                    laneName4588 == "SHITCOIN" ||
                                    laneName4588 == "EXPRESS"
                                val oneStrikeCatastrophic4588 = catastrophicLane4588 && !phantomRead && pnlPctNow <= TICK_HARD_FLOOR_PCT
                                // Update the strike flag for the next tick. Confirmed catastrophic
                                // executable-price reads bypass the old phantom dead-zone immediately.
                                pos.lastTickFloorBreach = (pnlPctNow <= TICK_HARD_FLOOR_PCT && !phantomRead)
                                if (pnlPctNow <= TICK_HARD_FLOOR_PCT && (catastrophicConfirmed4485 || oneStrikeCatastrophic4588 || (!phantomRead && twoStrike))) {
                                    ErrorLogger.warn("BotService",
                                        "рҹӣ‘ TICK_HARD_FLOOR ${ts.symbol} ${"%.1f".format(pnlPctNow)}% " +
                                        "вүӨ ${TICK_HARD_FLOOR_PCT.toInt()}% вҖ” immediate exit (peak=${"%.1f".format(peakPct)}% catastrophic=$catastrophicConfirmed4485 oneStrikeLane=$oneStrikeCatastrophic4588)")
                                    try {
                                        if (catastrophicConfirmed4485) {
                                            PipelineHealthCollector.labelInc("TICK_CATASTROPHIC_CONFIRMED_BYPASS_PHANTOM_4495")
                                            ForensicLogger.lifecycle("TICK_CATASTROPHIC_CONFIRMED_BYPASS_PHANTOM_4495", "mint=${ts.mint.take(10)} symbol=${ts.symbol} raw=${"%.1f".format(rawTickPnlPctNow)} exec=${"%.1f".format(execPnlPctNow)} delta=${"%.1f".format(execVsRawDelta4485)} peak=${"%.1f".format(peakPct)} action=immediate_sell")
                                        }
                                        if (oneStrikeCatastrophic4588 && !catastrophicConfirmed4485) {
                                            PipelineHealthCollector.labelInc("TICK_HARD_FLOOR_CATASTROPHIC_LANE_ONE_STRIKE_4588_$laneName4588")
                                            ForensicLogger.lifecycle("TICK_HARD_FLOOR_CATASTROPHIC_LANE_ONE_STRIKE_4588", "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$laneName4588 pnl=${"%.1f".format(pnlPctNow)}% peak=${"%.1f".format(peakPct)}% action=immediate_sell_no_two_strike_grace")
                                        }
                                        val cfgTick = ConfigStore.load(applicationContext)
                                        val walletTick = walletManager.getWallet()
                                        val balTick = status.getEffectiveBalance(cfgTick.paperMode)
                                        executor.requestSell(ts,
                                            if (catastrophicConfirmed4485) "TICK_CATASTROPHIC_CONFIRMED_${pnlPctNow.toInt()}PCT"
                                            else if (oneStrikeCatastrophic4588) "TICK_HARD_FLOOR_CATASTROPHIC_LANE_${laneName4588}_${pnlPctNow.toInt()}PCT_4588"
                                            else "TICK_HARD_FLOOR_${pnlPctNow.toInt()}PCT",
                                            walletTick, balTick)
                                    } catch (_: Throwable) {}
                                } else {
                                    // в”Җв”Җв”Җ Guard 2: TICK_PROFIT_LOCK (UI high-lock parity) в”Җв”Җв”Җ
                                    // Use FluidLearningAI's high-lock floor вҖ” the same value
                                    // rendered as "lock +X%" in the open-position card.
                                    val lockedFloor = try {
                                        com.lifecyclebot.v3.scoring.FluidLearningAI.getDynamicFluidStop(
                                            modeDefaultStop = 20.0,
                                            currentPnlPct = pnlPctNow,
                                            peakPnlPct = peakPct,
                                            holdTimeSeconds = ((System.currentTimeMillis() - pos.entryTime) / 1000.0).coerceAtLeast(0.0),
                                            volatility = ts.volatility ?: 50.0,
                                        )
                                    } catch (_: Throwable) { Double.NaN }
                                    if (!lockedFloor.isNaN() && lockedFloor > 0.0) {
                                        val highLockImmediate = peakPct >= 200.0 && pnlPctNow >= lockedFloor
                                        val lockBreached = pnlPctNow < lockedFloor && pnlPctNow > 0.0
                                        if (highLockImmediate || lockBreached) {
                                            // V5.9.1566 вҖ” doctrine: never bank a positive
                                            // pnl that doesn't beat cost + treasury feed.
                                            // Stop-loss path is unaffected (this branch
                                            // only fires on positive pnl give-back).
                                            val isPaperRt = try { com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() } catch (_: Throwable) { false }
                                            val beOk = com.lifecyclebot.engine.LiveRestoreExecutionPolicy.sellSideBreakEvenOk(ts, pnlPctNow, isPaperRt)
                                            if (!beOk) {
                                                // hold for more upside вҖ” high-lock will retry on next tick
                                            } else {
                                            ErrorLogger.warn("BotService",
                                                "рҹ”’ TICK_PROFIT_LOCK ${ts.symbol} " +
                                                "peak=${"%.1f".format(peakPct)}% now=${"%.1f".format(pnlPctNow)}% " +
                                                "floor=${"%.1f".format(lockedFloor)}% вҖ” locking profit")
                                            try {
                                                val cfgTick = ConfigStore.load(applicationContext)
                                                val walletTick = walletManager.getWallet()
                                                val balTick = status.getEffectiveBalance(cfgTick.paperMode)
                                                executor.requestSell(ts,
                                                    "TICK_PROFIT_LOCK_peak${peakPct.toInt()}_now${pnlPctNow.toInt()}",
                                                    walletTick, balTick)
                                            } catch (_: Throwable) {}
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    } catch (_: Throwable) { /* never break the tick loop */ }

                    updated++
                }

                // Forensic counter so the operator can verify the loop is alive.
                // Routed through onLifecycle so it shows up in the labelled
                // counters block of the Pipeline Health Snapshot dump as
                // LIFECYCLE/OPEN_POS_TICK with the updated/total ratio.
                try {
                    com.lifecyclebot.engine.PipelineHealthCollector.onLifecycle(
                        "OPEN_POS_TICK", "updated=$updated/${openMints.size}"
                    )
                } catch (_: Throwable) {}

                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // V5.9.955 вҖ” TICK-LOOP EXIT SWEEP (P0 doctrine fix).
                // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                // Problem: ALL exit decisions (Treasury TP/SL, V3 lane checkExit,
                // -15% hard floor, trailing stops) lived only inside the slow
                // bot loop which was taking 50-60s per cycle (operator forensic
                // dump 2026-05-19 17:28: BOT_LOOP_TICK=3 in 187s = ~62s/cycle).
                // Meanwhile prices were updating every ~660ms via this very
                // loop. Net result: LLORT bled to -49% before the next exit
                // sweep fired; Torqa ran past +4% target all the way to +32%
                // before a sell could be triggered; PTROLL +9.3% sat open with
                // lock +7% but no execution.
                //
                // Fix: now that we have fresh prices in ts.lastPrice (and we've
                // just broadcast them to every lane-private store), run the
                // canonical exit sweep here at ~2s cadence. This is 30x faster
                // than the bot loop and respects Prime Doctrine #11:
                //   "Exit safety NOT dependent on scanner throughput."
                //
                // Throttled to every 2s (not every tick) so we don't burn CPU
                // and so the bot-loop EXIT_SWEEP continues to serve as the
                // authoritative path for orphan/edge-case positions.
                try {
                    val nowSweepMs = System.currentTimeMillis()
                    if (nowSweepMs - lastTickExitSweepMs >= 30_000L) {
                        lastTickExitSweepMs = nowSweepMs
                        val cfgTick = try { ConfigStore.load(applicationContext) } catch (_: Throwable) { null }
                        val walletTick = try { walletManager.getWallet() } catch (_: Throwable) { null }
                        if (cfgTick != null) {
                            // V5.9.1196 вҖ” fallback only. The hotExitJob above owns
                            // the 2s strict-SL/profit-lock path. This loop's primary
                            // job is now fresh pricing; only launch heavy sweep backup
                            // if hotExit hasn't touched exits for 30s.
                            launchExitSweepAsync("OPEN_POSITION_TICK_STALE_BACKUP")
                            launchUniversalSlSweepAsync(cfgTick, walletTick)
                        }
                    }
                } catch (_: Throwable) { /* never break the tick loop */ }

                kotlinx.coroutines.delay(TICK_MS)

            } catch (ce: kotlinx.coroutines.CancellationException) {
                throw ce
            } catch (e: Exception) {
                ErrorLogger.error("BotService", "OpenPositionTickLoop error: ${e.message}")
                kotlinx.coroutines.delay(2_000L)
            }
        }
