    // V5.9.495z54c вҖ” extracted from botLoop() to fit JVM 64KB method limit.
    /**
     * V5.9.626 вҖ” CANONICAL PROTECTED MEME INTAKE.
     *
     * All raw Solana/meme discovery sources must converge here:
     *   - SolanaMarketScanner вҶ’ TokenMergeQueue
     *   - PumpPortal WS
     *   - DataOrchestrator Pump.fun callback
     *   - any future discovery bridge
     *
     * This method is intentionally non-destructive and fail-open for ARRIVAL.
     * It guarantees GlobalTradeRegistry + status.tokens hydration so the Meme
     * Trader UI/loop cannot split-brain between "config watchlist", registry,
     * and runtime token state. Entry quality is still enforced downstream by
     * FDG/safety/sub-trader execution gates.
     */
    // V5.9.768 вҖ” INTAKE DEDUPE. Operator forensic dump @ V5.9.767 showed
    // INTAKE=5478 events / 1688s uptime, with Ebola=191x, immunecoin=109x,
    // COAR=79x. Root cause: line 3095 emits with src=SCANNER_DIRECT_<X>
    // and line 3118 ALSO emits with src=<X> for the same mint when
    // isWatching==true (MemeMintRegistry pre-hydration makes that always
    // true after restart). Plus other call sites (TokenMergeQueue,
    // PumpPortal WS, DataOrchestrator) hit the same mint repeatedly.
    // This map gates the function entry on a per-mint TTL so the
    // forensic dump (and the registry/state hydration work) is done at
    // most once per mint per TTL_MS. Idempotent semantics preserved:
    // GlobalTradeRegistry.addToWatchlist + status.tokens.getOrPut are
    // already fail-open, so the dedupe gate is purely a noise filter.
    private val intakeLastAcceptMs = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private val intakeDedupCount = java.util.concurrent.ConcurrentHashMap<String, Int>()
    private val intakeDedupTtlMs: Long = 30_000L
    // V5.9.1464 вҖ” FAMILY-LEVEL intake burst gate (spec item 7). The per-mint
    // dedupe above stops the SAME mint re-flooding, but pump.fun spam ships the
    // SAME narrative/family under MANY fresh mints (PIГ‘A/JosГ©/JOTCHUA bursts).
    // Track the first admit time per normalized family; within the window, extra
    // DISTINCT mints of that family are still journaled/trained but flagged so the
    // watchlist keeps ONE canonical family row instead of N near-identical rows.
    private val familyFirstAdmitMs = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private val familyAdmitCount = java.util.concurrent.ConcurrentHashMap<String, Int>()
    private val familyIntakeTtlMs: Long = 180_000L  // 3-min window for symbol-family floods
    // V5.9.1466 вҖ” first-seen liquidity baseline per mint, for PROBE GRADUATION.
    // Lets laneQualifiedBuyDecision detect a "liquidity rising" confirmation tick
    // (a spec-listed promotion signal) without adding a TokenState field.
    private val firstSeenLiqUsd = java.util.concurrent.ConcurrentHashMap<String, Double>()
    // V5.9.1466 вҖ” probe size resolver: dust by default, graduated once confirmed.
    private fun resolveProbeSizeMult(mint: String, currentLiqUsd: Double): Double {
        return try {
            if (mint.isBlank() || currentLiqUsd <= 0.0) return LANE_DUST_PROBE_SIZE_MULT
            val baseline = firstSeenLiqUsd.putIfAbsent(mint, currentLiqUsd) ?: currentLiqUsd
            // never let the baseline drift UP (so a later-rising read still graduates);
            // take-min keeps the earliest/lowest observed liquidity as the reference.
            if (currentLiqUsd < baseline) firstSeenLiqUsd[mint] = currentLiqUsd
            val ref = firstSeenLiqUsd[mint] ?: currentLiqUsd
            val rise = if (ref > 0.0) (currentLiqUsd - ref) / ref else 0.0
            if (rise >= PROBE_GRADUATION_LIQ_RISE_FRAC) {
                try { ForensicLogger.lifecycle("PROBE_GRADUATED", "mint=${mint.take(10)} liq=\$${currentLiqUsd.toInt()} baseline=\$${ref.toInt()} rise=${(rise*100).toInt()}% вҶ’ confirmed-probe size") } catch (_: Throwable) {}
                LANE_CONFIRMED_PROBE_SIZE_MULT
            } else {
                LANE_DUST_PROBE_SIZE_MULT
            }
        } catch (_: Throwable) { LANE_DUST_PROBE_SIZE_MULT }
    }

    // V5.9.1035 вҖ” Part 2 (C): symbol-burst spam tracker. Per-symbol
    // sliding window of recent (mint, timestamp) admits; if >5 distinct
    // mints land for the same symbol inside 60s the rest are rejected
    // at the door (clone-storm guaranteed rugs).
    private val symbolBurstWindow = java.util.concurrent.ConcurrentHashMap<String, java.util.concurrent.ConcurrentLinkedDeque<Pair<String, Long>>>()
    private val SYMBOL_BURST_WINDOW_MS: Long = 60_000L
    private val SYMBOL_BURST_MAX_MINTS: Int = 5

    private fun normalizedSymbolBurstKey(symbol: String): String {
        val raw = symbol.trim().lowercase(java.util.Locale.US)
        if (raw.isBlank()) return ""
        val alnum = raw.replace(Regex("[^a-z0-9]+"), "")
        if (alnum.isBlank()) return ""
        // V5.9.1181 вҖ” pump.fun clone storms mutate symbols with prefixes/suffixes,
        // case changes, and numeric counters (TangTang/TANGTANG/ITSTANGTANG,
        // PEPE2/PEPE3, THEPEPE, etc.). Exact lowercase keys miss those families
        // and let them flood WATCHLIST_AFFINITY. Use a conservative family root:
        // remove common hype wrappers and trailing numeric spam only when the root
        // remains meaningful. This is intake spam filtering, not scanner pruning.
        var root = alnum
            .removePrefix("the")
            .removePrefix("its")
            .removePrefix("official")
            .removePrefix("real")
            .removePrefix("new")
        root = root.replace(Regex("(coin|token|sol|cto|pump|fun|onsol|army|dao)$"), "")
        root = root.replace(Regex("[0-9]+$"), "")
        return if (root.length >= 3) root else alnum
    }

    // V5.9.1364 вҖ” BOOTSTRAP DATA-STARVATION PROBE WHITELIST (SHITCOIN volume fix).
    // Operator: WR climbed to 51% (good) but VOLUME cratered everywhere (~50/day vs
    // doctrine floor 500-1000). Root cause: SHITCOIN was the ONLY meme lane whose
    // FDG path was a blanket "!canExecute() -> return" hard veto with no
    // structural/probe split (MOONSHOT & MANIPULATED already split structural-block
    // vs soft-probe). 44% of ALL rejects were SHITCOIN_FDG_HARD_VETO for
    // insufficient_data_thin_market / thin_data_hist_N / signal_is_wait вҖ” pure
    // DATA-STARVATION on fresh pump.fun tokens (1-2 candles, no learned bucket).
    // FDG WAITs -> lane hard-vetoes -> no trade -> no data -> WAITs forever. The
    // very trades that would teach the lane its sweet spot were the ones being
    // killed. This whitelist marks the SOFT reasons that bootstrap may probe
    // through (tiny size); every genuine safety/integrity reason stays a hard veto.
    private fun isPaperBootstrapProbeableFdgBlock(reason: String?): Boolean {
        if (reason.isNullOrBlank()) return false
        val r = reason.lowercase()
        // Hard safety / integrity вҖ” NEVER probe through these (FDG stays hard veto).
        val hardKill = listOf(
            "rug", "freeze", "zero_liquidity", "scam", "toxic", "reentry",
            "circuit", "sell_pressure", "top_holder", "negative_ev", "high_rug",
            "ml_rug", "narrative", "banned", "blacklist", "danger_zone",
            "memory_negative", "behavior_block", "distribution", "symbolic_universe",
            "liquidity_below", "gemini", "kris_rule", "lane_disabled",
            "emergency_stop", "copy_trade"
        )
        if (hardKill.any { r.contains(it) }) return false
        // Soft data-starvation / low-conviction reasons bootstrap should probe.
        val softProbeable = listOf(
            "thin_market", "thin_data", "insufficient_data", "insufficient data",
            "signal_is_wait", "signal is wait", "not buy", "not_buy",
            "bootstrap", "unknown_phase", "low_conviction", "low_confidence",
            "confidence_floor", "c_grade_confidence", "edge_veto", "edge_distribution",
            "fdg_block", "fdg_caution"
        )
        return softProbeable.any { r.contains(it) }
    }


    /**
     * V5.0.4553 вҖ” manipulated overlay ownership.
     * Tokens flagged by wallet/RugCheck UI as single-holder ownership,
     * unverified, or high holder concentration are not normal SHITCOIN /
     * MOONSHOT / EXPRESS bait. They are literal manipulation setups. Only the
     * MANIPULATED lane may attempt them; all other lanes must reject before
     * WAIT/dust-probe override can rescue the buy.
     */
    private fun manipulatedOnlyOverlayActive4553(ts: com.lifecyclebot.data.TokenState?): Boolean {
        val safety = ts?.safety ?: return false
        val text = buildString {
            append(safety.summary).append(' ')
            append(safety.nameFlag).append(' ')
            append(safety.bundleRisk).append(' ')
            append(safety.bundleReason).append(' ')
            safety.hardBlockReasons.forEach { append(it).append(' ') }
            safety.softPenalties.forEach { append(it.first).append(' ') }
        }.lowercase()
        if (text.contains("manipulated_only_overlay_4553")) return true
        val singleHolder = text.contains("single holder") || text.contains("single wallet") || text.contains("holder ownership")
        val unverified = text.contains("unverified token") || text.contains("unverified")
        val holderConcentration = text.contains("holder concentration") || text.contains("top holders") || text.contains("top holder") || safety.topHolderPct >= 50.0
        val trueRug = text.contains("honeypot") || text.contains("cannot_sell") || text.contains("blacklist") || text.contains("confirmed rug") || text.contains("lp unlocked with low liquidity")
        return !trueRug && (singleHolder || unverified || holderConcentration)
    }

    private data class ToolkitGoodLaneBridge6022(
        val lane: String,
        val score: Int,
        val sizeSol: Double,
        val tpPct: Double,
        val slPct: Double,
        val reason: String,
    )

    private fun toolkitGoodLaneBridge6022(ts: com.lifecyclebot.data.TokenState, lane: String, blockedReason: String = ""): ToolkitGoodLaneBridge6022? {
        return try {
            val laneKey = lane.uppercase().replace('-', '_').replace(' ', '_')
            if (laneKey !in setOf("QUALITY", "BLUECHIP", "BLUE_CHIP", "TREASURY", "CASHGEN", "MOONSHOT", "STANDARD")) return null
            if (ts.safety.isBlocked || ts.safety.tier == com.lifecyclebot.engine.SafetyTier.HARD_BLOCK || ts.safety.hardBlockReasons.isNotEmpty()) return null
            val liq = ts.lastLiquidityUsd.takeIf { it.isFinite() } ?: 0.0
            if (liq < 1_500.0) return null
            val sheet = try { ToolkitSignalSheet.snapshot(ts) } catch (_: Throwable) { return null }
            val setup = sheet.setup.name
            val setupGood = setup in setOf(
                "LIQUIDITY_DEPTH_QUALITY", "DIAMOND_HANDS_RUNNER", "CHART_BREAKOUT",
                "CHART_PULLBACK_RECLAIM", "SMART_WALLET_COPY_FOLLOW", "MAINSTREAM_CRYPTO_SWING",
                "NARRATIVE_SOCIAL_IGNITION", "VOLUME_IGNITION_SCALP"
            )
            val laneVoted = sheet.laneVotes.any { it.equals(laneKey, true) || (laneKey == "BLUE_CHIP" && it.equals("BLUECHIP", true)) }
            val chartGood = sheet.chartPattern.contains("accumulation", true) || sheet.chartPattern.contains("breakout", true) ||
                sheet.chartPattern.contains("runner", true) || sheet.chartPattern.contains("pullback", true) ||
                sheet.chartPattern.contains("smart_wallet", true) || sheet.chartPattern.contains("quality", true)
            if (!setupGood && !laneVoted && !chartGood) return null
            val conf = sheet.confidence.coerceIn(0.0, 100.0)
            val score = maxOf(conf.toInt(), (ts.lastV3Score ?: ts.entryScore.toInt()).coerceIn(0, 100), 42).coerceIn(25, 88)
            val sizeBase = when (laneKey) {
                "QUALITY" -> 0.020
                "BLUECHIP", "BLUE_CHIP" -> 0.018
                "TREASURY", "CASHGEN" -> 0.014
                "MOONSHOT" -> 0.018
                else -> 0.016
            }
            val size = (sizeBase * sheet.sizeMult.coerceIn(0.65, 1.25)).coerceIn(0.010, 0.040)
            val tp = when (laneKey) {
                "QUALITY" -> 18.0
                "BLUECHIP", "BLUE_CHIP" -> 14.0
                "TREASURY", "CASHGEN" -> 5.0
                "MOONSHOT" -> 28.0
                else -> 12.0
            } * sheet.tpMult.coerceIn(0.75, 1.35)
            val sl = when (laneKey) {
                "TREASURY", "CASHGEN" -> -4.0
                "BLUECHIP", "BLUE_CHIP" -> -6.0
                else -> -8.0
            }
            val reason = "TOOLKIT_GOOD_LANE_BRIDGE_6022 setup=$setup chart=${sheet.chartPattern.take(40)} conf=${conf.toInt()} votes=${sheet.laneVotes.joinToString("/").take(60)} blocked=${blockedReason.take(80)}"
            try {
                PipelineHealthCollector.labelInc("TOOLKIT_GOOD_LANE_BRIDGE_6022")
                PipelineHealthCollector.labelInc("TOOLKIT_BRIDGE_${laneKey}")
                ForensicLogger.lifecycle("TOOLKIT_GOOD_LANE_BRIDGE_6022", "mint=${ts.mint.take(10)} symbol=${ts.symbol} lane=$laneKey score=$score size=${"%.3f".format(size)} $reason action=send_to_fdg")
            } catch (_: Throwable) {}
            ToolkitGoodLaneBridge6022(laneKey, score, size, tp, sl, reason)
        } catch (_: Throwable) { null }
    }

    private fun laneQualifiedBuyDecision(
        base: com.lifecyclebot.data.CandidateDecision,
        lane: String,
        confidenceFloor: Double = 60.0,
        liquidityUsd: Double = -1.0,   // V5.9.1355 P0.3 вҖ” -1 = unknown (don't liq-gate; still zero-score-gate)
        mintForProbe: String = "",     // V5.9.1466 вҖ” for PROBE GRADUATION (CandidateDecision has no mint field)
    ): com.lifecyclebot.data.CandidateDecision {
        val cleanQuality = when {
            base.finalQuality.isNotBlank() && base.finalQuality != "SKIP" -> base.finalQuality
            base.setupQuality.isNotBlank() && base.setupQuality != "SKIP" -> base.setupQuality
            else -> "C"
        }
        val xTalkShape4262 = try {
            val tsForProbe = mintForProbe.takeIf { it.isNotBlank() }?.let { status.tokens[it] }
            if (tsForProbe != null) MemeCrossTalkEntryBridge.shapeLaneEntry(lane, tsForProbe, confidenceFloor, isOpenPosition = false) else null
        } catch (_: Throwable) { null }
        val shapedConfidenceFloor4262 = xTalkShape4262?.confidenceFloor ?: confidenceFloor
        // V5.0.4591 вҖ” TIGHTEN ENTRY SCORE for weak lanes (operator P1 Issue 2a).
        // Operator: "small losers still bleeding wallet вҖ” 42 new BUYs at ~0.008 SOL
        // Г— ~85% loss rate = death by a thousand cuts". Only STANDARD/MOONSHOT/
        // BLUECHIP have positive expectancy (49-56% WR). All others need higher
        // conviction to admit. Raise the confidence floor by +10 for weak lanes so
        // only high-conviction picks fire. Never touches paper/sandbox.
        val laneUpperForFloor4591 = lane.uppercase()
        val isProvenLane4591 = laneUpperForFloor4591 == "STANDARD" ||
            laneUpperForFloor4591 == "MOONSHOT" ||
            laneUpperForFloor4591 == "BLUECHIP" ||
            laneUpperForFloor4591 == "BLUE_CHIP" ||
            laneUpperForFloor4591 == "QUALITY" ||
            laneUpperForFloor4591 == "CASHGEN" ||
            laneUpperForFloor4591 == "TREASURY" ||
            laneUpperForFloor4591 == "CORE" ||
            laneUpperForFloor4591 == "V3"
        // V5.0.6020 вҖ” fluid score scaffolding. Fixed floors were choking the exact
        // lanes that should produce early samples. Score floors are soft at BOOTSTRAP,
        // tighten briefly during ADVISORY calibration, then fade as the AGI/SSI policy
        // head reaches LEARNED/AUTHORITATIVE authority.
        val agiAuthority6020 = try { com.lifecyclebot.engine.UnifiedPolicyHead.currentAuthority(laneUpperForFloor4591) } catch (_: Throwable) { com.lifecyclebot.engine.UnifiedPolicyHead.AuthorityTier.BOOTSTRAP }
        val structuralFloor6020 = if (!isProvenLane4591) (shapedConfidenceFloor4262 + 10.0).coerceAtMost(90.0) else shapedConfidenceFloor4262
        val entryScoreTightenedFloor4591Base = when (agiAuthority6020) {
            com.lifecyclebot.engine.UnifiedPolicyHead.AuthorityTier.BOOTSTRAP -> (structuralFloor6020 - 18.0).coerceAtLeast(25.0)
            com.lifecyclebot.engine.UnifiedPolicyHead.AuthorityTier.ADVISORY -> (structuralFloor6020 + 4.0).coerceAtMost(88.0)
            com.lifecyclebot.engine.UnifiedPolicyHead.AuthorityTier.LEARNED -> (structuralFloor6020 - 12.0).coerceAtLeast(20.0)
            com.lifecyclebot.engine.UnifiedPolicyHead.AuthorityTier.AUTHORITATIVE -> 0.0
        }
        // V5.0.6044 вҖ” QUALITY WR-based auto-raise + MOONSHOT volume relief.
        // Report 2026-07-03 05:16 showed QUALITY n=22 WR=31.6% EV=-6.52%/trade
        // (mid-tier bleeder) and MOONSHOT n=1 only (dormant proven-EV lane).
        // Auto-raise QUALITY floor +10 while clean WR<40% AND sample>=5
        // (bootstrap-safe, releases when WR recovers >=40%). Lower MOONSHOT
        // floor -5 to drive volume. Applied AFTER the AGI authority delegation
        // so the AGI still has final say via the AUTHORITATIVE tier (which
