            return base.copy(
                signal = "WAIT", finalSignal = "WAIT", shouldTrade = false,
                blockReason = "MANIPULATED_ONLY_OVERLAY_NON_MANIPULATED_LANE_4553",
            )
        }
        val laneBase0 = if (chopPenalty > 0) {
            try {
                PipelineHealthCollector.labelInc("CHOP_FILTER_SOFT_SHAPED_4206")
                ForensicLogger.lifecycle("CHOP_FILTER_SOFT_SHAPED_4206", "lane=$lane source=$sourceForChop phase=${base.phase} score=${base.entryScore.toInt()} penalty=$chopPenalty action=fdg_score_penalty")
            } catch (_: Throwable) {}
            base.copy(entryScore = (base.entryScore - chopPenalty).coerceAtLeast(0.0))
        } else base
        // V5.0.6011 вҖ” MANIP overlay dust-probe penalty (Issue 3 RCA):
        // When MANIP lane is quarantined and overlay fires, the candidate falls
        // through above instead of hard reject. Apply a heavy entryScore penalty
        // (-40) so downstream sizing shrinks to dust-probe rather than full size.
        val laneBase = if (manipOverlayDustProbe6011) {
            try {
                PipelineHealthCollector.labelInc("MANIP_OVERLAY_DUST_PROBE_SCORE_PENALTY_6011")
                ForensicLogger.lifecycle("MANIP_OVERLAY_DUST_PROBE_SCORE_PENALTY_6011", "lane=$lane mint=${mintForProbe.take(10)} priorScore=${laneBase0.entryScore.toInt()} penalty=40 action=shrink_to_dust_probe")
            } catch (_: Throwable) {}
            laneBase0.copy(entryScore = (laneBase0.entryScore - 40.0).coerceAtLeast(0.0))
        } else laneBase0
        // V5.9.1296 вҖ” NOTE: we deliberately do NOT overwrite entryScore here.
        // entryScore feeds two FDG entry gates (unknown-phase conviction @ ~2331
        // and the LIVE edge override @ ~2394); inflating it would loosen entry and
        // push volume even further above the 1000/day ceiling. The lane's real score
        // is instead threaded into the LEARNING CONTEXT only, via the laneScore arg
        // on FDG.evaluate (see V5.9.1296 call-site wiring), so AutonomousMetaPolicy /
        // ForwardOutcomeModel can finally bucket by true lane quality WITHOUT
        // changing which candidates pass the gates.
        //
        // V5.9.1355 P0.3 вҖ” WAIT-OVERRIDE GUARD. Previously this method flipped ANY
        // base decision to normal BUY even when baseFinal=WAIT with score=0/conf=0/
        // "Insufficient data". That sprayed full-size entries into provably-blind
        // contexts and corrupted learning. Now: when the base is a weak WAIT we do
        // NOT promote to a normal buy вҖ” at most we allow a labelled dust-probe
        // (tiny size via qualityPenalty) so the bucket can still learn, and only
        // when liquidity clears the execution floor.
        val baseBlock = laneBase.blockReason
        val weakWait = laneBase.finalSignal.equals("WAIT", ignoreCase = true) ||
            laneBase.entryScore <= 0.0 ||
            laneBase.aiConfidence <= 10.0 ||
            baseBlock.contains("Insufficient data", ignoreCase = true) ||
            baseBlock.contains("thin", ignoreCase = true) ||
            baseBlock.contains("unknown h1", ignoreCase = true) ||
            baseBlock.contains("RC pending", ignoreCase = true)
        // -1 liquidity = unknown вҶ’ treat as "not a liquidity reject" (zero-score gate still applies)
        val liqOk = liquidityUsd < 0.0 || liquidityUsd >= LANE_PROBE_MIN_LIQ_USD
        try { PipelineHealthCollector.labelInc("PREFDG_LANE_CANDIDATE_${lane.uppercase()}") } catch (_: Throwable) {}
        if (weakWait) {
            try { PipelineHealthCollector.labelInc("PREFDG_WEAK_WAIT_${lane.uppercase()}") } catch (_: Throwable) {}
            // V5.9.1361 P0.7/mandate вҖ” TWO distinct rejects, carefully separated:
            //  (a) liquidity too thin to even exit a dust probe  вҶ’ HARD BLOCK (we
            //      could not sell it; blocking is genuine safety, not a strategy kill).
            //  (b) zero-signal (score<=0 && conf<=10) but liquidity OK вҶ’ route to a
            //      labelled DUST PROBE, NOT a hard block. P0.7 forbids a NORMAL-size
            //      buy from score=0/conf=0 вҖ” a tiny PROBE_ONLY trade is not a normal
            //      buy, and the never-disable mandate requires these blind pockets to
            //      keep getting real outcomes (trade SMALL, never zero) so the brain
            //      can learn where/whether they are ever tradeable. This is the lever
            //      that lifts projected exec/day back toward the 500-1000 floor
            //      without spraying full-size capital.
            if (!liqOk) {
                try {
                    PipelineHealthCollector.labelInc("LANE_WAIT_OVERRIDE_BLOCKED")
                    PipelineHealthCollector.labelInc("FDG_THIN_LIQ_BUY_REJECTED")
                    PipelineHealthCollector.labelInc("PREFDG_DROP_THIN_LIQ_${lane.uppercase()}")
                    ForensicLogger.lifecycle("LANE_WAIT_OVERRIDE_BLOCKED",
                        "lane=$lane score=${"%.0f".format(laneBase.entryScore)} conf=${"%.0f".format(laneBase.aiConfidence)} liqUsd=${"%.0f".format(liquidityUsd)} reason=thin_liq block=${baseBlock.take(50)}")
                    LearningLifecycleBus.preFdgReject("DROP_THIN_LIQ", lane, sourceForChop, mintForProbe, edgeSymbol4529, baseBlock, laneBase.entryScore, laneBase.aiConfidence, liquidityUsd, edgeMcap4529, edgeRegime4529)
                } catch (_: Throwable) {}
                return laneBase.copy(
                    signal = "WAIT", finalSignal = "WAIT", shouldTrade = false,
                    blockReason = if (baseBlock.isBlank()) "WAIT_OVERRIDE_BLOCKED_THIN_LIQ" else baseBlock,
                )
            }
            val zeroSignal = laneBase.entryScore <= 0.0 && laneBase.aiConfidence <= 10.0
            val goodLaneVolume6020 = isProvenLane4591 && !zeroSignal && liqOk &&
                (laneBase.entryScore >= entryScoreTightenedFloor4591 || laneBase.aiConfidence >= entryScoreTightenedFloor4591)
            if (goodLaneVolume6020) {
                try {
                    PipelineHealthCollector.labelInc("GOOD_LANE_WAIT_VOLUME_PIVOT_6020")
                    PipelineHealthCollector.labelInc("PREFDG_GOOD_LANE_VOLUME_${lane.uppercase()}")
                    ForensicLogger.lifecycle("GOOD_LANE_WAIT_VOLUME_PIVOT_6020",
                        "lane=$lane auth=${agiAuthority6020.name} score=${"%.0f".format(laneBase.entryScore)} conf=${"%.0f".format(laneBase.aiConfidence)} floor=${"%.0f".format(entryScoreTightenedFloor4591)} liqUsd=${"%.0f".format(liquidityUsd)} action=real_buy_not_probe")
                    LearningLifecycleBus.preFdgAdmit(lane, sourceForChop, mintForProbe, edgeSymbol4529, laneBase.entryScore, laneBase.aiConfidence, liquidityUsd, edgeMcap4529, edgeRegime4529)
                } catch (_: Throwable) {}
                return laneBase.copy(
                    signal = "BUY", finalSignal = "BUY", shouldTrade = true,
                    blockReason = "GOOD_LANE_VOLUME_PIVOT_6020",
                    edgeVeto = false,
                    edgeQuality = if (laneBase.edgeQuality == "SKIP") "B" else laneBase.edgeQuality,
                    finalQuality = if (cleanQuality == "C") "B" else cleanQuality,
                    qualityPenalty = (0.72 * crossTalkSizeMult4262).coerceIn(0.35, 1.18),
                    aiConfidence = laneBase.aiConfidence.coerceAtLeast(entryScoreTightenedFloor4591),
                )
            }
            if (zeroSignal) {
                // V5.0.4164 вҖ” zero-signal is not full live capital, but it must not park
                // the meme trader. If liquidity is exitable, send it through the existing
                // PROBE_ONLY tiny-size path so learning gets real outcomes without spraying
                // normal size. Thin liquidity stayed blocked above.
                try {
                    PipelineHealthCollector.labelInc("LANE_WAIT_OVERRIDE_ZERO_SIGNAL_DUST_PROBE_4164")
                    PipelineHealthCollector.labelInc("FDG_ZERO_SCORE_DUST_PROBE_4164")
                    PipelineHealthCollector.labelInc("PREFDG_ZERO_SIGNAL_${lane.uppercase()}")
                    ForensicLogger.lifecycle("LANE_WAIT_OVERRIDE_ZERO_SIGNAL_DUST_PROBE_4164",
                        "lane=$lane score=${"%.0f".format(laneBase.entryScore)} conf=${"%.0f".format(laneBase.aiConfidence)} liqUsd=${"%.0f".format(liquidityUsd)} action=probe_only_live_learning")
                    LearningLifecycleBus.preFdgProbe("ZERO_SIGNAL_PROBE", lane, sourceForChop, mintForProbe, edgeSymbol4529, baseBlock, laneBase.entryScore, laneBase.aiConfidence, liquidityUsd, edgeMcap4529, resolveProbeSizeMult(mintForProbe, liquidityUsd), edgeRegime4529)
                } catch (_: Throwable) {}
            }
            // Liquidity OK but still weak вҶ’ DUST-PROBE only (explicit + tiny size).
            try {
                PipelineHealthCollector.labelInc("LANE_WAIT_OVERRIDE_DUST_PROBE")
                PipelineHealthCollector.labelInc("PREFDG_DUST_PROBE_${lane.uppercase()}")
                ForensicLogger.lifecycle("LANE_WAIT_OVERRIDE_DUST_PROBE",
                    "lane=$lane score=${"%.0f".format(laneBase.entryScore)} conf=${"%.0f".format(laneBase.aiConfidence)} liqUsd=${"%.0f".format(liquidityUsd)}")
                LearningLifecycleBus.preFdgProbe("DUST_PROBE", lane, sourceForChop, mintForProbe, edgeSymbol4529, baseBlock, laneBase.entryScore, laneBase.aiConfidence, liquidityUsd, edgeMcap4529, resolveProbeSizeMult(mintForProbe, liquidityUsd), edgeRegime4529)
            } catch (_: Throwable) {}
            return laneBase.copy(
                signal = "BUY", finalSignal = "BUY", shouldTrade = true,
                blockReason = "PROBE_ONLY",
                edgeVeto = false,
                edgeQuality = if (laneBase.edgeQuality == "SKIP") "C" else laneBase.edgeQuality,
                finalQuality = "C",
                qualityPenalty = (resolveProbeSizeMult(mintForProbe, liquidityUsd) * crossTalkSizeMult4262).coerceIn(0.05, 1.18),
                aiConfidence = laneBase.aiConfidence.coerceAtLeast(entryScoreTightenedFloor4591),
            )
        }
        try {
            PipelineHealthCollector.labelInc("PREFDG_BUY_QUALIFIED_${lane.uppercase()}")
            LearningLifecycleBus.preFdgAdmit(lane, sourceForChop, mintForProbe, edgeSymbol4529, laneBase.entryScore, laneBase.aiConfidence, liquidityUsd, edgeMcap4529, edgeRegime4529)
        } catch (_: Throwable) {}
        return laneBase.copy(
            signal = "BUY",
            finalSignal = "BUY",
            shouldTrade = true,
            blockReason = "",
            edgeVeto = false,
            edgeQuality = if (laneBase.edgeQuality == "SKIP") "C" else laneBase.edgeQuality,
            finalQuality = cleanQuality,
            aiConfidence = laneBase.aiConfidence.coerceAtLeast(entryScoreTightenedFloor4591),
        ).also {
            try {
                ForensicLogger.lifecycle(
                    "LANE_BUY_INTENT_OVERRIDES_BASE_WAIT",
                    "lane=$lane baseSignal=${laneBase.signal} baseFinal=${laneBase.finalSignal} baseBlock=${laneBase.blockReason.take(80)}"
                )
            } catch (_: Throwable) {}
        }
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.1414 вҖ” CHARACTER-DRIVEN LANE ROUTING.
    // Root cause of the SHITCOIN monopoly: inferIntakeLaneAffinity tagged lanes
    // from the raw SOURCE string at birth, before ModeRouter classified the
    // token's CHARACTER. The rich 7-archetype classification (FRESH_LAUNCH,
    // BREAKOUT_CONTINUATION, REVERSAL_RECLAIM, WHALE_ACCUMULATION, GRADUATION,
    // TREND_PULLBACK, SENTIMENT_IGNITION) was computed every tick then ignored
    // for routing. This maps the classifier verdict to the lane that OWNS that
    // trade archetype, so winners/runners/snipes/diamond-hands are fed to the
    // appropriate trader. Source-agnostic вҖ” works for every feed (PumpPortal,
    // Birdeye, Dex, CoinGecko, Raydium, Solana scanner, smart-money). Additive:
    // merged onto existing affinity, never amputates a lane (doctrine #105).
    private fun laneAffinityForTradeType(tt: ModeRouter.TradeType): Set<String> = when (tt) {
        // V5.0.4129 вҖ” STARVED-LANE WAKEUP. Original mapping only fed 6 of 12 enabled
        // lanes (CASHGEN, CYCLIC, MANIPULATED, MEME, DIP_HUNTER, EXPRESS were silent).
        // AgenticStyleRouter.boundedLanes still caps each token to 2 lanes (primary +
        // one alternate via stablePick), so this broadens the CANDIDATE pool вҖ” it
        // doesn't explode lane_eval. Variety rotates over cycles.
        ModeRouter.TradeType.FRESH_LAUNCH        -> setOf("SHITCOIN", "PROJECT_SNIPER", "EXPRESS", "MANIPULATED")  // quick snipe
        ModeRouter.TradeType.BREAKOUT_CONTINUATION -> setOf("MOONSHOT", "CYCLIC", "EXPRESS")                       // runner
        ModeRouter.TradeType.GRADUATION          -> setOf("MOONSHOT", "MANIPULATED", "CYCLIC")                     // chaosвҶ’structure
        ModeRouter.TradeType.INSIDER_SHARK      -> setOf("INSIDER_SHARK", "MOONSHOT", "QUALITY")                     // named-wallet/social shark alpha
        ModeRouter.TradeType.WHALE_ACCUMULATION  -> setOf("QUALITY", "BLUECHIP", "CYCLIC")                         // smart money
        ModeRouter.TradeType.REVERSAL_RECLAIM    -> setOf("DIP_HUNTER", "CASHGEN", "TREASURY")                     // dip reclaim
        ModeRouter.TradeType.TREND_PULLBACK      -> setOf("QUALITY", "TREASURY", "CYCLIC", "CASHGEN")              // orderly uptrend
        ModeRouter.TradeType.SENTIMENT_IGNITION  -> setOf("MANIPULATED", "SHITCOIN", "CASHGEN")                    // narrative burst
        else                                     -> emptySet()
    }

    private fun canonicalCycleLaneFor(ts: com.lifecyclebot.data.TokenState, classification: ModeRouter.Classification): String {
        // V5.9.1578 вҖ” ONE CANONICAL BUY LANE PER MINT/VERSION/CYCLE.
        // 5.0.3641 showed intake=252 but lane_eval=12271 and FDG/intakeвүҲ12x:
        // every candidate was still walking all lane sections before finality.
        // Pick the style/elected primary once, before lane FDG, and suppress all
        // non-primary BUY lanes unless the operator explicitly forces a primary.
        return try {
            val forced = RuntimeConfigOverlay.forcedPrimaryLane()?.takeIf { it.isNotBlank() }
            val styleLanes = AgenticStyleRouter.lanesFor(ts, classification, laneAffinityForTradeType(classification.tradeType)).toList()
            val stylePrimary = RuntimeConfigOverlay.normalizeLane(forced ?: styleLanes.firstOrNull() ?: ts.laneAffinity.firstOrNull() ?: "SHITCOIN")
            val metricPrimary = TokenMetricStageRouter.preferredPrimaryLane(ts, stylePrimary)
            val scoreForPivot4524 = (ts.lastV3Score ?: ts.entryScore.toInt()).coerceIn(0, 100)
            val electedPrimary4524 = RuntimeConfigOverlay.normalizeLane(forced ?: metricPrimary)
            val pivotedPrimary4524 = if (forced.isNullOrBlank() && LaneToxicityGuard.isNetNegativeDanger(electedPrimary4524, scoreForPivot4524)) {
                // V5.0.4547 вҖ” inner-lane primary doctrine. Do not replace a toxic
                // primary with QUALITY/DIP/TREASURY/etc. Keep the elected lane and
                // stamp the treatment so AgenticStyleRouter/LiveStylePivotRouter can
                // re-educate tactic/style/confirmation inside that same lane.
                val treatment4547 = try { LaneToxicityGuard.treatmentFor(electedPrimary4524, scoreForPivot4524).name } catch (_: Throwable) { "REEDUCATE_TACTIC" }
                try {
                    ForensicLogger.lifecycle("PRIMARY_STRATEGY_REEDUCATE_INNER_LANE_4547", "symbol=${ts.symbol} mint=${ts.mint.take(10)} lane=$electedPrimary4524 score=$scoreForPivot4524 treatment=$treatment4547 stylePrimary=$stylePrimary metricPrimary=$metricPrimary no_lane_jump=true")
                    PipelineHealthCollector.labelInc("PRIMARY_STRATEGY_REEDUCATE_INNER_LANE_4547_${electedPrimary4524}_${treatment4547}")
                } catch (_: Throwable) {}
                electedPrimary4524
            } else electedPrimary4524
            try {
                val snap = TokenMetricStageRouter.snapshot(ts)
                ForensicLogger.lifecycle("TOKEN_METRIC_STAGE_PRIMARY", "symbol=${ts.symbol} mint=${ts.mint.take(10)} stylePrimary=$stylePrimary metricPrimary=$metricPrimary finalPrimary=$pivotedPrimary4524 ${snap.compact}")
                PipelineHealthCollector.labelInc("TOKEN_METRIC_STAGE_${snap.stage.name}")
            } catch (_: Throwable) {}
            pivotedPrimary4524
        } catch (_: Throwable) { "SHITCOIN" }
    }

    private fun catastrophicPaperLowScoreSpecialistBleed(ts: com.lifecyclebot.data.TokenState, lane: String): Boolean {
        return try {
            if (!com.lifecyclebot.engine.RuntimeModeAuthority.isPaper()) return false
            val l = lane.uppercase()
            val nonMemeSpecialist = (l == "MANIPULATED" || l == "QUALITY" || l == "DIP_HUNTER"
                || l == "PROJECT_SNIPER" || l == "TREASURY" || l == "BLUECHIP")
            if (!nonMemeSpecialist) return false
            val score = (ts.lastV3Score ?: ts.entryScore.toInt()).coerceIn(-100, 150)
            if (score > 10) return false
            // V5.0.3716/3718 вҖ” CATASTROPHIC_PAPER_SPECIALIST_BLEED_GUARD.
            // 3716 used RegimeDetector.current() here, but this method runs per
            // lane and RegimeDetector can synchronously scan TradeHistoryStore on
            // cache expiry. Use the O(1) cached guard instead.
            com.lifecyclebot.engine.CatastrophicPaperBleedGuard.isActive()
        } catch (_: Throwable) { false }
    }

    private fun shouldRunBuyLaneForCycle(ts: com.lifecyclebot.data.TokenState, lane: String, primaryLane: String): Boolean {
        // V5.0.6002 вҖ” LANE QUARANTINE (operator directive 2026-07-02).
        // MANIPULATED, PROJECT_SNIPER, DIP_HUNTER are hard-paused for new
        // BUY entries until the LLM Lab autonomously promotes a strategy
        // that targets each lane (вүҘ5 paper trades, вүҘ50% WR, вүҘ+0 SOL PnL,
        // strategy name/rationale mentions the lane). Open positions in
        // these lanes ride out untouched; exits still work. Priority:
        // this check runs BEFORE primary-lane override so a bleeder cannot
        // sneak in as primary.
        try {
            if (LaneQuarantineController.isQuarantined(lane)) {
                LaneQuarantineController.logBlockedEntry(lane, ts.symbol, ts.mint, primaryLane)
                return false
            }
        } catch (_: Throwable) { /* quarantine must never break the gate */ }
        // V5.9.1586 вҖ” restore 3501 lane behavior. Primary lane is display/default
        // metadata only; it is NOT a pre-FDG execution suppressor. Every enabled
        // lane may evaluate, and FDG receives a candidate only if that lane actually
        // produces BUY/PROBE intent. Runtime lane disable is already a no-op unless
        // an explicit operator policy is added later.
        //
        // V5.9.1561 вҖ” fanout collapse must NEVER suppress Standard V3/Core lanes
        // (regression guard: GoldenTapeRegressionTest.fanout_suppression_never_вҖҰ).
        // The legacy STANDARD/CORE/V3 lanes are the trunk path; any future suppressor
        // must explicitly whitelist them: l == "STANDARD" || l == "CORE" || l == "V3".
        //
        // V5.0.3684 вҖ” FANOUT CONTAINMENT (operator deep-audit P1).
        //
        // Diagnosis from the live snapshot:
        //   LANE_EVAL=16084  INTAKE=716  вҶ’ laneEval/intake = 22.42 (target вүӨ 3)
        //   QUALITY=2282, MOONSHOT=2262, SHITCOIN=2248, MANIPULATED=2237,
        //   DIP_HUNTER=2236, PROJECT_SNIPER=2236, TREASURY=2220, BLUECHIP=363
        // All 8 lanes evaluating every meme candidate even with enabled=[MEME].
        // FDG was running multiple times per token вҶ’ executor starved вҶ’ 0 live buys.
        //
        // Doctrine:
        //   1. STANDARD/CORE/V3 ALWAYS pass вҖ” regression-guarded trunk path.
        //   2. The token's primary lane ALWAYS passes вҖ” that's the route the
        //      AgenticStyleRouter chose for this candidate.
        //   3. EnabledTraderAuthority.isMemeLiveOnly() вҮ’ suppress every non-meme
        //      specialist (MANIPULATED, QUALITY, DIP_HUNTER, PROJECT_SNIPER,
        //      TREASURY, BLUECHIP). Only MEME-family lanes (SHITCOIN, MOONSHOT)
        //      may evaluate alongside the primary.
        //   4. Mixed/full mode вҮ’ allow primary + ONE rescue lane drawn from the
        //      token's intake-affinity set (already capped at 2-4 lanes per
        //      intake by inferIntakeLaneAffinity). The token's affinity set is
        //      the operator's signal that this candidate "looks like" multiple
        //      lane shapes вҖ” but we still cap fanout per the operator P1 spec:
        //      "primary lane + at most one rescue lane".
        val l = lane.uppercase()
        // V5.0.4178 вҖ” L7 WORST-LANE SUPPRESSION (operator directive).
        // SHITCOIN / EXPRESS / MANIPULATED / DIP_HUNTER all bleed (0% WR in
        // journal). While the bot is below the 45% LIVE_ADAPTIVE doctrine
        // floor, suppress these from EVALUATING entirely so capital + cycle
        // budget concentrate on MOONSHOT / STANDARD (the two вүҘ22% WR
        // performers). Auto-resumes when WR recovers above the floor.
        // Primary-lane override and STANDARD/CORE/V3 trunk are always allowed
        // (regression guard handled below at line ~9210).
        if (l in setOf("SHITCOIN", "EXPRESS", "MANIPULATED", "DIP_HUNTER")
            && !l.equals(primaryLane, ignoreCase = true)) {
            try {
                val wr = com.lifecyclebot.engine.LiveLayerGateRelaxer.currentLiveWrPct()
                val liveN = com.lifecyclebot.engine.LiveLayerGateRelaxer.currentLiveTerminalCount()
                // V5.0.4300 вҖ” paper learning wins by sampling all layers first.
                // Do not suppress non-primary meme lanes on a tiny live sample;
                // let FDG/sizing soft-shape until enough terminal closes exist.
                if (liveN >= 40 && wr < 45.0) {
                    PipelineHealthCollector.labelInc("L7_LANE_SUPPRESSED_LOW_WR_$l")
                    return false
                } else if (liveN < 40 && wr < 45.0) {
                    PipelineHealthCollector.labelInc("L7_LANE_SOFT_START_ALLOWED_4300_$l")
                }
            } catch (_: Throwable) {}
        }
        val metricFit = try { TokenMetricStageRouter.laneFit(ts, l) } catch (_: Throwable) { TokenMetricStageRouter.LaneFit(true, l, TokenMetricStageRouter.Stage.UNKNOWN, "fit_error") }
        if (RuntimeModeAuthority.isLive() && !metricFit.allowed) {
            try {
                ForensicLogger.lifecycle("TOKEN_METRIC_STAGE_LANE_SOFT_MISMATCH_4162", "lane=$l primary=$primaryLane symbol=${ts.symbol} mint=${ts.mint.take(10)} ${metricFit.reason}")
                PipelineHealthCollector.labelInc("TOKEN_METRIC_STAGE_LANE_SOFT_MISMATCH_${metricFit.stage.name}")
            } catch (_: Throwable) {}
            // V5.0.4162 вҖ” stage mismatch is not a lane veto. Runtime showed
            // DIP_HUNTER primaries suppressing every other MemeTrader lane before
            // FDG/intent, so all-lanes-enabled was cosmetic. Keep true rug-prone
            // stage as hard safety; otherwise let the lane express intent and let
            // FDG/sizing handle risk.
            if (metricFit.stage == TokenMetricStageRouter.Stage.RUG_PRONE) return false
        }
        fun qualityLaneProofOk(): Boolean {
            val routeProof = ts.lastPrice > 0.0 && (ts.lastPriceSource.isNotBlank() || ts.source.isNotBlank())
            val holderProof = try { ts.safety.topHolderPct > 0.0 || ts.peakHolderCount > 0 || ts.holderGrowthRate != 0.0 } catch (_: Throwable) { false }
            val safeEnough = try { !ts.safety.isBlocked && ts.safety.hardBlockReasons.isEmpty() } catch (_: Throwable) { false }
            val qualityStructure = routeProof && safeEnough && ts.lastLiquidityUsd >= 15_000.0 && ts.lastMcap >= 25_000.0
            if (qualityStructure && !holderProof) {
                try {
                    ForensicLogger.lifecycle(
                        "QUALITY_OWNER_HOLDER_PROOF_BLIND_SOFT_ALLOW",
                        "symbol=${ts.symbol} mint=${ts.mint.take(10)} liq=${ts.lastLiquidityUsd.toInt()} mcap=${ts.lastMcap.toInt()} src=${ts.lastPriceSource.ifBlank { ts.source }} holder=${ts.safety.topHolderPct} action=size_shape_downstream_not_owner_starve",
                    )
                    PipelineHealthCollector.labelInc("QUALITY_OWNER_HOLDER_PROOF_BLIND_SOFT_ALLOW")
                } catch (_: Throwable) {}
            }
            return qualityStructure
        }
        // V5.0.6047 вҖ” ROOT CAUSE FIX: CASHGEN/TREASURY were being gated by
        // qualityLaneProofOk() (liq>=$15K + mcap>=$25K). That's a BLUECHIP-tier
        // structural proof вҖ” inappropriate for CASHGEN's doctrine (scalp small
        // tokens for 3-5% cashflow, 100+ trades/day, wallet compounder).
        // Report 2026-07-03 06:03 showed CASHGEN with 65 lane_evals and ZERO
        // trades вҖ” the wallet-feeder was completely dead because it couldn't
        // clear a BLUECHIP-tier proof. CASHGEN needs its OWN permissive proof:
        // real price, not-hard-blocked, and liquidity >= $2K (executable but
        // small). This is the operator's explicit doctrine per PRD:
        //   "CashGen/Treasury literally is meant to make the bot a free
        //    trading engine ... 100+ trades/day of quick 3-5% scalps"
        fun cashGenProofOk(): Boolean {
            val routeProof = ts.lastPrice > 0.0 && (ts.lastPriceSource.isNotBlank() || ts.source.isNotBlank())
            val safeEnough = try { !ts.safety.isBlocked && ts.safety.hardBlockReasons.isEmpty() } catch (_: Throwable) { false }
            val executable = ts.lastLiquidityUsd >= 2_000.0  // scalp-executable, not BLUECHIP-tier
            val ok = routeProof && safeEnough && executable
            if (ok) {
                try { PipelineHealthCollector.labelInc("CASHGEN_TREASURY_PROOF_OK_6047") } catch (_: Throwable) {}
            }
            return ok
        }
        // (1) Regression guard вҖ” must remain literally these tokens.
        if (l == "STANDARD" || l == "CORE" || l == "V3") return true
        // (2) Primary normally evaluates, except catastrophic paper S0-10
        // specialist bleed. This prevents a low-score DIP/QUALITY/TREASURY/etc
        // primary from bypassing the bounded rescue cap during a sub-bootstrap
        // WR collapse while preserving meme-family training volume.
        if (l.equals(primaryLane, ignoreCase = true)) {
            if (l in setOf("QUALITY", "BLUECHIP") && !qualityLaneProofOk()) {
                try { ForensicLogger.lifecycle("QUALITY_PRIMARY_PROOF_REJECTED", "lane=$l symbol=${ts.symbol} mint=${ts.mint.take(10)} liq=${ts.lastLiquidityUsd.toInt()} mcap=${ts.lastMcap.toInt()} src=${ts.lastPriceSource.ifBlank { ts.source }} holder=${ts.safety.topHolderPct}") } catch (_: Throwable) {}
                return false
            }
            // V5.0.6047 вҖ” TREASURY uses permissive cashGenProofOk (scalp/compounder role)
            if (l == "TREASURY" && !cashGenProofOk()) {
                try { ForensicLogger.lifecycle("CASHGEN_TREASURY_PRIMARY_PROOF_REJECTED_6047", "lane=$l symbol=${ts.symbol} mint=${ts.mint.take(10)} liq=${ts.lastLiquidityUsd.toInt()} mcap=${ts.lastMcap.toInt()} src=${ts.lastPriceSource.ifBlank { ts.source }}") } catch (_: Throwable) {}
                return false
            }
            if (catastrophicPaperLowScoreSpecialistBleed(ts, l)) {
                try { ForensicLogger.lifecycle("LANE_PRIMARY_SUPPRESSED_CATASTROPHIC_PAPER_BLEED", "lane=$l symbol=${ts.symbol} mint=${ts.mint.take(10)} score=${ts.lastV3Score ?: ts.entryScore.toInt()}") } catch (_: Throwable) {}
                return false
            }
            return true
        }

        val memeOnly = try {
            com.lifecyclebot.engine.EnabledTraderAuthority.isMemeLiveOnly()
        } catch (_: Throwable) { false }
        val memeFamily = (l == "SHITCOIN" || l == "MOONSHOT" || l == "EXPRESS")
        val nonMemeSpecialist = (l == "MANIPULATED" || l == "QUALITY" || l == "DIP_HUNTER"
            || l == "PROJECT_SNIPER" || l == "TREASURY" || l == "BLUECHIP")

        val affinity = try {
            ts.laneAffinity.map { it.uppercase() }.toSet()
        } catch (_: Throwable) { emptySet() }

        if (memeOnly) {
            // V5.0.6014 вҖ” successful-lane feed correction. Do NOT spend the
            // evaluator budget on MANIPULATED/SHITCOIN/EXPRESS/DIP/PROJECT just
            // because they are enabled. The operator wants capital and attention
            // pushed into succeeding lanes: STANDARD/CORE/V3 are already trunk
            // passes below, while QUALITY/MOONSHOT/BLUECHIP/CRYPTO need a bounded
            // live fast-path so owner rotation cannot starve them. This remains
            // explicit-affinity/quality-proof gated; hard safety, FDG, sizing and
            // pause guards still decide execution.
            val successfulFeedLanes6014 = setOf("QUALITY", "MOONSHOT", "BLUECHIP", "CRYPTO", "MARKETS")
            val successfulFeedAffinity6014 = l in successfulFeedLanes6014 && (affinity.contains(l) || l.equals(primaryLane, ignoreCase = true))
            if (RuntimeModeAuthority.isLive() && successfulFeedAffinity6014) {
                val paused6014 = try { LaneAutoPauseGuard.isPaused(l) } catch (_: Throwable) { false }
                val qualityProofRequired6014 = l in setOf("QUALITY", "BLUECHIP")
                val qualityProofOk6014 = !qualityProofRequired6014 || qualityLaneProofOk()
                if (!paused6014 && qualityProofOk6014) {
                    try {
                        ForensicLogger.lifecycle("SUCCESSFUL_LANE_FEED_RESTORED_6014", "lane=$l primary=$primaryLane symbol=${ts.symbol} mint=${ts.mint.take(10)} affinity=${affinity.joinToString("+")} action=feed_success_lane_not_manipulated")
                        PipelineHealthCollector.labelInc("SUCCESSFUL_LANE_FEED_RESTORED_6014_$l")
                    } catch (_: Throwable) {}
                    return true
                } else {
                    try { PipelineHealthCollector.labelInc("SUCCESSFUL_LANE_FEED_DENIED_6014_$l") } catch (_: Throwable) {}
                }
            }
            // V5.0.3934 вҖ” LIVE_RING_OWNER_COLLAPSE.
            // 3914's LIVE_FULL_RING_OBSERVATION returned true for every internal
            // meme/toolkit lane before owner rotation. Runtime 3933 proved that was
            // self-caused fanout: laneEval/intake=35.25, FDG/intake=3.35, EXEC_GATE
            // allow=1346 but live EXEC attempt=0. Observation cannot mean all lanes
            // run FDG/executor. Live uses the same bounded owner rotation below:
            // exactly one primary executable lane per mint/cycle, with the full ring
            // still represented over time by MEMETRADER_OWNER_LANE rotation.
            if (com.lifecyclebot.engine.RuntimeModeAuthority.isLive()) {
                try { ForensicLogger.lifecycle("LIVE_RING_OWNER_COLLAPSE", "lane=$l primary=$primaryLane symbol=${ts.symbol} mint=${ts.mint.take(10)} reason=prevent_lane_fdg_fanout") } catch (_: Throwable) {}
            }
            // V5.0.3710 вҖ” INTERNAL_TOOLKIT_STARVATION_FIX.
            // MEME-only means external markets/perps/cyclic/sniper-family engines stay
            // isolated by EnabledTraderAuthority. It must NOT make the internal meme
            // toolkit silent. EXPRESS is a meme-family lane.
            //
            // V5.0.3712 вҖ” BOUNDED_INTERNAL_TOOLKIT_RESCUE.
            // 3710 correctly woke QUALITY/BLUECHIP/TREASURY/DIP/SNIPER/MANIP, but
            // because laneAffinity is additive over time it allowed EVERY tagged
            // specialist to evaluate. Runtime 5.0.3710 showed FDG/intake=5.52 and
            // LANE_EVAL=271 in 72s. Keep the toolkit alive but bounded: meme-family
            // lanes may run, the primary always already passed above, and at most ONE
            // non-meme specialist rescue lane is admitted per mint from current
            // affinity. This restores the "primary + bounded rescue" contract without
            // returning to SHITCOIN/MOONSHOT monoculture.
            // V5.0.3714 вҖ” PAPER_WR_DILUTION_FIX.
            // 3712 bounded only the non-meme specialist side. Runtime paper WR
            // then fell under 50% because MEME-only still admitted every meme-family
            // lane (SHITCOIN + MOONSHOT + EXPRESS) for the same candidate, so one bad
            // mint could become multiple paper losses. This is not alpha diversity;
            // it is duplicate exposure. Keep throughput by preserving the primary
            // lane and one deterministic meme-family rescue, plus one specialist
            // rescue if source/style affinity explicitly asked for it.
            val scoreForToxicity = (ts.lastV3Score ?: ts.entryScore.toInt()).coerceIn(-100, 150)
            // V5.0.3864 вҖ” MEMETRADER_CONTRIBUTION_ROTATION.
            // 3862 runtime: intake=165 but laneEval=9; only SHITCOIN/MOONSHOT/
            // DIP/QUALITY contributed while 90% of MemeTrader sat idle. The old
            // primary+one-rescue contract protected against fanout explosions but
            // it starved the internal trader surface. Keep bounded fanout, but make
            // ownership rotate across the whole MemeTrader ring: exactly ONE owner
            // lane per token/cycle (plus STANDARD/CORE/V3 trunk above), with affinity
            // lanes first and toxicity treatment, not lane amputation. This raises contribution without
            // returning to every-token/every-lane FDG storms.
            // V5.0.4599 вҖ” SPECIALIST TRADER RESET (operator directive:
            // "project Sniper is meant to be a specialist trader not a lane
            // or layer. it needs to be reset to one. same as shitcoin
            // express"). Removed PROJECT_SNIPER, SHITCOIN, EXPRESS from the
            // owner-lane ring. They are specialist traders that own tokens
            // from entry through mission-complete condition, THEN hand off
            // via LaneTransitionManager (V5.0.4599). No longer eligible for
            // owner-lane election competition. They still evaluate entries
            // via their dedicated AI classes but their positions are owned
            // by them, not passed to the memetrader ring.
            val fullMemeTraderRing = listOf(
                "MOONSHOT",
                "MANIPULATED", "QUALITY", "DIP_HUNTER", "TREASURY", "CASHGEN", "BLUECHIP"
            )
            val qualityEligible = qualityLaneProofOk()
            val cashGenEligible = cashGenProofOk()  // V5.0.6047 вҖ” CASHGEN/TREASURY have their own permissive proof
            val affinityRanked = affinity.filter { it in fullMemeTraderRing }.sorted()
            val rawOwnerPool0 = (listOf(primaryLane.uppercase()) + affinityRanked + fullMemeTraderRing).distinct()
            val rawOwnerPool = rawOwnerPool0.filter { laneName ->
                when (laneName) {
                    "QUALITY", "BLUECHIP" -> qualityEligible
                    "TREASURY", "CASHGEN" -> cashGenEligible  // V5.0.6047 вҖ” permissive proof for scalp/compounder lanes
                    else -> true
                }
            }.ifEmpty { rawOwnerPool0.filter { it !in setOf("QUALITY", "BLUECHIP", "TREASURY", "CASHGEN") }.ifEmpty { rawOwnerPool0 } }
            if (!qualityEligible && rawOwnerPool0.any { it in setOf("QUALITY", "BLUECHIP", "TREASURY", "CASHGEN") }) {
                try { ForensicLogger.lifecycle("QUALITY_OWNER_PROOF_REJECTED", "symbol=${ts.symbol} mint=${ts.mint.take(10)} liq=${ts.lastLiquidityUsd.toInt()} mcap=${ts.lastMcap.toInt()} src=${ts.lastPriceSource.ifBlank { ts.source }} holder=${ts.safety.topHolderPct} primary=$primaryLane cashGenEligible=$cashGenEligible") } catch (_: Throwable) {}
            }
            val ownerPool = com.lifecyclebot.engine.LaneToxicityGuard.filterNonToxic(rawOwnerPool, scoreForToxicity).ifEmpty { rawOwnerPool }
            val rot = try { (System.currentTimeMillis() / 3_000L).toInt() } catch (_: Throwable) { 0 }
            val ownerLane = ownerPool[((ts.mint.hashCode() xor rot) and 0x7fffffff) % ownerPool.size]
            // V5.0.3986 вҖ” LIVE PROFITABLE-FANOUT REPAIR. Owner rotation prevents
            // FDG storms, but a strict single owner starves the quality lanes the
            // operator expects to make money. In LIVE, allow bounded affinity/
            // character-confirmed quality rescue lanes in addition to the owner;
            // the actual lane must still emit BUY intent and pass FDG/executor.
            val fanoutPressure4522 = try { LiveLaneFanoutPressure.snapshot() } catch (_: Throwable) { LiveLaneFanoutPressure.Snapshot(false, 0.0, 0.0, 0, "error") }
            // V5.0.6072 вҖ” CASHGEN/TREASURY rescue extended to PAPER. The rescue
            // path was live-only, so in paper the money-printer lanes only ran
            // when they won the 1-of-7 owner rotation вҖ” starving the compounder
            // learning surface. Quality-family rescue stays live-only (paper WR
            // dilution guard); TREASURY/CASHGEN rescue is bounded by
            // cashGenEligible + affinity/score/liq conditions below.
            val rescueModeAllowed6072 = RuntimeModeAuthority.isLive() || l in setOf("TREASURY", "CASHGEN")
            val profitableRescue = rescueModeAllowed6072 && l in setOf("QUALITY", "TREASURY", "CASHGEN", "BLUECHIP", "MOONSHOT", "PROJECT_SNIPER") && (
                if (fanoutPressure4522.active) {
                    // V5.0.4522 вҖ” pressure mode: keep owner rotation + explicit affinity,
                    // but remove broad score/liquidity rescue that lets every quality-family
                    // lane evaluate the same mint during live WR collapse. This is not lane
                    // amputation: primary lane and affinity-proven rescue still run.
                    // V5.0.6047 вҖ” CASHGEN/TREASURY use cashGenEligible (permissive scalp proof)
                    (l in setOf("QUALITY", "BLUECHIP") && qualityEligible && affinity.contains(l)) ||
                        (l in setOf("TREASURY", "CASHGEN") && cashGenEligible && affinity.contains(l)) ||
                        (l == "MOONSHOT" && (affinity.contains(l) || l == primaryLane.uppercase() || scoreForToxicity >= 65 || ts.meta.momScore >= 70.0)) ||
                        (l == "PROJECT_SNIPER" && qualityEligible && affinity.contains(l))
                } else {
                    // V5.0.6047 вҖ” CASHGEN/TREASURY use cashGenEligible (liq>=$2K) instead of qualityEligible (liq>=$15K)
                    (l in setOf("QUALITY", "BLUECHIP") && qualityEligible && (affinity.contains(l) || l == primaryLane.uppercase() || scoreForToxicity >= 55 || ts.lastLiquidityUsd >= 15_000.0)) ||
                        (l in setOf("TREASURY", "CASHGEN") && cashGenEligible && (affinity.contains(l) || l == primaryLane.uppercase() || scoreForToxicity >= 45 || ts.lastLiquidityUsd >= 2_000.0)) ||
                        (l == "MOONSHOT" && (affinity.contains(l) || l == primaryLane.uppercase() || scoreForToxicity >= 55 || ts.meta.momScore >= 60.0)) ||
                        (l == "PROJECT_SNIPER" && qualityEligible && affinity.contains(l))
                }
            )
            if (fanoutPressure4522.active && l in setOf("QUALITY", "TREASURY", "CASHGEN", "BLUECHIP") && !profitableRescue) {
                try { PipelineHealthCollector.labelInc("LIVE_FANOUT_PRESSURE_RESCUE_NARROWED_4522_$l") } catch (_: Throwable) {}
            }
            if (l in fullMemeTraderRing) {
                // V5.0.4598 вҖ” RESPECT LaneAutoPauseGuard IN OWNER-LANE BYPASS.
                // Field V5.0.4597 exposed the MANIPULATED bleed source: this
                // owner-lane / all-lane-contribution path lets any ring lane
                // execute when it matches ownerLane, bypassing the pause
                // check at FDG:3238 + TokenSafetyChecker:487 + BotService:9216.
                // The hard-seed pause on EXPRESS/MANIPULATED was never
                // consulted here. Now: if the lane is paused, the owner-
                // lane election is denied. Downstream fluid dampener at
                // LiveProbabilityEngine (V5.0.4596) is the safety net if
                // any other path still slips through, but this closes the
                // primary bypass channel.
                val laneIsPaused4598 = try { LaneAutoPauseGuard.isPaused(l) } catch (_: Throwable) { false }
                val allowed = (l == ownerLane || profitableRescue) && !laneIsPaused4598
                if (laneIsPaused4598) {
                    try {
                        ForensicLogger.lifecycle(
                            "OWNER_LANE_PAUSED_DENIED_4598",
                            "lane=$l primary=$primaryLane owner=$ownerLane symbol=${ts.symbol} mint=${ts.mint.take(10)} reason=lane_auto_paused_by_guard",
                        )
                        PipelineHealthCollector.labelInc("OWNER_LANE_PAUSED_DENIED_4598_$l")
                    } catch (_: Throwable) {}
                }
                if (com.lifecyclebot.engine.RuntimeModeAuthority.isLive()) {
                    try {
                        ForensicLogger.lifecycle("LIVE_ALL_LANE_CONTRIBUTION_4469", "lane=$l primary=$primaryLane owner=$ownerLane ownerSelected=$allowed rescue=$profitableRescue symbol=${ts.symbol} mint=${ts.mint.take(10)} pool=${ownerPool.joinToString("+")} action=considered_bounded_owner_rotation")
                        PipelineHealthCollector.labelInc("LIVE_ALL_LANE_CONTRIBUTION_4469_$l")
                        if (!allowed) PipelineHealthCollector.labelInc("LIVE_ALL_LANE_CONTRIBUTION_SUPPRESSED_4478_$l")
                    } catch (_: Throwable) {}
                    if (allowed) {
                        try { ForensicLogger.lifecycle("MEMETRADER_OWNER_LANE", "lane=$l primary=$primaryLane owner=$ownerLane rescue=$profitableRescue symbol=${ts.symbol} mint=${ts.mint.take(10)} pool=${ownerPool.joinToString("+")}") } catch (_: Throwable) {}
                    } else {
                        try { ForensicLogger.lifecycle("LANE_SUPPRESSED_BY_OWNER_ROTATION", "lane=$l primary=$primaryLane owner=$ownerLane symbol=${ts.symbol} mint=${ts.mint.take(10)} reason=bounded_live_all_lane_contribution_no_fdg") } catch (_: Throwable) {}
                        // V5.0.6070 вҖ” WIDEN LANE_EVAL VISIBILITY. Operator: "its
                        // meant to be standard, v3, core, shit coin, bluechip,
                        // quality, moonshot, shit coin express, sniper, manipulated
                        // and the cyclic trader." Prior code only emitted the
                        // shadow LANE_EVAL beacon for QUALITY/MOONSHOT, so the
                        // pipeline counters showed 0 for SHITCOIN, EXPRESS,
                        // MANIPULATED, PROJECT_SNIPER, DIP_HUNTER, TREASURY,
                        // CASHGEN, CYCLIC вҖ” even though those lanes ARE being
                        // routed. Widen to the full doctrine surface so the
                        // report reflects the actual lane fanout.
                        // V5.0.4489 core invariant (preserved for GoldenTapeRegressionTest
                        // botService_4489QualityMoonshotAndCoreVisibilityCannotDisappear):
                        // QUALITY and MOONSHOT MUST retain a live read-floor when owner
                        // rotation suppresses FDG. Do not remove this literal setOf.
                        val qualityMoonshotFloor4489 = setOf("QUALITY", "MOONSHOT")
                        // V5.0.6070 вҖ” WIDEN LANE_EVAL VISIBILITY. Operator: "its
                        // meant to be standard, v3, core, shit coin, bluechip,
                        // quality, moonshot, shit coin express, sniper, manipulated
                        // and the cyclic trader." Extend the read-floor to the full
                        // doctrine surface so the pipeline counters no longer show 0
                        // for SHITCOIN/EXPRESS/MANIPULATED/PROJECT_SNIPER/etc even
                        // though those lanes ARE being routed. The QUALITY/MOONSHOT
                        // pair above remains a hard invariant.
                        val widenedLaneReadFloor4489 = qualityMoonshotFloor4489 + setOf(
                            "SHITCOIN", "MEME", "EXPRESS",
                            "SHITCOIN_EXPRESS", "PROJECT_SNIPER", "SNIPER",
                            "MANIPULATED", "DIP_HUNTER", "BLUECHIP", "BLUE_CHIP",
                            "TREASURY", "CASHGEN", "STANDARD", "CYCLIC", "MARKETS",
                            "CRYPTO_ALT", "STOCK"
                        )
                        if (l in widenedLaneReadFloor4489) {
                            try {
                                ForensicLogger.phase(
                                    ForensicLogger.PHASE.LANE_EVAL,
                                    ts.symbol,
                                    "lane=$l shadow=LIVE_LANE_READ_FLOOR_4489 no_fdg=true primary=$primaryLane owner=$ownerLane rescue=$profitableRescue mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore}"
                                )
                                PipelineHealthCollector.labelInc("LIVE_LANE_READ_FLOOR_4489_$l")
                            } catch (_: Throwable) {}
                        }
                    }
                    return allowed
                }
                if (allowed) {
                    try { ForensicLogger.lifecycle("MEMETRADER_OWNER_LANE", "lane=$l primary=$primaryLane owner=$ownerLane rescue=$profitableRescue symbol=${ts.symbol} mint=${ts.mint.take(10)} pool=${ownerPool.joinToString("+")}") } catch (_: Throwable) {}
                } else {
                    try { ForensicLogger.lifecycle("LANE_SUPPRESSED_BY_OWNER_ROTATION", "lane=$l primary=$primaryLane owner=$ownerLane symbol=${ts.symbol} mint=${ts.mint.take(10)}") } catch (_: Throwable) {}
                }
                return allowed
            }
            return false
        }

        // (4) Mixed mode: primary + at most one rescue from the token's
        // affinity set. Skip non-meme specialists that the affinity router
        // didn't tag for this candidate.
        if (nonMemeSpecialist) {
            return affinity.contains(l)
        }
        // Default: allow (preserves SHITCOIN/MOONSHOT/MEME side-by-side learning).
        return true
    }

    private fun walletCorrespondentOpenPrice4481(ts: com.lifecyclebot.data.TokenState, rawPrice: Double, context: String): Double {
        val pos = ts.position
        val entry = pos.entryPrice
        if (entry <= 0.0 || rawPrice <= 0.0 || !entry.isFinite() || !rawPrice.isFinite()) return rawPrice
        val entryMcap = pos.entryMcap.takeIf { it > 0.0 && it.isFinite() } ?: return rawPrice
        val currentMcap = ts.lastMcap.takeIf { it > 0.0 && it.isFinite() } ?: return rawPrice
        val rawGain = ((rawPrice - entry) / entry) * 100.0
        val mcapGain = ((currentMcap - entryMcap) / entryMcap) * 100.0
        val contradiction = kotlin.math.abs(rawGain - mcapGain) >= 250.0 && kotlin.math.abs(rawGain) >= 500.0
        val oppositeSign = (rawGain > 250.0 && mcapGain < 0.0) || (rawGain < -80.0 && mcapGain > 250.0)
        if (!contradiction && !oppositeSign) return rawPrice
        val comparable = entry * (currentMcap / entryMcap)
        if (comparable <= 0.0 || !comparable.isFinite()) return rawPrice
        try { PipelineHealthCollector.labelInc("EXIT_TRIGGER_BASIS_REBASED_4481") } catch (_: Throwable) {}
        try {
            ForensicLogger.lifecycle(
                "EXIT_TRIGGER_BASIS_REBASED_4481",
                "context=$context mint=${ts.mint.take(10)} symbol=${ts.symbol} rawGain=${"%.1f".format(rawGain)} mcapGain=${"%.1f".format(mcapGain)} raw=$rawPrice comparable=$comparable entry=$entry entryMcap=${entryMcap.toInt()} currentMcap=${currentMcap.toInt()} action=wallet_correspondent_exit_trigger"
            )
        } catch (_: Throwable) {}
        return comparable
    }

    private fun walletCorrespondentPnlPct4481(ts: com.lifecyclebot.data.TokenState, rawPrice: Double, context: String): Double {
        val entry = ts.position.entryPrice
        val px = walletCorrespondentOpenPrice4481(ts, rawPrice, context)
        return if (entry > 0.0 && px > 0.0) ((px - entry) / entry) * 100.0 else 0.0
    }

    private fun inferIntakeLaneAffinity(source: String, allSources: Set<String>, marketCapUsd: Double, liquidityUsd: Double): Set<String> {
        val tags = (allSources + source).joinToString("|").uppercase()
        val out = linkedSetOf<String>()
        // V5.9.1576 вҖ” source-only birth affinity must be a seed, not a full
        // strategy fanout. 1575's AgenticStyleRouter now expands/ranks lanes
        // once character is known. If raw source already adds 3-4 lanes here,
        // every token pays FDG for the whole toolbox before style selection.
        // V5.0.4129 вҖ” extend seed pool so CASHGEN/CYCLIC/MANIPULATED can also be
        // candidates from intake; boundedLanes still caps to 2 per token.
        if (tags.contains("PUMP") || tags.contains("PORTAL")) out += listOf("SHITCOIN", "PROJECT_SNIPER", "EXPRESS")
        if (tags.contains("RAYDIUM") || tags.contains("NEW_POOL")) out += listOf("MOONSHOT", "DIP_HUNTER", "CYCLIC")
        if (tags.contains("DEX_BOOSTED") || tags.contains("DEX_TRENDING") || tags.contains("COINGECKO")) out += listOf("QUALITY", "TREASURY", "CASHGEN")
        if (marketCapUsd in 75_000.0..1_000_000.0) out += "QUALITY"
        if (marketCapUsd >= 1_000_000.0 || liquidityUsd >= 75_000.0) out += "BLUECHIP"
        // V5.0.6016 вҖ” meme volume recovery via successful-lane source breadth.
        // 6014 made QUALITY/MOONSHOT/BLUECHIP the right execution budget, but
        // Pump/Raydium births still seeded mostly degen/specialist lanes. Runtime
        // 6014 showed quality was up but volume narrowed: direct Pump/Raydium
        // dominated intake while DEX/smart feeds were degraded. Mid-liq/exitable
        // Pump/Raydium candidates should feed the winning lane cluster instead of
        // starving behind SHITCOIN/EXPRESS/PROJECT/MANIP affinity. STANDARD/CORE/V3
        // are trunk passes elsewhere; this adds affinity only for bounded rescue.
        val successfulMemeSourceBreadth6016 =
            liquidityUsd >= 7_500.0 ||
                marketCapUsd >= 25_000.0 ||
                tags.contains("DEX") || tags.contains("RAYDIUM") || tags.contains("GECKO") || tags.contains("SMART") || tags.contains("WALLET")
        if (successfulMemeSourceBreadth6016) {
            out += "QUALITY"
            out += "MOONSHOT"
            if (liquidityUsd >= 12_000.0 || marketCapUsd >= 75_000.0 || tags.contains("SMART") || tags.contains("WALLET")) out += "BLUECHIP"
            try {
                PipelineHealthCollector.labelInc("SUCCESSFUL_MEME_SOURCE_BREADTH_6016")
                ForensicLogger.lifecycle("SUCCESSFUL_MEME_SOURCE_BREADTH_6016", "src=$source tags=${tags.take(160)} liq=${liquidityUsd.toInt()} mcap=${marketCapUsd.toInt()} lanes=${out.joinToString("+")}")
            } catch (_: Throwable) {}
        }
        // V5.0.6016 вҖ” do NOT source-feed MANIPULATED from generic Pump thin-liq.
        // Manipulated still has true safety/overlay routing, but it should not burn
        // hundreds of evaluations just because Pump/Raydium volume is present.
        if (out.isEmpty()) out += listOf("SHITCOIN", "MOONSHOT")

        // V5.0.4149 вҖ” REGIME-AWARE INTAKE PIVOT.
        // Operator: 'its not meant to disable its meant to pivot to the right strategy'
        //
        // The previous source-only affinity locks intake into MOONSHOT/SHITCOIN/
        // PROJECT_SNIPER during a DUMP regime вҖ” exactly the lanes that are
        // bleeding. AgenticStyleRouter.weakChopStylePivot DOES later try to push
        // toward QUALITY/DIP_HUNTER, but by then the watchlist entry's
        // laneAffinity is already locked to the degen seed and the defensive
        // lanes (DIP_HUNTER/TREASURY/CASHGEN) get NO evaluations.
        //
        // Operator dump (2026-06-25 19:18, regime=DUMP n=100 wr=4.0%):
        //   LANE_EVAL by lane:  PROJECT_SNIPER=18  MOONSHOT=9  SHITCOIN=7
        //   EXPRESS=7  QUALITY=0  DIP_HUNTER=0  TREASURY=0  CASHGEN=0
        //
        // Fix: during DUMP regime, prepend the defensive-regime lanes to the
        // output (preserves the existing degen lanes as fallbacks for variety
        // & to keep STANDARD-mode V3 evaluations alive) so the watchlist
        // affinity carries the regime-appropriate options FIRST. boundedLanes
        // in AgenticStyleRouter still caps the per-token fanout downstream.
        try {
            val regime = com.lifecyclebot.engine.RegimeDetector.currentRegime()
            if (regime == com.lifecyclebot.engine.RegimeDetector.Regime.DUMP) {
                val defensive = linkedSetOf("QUALITY", "DIP_HUNTER", "TREASURY", "CASHGEN", "BLUECHIP")
                // PROJECT_SNIPER may still be useful in DUMP for sniping panic-reversion
                // launches; keep it but de-prioritize. MOONSHOT/SHITCOIN/EXPRESS get
                // demoted to fallback positions.
                val degen = out.filter { it !in defensive }
                val pivoted = linkedSetOf<String>().apply {
                    addAll(defensive.filter { it == "QUALITY" || it == "DIP_HUNTER" || it == "TREASURY" || it == "CASHGEN" || it in out })
                    addAll(degen)
                }
                if (pivoted != out) {
                    try { ForensicLogger.lifecycle("REGIME_PIVOT_INTAKE_V4149", "regime=DUMP src=$source liq=$liquidityUsd mcap=$marketCapUsd before=${out.joinToString("+")} after=${pivoted.joinToString("+")}") } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("REGIME_PIVOT_INTAKE_DUMP") } catch (_: Throwable) {}
                    out.clear(); out.addAll(pivoted)
                }
            }
        } catch (_: Throwable) {}

        return out
    }

    private fun inferIntakeToolAffinity(source: String, allSources: Set<String>, marketCapUsd: Double, liquidityUsd: Double): Set<String> {
        val tags = (allSources + source).joinToString("|").uppercase()
        val out = linkedSetOf<String>()
        if (tags.contains("PUMP") || tags.contains("PORTAL")) out += listOf("PUMP_FUN", "MEME", "SNIPER")
        if (tags.contains("RAYDIUM") || tags.contains("NEW_POOL")) out += listOf("RAYDIUM", "NEW_POOL", "MEME")
        if (tags.contains("DEX")) out += "DEX"
        if (tags.contains("COINGECKO")) out += "TRENDING"
        if (marketCapUsd >= 75_000.0 || liquidityUsd >= 25_000.0) out += "QUALITY_DEPTH"
        return out
    }

    private fun isPumpDominanceSourceTag(tag: String): Boolean {
        val t = tag.uppercase()
        return t.contains("PUMP_PORTAL") || t.contains("PUMPPORTAL") ||
            t.contains("PUMP_FUN") || t.contains("PUMPFUN") ||
            t.contains("PUMP_GRADUATE") || t.contains("PUMPGRADUATE")
    }

    private fun hasNonPumpConfirmationTag(tag: String): Boolean {
        val t = tag.uppercase()
        return t.contains("DEX") || t.contains("RAYDIUM") || t.contains("COINGECKO") ||
            t.contains("GECKO") || t.contains("METEORA") || t.contains("BIRDEYE") ||
            t.contains("ORCA") || t.contains("JUPITER") || t.contains("HELIUS") ||
            t.contains("SOLANA") || t.contains("WALLET") || t.contains("APP") ||
            t.contains("CMC") || t.contains("WHALE") || t.contains("BOOSTED") ||
            t.contains("TRENDING") || t.contains("V3_PREMIUM")
    }

    /** V5.9.1560 вҖ” actively drain existing pump.fun dominance from hot runtime. */
    private fun rebalanceHotWatchlistSources(reason: String) {
        try {
            val entries = com.lifecyclebot.engine.GlobalTradeRegistry.getWatchlistEntries()
            if (entries.size < 12) return
            fun isPumpOnly(e: com.lifecyclebot.engine.GlobalTradeRegistry.WatchlistEntry): Boolean {
                val tag = e.addedBy + "|" + e.source
                return isPumpDominanceSourceTag(tag) && !hasNonPumpConfirmationTag(tag)
            }
            val pumpEntries = entries.filter { isPumpOnly(it) }.sortedBy { it.addedAt }
            val total = entries.size
            // V5.0.3708 вҖ” match strict GlobalTradeRegistry policy. Pump-only
            // rows are allowed as a minority hot feed, not as the majority of
            // the Solana scanner bench.
            val dynamicCap = kotlin.math.ceil(total * 0.35).toInt().coerceAtLeast(1)
            val reserveCap = if (total > 80) (total - 80).coerceAtLeast(1) else dynamicCap
            val cap = minOf(175, minOf(dynamicCap, reserveCap))
            val excess = (pumpEntries.size - cap).coerceAtLeast(0)
            if (excess <= 0) return
            var demoted = 0
            for (entry in pumpEntries.take(excess)) {
                // V5.0.3685 вҖ” guard: never evict a mint that is in-flight (pendingVerify)
                // or already open. mid-buy verification sets pendingVerify=true BEFORE
                // confirming token arrival; evicting here loses the position permanently.
                val open = try { synchronized(status.tokens) {
                    val pos = status.tokens[entry.mint]?.position
                    pos?.isOpen == true || pos?.pendingVerify == true || (pos?.qtyToken ?: 0.0) > 0.0
                } } catch (_: Throwable) { false }
                if (open || liveHeldOrManagedMint(entry.mint)) {
                    try { PipelineHealthCollector.labelInc("LIVE_HELD_SOURCE_REBALANCE_EVICT_BLOCKED_4550") } catch (_: Throwable) {}
                    try { ForensicLogger.lifecycle("LIVE_HELD_SOURCE_REBALANCE_EVICT_BLOCKED_4550", "mint=${entry.mint.take(10)} reason=$reason action=keep_watchlist") } catch (_: Throwable) {}
                    continue
                }
                // V5.0.3732 вҖ” do not fabricate zero-liquidity probation rows.
                // Report 5.0.3730 showed fresh tokens admitted with real liq ($5k+)
                // immediately demoted as SOURCE_BALANCE_PUMP_DOMINANCE with liq=$0
                // because rebalance runs before status.tokens hydration. Use registry
                // intake metadata first, then any live TokenState fallback.
                val demoteLiq = try {
                    val liveLiq = synchronized(status.tokens) { status.tokens[entry.mint]?.lastLiquidityUsd ?: 0.0 }
                    maxOf(entry.initialLiquidityUsd, liveLiq)
                } catch (_: Throwable) { entry.initialLiquidityUsd }
                val demoteConf = entry.initialConfidence.coerceAtLeast(0)
                val ok = try {
                    com.lifecyclebot.engine.GlobalTradeRegistry.demoteWatchlistToProbation(
                        mint = entry.mint,
                        reason = "SOURCE_BALANCE_PUMP_DOMINANCE_$reason",
                        liquidityUsd = demoteLiq,
                        confidence = demoteConf,
                        isEstimatedLiquidity = demoteLiq <= 0.0,
                    )
                } catch (_: Throwable) { false }
                if (ok) {
                    try { synchronized(status.tokens) { status.tokens.remove(entry.mint) } } catch (_: Throwable) {}
                    demoted++
                }
            }
            if (demoted > 0) {
                try {
                    ForensicLogger.lifecycle(
                        "HOT_WATCHLIST_SOURCE_REBALANCED",
                        "reason=$reason demoted=$demoted pump=${pumpEntries.size} cap=$cap total=$total"
                    )
                } catch (_: Throwable) {}
            }
        } catch (_: Throwable) {}
    }

    private fun admitProtectedMemeIntake(
        mint: String,
        symbol: String,
        name: String = symbol,
        source: String,
        marketCapUsd: Double = 0.0,
        liquidityUsd: Double = 0.0,
        volumeH1: Double = 0.0,
        confidence: Int = 50,
        allSources: Set<String> = setOf(source),
        playSound: Boolean = false,
        operatorLog: Boolean = false,
        expectedRuntimeGeneration: Long? = null,
    ): Boolean {
        // V5.0.3689 вҖ” runtime generation is now an intake contract.
        // Any scanner/self-heal/WS emitter must pass the generation captured at
        // construction. If that generation is no longer the live RUNNING generation,
        // the callback is stale and must die before touching watchlist/state.
        expectedRuntimeGeneration?.let { expectedGen ->
            if (!com.lifecyclebot.engine.BotRuntimeController.isLiveGeneration(expectedGen)) {
                try {
                    com.lifecyclebot.engine.ForensicLogger.lifecycle(
                        "INTAKE_DROPPED_STALE_GENERATION",
                        "mint=${mint.take(10)} symbol=$symbol src=$source expectedGen=$expectedGen currentGen=${com.lifecyclebot.engine.BotRuntimeController.currentGeneration()} state=${com.lifecyclebot.engine.BotRuntimeController.snapshot().state}"
                    )
                } catch (_: Throwable) {}
                return false
            }
        }
        if (mint.isBlank() || mint.length < 30) {
            ErrorLogger.debug("BotService", "рҹӣЎ protected intake ignored invalid mint ${mint.take(8)} source=$source")
            ForensicLogger.gate(ForensicLogger.PHASE.INTAKE, symbol.ifBlank { mint.take(6) }, allow=false, reason="INVALID_MINT mint=${mint.take(8)} src=$source")
            return false
        }

        if (ScannerHardRejectStore.isRejected(mint)) {
            val hardReason = ScannerHardRejectStore.reason(mint)
            try {
                ForensicLogger.lifecycle("INTAKE_HARD_REJECT_SKIPPED", "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source reason=${hardReason.take(100)} no_watchlist=true no_probation=true")
                PipelineHealthCollector.labelInc("INTAKE_HARD_REJECT_SKIPPED")
            } catch (_: Throwable) {}
            return false
        }

        // V5.9.1440 вҖ” P0 BASE/QUOTE/STABLE MINT QUARANTINE (data-integrity).
        // The USDC mint EPjFWdd5вҖҰ reached SHITCOIN as a TARGET and fabricated a
        // +8722 SOL / +$587k row that poisoned expectancy, the lane tuner, the
        // policy head and tax/PnL. The scanners only filtered by SYMBOL, which
        // leaked. This is the canonical single-source intake funnel, so one
        // address-keyed guard here blocks every scanner / WS / orchestrator path.
        // Reject EARLY вҖ” no learning, no expectancy, no journal write occurs.
        if (com.lifecyclebot.engine.guard.BaseQuoteMintGuard.shouldQuarantine(mint, symbol)) {
            ForensicLogger.gate(ForensicLogger.PHASE.INTAKE, symbol.ifBlank { mint.take(6) },
                allow=false, reason="${com.lifecyclebot.engine.guard.BaseQuoteMintGuard.REJECT_REASON} mint=${mint.take(8)} src=$source")
            ErrorLogger.warn("BotService", "рҹӣ‘ BASE_QUOTE_QUARANTINE: ${symbol.ifBlank{mint.take(8)}} mint=${mint.take(12)} src=$source вҖ” rejected pre-intake (no learn/journal/PnL)")
            ScannerHardRejectStore.mark(mint, symbol, com.lifecyclebot.engine.guard.BaseQuoteMintGuard.REJECT_REASON, source)
            return false
        }

        // V5.0.4199 вҖ” scanner-intake rug-sheet block. The operator screenshot
        // showed a token with LP unlocked + low liquidity + low holders/few LP
        // providers reaching the trading surface. That class must not merely be
        // blocked at FDG/liveBuy; it should never consume hot watchlist or
        // probation slots. Run a narrow, live-only safety precheck before any
        // registry/probation admission for low-liq scanner candidates. Paper is
        // still allowed to learn; user/restored paths keep explicit intent.
        run {
            val isUserAdded = source == "USER" || source.contains("USER_ADDED", ignoreCase = true)
            val isRestoredVetted = source == "MEME_REGISTRY_RESTORE" || source == "PROBATION"
            val liveMode = try { !com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() } catch (_: Throwable) { true }
            val lowLiqScannerRisk = liquidityUsd in 0.0..5_000.0 || confidence < 45 || source.contains("SCANNER", ignoreCase = true) || source.contains("PUMP", ignoreCase = true)
            if (liveMode && !isUserAdded && !isRestoredVetted && lowLiqScannerRisk && this::safetyChecker.isInitialized) {
                val intakeSafety = try {
                    safetyChecker.check(
                        mint = mint,
                        symbol = symbol.ifBlank { mint.take(6) },
                        name = name.ifBlank { symbol.ifBlank { mint.take(6) } },
                        currentLiquidityUsd = liquidityUsd,
                        score = confidence.coerceIn(0, 100),
                    )
                } catch (e: Throwable) {
                    try { ForensicLogger.lifecycle("INTAKE_SAFETY_PRECHECK_FAILED_4199", "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source err=${e.javaClass.simpleName}:${e.message?.take(80)} action=fail_open_to_later_safety") } catch (_: Throwable) {}
                    null
                }
                if (intakeSafety?.hardBlockReasons?.isNotEmpty() == true) {
                    val reason = intakeSafety.hardBlockReasons.joinToString("|").take(160)
                    try {
                        ForensicLogger.lifecycle(
                            "INTAKE_SAFETY_HARD_REJECT_4199",
                            "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source liq=${liquidityUsd.toInt()} conf=$confidence reason=$reason no_watchlist=true no_probation=true",
                        )
                        PipelineHealthCollector.labelInc("INTAKE_SAFETY_HARD_REJECT_4199")
                    } catch (_: Throwable) {}
                    ScannerHardRejectStore.mark(mint, symbol, "INTAKE_SAFETY_HARD_REJECT_4199:$reason", source)
                    return false
                }
            }
        }

        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.9.1310 вҖ” HARD STOP-STATE GUARD (single canonical authority).
        // OPERATOR REGRESSION: pressed Stop, ACTION_STOP/LIFECYCLE_STOP_ACCEPTED
        // fired, restart alarms + watchdog cancelled вҖ” yet PumpPortal WS intake
        // (VEXLN, QTD, PokeBurn, Cheese, PEG, HenryвҖҰ) kept flowing into protected
        // intake + WATCHLIST_AFFINITY. Root cause: orchestrator.stop() (which
        // disconnects the WS) sits at the TAIL of a long, cancellable stopBot()
        // body; if the shutdown coroutine is cancelled or an earlier step throws,
        // the WS never disconnects, and even a clean disconnect races against an
        // in-flight onMessage that already called onNewToken. The bot also had NO
        // gate rejecting intake while stopping вҖ” every WS message admitted.
        //
        // FIX: gate ALL intake on the ONE runtime authority (BotRuntimeController).
        // admitProtectedMemeIntake is the canonical single-source intake funnel
        // (every path вҖ” PumpPortal WS, DataOrchestrator, TokenMergeQueue, all 8
        // scanners, MEME_REGISTRY_RESTORE вҖ” flows through here), so one guard here
        // hard-blocks intake the instant the runtime leaves RUNNING. Fail-SAFE:
        // anything other than RUNNING rejects (STOPPING/STOPPED/STARTING). This is
        // independent of WS teardown timing, so even a stray post-stop WS message
        // or an auto-reconnect can no longer pollute the watchlist.
        run {
            val rt = try { BotRuntimeController.snapshot().state } catch (_: Throwable) { null }
            val isRunningAuthority = rt == BotRuntimeController.RuntimeState.RUNNING ||
                                     rt == BotRuntimeController.RuntimeState.STARTING
            // USER adds are always allowed (explicit operator intent), even pre-start.
            val isUserAdd = source.contains("USER", ignoreCase = true)
            if (!isUserAdd && (isShuttingDown || stopInProgress || !isRunningAuthority)) {
                try {
                    val rtSnap = try { BotRuntimeController.snapshot() } catch (_: Throwable) { null }
                    val enabled = try { com.lifecyclebot.engine.EnabledTraderAuthority.snapshotStr() } catch (_: Throwable) { "?" }
                    ForensicLogger.lifecycle(
                        "INTAKE_BLOCKED_RUNTIME_STOPPED",
                        "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source rtState=$rt shuttingDown=$isShuttingDown stopInProgress=$stopInProgress",
                    )
                    // V5.0.3682 вҖ” RUNTIME_AUTH_SNAPSHOT at every intake block so
                    // a single forensic line is enough to diagnose why intake is
                    // rejecting (generation, state, loop, scanner, traders).
                    ForensicLogger.lifecycle(
                        "RUNTIME_AUTH_SNAPSHOT",
                        "at=INTAKE_BLOCK gen=${rtSnap?.runtimeGeneration} state=${rtSnap?.state} " +
                            "shuttingDown=$isShuttingDown stopInProgress=$stopInProgress " +
                            "loopActive=${rtSnap?.botLoopJobActive} scannerActive=${rtSnap?.scannerActive} " +
                            "enabled=[$enabled] src=$source"
                    )
                } catch (_: Throwable) {}
                return false
            }
        }

        val quarantine = QuarantineStore.evaluate(
            mint = mint,
            symbol = symbol,
            source = source,
            liquidityUsd = liquidityUsd,
            marketCapUsd = marketCapUsd,
            restoredLosses = 0,
            hasExternalLiquidityProof = liquidityUsd > 0.0,
        )
        if (quarantine.quarantined) {
            if (quarantine.telemetryDue) {
                val qSymbol = if (symbol.isBlank()) mint.take(6) else symbol
                try { ForensicLogger.lifecycle("INTAKE_QUARANTINED", "symbol=$qSymbol mint=${mint.take(10)} src=$source reason=${quarantine.reason} stage=protected_intake") } catch (_: Throwable) {}
            }
            return false
        }

        // V5.9.771 вҖ” EMERGENT-MEME #8: blocked-symbol FINAL enforcement.
        // Operator dump V5.9.770 showed:
        //   FILTER REJECT USDT: blocked symbol 'usdt'
        //   WATCHLISTED: USDT
        //   MEME_DIRECT_INTAKE: USDT
        //   PROTECTED_INTAKE: USDT
        // The scanner-side reject was only protecting one of 11 intake
        // paths. This single gate at the canonical intake function
        // now catches every path: TokenMergeQueue, PumpPortal WS,
        // DataOrchestrator, MEME_REGISTRY_RESTORE, all 8 scanner
        // sources, etc. Single source of truth.
        if (com.lifecyclebot.data.CanonicalMint.isBlockedMemeSymbol(symbol)) {
            try {
                ForensicLogger.lifecycle(
                    "INTAKE_BLOCKED_SYMBOL_FINAL",
                    "symbol=$symbol mint=${mint.take(10)} src=$source no_watchlist=true",
                )
            } catch (_: Throwable) {}
            ScannerHardRejectStore.mark(mint, symbol, "BLOCKED_SYMBOL_FINAL", source)
            return false
        }

        // V5.9.1035 вҖ” PART 2 (D): ZERO-LIQUIDITY INTAKE REJECT.
        // V5.9.1036 вҖ” TIGHTENED: dropped the single-source guard. Operator
        // V5.9.1034b dump showed pump.fun spam landing with liq=$0 + mcap=$0
        // + sources=2 (DATA_ORCHESTRATOR injects every emission with 2
        // scanners already attributed, and the MULTI-SCANNER BYPASS path
        // queues $0-liq tokens through the watchlist floor regardless of
        // source count). Source count doesn't redeem a dust mint вҖ” no
        // executable pool, no FDG signal, just memory + scanner cycles
        // burned. Reject on liq+mcap alone unless user/registry-restore attributed.
        // V5.0.4507 вҖ” probation promotion is NOT registry restore. Operator logs
        // still showed liq=$0 / mcap=$0 SOURCE_UPGRADE + WATCHLIST_AFFINITY spam:
        // source=PROBATION was bundled with MEME_REGISTRY_RESTORE and bypassed
        // the pure-zero reject. A probation candidate can promote only after it
        // has executable liquidity; otherwise it stays cold/no-watchlist.
        run {
            // V5.9.1036 вҖ” pure-zero ALSO covers sub-cent dust (no executable
            // pool, no realistic FDG signal). liq<$1 + mcap<$10 is dust.
            val isDustLiq = liquidityUsd < 1.0 && marketCapUsd < 10.0
            val isUserAdded = source == "USER" || source.contains("USER_ADDED")
            val isRegistryRestore = source == "MEME_REGISTRY_RESTORE"
            val isProbationPromotion = source == "PROBATION"
            if (isDustLiq && isProbationPromotion && !isUserAdded) {
                try {
                    ForensicLogger.lifecycle(
                        "INTAKE_PROBATION_LIQ_ZERO_REJECT_4507",
                        "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source srcN=${allSources.size} liq=${"%.4f".format(liquidityUsd)} mcap=${"%.4f".format(marketCapUsd)} no_watchlist=true",
                    )
                } catch (_: Throwable) {}
                ScannerHardRejectStore.mark(mint, symbol, "PROBATION_LIQ_ZERO_REJECT_4507", source)
                return false
            }
            if (isDustLiq && !isUserAdded && !isRegistryRestore) {
                try {
                    ForensicLogger.lifecycle(
                        "INTAKE_LIQ_ZERO_REJECT",
                        "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source srcN=${allSources.size} liq=${"%.4f".format(liquidityUsd)} mcap=${"%.4f".format(marketCapUsd)}",
                    )
                } catch (_: Throwable) {}
                return false
            }
        }

        // V5.9.1228 вҖ” PumpPortal cold-flow goes to probation-only, not hot
        // watchlist. 3195 had PUMP_PORTAL_WS=7404 intake hits, vol1h=0 on the
        // repeated rows, WATCHLIST_PROBATION_DEMOTE=626, and projected execs
        // collapsed to 112/day. The scanner pool remains protected: these mints
        // are retained/promotable in probation, but they stop burning main
        // supervisor/render bandwidth until another source/price action confirms.
        run {
            val tags = (source + "|" + allSources.joinToString("|")).uppercase()
            val isPumpPortalWs = tags.contains("PUMP_PORTAL_WS") || tags.contains("PUMPPORTAL")
            val isUserAdded = source == "USER" || source.contains("USER_ADDED")
            val isRestoredVetted = source == "MEME_REGISTRY_RESTORE" || source == "PROBATION"
            // V5.9.1243 вҖ” PAPER MUST NOT COLD-QUARANTINE PUMP.FUN INTAKE.
            // 1228 sent every cold Pump.fun WS graduate (vol1h=0, liq<$5k) to
            // probation-only to protect LIVE supervisor/render bandwidth. But
            // probation only promotes on price-upвүҘ5% / multi-scanner / RCвүҘ2 вҖ”
            // none of which a fresh single-source graduate gets вҖ” so in PAPER
            // they all aged out at PROBATION_MAX_TIME (5min) вҶ’ "PROBATION
            // REJECTED | TIMEOUT". Forensic 65525e7f: every intake (ORGY, Lilo,
            // STINKEYE, zzz, UpCookie, pickle, GOONABLE...) hit SINGLE_SOURCE,
            // WATCHLIST_RR fresh=0 EVERY cycle, positions pinned at 17 stale
            // bags вҖ” total entry starvation. The registry's own contract
            // (PROBATION ROUTING, line 400) is "paper mode is MUCH more lenient
            // for maximum learning exposure". Restore it: the cold-quarantine
            // applies in LIVE only (where bandwidth/risk justify it). In paper
            // only, fresh graduates flow straight to the watchlist so
            // the lanes can actually evaluate + trade them. Scanner pool stays
            // protected; this UN-chokes intake, it does not prune it.
            val lenientIntake = try {
                com.lifecyclebot.engine.RuntimeModeAuthority.isPaper()
            } catch (_: Throwable) { false }   // fail-closed in live: no safety/intake bypass on uncertainty
            val pressureDecision = try {
                // V5.9.1548b вҖ” source-neutral pressure diversion. This is NOT
                // pump.fun-only: DexScreener/CoinGecko/CMC-backed/Raydium/etc
                // cold dust can go probation-only under supervisor pressure, while
                // real-liq/multi-source candidates keep hot watchlist priority.
                com.lifecyclebot.engine.ProtectedIntakeAdmissionGate.decide(
                    source = source,
                    allSources = allSources,
                    liquidityUsd = liquidityUsd,
                    marketCapUsd = marketCapUsd,
                    volumeH1 = volumeH1,
                    supervisorTimeouts10m = supervisorTimeoutWindowCount,
                    supervisorActive = supervisorLeases.size,
                    supervisorLiveCap = supervisorEffectiveCap(),
                )
            } catch (_: Throwable) { com.lifecyclebot.engine.ProtectedIntakeAdmissionGate.Decision(false, "gate_error_fail_open") }
            // V5.0.4195 вҖ” wire ScannerSourceBrain into admission pressure, not just
            // downstream size/reporting. This remains soft-shape only: weak learned
            // single-source feeds go probation; strong learned or multi-source feeds
            // can avoid generic pressure quarantine. No source is hard-blocked.
            val sourceBrainMult = try {
                (allSources + source).map { ScannerSourceBrain.intakeMultiplier(it) }.maxOrNull() ?: 1.0
            } catch (_: Throwable) { 1.0 }
            val multiSourceConfirmed = allSources.size >= 2 || allSources.any { hasNonPumpConfirmationTag(it) }
            val sourceBrainProbationOnly = !lenientIntake && !isUserAdded && !isRestoredVetted && !multiSourceConfirmed &&
                sourceBrainMult < 0.65 && liquidityUsd < 7_500.0 && volumeH1 <= 0.0
            val sourceBrainHotRescue = sourceBrainMult >= 1.25 && (multiSourceConfirmed || liquidityUsd >= 10_000.0 || volumeH1 > 0.0)
            val coldPumpBase = !lenientIntake && isPumpPortalWs && !isUserAdded && !isRestoredVetted && volumeH1 <= 0.0 && liquidityUsd < 5_000.0
            val coldPump = coldPumpBase || sourceBrainProbationOnly || (pressureDecision.probationOnly && !sourceBrainHotRescue)
            if (sourceBrainProbationOnly || sourceBrainHotRescue) {
                try {
                    ForensicLogger.lifecycle(
                        "SCANNER_SOURCE_BRAIN_ADMISSION_SHAPED_4195",
                        "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source mult=${"%.2f".format(sourceBrainMult)} probation=$sourceBrainProbationOnly hotRescue=$sourceBrainHotRescue multi=$multiSourceConfirmed liq=${liquidityUsd.toInt()} vol1h=${volumeH1.toInt()} pressure=${pressureDecision.probationOnly}:${pressureDecision.reason}"
                    )
                    PipelineHealthCollector.labelInc(if (sourceBrainProbationOnly) "SCANNER_SOURCE_BRAIN_PROBATION_4195" else "SCANNER_SOURCE_BRAIN_HOT_RESCUE_4195")
                } catch (_: Throwable) {}
            }
            if (coldPump) {
                val laneAffinity = inferIntakeLaneAffinity(source, allSources, marketCapUsd, liquidityUsd)
                val toolAffinity = inferIntakeToolAffinity(source, allSources, marketCapUsd, liquidityUsd)
                val added = try {
                    GlobalTradeRegistry.addToProbationOnly(
                        mint = mint,
                        symbol = symbol.ifBlank { mint.take(6) },
                        addedBy = source,
                        source = allSources.joinToString("+").ifBlank { source },
                        initialMcap = marketCapUsd,
                        liquidityUsd = liquidityUsd,
                        confidence = confidence,
                        isEstimatedLiquidity = liquidityUsd <= 0.0,
                        price = 0.0,
                        laneAffinity = laneAffinity,
                        toolAffinity = toolAffinity,
                    )
                } catch (_: Throwable) { null }
                try {
                    val probationResult = added?.reason ?: "err"
                    ForensicLogger.lifecycle(
                        "INTAKE_PROBATION_ONLY",
                        "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source liq=${liquidityUsd.toInt()} mcap=${marketCapUsd.toInt()} vol1h=${volumeH1.toInt()} sourceNeutralPressure=${pressureDecision.probationOnly} pressureReason=${pressureDecision.reason} sourceBrainMult=${"%.2f".format(sourceBrainMult)} sourceBrainProbation=$sourceBrainProbationOnly result=$probationResult"
                    )
                } catch (_: Throwable) {}
                return added?.probation == true || added?.reason?.contains("PROBATION", ignoreCase = true) == true
            }
        }

        // V5.9.1035 вҖ” PART 2 (C): SYMBOL-BURST HARD REJECT.
        // Pump.fun spam clone-storms (5+ different mints with the same
        // symbol in <60s) are guaranteed rugs вҖ” bot-name patterns being
        // mass-deployed by orchestrators. Per-mint dedupe doesn't catch
        // them (different mints) and family-dedup runs much later (only
        // on open positions). Track recent admit timestamps per
        // case-insensitive symbol key; if 5+ DISTINCT mints land in 60s,
        // reject the rest. User/restore paths exempt. Sliding-window list
        // is pruned-on-write so the map cannot grow unbounded.
        run {
            val sym = normalizedSymbolBurstKey(symbol)
            if (sym.isBlank()) return@run
            val isUserAdded = source == "USER" || source.contains("USER_ADDED")
            val isRestoredVetted = source == "MEME_REGISTRY_RESTORE" || source == "PROBATION"
            if (isUserAdded || isRestoredVetted) return@run
            val burst = symbolBurstWindow.getOrPut(sym) { java.util.concurrent.ConcurrentLinkedDeque() }
            val cutoff = System.currentTimeMillis() - SYMBOL_BURST_WINDOW_MS
            // Prune stale entries.
            while (true) {
                val head = burst.peekFirst() ?: break
                if (head.second < cutoff) burst.pollFirst() else break
            }
            // Count distinct mints in the live window (excluding this mint).
            val distinctMints = burst.asSequence().map { it.first }.distinct().count { it != mint }
            if (distinctMints >= SYMBOL_BURST_MAX_MINTS) {
                try {
                    ForensicLogger.lifecycle(
                        "INTAKE_BURST_REJECT",
                        "symbol=$sym rawSymbol=${symbol.take(32)} distinctMints=$distinctMints windowMs=$SYMBOL_BURST_WINDOW_MS src=$source thisMint=${mint.take(10)}",
                    )
                } catch (_: Throwable) {}
                return false
            }
            burst.addLast(mint to System.currentTimeMillis())
            // Opportunistic outer-map prune. Keeps total entries bounded
            // across long sessions without scanning every tick.
            if (symbolBurstWindow.size > 512) {
                val it = symbolBurstWindow.entries.iterator()
                while (it.hasNext()) {
                    val e = it.next()
                    if (e.value.isEmpty() || (e.value.peekLast()?.second ?: 0L) < cutoff) it.remove()
                }
            }
        }

        // V5.9.768 вҖ” per-mint intake dedupe (see field-doc above).
        // V5.9.769 вҖ” even on a dedupe hit we MUST still let liq/mcap freshness
        // propagate to the existing TokenState. The original (V5.9.768) early
        // return was discarding fresh Raydium liq=$23,579 for SOLMAN because
        // a PUMP_PORTAL_WS hit had already seeded liq=$2,311 inside the 30s
        // window, leaving FDG to evaluate against the stale $2,311 value
        // (which sat just below the $2,100 SHITCOIN floor). Max-take
        // semantics: never overwrite a higher value with a lower one.
        val nowMs = System.currentTimeMillis()
        val prevAt = intakeLastAcceptMs[mint]
        if (prevAt != null && (nowMs - prevAt) < intakeDedupTtlMs) {
            // V5.9.769 вҖ” freshness max-take even on dedupe hits.
            if (liquidityUsd > 0.0 || marketCapUsd > 0.0) {
                try {
                    synchronized(status.tokens) {
                        val tsExisting = status.tokens[mint]
                        if (tsExisting != null) {
                            if (liquidityUsd > tsExisting.lastLiquidityUsd) {
                                tsExisting.lastLiquidityUsd = liquidityUsd
                            }
                            if (marketCapUsd > tsExisting.lastMcap) {
                                tsExisting.lastMcap = marketCapUsd
                            }
                        }
                    }
                } catch (_: Throwable) {}
            }
            val cnt = (intakeDedupCount[mint] ?: 0) + 1
            intakeDedupCount[mint] = cnt
            // Emit ONE dedupe forensic per mint per TTL window so the dump
            // proves the drop happened without re-flooding (dedupe spam
            // would defeat the point). Subsequent drops within the same
            // window are silent вҖ” the counter is exposed via the
            // ConcurrentHashMap for any future "top dedupe offenders" UI.
            if (cnt == 1) {
                try {
                    ForensicLogger.lifecycle(
                        "INTAKE_DEDUPE_DROP",
                        "mint=${mint.take(10)} symbol=${symbol.ifBlank { mint.take(6) }} src=$source ageMs=${nowMs - prevAt}",
                    )
                } catch (_: Throwable) {}
            }
            return true   // semantically still admitted (already in registry)
        }
        intakeLastAcceptMs[mint] = nowMs
        intakeDedupCount[mint] = 0

        // V5.9.1464 вҖ” FAMILY-LEVEL burst gate (spec item 7). Collapse same-family
        // mint floods so the watchlist/UI isn't inflated by PIГ‘A/JosГ©/JOTCHUA-style
        // bursts. The FIRST mint of a family in the 3-min window passes normally; a
        // DIFFERENT mint of the SAME family inside the window is still admitted
        // (so it journals + trains вҖ” never silently dropped) but marked as a family
        // duplicate so downstream watchlist render attaches it to the canonical
        // family record rather than spawning a fresh row. We do NOT suppress when
        // the symbol is blank (unknown family) or when liquidity materially differs
        // (a genuinely different, deeper pool deserves its own evaluation).
        try {
            val famSym = symbol.ifBlank { "" }
            if (famSym.isNotBlank()) {
                val fam = normalizeSymbolFamily(famSym)
                val firstAt = familyFirstAdmitMs[fam]
                if (firstAt == null || (nowMs - firstAt) >= familyIntakeTtlMs) {
                    // new/expired window вҶ’ this mint is the canonical family rep
                    familyFirstAdmitMs[fam] = nowMs
                    familyAdmitCount[fam] = 1
                } else {
                    val c = (familyAdmitCount[fam] ?: 0) + 1
                    familyAdmitCount[fam] = c
                    // materially-different pool (>3x the typical dust band) bypasses
                    // the collapse so a real graduate isn't hidden behind spam.
                    val materiallyDifferent = liquidityUsd >= 7500.0
                    if (!materiallyDifferent && c >= 2) {
                        try {
                            ForensicLogger.lifecycle(
                                "INTAKE_FAMILY_DEDUPE",
                                "family=$fam mint=${mint.take(10)} symbol=$famSym src=$source count=$c liq=\$${liquidityUsd.toInt()} (canonical kept, dup trained)"
                            )
                        } catch (_: Throwable) {}
                        // NOTE: we deliberately do NOT mutate the TokenState.phase here.
                        // The existing dedupeWatchlistByFamily() render pass already
                        // collapses same-family rows to one canonical entry, and the
                        // family burst-suppression maps it shares are unaffected. Mutating
                        // phase risks routing the token into a shadow lane / idle column
                        // and could suppress training вҖ” which would violate the spec's
                        // "weak candidates must still journal/train" rule. The forensic
                        // counter above is the dedupe signal; trading/learning untouched.
                    }
                }
                // opportunistic prune
                if (familyFirstAdmitMs.size > 512) {
                    val cutoff = nowMs - familyIntakeTtlMs
                    val it = familyFirstAdmitMs.entries.iterator()
                    while (it.hasNext()) { val e = it.next(); if (e.value < cutoff) { it.remove(); familyAdmitCount.remove(e.key) } }
                }
            }
        } catch (_: Throwable) {}
        // Opportunistic prune so the maps cannot grow unbounded across
        // long sessions. Cheap O(n) only when we cross the cap.
        if (intakeLastAcceptMs.size > 1024) {
            val cutoff = nowMs - intakeDedupTtlMs
            val it = intakeLastAcceptMs.entries.iterator()
            while (it.hasNext()) {
                val e = it.next()
                if (e.value < cutoff) {
                    it.remove()
                    intakeDedupCount.remove(e.key)
                }
            }
        }

        // V5.9.651 вҖ” forensic intake entry log
        ForensicLogger.phase(
            ForensicLogger.PHASE.INTAKE,
            symbol.ifBlank { mint.take(6) },
            "src=$source liq=$$liquidityUsd mcap=$$marketCapUsd vol1h=$$volumeH1 conf=$confidence sources=${allSources.size}"
        )

        val joinedSources = allSources.ifEmpty { setOf(source) }.joinToString(",")
        val laneAffinity = inferIntakeLaneAffinity(source, allSources, marketCapUsd, liquidityUsd)
        val toolAffinity = inferIntakeToolAffinity(source, allSources, marketCapUsd, liquidityUsd)
        try {
            val affinitySymbol = if (symbol.isBlank()) mint.take(6) else symbol
            val laneAffinityLabel = laneAffinity.joinToString("+")
            val toolAffinityLabel = toolAffinity.joinToString("+")
            ForensicLogger.lifecycle(
                "WATCHLIST_AFFINITY",
                "symbol=$affinitySymbol mint=${mint.take(10)} lanes=$laneAffinityLabel tools=$toolAffinityLabel src=$source"
            )
        } catch (_: Throwable) {}

        // V5.9.961 вҖ” PROBATION TIER ROUTING (was dormant pre-V5.9.961).
        // Operator: 'we did have a probation section that never gets used can
        // we use that to help the bot loop as well?' The probation system in
        // GlobalTradeRegistry was fully implemented but no intake path ever
        // routed tokens to it вҖ” every mint went straight to the main watchlist
        // and got polled every cycle by processTokenCycle. That bloats the
        // watchlist with low-quality candidates and starves the bot loop.
        //
        // ROUTING RULE вҖ” token goes to probation if:
        //   1. confidence < PROBATION_CONF_THRESHOLD (50 live / 22 paper), AND
        //   2. single-source (allSources.size == 1), AND
        //   3. NOT a USER add, NOT from MEME_REGISTRY_RESTORE (already vetted)
        //
        // Probation has its own cheap promote/reject lifecycle:
        //   - Multi-scanner confirm вҶ’ promote
        //   - Price up 5% вҶ’ promote
        //   - Price down 20% вҶ’ reject
        //   - 5min timeout вҶ’ reject
        //   - RC score >= 2 вҶ’ promote
        //
        // None of those gates require the bot loop to poll the token вҖ”
        // they're driven by future scanner hits and price ticks the WS feeds
        // already deliver. So probation tokens cost ZERO bot-loop cycles
        // until they either prove themselves and get promoted, or they age
        // out and get auto-rejected.
        val isProbationEligible = run {
            val isPaper = try { ConfigStore.load(applicationContext).paperMode } catch (_: Throwable) { true }
            val confThreshold = if (isPaper) 22 else 50
            val isLowConf = confidence < confThreshold
            val isSingleSrc = allSources.size <= 1
            val isUserAdded = source == "USER" || source.contains("USER_ADDED")
            val isRestoredVetted = source == "MEME_REGISTRY_RESTORE" || source == "PROBATION"
            isLowConf && isSingleSrc && !isUserAdded && !isRestoredVetted
        }

        val addResult = try {
            if (isProbationEligible) {
                // Send to probation. If it gets multi-scanner-confirmed or
                // its price action proves out, processProbation() will
                // promote it and the existing PROMOTED handler at line ~7039
                // calls admitProtectedMemeIntake(source="PROBATION"). V5.0.4507:
                // that path may bypass probation routing, but it must still pass
                // the pure-zero liquidity reject before hot watchlist hydration.
                try {
                    val probSym = if (symbol.isBlank()) mint.take(6) else symbol
                    com.lifecyclebot.engine.ForensicLogger.lifecycle(
                        "PROBATION_ROUTED",
                        "symbol=$probSym src=$source conf=$confidence liq=$liquidityUsd"
                    )
                } catch (_: Throwable) {}
                GlobalTradeRegistry.addWithProbation(
                    mint = mint,
                    symbol = symbol.ifBlank { mint.take(6) },
                    addedBy = source,
                    source = joinedSources,
                    initialMcap = marketCapUsd,
                    liquidityUsd = liquidityUsd,
                    confidence = confidence,
                    isMultiSource = allSources.size > 1,
                    laneAffinity = laneAffinity,
                    toolAffinity = toolAffinity,
                )
            } else {
                GlobalTradeRegistry.addToWatchlist(
                    mint = mint,
                    symbol = symbol.ifBlank { mint.take(6) },
                    addedBy = source,
                    source = joinedSources,
                    initialMcap = marketCapUsd,
                    initialLiquidityUsd = liquidityUsd,
                    confidence = confidence,
                    laneAffinity = laneAffinity,
                    toolAffinity = toolAffinity,
                )
            }
        } catch (e: Throwable) {
            ErrorLogger.error("BotService", "Protected intake registry add failed for ${symbol.ifBlank { mint.take(6) }}: ${e.message}", e)
            null
        }


        rebalanceHotWatchlistSources("post_intake")

        // V5.9.1560 вҖ” HOT WATCHLIST MEANS status.tokens too.
        // Previous code claimed probation costs zero bot-loop cycles, then hydrated
        // every probation-only mint into status.tokens anyway. The screenshot showed
        // the result: visible scanner/watchlist still dominated by PF/RC pump.fun
        // rows. If registry says probation-only, keep it out of the hot runtime map
        // unless it already exists/open; future promotion will re-enter here with
        // source=PROBATION and hydrate normally.
        if (addResult?.probation == true && addResult.added == false) {
            val alreadyHot = try { synchronized(status.tokens) { status.tokens.containsKey(mint) } } catch (_: Throwable) { false }
            if (!alreadyHot) {
                try {
                    ForensicLogger.lifecycle(
                        "HOT_WATCHLIST_HYDRATE_SKIPPED_PROBATION",
                        "symbol=${symbol.ifBlank { mint.take(6) }} mint=${mint.take(10)} src=$source reason=${addResult.reason}"
                    )
                } catch (_: Throwable) {}
                return true
            }
        }

        // Hydrate runtime token state for hot watchlist entries / duplicates. Legacy
        // rejection memory must never leave registry/status/UI divergent, but
        // probation-only rows intentionally stay cold.
        try {
            synchronized(status.tokens) {
                // V5.9.1193 вҖ” hot cache lookup BEFORE getOrPut. 3157 showed
                // TokenMetaCache writes increasing but 0% hit rate because only
                // the first TokenState creation path consulted the cache. Once
                // status.tokens already held a mint, duplicate source hits skipped
                // lookup entirely, so cached pair/price metadata could not refill
                // missing runtime fields and telemetry looked dead. This is pure
                // in-memory lookup; never blocks scanner intake or execution.
                val cachedForIntake = try {
                    com.lifecyclebot.engine.TokenMetaCache
                        .get(applicationContext).lookup(mint)
                } catch (_: Throwable) { null }
                val hiveForIntake = try {
                    com.lifecyclebot.collective.CollectiveLearning.getCachedTokenMint(mint)
                } catch (_: Throwable) { null }
                val ts = status.tokens.getOrPut(mint) {
                    // V5.9.948 вҖ” warm-boot hydration from disk-backed cache.
                    // If we've seen this mint before, restore the
                    // static-ish fields (symbol/pair/logo/dex/poolAddr) +
                    // the slow-moving last-snapshot (mcap/liq/fdv/price).
                    // Skips a Birdeye + DexScreener round-trip per restart.
                    val cached = cachedForIntake
                    com.lifecyclebot.data.TokenState(
                        mint = mint,
                        symbol = symbol.ifBlank { cached?.symbol?.takeIf { it.isNotBlank() } ?: hiveForIntake?.symbol?.takeIf { it.isNotBlank() } ?: mint.take(6) },
                        name = name.ifBlank { cached?.name?.takeIf { it.isNotBlank() } ?: hiveForIntake?.name?.takeIf { it.isNotBlank() } ?: symbol.ifBlank { mint.take(6) } },
                        pairAddress = cached?.pairAddress?.takeIf { it.isNotBlank() } ?: hiveForIntake?.pairAddress ?: "",
                        pairUrl = cached?.pairUrl?.takeIf { it.isNotBlank() } ?: hiveForIntake?.pairUrl ?: "",
                        candleTimeframeMinutes = 1,
                        source = joinedSources.ifBlank { hiveForIntake?.source ?: "" },
                        logoUrl = cached?.logoUrl?.takeIf { it.isNotBlank() } ?: hiveForIntake?.logoUrl ?: "",
                    ).also { fresh ->
                        fresh.laneAffinity.addAll(laneAffinity)
                        fresh.toolAffinity.addAll(toolAffinity)
                        if (cached != null) {
                            // Warm slow-moving snapshot fields. These are SAFE
                            // to seed because every fresh tick will overwrite
                            // them; they only matter for the first few seconds
                            // post-boot when the scanner hasn't ticked yet.
                            if (cached.lastPrice > 0.0) fresh.lastPrice = cached.lastPrice
                            if (cached.lastMcap > 0.0) fresh.lastMcap = cached.lastMcap
                            if (cached.lastLiquidityUsd > 0.0) fresh.lastLiquidityUsd = cached.lastLiquidityUsd
                            if (cached.lastFdv > 0.0) fresh.lastFdv = cached.lastFdv
                            if (cached.lastPriceDex.isNotBlank()) fresh.lastPriceDex = cached.lastPriceDex
                            if (cached.lastPricePoolAddr.isNotBlank()) fresh.lastPricePoolAddr = cached.lastPricePoolAddr
                            if (cached.lastPriceSource.isNotBlank()) fresh.lastPriceSource = cached.lastPriceSource
                        }
                        if (cached == null && hiveForIntake != null) {
                            if (hiveForIntake.lastMcapUsd > 0.0) fresh.lastMcap = hiveForIntake.lastMcapUsd
                            if (hiveForIntake.lastLiquidityUsd > 0.0) fresh.lastLiquidityUsd = hiveForIntake.lastLiquidityUsd
                            if (hiveForIntake.pairDex.isNotBlank()) fresh.lastPriceDex = hiveForIntake.pairDex
                            if (hiveForIntake.lastPriceSource.isNotBlank()) fresh.lastPriceSource = hiveForIntake.lastPriceSource
                        }
                    }
                }
                // symbol/name are immutable identity fields on TokenState; the
                // getOrPut initializer above is the authority for first hydrate.
                // V5.9.1193 вҖ” if the token already existed in runtime, use the
                // same cache hit to fill only empty/stale metadata fields. Fresh
                // scanner values below still win via max-take semantics.
                if (cachedForIntake != null) {
                    // pairAddress/pairUrl are immutable val fields on TokenState;
                    // those are still hydrated on first creation above. Existing
                    // runtime tokens only refill mutable quote/visual fields here.
                    if (ts.logoUrl.isBlank() && cachedForIntake.logoUrl.isNotBlank()) ts.logoUrl = cachedForIntake.logoUrl
                    if (ts.lastPrice <= 0.0 && cachedForIntake.lastPrice > 0.0) ts.lastPrice = cachedForIntake.lastPrice
                    if (ts.lastMcap <= 0.0 && cachedForIntake.lastMcap > 0.0) ts.lastMcap = cachedForIntake.lastMcap
                    if (ts.lastLiquidityUsd <= 0.0 && cachedForIntake.lastLiquidityUsd > 0.0) ts.lastLiquidityUsd = cachedForIntake.lastLiquidityUsd
                    if (ts.lastFdv <= 0.0 && cachedForIntake.lastFdv > 0.0) ts.lastFdv = cachedForIntake.lastFdv
                    if (ts.lastPriceDex.isBlank() && cachedForIntake.lastPriceDex.isNotBlank()) ts.lastPriceDex = cachedForIntake.lastPriceDex
                    if (ts.lastPricePoolAddr.isBlank() && cachedForIntake.lastPricePoolAddr.isNotBlank()) ts.lastPricePoolAddr = cachedForIntake.lastPricePoolAddr
                    if (ts.lastPriceSource.isBlank() && cachedForIntake.lastPriceSource.isNotBlank()) ts.lastPriceSource = cachedForIntake.lastPriceSource
                } else if (hiveForIntake != null) {
                    if (ts.logoUrl.isBlank() && hiveForIntake.logoUrl.isNotBlank()) ts.logoUrl = hiveForIntake.logoUrl
                    if (ts.lastMcap <= 0.0 && hiveForIntake.lastMcapUsd > 0.0) ts.lastMcap = hiveForIntake.lastMcapUsd
                    if (ts.lastLiquidityUsd <= 0.0 && hiveForIntake.lastLiquidityUsd > 0.0) ts.lastLiquidityUsd = hiveForIntake.lastLiquidityUsd
                    if (ts.lastPriceDex.isBlank() && hiveForIntake.pairDex.isNotBlank()) ts.lastPriceDex = hiveForIntake.pairDex
                    if (ts.lastPriceSource.isBlank() && hiveForIntake.lastPriceSource.isNotBlank()) ts.lastPriceSource = hiveForIntake.lastPriceSource
                    if (hiveForIntake.socialCount > 0 || hiveForIntake.coingeckoId.isNotBlank()) {
                        com.lifecyclebot.engine.BirdeyeMetaDataProvider.seedFromHive(
                            mint = ts.mint,
                            name = hiveForIntake.name,
                            symbol = hiveForIntake.symbol,
                            twitter = hiveForIntake.twitter,
                            telegram = hiveForIntake.telegram,
                            discord = hiveForIntake.discord,
                            website = hiveForIntake.website,
                            coingeckoId = hiveForIntake.coingeckoId,
                        )
                    }
                }
                if (ts.source.isBlank()) ts.source = joinedSources
                ts.laneAffinity.addAll(laneAffinity)
                ts.toolAffinity.addAll(toolAffinity)
                try { GlobalTradeRegistry.mergeAffinity(mint, laneAffinity, toolAffinity) } catch (_: Throwable) {}

                if (liquidityUsd > ts.lastLiquidityUsd) {
                    // V5.9.769 вҖ” max-take semantics (was `<= 0.0` guard, which
                    // froze stale low-liq seeds and starved FDG). Fresh higher
                    // liquidity from any source (DexScreener/Raydium) always
                    // wins over older Pump-portal/WS seeds.
                    ts.lastLiquidityUsd = liquidityUsd
                }
                if (marketCapUsd > ts.lastMcap) {
                    // V5.9.769 вҖ” max-take (was `<= 0.0`).
                    ts.lastMcap = marketCapUsd
                }
                // V5.9.655 вҖ” operator triage: 391 of 392 PumpPortal tokens
                // were never reaching SAFETY/V3/LANE_EVAL because
                // synthesizeFallbackPair() requires ts.lastPrice > 0.0 and
                // intake never seeded a price. DexScreener/Birdeye/Oracle
                // fallbacks all fail for brand-new pump.fun mints (not yet
                // indexed), so processTokenCycle silently returned at the
                // line 6958 ?: run { вҖҰ return } branch with zero log
                // output. Pump.fun tokens are always 1B supply by protocol,
                // so priceUsd = mcap / 1_000_000_000 is exact and free.
                // tryFallbackPriceData uses the same formula at line 12363
                // when the pump.fun frontend API later succeeds вҖ” we just
                // pre-seed it so the bot can start scoring/safety-checking
                // immediately instead of waiting for an oracle round-trip
                // that often fails for fresh launches.
                if (marketCapUsd > 0.0 && ts.lastPrice <= 0.0) {
                    ts.lastPrice = marketCapUsd / 1_000_000_000.0
                    ts.lastPriceUpdate = System.currentTimeMillis()
                    // V5.9.744 вҖ” tag synthetic source. Pump.Fun protocol guarantees
                    // 1B fixed supply on BC, so mcap/1B is the exact per-token price
                    // ON THAT SCALE. But when the token graduates to Raydium/Bonk,
                    // DexScreener WS will overwrite this with the REAL pool quote
                    // on a different basis. getActualPrice detects the basis switch
                    // and rescales entryPrice once so PnL stays honest.
                    ts.lastPriceSource = "PUMP_FUN_BC_SYNTHETIC"
                    ts.lastPriceDex = "PUMP_FUN"
                } else if (marketCapUsd > 0.0 && ts.lastPriceSource == "PUMP_FUN_BC_SYNTHETIC") {
                    // V5.9.1328 вҖ” ROOT FIX F: Synthetic price refresh.
                    // The initial seed above only fires once (lastPrice <= 0
                    // guard). As pump-portal WS keeps streaming updated mcaps
                    // for the same fresh-launch mint, the synthetic price was
                    // frozen at the FIRST sighting forever, so the
                    // priceAgeMs check used by AntiChoke's unpriced-fresh
                    // counter saw 498/500 tokens as "stale unpriced" even
                    // though pump-portal was actively feeding mcap updates.
                    // Refresh the synthetic price + price-update timestamp
                    // every WS tick so the freshness sentinel reads honest
                    // staleness. The 1B-supply formula is still exact for
                    // pump.fun BC tokens. After graduation to Raydium,
                    // lastPriceSource flips and this branch stops firing.
                    val newPrice = marketCapUsd / 1_000_000_000.0
                    if (newPrice != ts.lastPrice) {
                        ts.lastPrice = newPrice
                        ts.lastPriceUpdate = System.currentTimeMillis()
                    }
                }
                if (confidence > 0 && ts.entryScore <= 0.0) {
                    ts.entryScore = confidence.toDouble()
                }
                if (volumeH1 > 0.0 && ts.history.isEmpty()) {
                    val seedPrice = if (ts.lastPrice > 0) ts.lastPrice else 0.0
                    val seedMcap = if (ts.lastMcap > 0) ts.lastMcap else marketCapUsd
                    val seedCandle = com.lifecyclebot.data.Candle(
                        ts = System.currentTimeMillis(),
                        priceUsd = seedPrice,
                        marketCap = seedMcap,
                        volumeH1 = volumeH1,
                        volume24h = 0.0,
                        buysH1 = 0,
                        sellsH1 = 0,
                        highUsd = seedPrice,
                        lowUsd = seedPrice,
                        openUsd = seedPrice,
                    )
                    synchronized(ts.history) { ts.history.addLast(seedCandle) }
                }
                // V5.9.655 вҖ” fresh-mint candle seed even when volumeH1=0 (brand
                // new pump.fun launches always have volumeH1=0 at intake). This
                // gives processTokenCycle's hot-path momentum/history readers a
                // non-empty history list immediately rather than waiting for
                // the next DexScreener tick. seedPrice is now non-zero thanks
                // to the mcap/1B fallback above, so the candle is meaningful.
                if (ts.history.isEmpty() && ts.lastPrice > 0.0) {
                    val seedCandle = com.lifecyclebot.data.Candle(
                        ts = System.currentTimeMillis(),
                        priceUsd = ts.lastPrice,
                        marketCap = ts.lastMcap.coerceAtLeast(marketCapUsd),
                        volumeH1 = 0.0,
                        volume24h = 0.0,
                        buysH1 = 0,
                        sellsH1 = 0,
                        highUsd = ts.lastPrice,
                        lowUsd = ts.lastPrice,
                        openUsd = ts.lastPrice,
                    )
                    synchronized(ts.history) { ts.history.addLast(seedCandle) }
                }
                // V5.9.1183 вҖ” persist the intake-time synthetic snapshot immediately.
                // 3145 showed TokenMetaCache liveRows=17,929 but hitRate=6.7%:
                // fresh PumpPortal mints were being hydrated/scored in memory, yet the
                // cache mostly learned only later pair metadata. Register the cheap
                // mcap/liquidity/price seed at the same point status.tokens is updated
                // so restarts and duplicate source hits can reuse it instead of falling
                // back through slow no-pair oracle paths. Best-effort only; never gates.
                try {
                    com.lifecyclebot.engine.TokenMetaCache.get(applicationContext).register(
                        mint = mint,
                        symbol = ts.symbol,
                        name = ts.name,
                        pairAddress = ts.pairAddress,
                        pairUrl = ts.pairUrl,
                        logoUrl = ts.logoUrl,
                        lastPriceSource = ts.lastPriceSource,
                        lastPricePoolAddr = ts.lastPricePoolAddr,
                        lastPriceDex = ts.lastPriceDex,
                        lastPrice = ts.lastPrice.takeIf { it > 0.0 },
                        lastMcap = ts.lastMcap.takeIf { it > 0.0 } ?: marketCapUsd.takeIf { it > 0.0 },
                        lastLiquidityUsd = ts.lastLiquidityUsd.takeIf { it > 0.0 } ?: liquidityUsd.takeIf { it > 0.0 },
                        lastFdv = ts.lastFdv.takeIf { it > 0.0 } ?: marketCapUsd.takeIf { it > 0.0 },
                        creationTimeMs = ts.addedToWatchlistAt.takeIf { it > 0L },
                    )
                } catch (_: Throwable) {}
            }

            try {
                com.lifecyclebot.engine.MemeMintRegistry.touch(
                    mint = mint,
                    symbol = symbol.ifBlank { mint.take(6) },
                    name = name.ifBlank { symbol.ifBlank { mint.take(6) } },
                    source = joinedSources,
                )
            } catch (_: Throwable) {}

            // V5.9.948 вҖ” write-through to TokenMetaCache so a future warm boot
            // can hydrate without round-tripping any API. Cheap: pure memory
            // mutation, the next 60s flush ticks it to SQLite.
            try {
                com.lifecyclebot.engine.TokenMetaCache.get(applicationContext).register(
                    mint = mint,
                    symbol = symbol.ifBlank { null },
                    name = name.ifBlank { null },
                    lastMcap = marketCapUsd.takeIf { it > 0.0 },
                    lastLiquidityUsd = liquidityUsd.takeIf { it > 0.0 },
                )
            } catch (_: Throwable) { /* best-effort */ }

            try {
                val uploadNow = System.currentTimeMillis()
                val priorUpload = tokenMintUploadInFlight.put(mint, uploadNow) ?: 0L
                val shouldUploadMintMeta = uploadNow - priorUpload >= 60_000L
                if (shouldUploadMintMeta) kotlinx.coroutines.GlobalScope.launch(com.lifecyclebot.util.AppDispatchers.sideEffect) {
                    try {
                        val tsShared = synchronized(status.tokens) { status.tokens[mint] }
                        val creation = com.lifecyclebot.engine.BirdeyeCreationInfoProvider.peekCached(mint)
                        val socialMeta = com.lifecyclebot.engine.BirdeyeMetaDataProvider.peekCached(mint)
                        com.lifecyclebot.collective.CollectiveLearning.uploadTokenMint(
                            mint = mint,
                            symbol = tsShared?.symbol ?: symbol.ifBlank { mint.take(6) },
                            name = tsShared?.name ?: name.ifBlank { symbol.ifBlank { mint.take(6) } },
                            source = tsShared?.source ?: joinedSources,
                            creatorAddress = creation?.creatorAddress ?: "",
                            logoUrl = tsShared?.logoUrl ?: "",
                            twitter = socialMeta?.twitter ?: "",
                            telegram = socialMeta?.telegram ?: "",
                            discord = socialMeta?.discord ?: "",
                            website = socialMeta?.website ?: "",
                            coingeckoId = socialMeta?.coingeckoId ?: "",
                            socialCount = socialMeta?.socialChannelCount() ?: 0,
                            pairAddress = tsShared?.pairAddress ?: "",
                            pairUrl = tsShared?.pairUrl ?: "",
                            pairDex = tsShared?.lastPriceDex ?: "",
                            lastPriceSource = tsShared?.lastPriceSource ?: "",
                            quoteSuccessful = (tsShared?.pairAddress?.isNotBlank() == true) || (tsShared?.lastPrice ?: 0.0) > 0.0,
                            lastLiquidityUsd = tsShared?.lastLiquidityUsd ?: liquidityUsd,
                            lastMcapUsd = tsShared?.lastMcap ?: marketCapUsd,
                            createdAtMs = creation?.createdAtMs ?: tsShared?.addedToWatchlistAt ?: 0L,
                        )
                    } catch (_: Throwable) {
                    } finally {
                        try { tokenMintUploadInFlight.remove(mint) } catch (_: Throwable) {}
                    }
                }
            } catch (_: Throwable) {}

            try { orchestrator?.onTokenAdded(mint, symbol.ifBlank { mint.take(6) }) } catch (_: Throwable) {}
        } catch (e: Throwable) {
            ErrorLogger.error("BotService", "Protected intake TokenState hydrate failed for ${symbol.ifBlank { mint.take(6) }}: ${e.message}", e)
        }

        val added = addResult?.added == true
        if (added) {
            val newSize = try { GlobalTradeRegistry.size() } catch (_: Throwable) { -1 }
            TradeLifecycle.watchlisted(mint, newSize, "protected_intake: $source")
            ErrorLogger.info(
                "BotService",
                "рҹӣЎ PROTECTED_INTAKE: ${symbol.ifBlank { mint.take(6) }} | source=$source | liq=\$${liquidityUsd.toInt()} | conf=$confidence | watch=$newSize"
            )
            if (operatorLog) {
                addLog("рҹ“Ӣ WATCHLISTED: ${symbol.ifBlank { mint.take(6) }} ($source) | liq=\$${liquidityUsd.toInt()} | conf=$confidence | #$newSize", mint)
            }
            if (playSound) soundManager.playNewToken()
        } else {
            ErrorLogger.debug(
                "BotService",
                "рҹӣЎ PROTECTED_INTAKE_HYDRATED: ${symbol.ifBlank { mint.take(6) }} | source=$source | reason=${addResult?.reason ?: "registry_error"}"
            )
        }
        return added
    }

    private fun processTokenMergeQueue(loopCount: Int) {
        val mergedTokens = TokenMergeQueue.processQueue()
        for (merged in mergedTokens) {
            val boostLabel = if (merged.multiScannerBoost) " [MULTI-SCANNER]" else ""
            val scannersInfo = if (merged.allScanners.size > 1)
                " (${merged.allScanners.joinToString("+")})" else ""

            val added = admitProtectedMemeIntake(
                mint = merged.mint,
                symbol = merged.symbol,
                name = merged.symbol,
                source = merged.primaryScanner,
                marketCapUsd = merged.marketCapUsd,
                liquidityUsd = merged.liquidityUsd,
                volumeH1 = merged.volumeH1,
                confidence = merged.confidence,
                allSources = merged.allScanners,
                playSound = true,
                operatorLog = true,
                expectedRuntimeGeneration = com.lifecyclebot.engine.BotRuntimeController.currentGeneration(),
            )

            if (added) {
                try { com.lifecyclebot.engine.WatchlistTtlPolicy.mark(merged.symbol, merged.confidence) } catch (_: Throwable) {}
                TradeLifecycle.watchlisted(merged.mint, GlobalTradeRegistry.size(), "merged: ${merged.primaryScanner}$scannersInfo$boostLabel")
            }
        }

        val probationResults = GlobalTradeRegistry.processProbation()
        for (result in probationResults) {
            when (result.action) {
                "PROMOTED" -> {
                    addLog("вң… PROMOTED: ${result.symbol} | ${result.reason}", result.mint)
                    soundManager.playNewToken()
                    try {
                        val probEntry = GlobalTradeRegistry.getProbationEntry(result.mint)
                        admitProtectedMemeIntake(
                            mint = result.mint,
                            symbol = result.symbol,
                            name = result.symbol,
                            source = "PROBATION",
                            marketCapUsd = probEntry?.initialMcap ?: 0.0,
                            liquidityUsd = probEntry?.initialLiquidity ?: 0.0,
                            confidence = 50,
                            allSources = setOf("PROBATION"),
                            playSound = false,
                            operatorLog = false,
                            expectedRuntimeGeneration = com.lifecyclebot.engine.BotRuntimeController.currentGeneration(),
                        )
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "PROMOTED protected intake hydrate error: ${e.message}")
                    }
                }
                "REJECTED" -> {
                    // V5.9.626 вҖ” probation rejection is execution memory only;
                    // protected intake must not shrink or hide the universe.
                    ErrorLogger.debug("BotService", "рҹӣЎ PROBATION_SHADOW: ${result.symbol} | ${result.reason}")
                }
            }
        }

        if (loopCount % 30 == 0 && TokenMergeQueue.getPendingCount() > 0) {
            addLog("рҹ”Җ ${TokenMergeQueue.getStats()}")
        }
        if (loopCount % 30 == 0 && GlobalTradeRegistry.probationSize() > 0) {
            addLog("вҸі ${GlobalTradeRegistry.getProbationStats()}")
        }
        // V5.9.1370 вҖ” periodic tactic safety sweep. maybeRotateFromMemory() was
        // dead code (defined, never called), so quiet/low-frequency bleeding
        // buckets (e.g. SHITCOIN bands at 90%+ loss but trickling closes) never
        // rotated their tactic. Run the memory-driven sweep every ~30 ticks
        // (~2.5min) off the hot path; it iterates in-memory cell keys and the
        // heavy stats read is bounded inside LosingPatternMemory. NEVER disables a
        // bucket вҖ” only rotates its entry tactic (MOMENTUMвҶ’PULLBACKвҶ’...).
        if (loopCount % 30 == 0) {
            try {
                kotlinx.coroutines.GlobalScope.launch(com.lifecyclebot.util.AppDispatchers.sideEffect) {
                    try { com.lifecyclebot.engine.learning.TacticSwitcher.sweepAllBuckets() } catch (_: Throwable) {}
                }
            } catch (_: Throwable) {}
        }
    }

