    private suspend fun runReconcileSweep() {
        val cfgNow = ConfigStore.load(applicationContext)
        val w = wallet ?: return
        if (cfgNow.paperMode || !::executor.isInitialized) return

        val activeMints = mutableSetOf<String>()
        try {
            synchronized(status.tokens) {
                status.tokens.values.forEach { ts ->
                    if (ts.position.isOpen) activeMints.add(ts.mint)
                }
            }
        } catch (_: Exception) {}
        try {
            com.lifecyclebot.v3.scoring.ShitCoinTraderAI.getActivePositions()
                .forEach { activeMints.add(it.mint) }
        } catch (_: Exception) {}
        try {
            com.lifecyclebot.v3.scoring.MoonshotTraderAI.getActivePositions()
                .forEach { activeMints.add(it.mint) }
        } catch (_: Exception) {}
        try {
            com.lifecyclebot.v3.scoring.QualityTraderAI.getActivePositions()
                .forEach { activeMints.add(it.mint) }
        } catch (_: Exception) {}
        try {
            com.lifecyclebot.v3.scoring.BlueChipTraderAI.getActivePositions()
                .forEach { activeMints.add(it.mint) }
        } catch (_: Exception) {}
        val swept = executor.liveSweepWalletTokens(w, w.getSolBalance(), activeMints)
        if (swept > 0) {
            ErrorLogger.warn("BotService",
                "рҹ”„ RECONCILE SWEEP: liquidated $swept orphan token(s) leaked from V3 exits")
            addLog("рҹ”„ Reconcile: cleared $swept orphan position(s) from wallet")
        }
    }

    // V5.9.495z53 вҖ” extracted from botLoop() to keep the synthesized
    // bytecode under the JVM 64KB method-size limit (build was failing with
    // "Couldn't transform method node: botLoop"). No behavior change.
    private fun runLabUniverseTick() {
        com.lifecyclebot.engine.lab.LlmLabEngine.tick {
            val list = ArrayList<com.lifecyclebot.engine.lab.LlmLabEngine.LabUniverseTick>(
                status.tokens.size
            )
            val regime = try {
                val m = com.lifecyclebot.v4.meta.CrossMarketRegimeAI.assessRegime().mode
                when (m) {
                    com.lifecyclebot.v4.meta.GlobalRiskMode.RISK_ON,
                    com.lifecyclebot.v4.meta.GlobalRiskMode.TRENDING -> "BULL"
                    com.lifecyclebot.v4.meta.GlobalRiskMode.RISK_OFF -> "BEAR"
                    else -> "CHOP"
                }
            } catch (_: Throwable) { "ANY" }
            status.tokens.values.forEach { ts ->
                val price = ts.lastPrice.takeIf { it > 0 } ?: ts.history.lastOrNull()?.priceUsd ?: 0.0
                if (price <= 0) return@forEach
                val score = (ts.entryScore.toInt()).coerceIn(0, 100)
                list.add(com.lifecyclebot.engine.lab.LlmLabEngine.LabUniverseTick(
                    symbol = ts.symbol.ifBlank { ts.mint.take(8) },
                    mint = ts.mint,
                    asset = com.lifecyclebot.engine.lab.LabAssetClass.MEME,
                    price = price,
                    score = score,
                    regime = regime,
                ))
            }
            fun pushTick(symbol: String, mint: String, asset: com.lifecyclebot.engine.lab.LabAssetClass, price: Double) {
                if (price <= 0.0 || symbol.isBlank()) return
                list.add(com.lifecyclebot.engine.lab.LlmLabEngine.LabUniverseTick(
                    symbol = symbol, mint = mint, asset = asset,
                    price = price, score = 50, regime = regime,
                ))
            }
            try {
                com.lifecyclebot.perps.CryptoAltTrader.getOpenPositions().forEach { p ->
                    pushTick(p.marketSymbol, p.marketSymbol, com.lifecyclebot.engine.lab.LabAssetClass.ALT, p.currentPrice)
                }
            } catch (_: Throwable) {}
            try {
                com.lifecyclebot.perps.TokenizedStockTrader.getActivePositions().forEach { p ->
                    pushTick(p.market.symbol, p.market.symbol, com.lifecyclebot.engine.lab.LabAssetClass.STOCK, p.currentPrice)
                }
            } catch (_: Throwable) {}
            try {
                com.lifecyclebot.perps.PerpsTraderAI.getActivePositions().forEach { p ->
                    pushTick(p.market.symbol, p.market.symbol, com.lifecyclebot.engine.lab.LabAssetClass.MARKETS, p.currentPrice)
                }
            } catch (_: Throwable) {}
            try {
                com.lifecyclebot.perps.ForexTrader.getAllPositions().forEach { p ->
                    pushTick(p.market.symbol, p.market.symbol, com.lifecyclebot.engine.lab.LabAssetClass.FOREX, p.currentPrice)
                }
            } catch (_: Throwable) {}
            try {
                com.lifecyclebot.perps.MetalsTrader.getAllPositions().forEach { p ->
                    pushTick(p.market.symbol, p.market.symbol, com.lifecyclebot.engine.lab.LabAssetClass.METAL, p.currentPrice)
                }
            } catch (_: Throwable) {}
            try {
                com.lifecyclebot.perps.CommoditiesTrader.getAllPositions().forEach { p ->
                    pushTick(p.market.symbol, p.market.symbol, com.lifecyclebot.engine.lab.LabAssetClass.COMMODITY, p.currentPrice)
                }
            } catch (_: Throwable) {}
            list
        }
    }

    /**
     * V5.9.652 вҖ” extracted from botLoop() to dodge JVM 64KB method-size limit.
     * Emits one INFO-level forensic LOOP_TOP snapshot with full pipeline state
     * so the operator can grep "рҹ§¬[LOOP_TOP]" and instantly see what the bot
     * thinks the world looks like: scanner alive, merge queue depth, watchlist
     * size, open position count, paper/live mode, V3 toggle, etc.
     */
    private var lastBotLoopTickMs: Long = System.currentTimeMillis()
    // V5.9.1313 вҖ” when the botLoop coroutine actually began (for hotExit never-ran grace window).
    @Volatile private var botLoopStartedAtMs: Long = 0L

    // V5.9.955 вҖ” TICK-LOOP EXIT SWEEP throttle. Exits now fire from the
    // fast 1Hz open-position tick loop (not the slow 8s+ bot loop), so
    // hard floors / TP / trailing stops engage 30x faster. Throttled to
    // every 2s so we don't burn CPU on every 1Hz tick.
    private var lastTickExitSweepMs: Long = 0L
    // V5.9.1197 вҖ” botLoop POST_SUPERVISOR heavy sweep backup throttle.
    // Active exit management is owned by hotExitJob/open-position tick paths;
    // botLoop is a stale backup only. This prevents every 5s cycle from
    // hammering the single-flight gates and forcing resets.
    @Volatile private var lastPostSupervisorExitBackupMs: Long = 0L
    private val POST_SUPERVISOR_EXIT_BACKUP_MS: Long = 60_000L

    // V5.9.1198 вҖ” OFF-LOOP EXIT SWEEP COORDINATOR.
    // The old launchExitSweepAsync/launchUniversalSlSweepAsync functions spawned
    // a worker + watchdog per request. When botLoop/openPositionTick/hotExit all
    // signalled at once, the single-flight gates thrashed and produced hundreds
    // of COALESCED/FORCE_RESET events. These atomics feed one coordinator loop
    // instead. The coordinator owns heavy sweeps; requesters only set flags.
    @Volatile private var exitSweepCoordinatorJob: kotlinx.coroutines.Job? = null
    private val exitSweepCoordinatorLock = Any()
    private val fullExitSweepPending = AtomicBoolean(false)
    private val universalSlSweepPending = AtomicBoolean(false)
    private val exitCoordinatorLastFullMs = java.util.concurrent.atomic.AtomicLong(0L)
    private val exitCoordinatorLastUniversalMs = java.util.concurrent.atomic.AtomicLong(0L)
    private val EXIT_COORDINATOR_FULL_MIN_MS: Long = 30_000L
    private val EXIT_COORDINATOR_UNIVERSAL_MIN_MS: Long = 30_000L

    // V5.9.1009 вҖ” Exit sweeps must never block botLoop. A slow paperSell
    // learning/closeout fanout previously parked the main cycle in
    // POST_SUPERVISOR and stopped BOT_LOOP_TICK after ~3 iterations.
    private val exitSweepInFlight = AtomicBoolean(false)
    // V5.9.1079 вҖ” operator snapshot showed EXIT_SWEEP_SKIPPED=154 vs
    // ASYNC_DONE=42 in 1095s with 9 open positions and EXIT allow=191/block=0.
    // The exit gate kept approving exits but the actual paperSell never fired
    // because every cycle's sweep request was skipped on alreadyRunning=true.
    // Root cause: the 2.5s watchdog cancelled the worker but the worker's
    // own `finally` block also ran compareAndSet on the gate вҖ” whichever
    // ran first won, and if the worker's IO was wedged inside non-cooperative
    // code, the watchdog won the gate flip but the dead worker's reference
    // was lost. Subsequent sweeps then saw alreadyRunning=true forever
    // because nothing tracked the wedged worker for explicit cancel.
    // Fix: track the live worker Job + its start time. When a new sweep
    // arrives and the gate is held but the prior worker is older than the
    // watchdog budget, force-cancel the prior worker AND clear the gate
    // before proceeding. Stuck IO can never park exits again.
    @Volatile private var exitSweepWorker: kotlinx.coroutines.Job? = null
    @Volatile private var exitSweepStartedMs: Long = 0L
    // V5.9.1087 вҖ” owner token for the single-flight gate. A timed-out/late
    // worker from generation N must never clear the gate or worker ref for
    // generation N+1 after a force reset starts a fresh sweep.
    private val exitSweepGeneration = java.util.concurrent.atomic.AtomicLong(0L)
    private val exitSweepPending = AtomicBoolean(false)
    private val EXIT_SWEEP_HARD_MS: Long = 12_000L
    // V5.9.1082 вҖ” operator V5.9.1081b snapshot: EXIT_SWEEP_FORCE_RESET=54 in
    // ~18 min. That's a reset every 20s вҖ” meaning the previous 3s budget was
    // far below the realistic sweep duration. sweepUniversalExits iterates
    // all open positions and may invoke paperSell()'s learning fanout per
    // match; with 5-10 positions this routinely exceeds 5-10 seconds. Bumped
    // to 12s so the worker actually has time to finish on a healthy cycle.
    // The watchdog delay below was bumped in lock-step (2.5s вҶ’ 10s). Force
    // resets now indicate a TRULY stuck worker (>12s) rather than a
    // slow-but-progressing one.

    // V5.9.1019 вҖ” Operator V5.9.1018 snapshot showed cycles alternating
    // between fast (sub-200ms) and slow (11-44s). Forensic trace pinned
    // it on runUniversalSlSafetyNetSweep at line ~9763: it ran synchronously
    // on the bot loop thread at the end of EVERY cycle, iterating ALL open
    // positions and calling executor.requestSell() per match. With 5-10
    // open positions and paperSell's heavy learning fanout (~3-5s each),
    // one cycle could burn 30-50s blocking the loop. Next cycle finds the
    // positions closed вҶ’ fast вҶ’ and so on. Async-ify with the same pattern
    // as launchExitSweepAsync (V5.9.1010) вҖ” single-flight + worker + hard
    // timeout watchdog so the gate can never get stuck.
    private val slSafetyNetInFlight = AtomicBoolean(false)
    // V5.9.1079 вҖ” same pattern as exitSweepInFlight: track the live worker
    // + age so a wedged universal-SL sweep can be force-cancelled by the
    // next cycle instead of permanently parking position exits.
    @Volatile private var slSafetyNetWorker: kotlinx.coroutines.Job? = null
    @Volatile private var slSafetyNetStartedMs: Long = 0L
    // V5.9.1087 вҖ” same owner-token guard as exitSweepGeneration.
    private val slSafetyNetGeneration = java.util.concurrent.atomic.AtomicLong(0L)
    private val slSafetyNetPending = AtomicBoolean(false)

    // V5.9.1238 вҖ” REGRESSION FIX (bot-loop stall at POST_SUPERVISOR/PERSIST_DISPATCHED).
    // V5.9.1227 made cyclic "a real compounding lane" and ran CyclicTradeEngine.tick()
    // INLINE on the bot-loop coroutine. tick() synchronously calls FinalDecisionGate +
    // executor.treasuryBuy/paperSell, which drag in the full learning/persistence fanout вҖ”
    // the exact 30-50s-per-cycle blocking the V5.9.1019 SL-sweep fix had already cured by
    // moving off-loop. Operator log: 193s frozen at PERSIST_DISPATCHED вҶ’ forced rescue,
    // discarding the whole cycle. Cyclic now runs on the IO scope with single-flight +
    // timeout watchdog so a slow execution can never wedge the loop again.
    private val cyclicTickInFlight = AtomicBoolean(false)
    private val CYCLIC_TICK_TIMEOUT_MS = 20_000L
    private val UNIVERSAL_SL_HARD_MS: Long = 15_000L
    // V5.9.1082 вҖ” UNIVERSAL_SL_SWEEP_FORCE_RESET=52 in operator's 1081b
    // snapshot. Same root cause: 4s budget too tight for
    // runUniversalSlSafetyNetSweep iterating all positions. Bumped to 15s.

    private fun emitBotLoopTick(loopCount: Int) {
        // V5.9.659b вҖ” extracted from botLoop body to stay under JVM 64KB
        // method size. Tracks its own prev-cycle delta via class field.
        try {
            val now = System.currentTimeMillis()
            val prevCycleMs = now - lastBotLoopTickMs
            lastBotLoopTickMs = now
            // V5.9.762 вҖ” also touch the progress timestamp for the heartbeat.
            markProgress("BOT_LOOP_TICK")

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.1311 вҖ” DOZE DORMANCY DETECTOR + SELF-HEAL.
            // OPERATOR: "it stalled all night." Forensic: last trade 05:12,
            // snapshot 12:33 вҖ” 7h21m of ZERO trades, only 126 loop ticks across
            // 26839s (~3.6min/tick vs the 5.4s the loop actually takes), and only
            // 13 LOOP_HEARTBEAT_ALARM fires (should be ~450 at 60s). Classic deep
            // Doze: the process was SUSPENDED вҖ” coroutine delay() froze, alarms
            // were throttled to ~34min spacing. The wakelock + dual-alarm machinery
            // is correctly built but Android Doze overrides ALL of it unless the
            // app is battery-optimisation WHITELISTED. The bot looked ACTIVE
            // (coroutine object alive, suspended in delay()) so nothing rescued it.
            //
            // A normal cycle is <12s. If prevCycleMs is large, the device was
            // suspended between ticks вҖ” i.e. we just woke from Doze. On wake:
            //   1. Re-arm the heartbeat alarm IMMEDIATELY (don't wait for the
            //      next scheduled fire that Doze just throttled).
            //   2. Re-check battery-opt whitelist and re-prompt if NOT granted вҖ”
            //      this is the ONLY real cure for overnight dormancy.
            //   3. Emit a loud forensic marker so the dormancy is visible in the
            //      snapshot instead of looking like a slow loop.
            if (prevCycleMs > 90_000L && loopCount > 1) {
                try {
                    ForensicLogger.lifecycle(
                        "DOZE_DORMANCY_RECOVERED",
                        "gapSec=${prevCycleMs / 1000} loop=$loopCount вҖ” device was suspended (deep Doze); waking + re-arming heartbeat",
                    )
                } catch (_: Throwable) {}
                try { addLog("вҸ° Woke from ${prevCycleMs / 60000}min Doze suspension вҖ” resuming. Whitelist battery for 24/7.") } catch (_: Throwable) {}
                // Re-arm the heartbeat right now so the next gap is bounded.
                try { scheduleLoopHeartbeatAlarm() } catch (_: Throwable) {}
                // The real fix: ensure the OS exemption is in place. Re-prompt if
                // the device keeps Doze-suspending us (whitelisted check is cheap;
                // checkAndPromptBatteryOptimisation self-limits the dialog to once
                // per process via battery_opt_prompted_session).
                try {
                    val pmChk = getSystemService(Context.POWER_SERVICE) as? PowerManager
                    val whitelisted = pmChk?.isIgnoringBatteryOptimizations(packageName) ?: true
                    if (!whitelisted) {
                        try { ForensicLogger.lifecycle("DOZE_DORMANCY_NOT_WHITELISTED", "gapSec=${prevCycleMs/1000} reprompting=true") } catch (_: Throwable) {}
                        // Clear the once-per-session latch so the dialog can re-fire
                        // after a genuine overnight dormancy event (not just on boot).
                        try {
                            getSharedPreferences(RUNTIME_PREFS, Context.MODE_PRIVATE)
                                .edit().putBoolean("battery_opt_prompted_session", false).apply()
                        } catch (_: Throwable) {}
                        try { checkAndPromptBatteryOptimisation() } catch (_: Throwable) {}
                    }
                } catch (_: Throwable) {}
            }
            // V5.0.4175 вҖ” CYCLE OVERRUN ALARM (Fix D, partner to scan-batch cut).
            // Field 4175 log: cycle 17вҖ“48s (avg 7288ms, max 48693ms) with 22
            // EXIT_COORDINATOR_STALE_RESETs in 1394s because exits couldn't grab
            // their lock between bloated cycles. We don't hard-cancel the loop
            // body (too risky in this 23K-line method вҖ” could interrupt a buy
            // or sell mid-flight), but we DO surface every overrun + bump the
            // PipelineHealthCollector counter so the snapshot exposes the
            // pattern. Threshold 20s is well below the Doze detector's 90s
            // gate and above normal worst-case (~10s) with the V5.0.4175 scan
            // cuts. Sub-Doze gap (20sвҖ“90s) is the new diagnostic band.
            if (prevCycleMs in 20_000L..90_000L && loopCount > 1) {
                try {
                    ForensicLogger.lifecycle(
                        "BOT_LOOP_CYCLE_OVERRUN",
                        "cycleMs=$prevCycleMs loop=$loopCount threshold=20000 вҖ” cycle slow but not Doze; check scanner timeouts / Birdeye 5xx / supervisor worker timeouts",
                    )
                    com.lifecyclebot.engine.PipelineHealthCollector.labelInc("BOT_LOOP_CYCLE_OVERRUN")
                    val bucket = when {
                        prevCycleMs >= 60_000L -> "60s+"
                        prevCycleMs >= 40_000L -> "40s+"
                        prevCycleMs >= 30_000L -> "30s+"
                        else -> "20s+"
                    }
                    com.lifecyclebot.engine.PipelineHealthCollector.labelInc("BOT_LOOP_CYCLE_OVERRUN_$bucket")
                } catch (_: Throwable) {}
            }
            // V5.9.1310 вҖ” surface BOTH watchlist counters so the operator can see
            // they measure different things (was read as a "counters disagree" bug):
            //   localTokens = status.tokens   (BotService's in-memory token map; superset,
            //                                   includes recently-seen not-yet-pruned)
            //   regTokens   = GlobalTradeRegistry.size()  (the canonical pruned watchlist вҖ”
            //                                   THIS is the authority the loop actually polls)
            // The per-cycle WATCHLIST_CAP total= is the capped slice processed this tick.
            val watchSize = try { status.tokens.size } catch (_: Throwable) { -1 }
            val regSize = try { GlobalTradeRegistry.size() } catch (_: Throwable) { -1 }
            ForensicLogger.phase(
                ForensicLogger.PHASE.SCAN_CB,
                "_loop",
                "рҹ§¬[BOT_LOOP_TICK] n=$loopCount watch=$regSize localTokens=$watchSize prevCycleMs=$prevCycleMs",
            )

            // V5.9.864 вҖ” every 10 loop ticks, run AutoEndpointMigrator
            // health-driven migration. ApiHealthMonitor needs >=20 samples
            // and <10% success rate to trigger a swap, so this is rare and
            // safe to call frequently. Fallback rules are curated below
            // вҖ” if a host has zero fallback, this is a no-op.
            if (loopCount % 10 == 0) {
                try {
                    val fallbackMap = mapOf(
                        "frontend-api.pump.fun" to "frontend-api-v3.pump.fun",
                        // Future: register Helius / Birdeye / etc. fallbacks here
                    )
                    com.lifecyclebot.engine.AutoEndpointMigrator.maybeAutoMigrate(fallbackMap)
                } catch (_: Throwable) { /* observability never breaks loop */ }
            }
        } catch (_: Throwable) { /* never block the loop on a logging failure */ }
    }

    /** V5.9.762 вҖ” phase progress beacon.
     *  Every time the loop crosses a meaningful boundary it calls this with
     *  a phase tag. The heartbeat handler reads (now - lastProgressAtMs)
     *  and currentPhase to decide:
     *    - progress < 180s & phase in activeSet вҶ’ HEARTBEAT_OK
     *    - progress >= 180s & phase in activeSet вҶ’ HEARTBEAT_RESCUE_SUPPRESSED_ACTIVE_PHASE
     *    - progress >= 180s & phase NOT in activeSet вҶ’ HEARTBEAT_SLOW_NO_RESCUE (still no cancel)
     *    - active job dead вҶ’ RESCUE_RELAUNCHED_SERVICE_SCOPE with CAS
     *  Cheap volatile writes; safe to call from every cycle phase. */
    private fun markProgress(phase: String) {
        lastProgressAtMs = System.currentTimeMillis()
        currentPhase = phase
    }

    /** V5.9.762 вҖ” service-scope rescue with CAS guard.
     *  Called from the heartbeat handler ONLY when the active loop Job
     *  is genuinely dead (null / cancelled / completed). Uses the
     *  service-owned scope (NOT GlobalScope) and synchronizes the
     *  loopJob replacement via loopJobLock so two heartbeat fires or a
     *  startBot() race can never produce two parallel botLoops.
     *
     *  If the CAS observes loopJob has already been replaced by another
     *  path (e.g., user pressed Start) we abort with
     *  RESCUE_DENIED_EXISTING_JOB. Successful relaunch emits
     *  RESCUE_RELAUNCHED_SERVICE_SCOPE.  No GlobalScope, no ACTION_START
     *  intent вҖ” per EMERGENT V5.9.762 spec.
     */
    private fun performServiceScopeRescue(observedDeadJob: Job?, phase: String, progressGapMs: Long) {
        val rescueNow = System.currentTimeMillis()
        if (observedDeadJob?.isActive == true && rescueNow - lastRescueMs < LOOP_RESCUE_MIN_INTERVAL_MS && progressGapMs < LOOP_RESCUE_FORCE_STALE_MS) {
            try {
                ForensicLogger.lifecycle(
                    "RESCUE_DEBOUNCED_ACTIVE_JOB",
                    "phase=$phase progressGapSec=${progressGapMs / 1000} sinceLastRescueSec=${(rescueNow - lastRescueMs) / 1000}"
                )
            } catch (_: Throwable) {}
            return
        }
        synchronized(loopJobLock) {
            // CAS: ensure the job we observed is the same one still on the
            // class field. If something else has already replaced it (user
            // Start, a concurrent rescue) вҖ” abort.
            if (loopJob !== observedDeadJob) {
                ForensicLogger.lifecycle(
                    "RESCUE_DENIED_EXISTING_JOB",
                    "observedSame=false currentActive=${loopJob?.isActive == true}"
                )
                return
            }
            // Best-effort cancel the corpse. Cooperative вҖ” won't block the
            // bot loop on a wedged RPC; we're replacing the reference
            // either way.
            try {
                observedDeadJob?.cancel(
                    kotlinx.coroutines.CancellationException("V5.9.762 service-scope rescue")
                )
            } catch (_: Throwable) {}

            // Reset the heartbeat watermarks BEFORE launching so even if
            // the new loop takes a few seconds to enter botLoop body, the
            // next 60s alarm sees a fresh budget.
            val nowMs = System.currentTimeMillis()
            lastRescueMs = nowMs
            lastBotLoopTickMs = nowMs
            lastProgressAtMs = nowMs
            currentPhase = "RESCUE_LAUNCHING"

            val newJob = scope.launch(botLoopDispatcher) {
                try { botLoop() } catch (t: Throwable) {
                    ErrorLogger.error("BotService", "rescued botLoop threw: ${t.message}", t)
                    ForensicLogger.lifecycle(
                        "BOTLOOP_RESCUE_THREW",
                        "ex=${t::class.simpleName} msg=${t.message?.take(80)}"
                    )
                }
            }
            loopJob = newJob
            ForensicLogger.lifecycle(
                "RESCUE_RELAUNCHED_SERVICE_SCOPE",
                "newJobActive=${newJob.isActive} progressGapSec=${progressGapMs / 1000} phase=$phase usedGlobalScope=false"
            )
        }
    }

    // V5.9.962 вҖ” extracted from botLoop to keep that method under the JVM
    // 64KB bytecode cap. V5.9.960 inline run{} added ~3KB of bytecode and
    // V5.9.961 added another ~1.5KB. Together they tripped Back-end (JVM)
    // Internal error: Couldn't transform method node. Moving the selection
    // into its own method costs ONE JVM method dispatch per cycle (~50ns)
    // and frees ~5KB inside botLoop. Same selection logic вҖ” fresh + unseen
    // + cold rotation with stale eviction.
    // V5.9.1319 (Item 7) вҖ” SYMBOL-FAMILY DEDUPE + BURST SUPPRESSION.
    // The watchlist showed repeated same-symbol bursts (Leland/Lee, HITLER/CHUD/WORK/RK...).
    // Each distinct mint of the same meme name burns a full processTokenCycle. This collapses
    // a family to ONE representative mint per cycle and suppresses families that spawn >=5
    // distinct mints in 60s for 60s. It runs on the PER-CYCLE slice only вҖ” it NEVER prunes the
    // protected 500-token intake pool (that pool still holds every mint; we just stop spending
    // expensive supervisor work on near-duplicate names each tick).
    private val symbolFamilyMintsSeen = java.util.concurrent.ConcurrentHashMap<String, MutableSet<String>>()
    private val symbolFamilyWindowStart = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private val symbolFamilySuppressedUntil = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private fun normalizeSymbolFamily(symbol: String): String {
        // Lowercase, strip non-letters (digits/punct/emoji), collapse вҖ” "LEE2"/"lee_"/"LEEрҹҡҖ" вҶ’ "lee".
        val base = symbol.lowercase().filter { it in 'a'..'z' }
        return if (base.length >= 2) base else symbol.lowercase().trim()
    }
    private fun dedupeWatchlistByFamily(mints: List<String>): List<String> {
        if (mints.isEmpty()) return mints
        val now = System.currentTimeMillis()
        val symbolByMint: Map<String, String> = try {
            com.lifecyclebot.engine.GlobalTradeRegistry.getWatchlistEntries().associate { it.mint to it.symbol }
        } catch (_: Throwable) { emptyMap() }
        val out = ArrayList<String>(mints.size)
        val familyTakenThisCycle = HashSet<String>()
        var collapsed = 0
        var burstSuppressed = 0
        for (mint in mints) {
            val sym = symbolByMint[mint] ?: ""
            if (sym.isBlank()) { out.add(mint); continue }  // unknown symbol вҶ’ never suppress
            val fam = normalizeSymbolFamily(sym)
            // window bookkeeping for >=5-in-60s burst
            val wStart = symbolFamilyWindowStart[fam] ?: 0L
            if (now - wStart >= 60_000L) {
                symbolFamilyWindowStart[fam] = now
                symbolFamilyMintsSeen[fam] = java.util.concurrent.ConcurrentHashMap.newKeySet()
            }
            symbolFamilyMintsSeen.getOrPut(fam) { java.util.concurrent.ConcurrentHashMap.newKeySet() }.add(mint)
            val distinct = symbolFamilyMintsSeen[fam]?.size ?: 1
            if (distinct >= 5) symbolFamilySuppressedUntil[fam] = now + 60_000L
            // suppression: drop families currently under burst-suppression (unless already taken)
            val suppressedUntil = symbolFamilySuppressedUntil[fam] ?: 0L
            if (now < suppressedUntil && fam !in familyTakenThisCycle) {
                // allow exactly ONE representative through even while suppressed (so the family
                // is never fully starved), drop the rest of the burst.
                if (familyTakenThisCycle.add(fam)) out.add(mint) else burstSuppressed++
                continue
            }
            // normal per-cycle dedupe: one mint per family per cycle
            if (familyTakenThisCycle.add(fam)) out.add(mint) else collapsed++
        }
        if (collapsed + burstSuppressed > 0) {
            try { ForensicLogger.lifecycle("WATCHLIST_FAMILY_DEDUPE", "in=${mints.size} out=${out.size} collapsed=$collapsed burstSuppressed=$burstSuppressed") } catch (_: Throwable) {}
        }
        return out
    }

    private fun selectOrderedMintsForCycle(
        forcedOpenMints: List<String>,
        otherMints: List<String>,
        orderedMintsRaw: List<String>,
    ): List<String> {
        val nowMs = System.currentTimeMillis()
        val FRESH_WINDOW_MS = 120_000L
        // V5.9.1190 вҖ” supervisor feed must match supervisor capacity.
        // Runtime 5.0.3157 proved V5.9.1188 was too soft: selection still
        // picked 200 while fireSupervisorWorkers could admit only 140, causing
        // SUPERVISOR_INFLIGHT_CAP every cycle (spawned=140 skipped=60). This
        // does NOT prune the protected 500-token intake pool; it only limits
        // the per-cycle slice handed to the supervisor so we stop manufacturing
        // 60 guaranteed skips per tick.
        try { supervisorPruneExpiredLeases("select_cycle") } catch (_: Throwable) {}
        val currentSupervisorLoad = try { supervisorLeases.size } catch (_: Throwable) { 0 }
        val effectiveSupervisorCap = try { supervisorEffectiveCap() } catch (_: Throwable) { SUPERVISOR_MAX_LIVE_WORKERS }
        // V5.0.3723 вҖ” HOT-POOL SOURCE FIX. The old selector always passed the
        // 24-pressure floor as maxInFlight, even while runtime was healthy and the
        // real worker pool was 48. That made scanner intake look alive while the
        // hot meme universe was under-sampled. Expand ONLY when clean: no timeout
        // debt in the current window, no active supervisor load, and effective cap
        // is healthy. Pressure windows still use the old 24 floor and planner caps.
        val supervisorTimeoutsForPlanning = if ((nowMs - supervisorTimeoutWindowStartMs) < 600_000L) supervisorTimeoutWindowCount else 0
        // V5.0.3819 вҖ” align selector health with the planner's real pressure band.
        // Report 5.0.3818 had timeouts10m=7, load=0, but selectorHealthy=false,
        // cap=24 and forcedOpen=21 consumed the whole supervisor slice. Real timeout
        // pressure still starts in SupervisorAdmissionPlanner at >=30 timeouts/10m.
        val lowTimeoutNoise = supervisorTimeoutsForPlanning < 30
        val selectorHealthy = lowTimeoutNoise && currentSupervisorLoad < (effectiveSupervisorCap / 2).coerceAtLeast(1) && effectiveSupervisorCap >= SUPERVISOR_BASE_MAX_WORKERS
        val selectorMaxInFlight = if (selectorHealthy) SUPERVISOR_HEALTHY_MEME_MAX_INFLIGHT else SUPERVISOR_MAX_INFLIGHT
        val basePerCycleCap = selectorMaxInFlight
        // V5.9.1548 вҖ” use one planner for the per-cycle selection cap. The live
        // worker cap was already adaptive at acquire time, but the selector still
        // handed 96 mints into a 24/16-worker pressure window, creating 0/96 churn.
        // Healthy runtime returns the full cap, so throughput is unchanged unless
        // the timeout/cap telemetry proves the scheduler is overloaded.
        val admissionPlan = com.lifecyclebot.engine.SupervisorAdmissionPlanner.plan(
            maxInFlight = selectorMaxInFlight,
            liveCap = effectiveSupervisorCap,
            currentLoad = currentSupervisorLoad,
            timeoutCount10m = supervisorTimeoutsForPlanning,
            forcedOpenCount = forcedOpenMints.size,
        )
        val PER_CYCLE_CAP = admissionPlan.perCycleCap
        if (PER_CYCLE_CAP != basePerCycleCap || admissionPlan.pressureBand != "healthy") {
            try {
                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                    "SUPERVISOR_ADMISSION_PLANNED",
                    "${admissionPlan.reason} legacy=$basePerCycleCap"
                )
            } catch (_: Throwable) {}
        }
        val STALE_PROCESS_COUNT_THRESHOLD = 96
        // V5.9.1114 вҖ” live-readiness refill. V5.9.1034's 250 cap + 12-pass /
        // 5-minute eviction overcorrected the old 1000-token firehose and now
        // starves the scanner (<50 active tokens). Restore the protected 500-token
        // intake pool while keeping round-robin per-cycle work bounded.
        val STALE_AGE_MS = 30L * 60_000L             // 30 minutes since last touch
        // V5.0.4171 вҖ” WATCHLIST CAP TIGHTENED 500 вҶ’ 300.
        // Operator dump: 281 GB / 29 days. Watchlist of 500 evict-eligible
        // entries was burning per-cycle refresh on tokens that mostly
        // never moved (WATCHLIST_FAMILY_DEDUPE collapsed 500 вҶ’ 261 unique
        // families anyway). 300 keeps the meme-trader idle-pool target
        // (вүҘ100) intact, plus 200 headroom for fresh and high-conviction
        // intakes, while cutting cold-tail refresh waste ~40%.
        //
        // MEME-TRADER SAFETY: eviction NEVER touches:
        //   - forcedOpenMints (any open position)
        //   - isHighConvictionUnseen (high-score candidates)
        //   - fresh-60s window (newly-arrived tokens)
        // Cap only evicts the oldest stale cold-tail entries. Verified
        // at the eviction site below (filterNot lines 11159вҖ“11160).
        val MAX_ACTIVE_WATCHLIST = 300

        val entriesByMint: Map<String, com.lifecyclebot.engine.GlobalTradeRegistry.WatchlistEntry> = try {
            com.lifecyclebot.engine.GlobalTradeRegistry.getWatchlistEntries()
                .associateBy { it.mint }
        } catch (_: Throwable) { emptyMap() }

        fun isFreshSolanaSource(entry: com.lifecyclebot.engine.GlobalTradeRegistry.WatchlistEntry?): Boolean {
            val tags = buildString {
                append(entry?.addedBy ?: ""); append('|'); append(entry?.source ?: ""); append('|')
                append(entry?.laneAffinity?.joinToString("|") ?: ""); append('|')
                append(entry?.toolAffinity?.joinToString("|") ?: "")
            }.uppercase()
            return tags.contains("PUMP") || tags.contains("MEME") || tags.contains("SHITCOIN") || tags.contains("MOONSHOT") || tags.contains("EXPRESS") ||
                tags.contains("RAYDIUM") || tags.contains("NEW_POOL") || tags.contains("DEX") || tags.contains("BOOSTED") || tags.contains("TRENDING") ||
                tags.contains("DATA_ORCHESTRATOR") || tags.contains("SCANNER_DIRECT") || tags.contains("BIRDEYE") || tags.contains("METEORA") ||
                tags.contains("ORCA") || tags.contains("JUPITER") || tags.contains("HELIUS") || tags.contains("GRADUATE") || tags.contains("MIGRATED")
        }
        fun isHighConvictionUnseen(mint: String, entry: com.lifecyclebot.engine.GlobalTradeRegistry.WatchlistEntry?): Boolean {
            val ts = try { status.tokens[mint] } catch (_: Throwable) { null }
            val liq = ts?.lastLiquidityUsd ?: 0.0
            val score = try { ts?.entryScore ?: 0.0 } catch (_: Throwable) { 0.0 }
            val processCount = entry?.processCount ?: 0
            val multiAffinity = ((entry?.laneAffinity?.size ?: 0) + (entry?.toolAffinity?.size ?: 0)) >= 2
            return processCount == 0 && (liq >= 10_000.0 || score >= 70.0 || multiAffinity)
        }

        // V5.9.1572 вҖ” SOURCE FIX: forced-open rows are mandatory EXIT surface,
        // but they must not be an unbounded SUPERVISOR prefix. Snapshot 5.0.3627
        // froze with forcedOpen=28, active=24/24, spawned=0 skipped=28; every loop
        // reselected the same open mints first, so fresh candidates never reached
        // workers. ExitCoordinator/open-position tick already protect hard floor and
        // sells; supervisor is only expensive re-evaluation. Under timeout pressure,
        // round-robin a bounded subset of forcedOpen through supervisor and leave the
        // rest to exit-specific loops this cycle. Healthy runtime still includes all.
        val forcedOpenForSupervisor: List<String> = try {
            val pressure = admissionPlan.pressureBand
            val forced = forcedOpenMints.distinct()
            val forcedBudget = when {
                // V5.0.3819 вҖ” forced-open paper rows are mandatory EXIT surface, not
                // mandatory supervisor prefix. When selector capacity is degraded/cooling
                // (report: cap=24 forcedOpen=21 picked=3), bound forced rows to half the
                // work slice and let ExitCoordinator/open-position tick own exits. This
                // preserves fresh discovery without dropping exit safety.
                pressure == "healthy" && !selectorHealthy -> maxOf(6, PER_CYCLE_CAP / 2)
                pressure == "healthy" -> forced.size
                pressure == "live_cap_near_full" -> maxOf(6, effectiveSupervisorCap / 2)
                pressure == "live_cap_saturated" -> maxOf(4, effectiveSupervisorCap / 3)
                pressure == "moderate_timeout_pressure" -> maxOf(6, effectiveSupervisorCap / 2)
                pressure == "heavy_timeout_pressure" -> maxOf(5, effectiveSupervisorCap / 3)
                else -> maxOf(4, effectiveSupervisorCap / 4) // severe timeout pressure
            }.coerceAtMost(forced.size)
            if (forcedBudget >= forced.size) forced else {
                val start = ((nowMs / 5_000L) % forced.size).toInt()
                (0 until forcedBudget).map { forced[(start + it) % forced.size] }
            }
        } catch (_: Throwable) { forcedOpenMints.distinct() }

        val mustInclude = forcedOpenForSupervisor.toMutableList()
        val budget = (PER_CYCLE_CAP - mustInclude.size).coerceAtLeast(0)
        if (budget == 0 || otherMints.isEmpty()) {
            try { emitWatchlistCapTrace(PER_CYCLE_CAP, orderedMintsRaw.size, forcedOpenMints.size) } catch (_: Throwable) {}
            if (forcedOpenForSupervisor.size < forcedOpenMints.size) {
                try { com.lifecyclebot.engine.ForensicLogger.lifecycle("FORCED_OPEN_SUPERVISOR_ROUND_ROBIN", "pressure=${admissionPlan.pressureBand} picked=${forcedOpenForSupervisor.size}/${forcedOpenMints.size} cap=$PER_CYCLE_CAP effectiveCap=$effectiveSupervisorCap budget=$budget") } catch (_: Throwable) {}
            }
            return mustInclude.distinct()
        }

        // V5.9.1497 вҖ” PRE-LANE PURGE (spec 5.0.3502 В§2): drop banned + quarantined
        // mints from the PER-CYCLE work set before lane evaluation so the bot stops
        // repeatedly reprocessing dead/dangerous targets. This does NOT shrink the
        // protected 500-token intake pool вҖ” the mints remain in GlobalTradeRegistry
        // and re-enter naturally if they clear ban/quarantine; we only skip them
        // this cycle. Cheap O(n) set lookups, no network.
        val preLaneFiltered = otherMints.filter { mint ->
            val banned = try { com.lifecyclebot.engine.BannedTokens.isBanned(mint) } catch (_: Throwable) { false }
            val quarantined = try { com.lifecyclebot.engine.QuarantineStore.isQuarantined(mint) } catch (_: Throwable) { false }
            val flatTokenBlacklisted = try {
                val ts = status.tokens[mint]
                ts?.position?.isOpen != true && com.lifecyclebot.engine.TokenBlacklist.isBlocked(mint)
            } catch (_: Throwable) { false }
            !(banned || quarantined || flatTokenBlacklisted)
        }
        val purgedCount = otherMints.size - preLaneFiltered.size
        if (purgedCount > 0) {
            try {
                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                    "WATCHLIST_PRELANE_PURGE",
                    "purged=$purgedCount kept=${preLaneFiltered.size} reason=banned_quarantined_or_flat_token_blacklist (pool intact, this-cycle skip only)",
                )
            } catch (_: Throwable) {}
        }
        val fresh = mutableListOf<String>()
        val unseen = mutableListOf<String>()
        val cold = mutableListOf<Pair<String, Long>>()
        val probationDemoted = mutableListOf<String>()
        preLaneFiltered.forEach { mint ->
            val entry = entriesByMint[mint]
            // V5.9.1226 вҖ” hot-watchlist probation demotion. This does not
            // shrink the protected scanner/intake universe; it moves repeatedly
            // processed dead weight to the slower probation lane so hot supervisor
            // bandwidth is spent on moving/executable candidates.
            if (entry != null && mint !in forcedOpenMints) {
                val tsForProbation = try { status.tokens[mint] } catch (_: Throwable) { null }
                val liqNow = tsForProbation?.lastLiquidityUsd ?: 0.0
                val volH1 = try { tsForProbation?.history?.lastOrNull()?.volumeH1 ?: 0.0 } catch (_: Throwable) { 0.0 }
                val priceNow = tsForProbation?.lastPrice ?: 0.0
                val priceAgeMs = tsForProbation?.lastPriceUpdate?.takeIf { it > 0L }?.let { nowMs - it } ?: Long.MAX_VALUE
                // V5.9.1564 вҖ” Only treat "stale" / "no-volume" as a demote signal when we
                // actually have a working price feed wired (priceAgeMs != MAX_VALUE).
                // Previously every non-pump intake landed with Long.MAX_VALUE priceAge,
                // hit pc>=5, and got demoted as "STALE_NO_MOVE" вҖ” that's why operator
                // dump 5.0.3671 showed watchlist=0 / probation=152 with healthy-liq
                // tokens (BrГ¶tchen $55K liq) being demoted. Also: never demote a token
                // with healthy liquidity (>= $10K) вҖ” that's a feed problem, not a token
                // problem; let it stay so any source can backfill the price later.
                val hasPriceFeed = (tsForProbation?.lastPriceUpdate ?: 0L) > 0L
                val healthyLiq = liqNow >= 10_000.0
                val ageMs = nowMs - entry.addedAt
                val firstDeepEvalProtected = entry.processCount == 0 && isHighConvictionUnseen(mint, entry)
                val solanaFresh = isFreshSolanaSource(entry) && ageMs < 10L * 60_000L
                val demoteProcessFloor = if (solanaFresh) 6 else 3
                val demoteAgeFloorMs = if (solanaFresh) 5L * 60_000L else 120_000L
                val coldEnough = entry.processCount >= demoteProcessFloor && ageMs > demoteAgeFloorMs
                val lowExecutableLiq = liqNow > 0.0 && liqNow < 2_000.0
                val noVolume = hasPriceFeed && volH1 <= 0.0 && entry.processCount >= maxOf(5, demoteProcessFloor) && ageMs > maxOf(180_000L, demoteAgeFloorMs)
                val staleNoMove = hasPriceFeed && priceAgeMs > maxOf(180_000L, demoteAgeFloorMs) && entry.processCount >= maxOf(5, demoteProcessFloor)
                if (!firstDeepEvalProtected && !healthyLiq && coldEnough && (lowExecutableLiq || noVolume || staleNoMove)) {
                    val why = when {
                        lowExecutableLiq -> "LOW_EXEC_LIQ_${liqNow.toInt()}"
                        noVolume -> "NO_H1_VOLUME"
                        else -> "STALE_NO_MOVE"
                    }
                    val demoted = try {
                        com.lifecyclebot.engine.GlobalTradeRegistry.demoteWatchlistToProbation(
                            mint = mint,
                            reason = why,
                            liquidityUsd = liqNow,
                            confidence = 0,
                            price = priceNow,
                            isEstimatedLiquidity = liqNow <= 0.0,
                        )
                    } catch (_: Throwable) { false }
                    if (demoted) {
                        probationDemoted.add(mint)
                        try { com.lifecyclebot.engine.ForensicLogger.lifecycle("WATCHLIST_PROBATION_DEMOTE", "mint=${mint.take(10)} symbol=${entry.symbol} reason=$why pc=${entry.processCount}/$demoteProcessFloor ageMs=$ageMs/$demoteAgeFloorMs liq=${liqNow.toInt()} vol1h=${volH1.toInt()} priceAgeMs=$priceAgeMs solanaFresh=$solanaFresh") } catch (_: Throwable) {}
                        return@forEach
                    }
                }
            }
            when {
                entry == null -> unseen.add(mint)
                (nowMs - entry.addedAt) < FRESH_WINDOW_MS -> fresh.add(mint)
                entry.processCount == 0 -> unseen.add(mint)
                else -> cold.add(mint to entry.lastProcessedAt)
            }
        }

        // V5.9.961 stale eviction
        val staleEvict = mutableListOf<String>()
        val coldFiltered = cold.filter { (mint, _) ->
            val entry = entriesByMint[mint] ?: return@filter true
            if (entry.processCount >= STALE_PROCESS_COUNT_THRESHOLD) {
                staleEvict.add(mint)
                false
            } else true
        }
        if (staleEvict.isNotEmpty()) {
            staleEvict.forEach { mint ->
                try {
                    com.lifecyclebot.engine.GlobalTradeRegistry.removeFromWatchlist(mint, "STALE_PROCESS_COUNT")
                } catch (_: Throwable) {}
            }
            try {
                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                    "WATCHLIST_STALE_EVICT",
                    "evicted=${staleEvict.size} threshold=$STALE_PROCESS_COUNT_THRESHOLD"
                )
            } catch (_: Throwable) {}
        }

        // V5.9.1114 вҖ” TIME-BASED stale eviction relaxed to 30 minutes.
        // Five minutes was shorter than enough scanner/source cycles to prove edge.
        // Applies only to tokens that have been processed at least once and
        // aren't open positions (forcedOpenMints set is the protection list).
        // This complements the existing process-count-based eviction; together
        // they drain the dormant pool without the operator-flagged loop burn.
        val timeStaleEvict = mutableListOf<String>()
        val coldAfterTime = coldFiltered.filter { (mint, lastTouch) ->
            if (mint in forcedOpenMints) return@filter true
            val entry = entriesByMint[mint] ?: return@filter true
            if (entry.processCount >= 1 && (nowMs - lastTouch) > STALE_AGE_MS) {
                timeStaleEvict.add(mint)
                false
            } else true
        }
        if (timeStaleEvict.isNotEmpty()) {
            timeStaleEvict.forEach { mint ->
                try {
                    com.lifecyclebot.engine.GlobalTradeRegistry.removeFromWatchlist(mint, "STALE_5MIN")
                } catch (_: Throwable) {}
            }
            try {
                com.lifecyclebot.engine.ForensicLogger.lifecycle(
                    "WATCHLIST_STALE_EVICT_TIME",
                    "evicted=${timeStaleEvict.size} ageMs=$STALE_AGE_MS"
                )
            } catch (_: Throwable) {}
        }

        // V5.9.1114 вҖ” HARD CAP enforcement at 500 active watchlist entries.
        // V5.9.1034b вҖ” Bugfix: original cap-evict pulled only from `cold`.
        // Operator snapshot (build 2995, watchlist 1693): cap-evict fired
        // (evicted=31 cap=250 sizeBefore=1694) but watchlist still rose
        // because the overflow lives in `unseen=1649`, not `cold=0`. Pump.fun
        // spam keeps adding processCount=0 mints faster than the supervisor
        // can graduate them to cold, so cold stays near-empty while unseen
        // pile up.
        //
        // Fix: include `unseen` in the eviction candidate pool. Sort by
        // entry.addedAt ASC (oldest unseen go first) so newly-arrived
        // tokens still get a chance to be picked up. Open positions
        // (forcedOpenMints) and the fresh-60s window remain exempt.
        val currentActiveSize = try {
            com.lifecyclebot.engine.GlobalTradeRegistry.getWatchlistEntries().size
        } catch (_: Throwable) { coldAfterTime.size + fresh.size + unseen.size + forcedOpenMints.size }
        var coldAfterCap = coldAfterTime
        if (currentActiveSize > MAX_ACTIVE_WATCHLIST) {
            val excess = currentActiveSize - MAX_ACTIVE_WATCHLIST
            // Build a unified eviction pool with (mint, sortKey) tuples.
            // For cold entries we use lastProcessedAt; for unseen we use
            // addedAt (since they've never been processed). Mints without
            // entries fall back to 0L = evict first.
            val unseenForEviction: List<Pair<String, Long>> = unseen.map { mint ->
                val entry = entriesByMint[mint]
                mint to (entry?.addedAt ?: 0L)
            }
            val capEvict = (coldAfterTime + unseenForEviction)
                .filterNot { it.first in forcedOpenMints }
                .filterNot { (mint, _) -> isHighConvictionUnseen(mint, entriesByMint[mint]) }
                .sortedBy { it.second }
                .take(excess)
            capEvict.forEach { (mint, _) ->
                try {
                    com.lifecyclebot.engine.GlobalTradeRegistry.removeFromWatchlist(mint, "CAP_${MAX_ACTIVE_WATCHLIST}")
                } catch (_: Throwable) {}
            }
            if (capEvict.isNotEmpty()) {
                try {
                    com.lifecyclebot.engine.ForensicLogger.lifecycle(
                        "WATCHLIST_CAP_EVICT",
                        "evicted=${capEvict.size} cap=$MAX_ACTIVE_WATCHLIST sizeBefore=$currentActiveSize"
                    )
                } catch (_: Throwable) {}
                val evictedSet = capEvict.map { it.first }.toSet()
                // Drop evicted from BOTH pools so picker doesn't try to
                // process tokens we just removed.
                coldAfterCap = coldAfterTime.filterNot { it.first in evictedSet }
                unseen.removeAll(evictedSet)
            }
        }

        val coldMutable = coldAfterCap.toMutableList()
        coldMutable.sortBy { it.second }

        // V5.9.1548b вҖ” source-balanced scanner inflow. Fresh/unseen/cold ordering
        // remains intact, but each tier is interleaved by source family so a single
        // PumpPortal/pump.fun flood cannot crowd DexScreener, CoinGecko,
        // CMC-backed, Raydium/Meteora, Birdeye, or generic scanner candidates out
        // of the per-cycle worker slice. This does not raise caps or relax gates.
        val balancedFresh = sourceBalancedWatchlistOrder(fresh, entriesByMint)
        val balancedUnseen = sourceBalancedWatchlistOrder(unseen, entriesByMint)
        val balancedCold = sourceBalancedWatchlistOrder(coldMutable.map { it.first }, entriesByMint)

        val picked = mutableListOf<String>()
        picked.addAll(balancedFresh.take(budget))
        if (picked.size < budget) picked.addAll(balancedUnseen.take(budget - picked.size))
        if (picked.size < budget) picked.addAll(balancedCold.take(budget - picked.size))

        try {
            emitWatchlistCapTrace(PER_CYCLE_CAP, orderedMintsRaw.size, forcedOpenMints.size)
            com.lifecyclebot.engine.ForensicLogger.lifecycle(
                "WATCHLIST_RR",
                "cap=$PER_CYCLE_CAP selectorHealthy=$selectorHealthy timeouts10m=$supervisorTimeoutsForPlanning load=$currentSupervisorLoad picked=${picked.size} fresh=${fresh.size} unseen=${unseen.size} cold=${cold.size} probationDemoted=${probationDemoted.size} forcedOpen=${forcedOpenMints.size} forcedSupervisor=${forcedOpenForSupervisor.size} total=${orderedMintsRaw.size} sourceBalanced=true"
            )
        } catch (_: Throwable) {}

        return (mustInclude + picked).distinct()
    }


    private fun sourceBalancedWatchlistOrder(
        mints: List<String>,
        entriesByMint: Map<String, com.lifecyclebot.engine.GlobalTradeRegistry.WatchlistEntry>,
    ): List<String> {
        if (mints.size <= 2) return mints
        val defaultPriority = listOf(
            "DEX", "COINGECKO", "CMC", "RAYDIUM", "BIRDEYE", "SCANNER", "PUMP", "OTHER"
        )
        val priority = try { ScannerDiversityBandit.orderedFamilies(defaultPriority) } catch (_: Throwable) { defaultPriority }
        try {
            if (priority != defaultPriority) {
                ForensicLogger.lifecycle("SCANNER_DIVERSITY_BANDIT_ORDER_4273", "priority=${priority.joinToString(">")} default=${defaultPriority.joinToString(">")} action=soft_order_only_no_source_block")
                PipelineHealthCollector.labelInc("SCANNER_DIVERSITY_BANDIT_ORDER_4273")
            }
        } catch (_: Throwable) {}
        val buckets = linkedMapOf<String, MutableList<String>>()
        priority.forEach { buckets[it] = mutableListOf() }
        fun bucketFor(mint: String): String {
            val e = entriesByMint[mint]
            val tags = buildString {
                append(e?.addedBy ?: "")
                append('|')
                append(e?.source ?: "")
                append('|')
                append(e?.laneAffinity?.joinToString("|") ?: "")
                append('|')
                append(e?.toolAffinity?.joinToString("|") ?: "")
            }.uppercase()
            return when {
                tags.contains("DEXSCREENER") || tags.contains("DEX_SCREENER") || tags.contains("DEX_TREND") || tags.contains("DEX_GAIN") || tags.contains("DEX_BOOST") -> "DEX"
                tags.contains("COINGECKO") || tags.contains("COIN_GECKO") || tags.contains("GECKO") -> "COINGECKO"
                tags.contains("COINMARKETCAP") || tags.contains("COIN_MARKET_CAP") || tags.contains("CMC") -> "CMC"
                tags.contains("RAYDIUM") || tags.contains("METEORA") || tags.contains("ORCA") || tags.contains("JUPITER") || tags.contains("NEW_POOL") -> "RAYDIUM"
                tags.contains("BIRDEYE") -> "BIRDEYE"
                tags.contains("SCANNER") || tags.contains("TRENDING") || tags.contains("BOOSTED") || tags.contains("GAINERS") -> "SCANNER"
                tags.contains("PUMP_PORTAL") || tags.contains("PUMPPORTAL") || tags.contains("PUMP.FUN") || tags.contains("PUMP_FUN") -> "PUMP"
                else -> "OTHER"
            }
        }
        mints.forEach { mint -> buckets.getOrPut(bucketFor(mint)) { mutableListOf() }.add(mint) }
        val out = mutableListOf<String>()
        var emitted: Boolean
        do {
            emitted = false
            for (key in priority) {
                val q = buckets[key] ?: continue
                if (q.isNotEmpty()) {
                    out.add(q.removeAt(0))
                    emitted = true
                }
            }
            // Include any future/unrecognized bucket keys without starving them.
            for ((key, q) in buckets) {
                if (key in priority) continue
                if (q.isNotEmpty()) {
                    out.add(q.removeAt(0))
                    emitted = true
                }
            }
        } while (emitted)
        return out
    }

