            )
        } catch (_: Throwable) {}
    }


    private fun emitLoopTopSnapshot(loopCount: Int) {
        try {
            val sc = marketScanner
            val scAlive = try { sc?.isAlive() ?: false } catch (_: Throwable) { false }
            val mqDepth = try { TokenMergeQueue.size() } catch (_: Throwable) { -1 }
            val wlSize = try { GlobalTradeRegistry.size() } catch (_: Throwable) { -1 }
            val openCount = status.tokens.values.count { it.position.isOpen }
            val cfg = ConfigStore.load(applicationContext)
            ForensicLogger.snapshot(
                "LOOP_TOP",
                "loop=$loopCount running=${status.running} loopJob=${loopJob?.isActive} scAlive=$scAlive mq=$mqDepth wl=$wlSize open=$openCount paper=${cfg.paperMode} v3=${cfg.v3EngineEnabled} memeT=${cfg.memeTraderEnabled} mode=${cfg.tradingMode}"
            )
        } catch (_: Throwable) {}
    }

    /**
     * V5.9.660 вҖ” extracted from botLoop to keep it under the JVM 64KB
     * method size limit. Same cadence (every 6 loops, ~30s), same
     * behavior. Operator-facing visibility line for silent scanner
     * failures + auto-recovery if marketScanner went null while running.
     */
    private fun runScannerHeartbeat() {
        try {
            val sc = marketScanner
            if (sc == null) {
                ErrorLogger.info("BotService", "рҹ©ә SCANNER_HEARTBEAT: marketScanner=NULL running=${status.running} watch=${GlobalTradeRegistry.size()}")
                // V5.9.1518 вҖ” PATCH ITEM 3: report scanner INACTIVE to the runtime
                // controller so scannerActive truthfully reflects a dead scanner
                // (markScannerActive was previously never called вҶ’ scannerActive
                // was permanently false even when the scanner was alive).
                try { com.lifecyclebot.engine.BotRuntimeController.markScannerActive(
                    com.lifecyclebot.engine.BotRuntimeController.currentGeneration(), false) } catch (_: Throwable) {}
                if (status.running && watchdogCooldownExpired()) {
                    addLog("рҹ©№ Heartbeat: scanner NULL вҖ” auto-recovering")
                    try { com.lifecyclebot.engine.ForensicLogger.lifecycle("SCANNER_WATCHDOG_RESTART", "reason=NULL running=${status.running}") } catch (_: Throwable) {}
                    bootMemeScanner(reason = "HEARTBEAT_NULL")
                    lastWatchdogRestartMs = System.currentTimeMillis()
                }
            } else {
                val snap = try { sc.getThroughputTelemetrySnapshot() } catch (_: Throwable) { null }
                // V5.9.1518 вҖ” PATCH ITEM 3: scanner alive-state truth + watchdog.
                // The scanner is "active" when it is alive AND has ticked within
                // the staleness window. Report that to BotRuntimeController so the
                // runtime snapshot stops showing scannerActive=false on a healthy
                // scanner. If the scanner is RUNNING but stale > WATCHDOG window,
                // force a boot (auto-restart unless the user explicitly disabled).
                val scannerAlive = try { sc.isAlive() } catch (_: Throwable) { false }
                val ageSec = snap?.ageSec ?: 9999L
                // V5.0.3720 вҖ” scanner-active truth. The 5.0.3717 report showed
                // SCANNER_INACTIVE while recent SCANNER_SOURCE_DONE events were
                // firing every second. A scan loop that is attempting sources but
                // finding raw=0 is LOW_OUTPUT, not dead/inactive. Mark active from
                // scannerAlive + recent source/cycle pulse; use stale age only for
                // restart decisions below.
                val healthy = scannerAlive && ageSec in 0..90L
                try { com.lifecyclebot.engine.BotRuntimeController.markScannerActive(
                    com.lifecyclebot.engine.BotRuntimeController.currentGeneration(), healthy) } catch (_: Throwable) {}
                if (!healthy && status.running && !RuntimeRepairState.isScannerUserDisabled() && watchdogCooldownExpired()) {
                    addLog("рҹ©№ Heartbeat: scanner inactive/stale (alive=$scannerAlive ageSec=$ageSec) вҖ” auto-restarting")
                    try { com.lifecyclebot.engine.ForensicLogger.lifecycle("SCANNER_WATCHDOG_RESTART", "reason=STALE alive=$scannerAlive ageSec=$ageSec") } catch (_: Throwable) {}
                    bootMemeScanner(reason = "HEARTBEAT_STALE")
                    lastWatchdogRestartMs = System.currentTimeMillis()
                }
                if (snap != null) {
                    ErrorLogger.info(
                        "BotService",
                        "рҹ©ә SCANNER_HEARTBEAT: alive=${snap.alive} ageSec=${snap.ageSec} src=${snap.src} ok=${snap.ok} err=${snap.err} raw=${snap.raw} enq=${snap.enq} cd=${snap.cd} liqRej=${snap.liqRej} watch=${GlobalTradeRegistry.size()}"
                    )
                } else {
                    ErrorLogger.info("BotService", "рҹ©ә SCANNER_HEARTBEAT: snapshot=null watch=${GlobalTradeRegistry.size()}")
                }
            }
        } catch (e: Throwable) {
            ErrorLogger.debug("BotService", "Scanner heartbeat tick error: ${e.message}")
        }
    }

    /** V5.9.1518 вҖ” PATCH ITEM 3: scanner is considered stale (watchdog restart)
     *  when its last successful tick is older than this. Heartbeat fires every
     *  6 loops; with a ~3-4s loop that is ~20-24s, matching the spec's 20s. */
    private val SCANNER_WATCHDOG_STALE_SEC: Long = 20L

    /** V5.0.3681 вҖ” P2 PATCH: scanner watchdog RESTART COOLDOWN. Heartbeat fires
     *  every 6 loops (~20-30s). Without a cooldown, a flaky scanner can be
     *  bootMemeScanner()'d back-to-back on every heartbeat вҶ’ SDK churn + thread
     *  thrash + LIQUIDITY scan storm. Enforce a 30s minimum between forced
     *  watchdog restarts. Manual `requestScannerRestart` bypasses (operator
     *  intent is explicit). */
    private val SCANNER_WATCHDOG_RESTART_COOLDOWN_MS: Long = 30_000L
    @Volatile private var lastWatchdogRestartMs: Long = 0L
    private fun watchdogCooldownExpired(): Boolean {
        val sinceLast = System.currentTimeMillis() - lastWatchdogRestartMs
        return sinceLast >= SCANNER_WATCHDOG_RESTART_COOLDOWN_MS
    }

    /**
     * V5.9.660 вҖ” extracted from botLoop to keep it under the JVM 64KB
     * method size limit. Same cadence (every 10 loops), same behavior.
     * Periodic SOL price refresh + SymbolicContext refresh + per-lane
     * health watchdogs, all gated by isMarketsLaneEnabled() so the
     * Markets engine is not silently restarted when the master toggle
     * is OFF.
     */
    private suspend fun runMarketsEngineWatchdog(
        loopCount: Int,
        cfg: com.lifecyclebot.data.BotConfig,
    ) {
        // V5.9.9: Periodic SOL price refresh вҖ” critical for USD display
        // Without this, paper mode with no wallet = stale $0 price
        try {
            val freshPrice = com.lifecyclebot.engine.WalletManager
                .getInstance(applicationContext).fetchSolPrice()
            if (freshPrice > 50.0) {
                com.lifecyclebot.engine.WalletManager.lastKnownSolPrice = freshPrice
            }
        } catch (_: Exception) {}

        // V5.9.10: Refresh global SymbolicContext вҖ” feeds all 50+ AI modules
        // + FinalDecisionGate with live 16-channel symbolic intelligence
        try { com.lifecyclebot.engine.SymbolicContext.refresh() } catch (_: Exception) {}

        try {
            // V5.9.469 вҖ” gate ALL Markets watchdogs by the master toggle.
            val marketsLaneOn = isMarketsLaneEnabled(cfg)
            if (!marketsLaneOn && com.lifecyclebot.perps.PerpsExecutionEngine.isRunning()) {
                ErrorLogger.info("BotService", "рҹ“ҙ Markets toggled OFF mid-session вҖ” stopping PerpsExecutionEngine + sub-traders")
                addLog("рҹ“ҙ Markets toggled OFF вҖ” stopping engine + sub-traders")
                try { com.lifecyclebot.perps.PerpsExecutionEngine.stop() } catch (_: Exception) {}
                try { com.lifecyclebot.perps.TokenizedStockTrader.stop() } catch (_: Exception) {}
                try { com.lifecyclebot.perps.CommoditiesTrader.stop() } catch (_: Exception) {}
                try { com.lifecyclebot.perps.MetalsTrader.stop() } catch (_: Exception) {}
                try { com.lifecyclebot.perps.ForexTrader.stop() } catch (_: Exception) {}
            }

            // PerpsExecutionEngine watchdog вҖ” only when Markets toggle is ON
            if (marketsLaneOn) {
                val healthy = com.lifecyclebot.perps.PerpsExecutionEngine.isHealthy()
                if (!healthy) {
                    ErrorLogger.warn("BotService", "вҡ пёҸ PerpsExecutionEngine NOT HEALTHY (loop #$loopCount) вҖ” restartingвҖҰ")
                    addLog("вҡЎ Markets engine watchdog: engine unhealthy, restartingвҖҰ")
                    com.lifecyclebot.perps.PerpsExecutionEngine.stop()
                    delay(500)
                    com.lifecyclebot.perps.PerpsExecutionEngine.start(applicationContext)
                    addLog("вҡЎ Markets engine restarted by watchdog")
                }
            }
            // CryptoAltTrader watchdog вҖ” only if enabled (V5.9.345: exempt from kill-switch)
            if (cfg.cryptoAltsEnabled && !com.lifecyclebot.perps.CryptoAltTrader.isHealthy()) {
                ErrorLogger.warn("BotService", "вҡ пёҸ CryptoAltTrader unhealthy (loop #$loopCount) вҖ” restartingвҖҰ")
                addLog("рҹӘҷ CryptoAlt watchdog: unhealthy, restartingвҖҰ")
                com.lifecyclebot.perps.CryptoAltTrader.start()
            }
            // TokenizedStockTrader watchdog вҖ” only if Markets+stocks enabled
            if (marketsLaneOn && cfg.stocksEnabled && !com.lifecyclebot.perps.TokenizedStockTrader.isHealthy()) {
                ErrorLogger.warn("BotService", "вҡ пёҸ TokenizedStockTrader unhealthy (loop #$loopCount) вҖ” restartingвҖҰ")
                addLog("рҹ“Ҳ Stock trader watchdog: unhealthy, restartingвҖҰ")
                com.lifecyclebot.perps.TokenizedStockTrader.start()
            }
            // CommoditiesTrader watchdog вҖ” only if Markets+commodities enabled
            if (marketsLaneOn && cfg.commoditiesEnabled && !com.lifecyclebot.perps.CommoditiesTrader.isHealthy()) {
                ErrorLogger.warn("BotService", "вҡ пёҸ CommoditiesTrader unhealthy (loop #$loopCount) вҖ” restartingвҖҰ")
                com.lifecyclebot.perps.CommoditiesTrader.start()
            }
            // MetalsTrader watchdog вҖ” only if Markets+metals enabled
            if (marketsLaneOn && cfg.metalsEnabled && !com.lifecyclebot.perps.MetalsTrader.isHealthy()) {
                ErrorLogger.warn("BotService", "вҡ пёҸ MetalsTrader unhealthy (loop #$loopCount) вҖ” restartingвҖҰ")
                com.lifecyclebot.perps.MetalsTrader.start()
            }
            // ForexTrader watchdog вҖ” only if Markets+forex enabled
            if (marketsLaneOn && cfg.forexEnabled && !com.lifecyclebot.perps.ForexTrader.isHealthy()) {
                ErrorLogger.warn("BotService", "вҡ пёҸ ForexTrader unhealthy (loop #$loopCount) вҖ” restartingвҖҰ")
                com.lifecyclebot.perps.ForexTrader.start()
            }
        } catch (e: Exception) {
            ErrorLogger.error("BotService", "Markets watchdog error: ${e.message}", e)
        }
    }

    /**
     * V5.9.1027 вҖ” ORPHAN BOT-LOOP EXIT CHECK.
     *
     * Operator V5.9.1026 snapshot showed loop=17 firing SEVEN
     * SUPERVISOR_CHUNK_TIMEOUTs and TWO POST_SUPERVISOR events. Cycle ms
     * strictly alternated short/long ([12282, 675, 12545, 80, 12800,
     * 180, ...]) вҖ” proof that TWO botLoop coroutines were running
     * concurrently on the dedicated single-thread dispatcher, alternating
     * at every suspension.
     *
     * Root cause: V5.9.1023 rescue calls `observedDeadJob?.cancel(...)`
     * which is cooperative. A corpse wedged in non-cancellable JNI
     * socket-read keeps running. When it unwedges, it resumes its
     * botLoop() body alongside the freshly launched replacement вҖ” two
     * concurrent supervisors, two PRE_SUPERVISOR/POST_SUPERVISOR pairs
     * per "loopCount".
     *
     * This helper is called at the top of every botLoop iteration.
     * Compares the caller's own Job reference (captured at entry) to
     * the canonical `loopJob` field. If they differ, the caller is the
     * orphan; emit a forensic event and return true so the caller's
     * `while` loop exits.
     *
     * NOTE: extracted out of botLoop() to keep that method's bytecode
     * under the JVM 64KB cap (same reason V5.9.1021 split out
     * runSupervisorPhase).
     */
    /**
     * V5.9.1028 вҖ” PAPER-MODE SETTLE-IN CHECK FOR STOPS.
     *
     * Returns true if the position is currently within its lane's settle-in
     * window вҖ” used by both STRICT_SL and RAPID_CATASTROPHE_STOP paths to
     * suppress kneejerk exits caused by paper-mode slippage simulation
     * (paperBuy +12% / paperSell -18% on <$5k pools = -26.8% birth tax).
     *
     * NOTE: extracted from botLoop() to keep that method's bytecode under
     * the JVM 64KB cap (same reason V5.9.1021 split out runSupervisorPhase
     * and V5.9.1027b split out checkBotLoopOrphan).
     */
    private fun isInPaperSettleIn(ts: TokenState, paperMode: Boolean): Boolean {
        if (!paperMode) return false
        val entryMs = ts.position.entryTime
        if (entryMs <= 0L) return false
        val ageMs = System.currentTimeMillis() - entryMs
        val lane = ts.position.tradingMode.ifBlank { "V3" }
        val settleInMinutes = try {
            com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidMinHoldMinutes(lane)
        } catch (_: Throwable) { 0.5 }
        val settleInMs = maxOf((settleInMinutes * 60_000.0).toLong(), 30_000L)
        return ageMs < settleInMs
    }

    /**
     * V5.9.1029 вҖ” AI-FLUID CATASTROPHE THRESHOLD HELPER.
     *
     * Returns the catastrophe stop threshold (negative pct) for the active
     * mode, routed through FluidLearningAI.getFluidStopLoss so bootstrap
     * protects with -15% and matures to the lane's true catastrophe band.
     * Falls open to the hardcoded raw value on any failure so the safety
     * net is never lost.
     *
     * NOTE: extracted from botLoop() to keep that method's bytecode under
     * the JVM 64KB cap (same reason V5.9.1021/1027b/1028b split out helpers).
     */
    private fun getCatastropheThreshold(paperMode: Boolean): Double {
        val raw = if (paperMode) -25.0 else -14.0
        return try {
            com.lifecyclebot.v3.scoring.FluidLearningAI.getFluidStopLoss(raw)
        } catch (_: Throwable) { raw }
    }

    /**
     * V5.9.1031 вҖ” RAPID MONITOR EXIT EVALUATOR.
     *
     * Returns true if a sell was issued and caller should `continue` to the
     * next token.
     *
     * Ladder (in order):
     *   1. Paper-mode settle-in window вҶ’ skip (return false)
     *   2. Catastrophe threshold (AI-fluid) вҶ’ RAPID_CATASTROPHE_STOP
     *   3. Drawdown-from-peak (peak вүҘ20% AND give-back вүҘ25pts) вҶ’
     *      RAPID_DRAWDOWN_FROM_PEAK_STOP
     *   4. Hard floor (pnl вүӨ -HARD_FLOOR_STOP_PCT) вҶ’ RAPID_HARD_FLOOR_STOP
     *
     * Extracted from botLoop() to keep that method's bytecode under the
     * JVM 64KB cap on Debug compile. The when-block held 4 suspending
     * executor.requestSell call sites; moving them into a helper
     * collapses 4 coroutine state-machine slots into 1.
     */
    private suspend fun evaluateRapidMonitorExit(
        ts: TokenState,
        pnlPct: Double,
        cfg: com.lifecyclebot.data.BotConfig,
        wallet: com.lifecyclebot.network.SolanaWallet?,
        effectiveBalance: Double,
    ): Boolean {
        // V5.9.1031b вҖ” local mirror of the legacy HARD_FLOOR_STOP_PCT
        // constant declared inside rapidStopLossMonitor(). The original
        // val was function-scoped (val HARD_FLOOR_STOP_PCT = 15.0) so it
        // isn't visible from this helper. Behaviour-preserving copy of
        // the same 15.0 hard floor.
        val HARD_FLOOR_STOP_PCT_CONST = 15.0
        val catastropheThreshold = getCatastropheThreshold(cfg.paperMode)
        val peakGainPct = ts.position.peakGainPct
        val drawdownFromPeak = peakGainPct - pnlPct
        val giveBackTrigger = peakGainPct >= 20.0 && drawdownFromPeak >= 25.0

        // V5.9.1521 вҖ” UNCONDITIONAL SAFETY MUST PRECEDE SETTLE-IN.
        // ROOT CAUSE of "live/paper trading really poorly": the paper settle-in
        // window returned FALSE on the very first line, bypassing BOTH the
        // catastrophe band AND the -15% hard floor for the entire settle window
        // (getFluidMinHoldMinutes can be several minutes). A token that rugged in
        // its first minutes (operator screenshot: MORT -97.5%, Puffins -50.9%,
        // both labelled "SL -20%") got ZERO stop protection and booked a near-total
        // loss вҖ” exactly the WR/P&L killer. Doctrine rule: the -15% hard floor is
        // UNCONDITIONAL for all open positions. So evaluate catastrophe + hard floor
        // FIRST; settle-in may only suppress the softer adaptive/give-back paths.
        if (pnlPct <= catastropheThreshold) {
            ErrorLogger.warn("BotService", "рҹҡЁ RAPID STOP (CATASTROPHE): ${ts.symbol} at ${pnlPct.toInt()}%")
            addLog("рҹӣ‘ RAPID CATASTROPHE STOP: ${ts.symbol} ${pnlPct.toInt()}% | EXIT")
            executor.requestSell(ts, "RAPID_CATASTROPHE_STOP", wallet, effectiveBalance)
            TradeStateMachine.startCatastropheCooldown(ts.mint, pnlPct)
            return true
        }
        if (pnlPct <= -HARD_FLOOR_STOP_PCT_CONST) {
            ErrorLogger.warn("BotService", "рҹҡЁ RAPID STOP (HARD_FLOOR/unconditional): ${ts.symbol} at ${pnlPct.toInt()}% (peak=${peakGainPct.toInt()}%)")
            addLog("рҹӣ‘ RAPID HARD_FLOOR STOP: ${ts.symbol} ${pnlPct.toInt()}% | EXIT")
            executor.requestSell(ts, "RAPID_HARD_FLOOR_STOP", wallet, effectiveBalance)
            TradeStateMachine.startCooldown(ts.mint)
            return true
        }

        // V5.0.6080 вҖ” RUNNER LOCK MUST PRECEDE SETTLE-IN.
        // Runtime 6069 showed winners like $TANIMAL peak +272% вҶ’ now +16% while
        // PAPER warmup/stale protection was still holding. Settle-in exists to
        // ignore entry noise; it must never suppress banking a runner that already
        // printed a large peak and breached its give-back/peak-lock boundary.
        if (giveBackTrigger) {
            ErrorLogger.warn(
                "BotService",
                "рҹҡЁ DRAWDOWN_FROM_PEAK_SETTLE_BYPASS_6080: ${ts.symbol} pnl=${pnlPct.toInt()}% peak=${peakGainPct.toInt()}% drawdown=${drawdownFromPeak.toInt()}pts"
            )
            addLog("рҹ“ү DRAWDOWN STOP: ${ts.symbol} ${pnlPct.toInt()}% (peak +${peakGainPct.toInt()}% вҶ’ -${drawdownFromPeak.toInt()}pts give-back)")
            try { PipelineHealthCollector.labelInc("DRAWDOWN_FROM_PEAK_SETTLE_BYPASS_6080") } catch (_: Throwable) {}
            try { ForensicLogger.lifecycle("DRAWDOWN_FROM_PEAK_SETTLE_BYPASS_6080", "mint=${ts.mint.take(10)} symbol=${ts.symbol} pnl=${pnlPct.toInt()} peak=${peakGainPct.toInt()} drawdown=${drawdownFromPeak.toInt()} action=runner_lock_before_settle") } catch (_: Throwable) {}
            executor.requestSell(ts, "RAPID_DRAWDOWN_FROM_PEAK_SETTLE_BYPASS_6080", wallet, effectiveBalance)
            TradeStateMachine.startCooldown(ts.mint)
            return true
        }

        // Settle-in only gates the SOFTER adaptive paths below. It cannot bypass
        // hard safety above or runner/give-back banking above.
        if (isInPaperSettleIn(ts, cfg.paperMode)) {
            return false
        }
        return false
    }

    private fun checkBotLoopOrphan(myJob: kotlinx.coroutines.Job?, loopCount: Int): Boolean {
        val canonical = loopJob
        if (myJob == null || canonical == null || canonical === myJob) return false
        try {
            ForensicLogger.lifecycle(
                "BOTLOOP_ORPHAN_EXIT",
                "myJobвү loopJob loop=$loopCount вҖ” corpse coroutine yielding to replacement"
            )
        } catch (_: Throwable) {}
        return true
    }

    /**
     * V5.9.1036 вҖ” Extracted from botLoop() to reduce JVM bytecode pressure
     * (botLoop was ~10800 bytes pre-extraction; the 64KB cap previously
     * blocked V5.9.1029 until catastropheThreshold was lifted out). This
     * watchdog is invoked roughly every pendingVerifyWatchdogIntervalMs to
     * promote/wipe stuck pendingVerify positions via on-chain RE-CHECK.
     * Logic identical to pre-extraction; uses Service-level state directly.
     */
    private fun runPendingVerifyWatchdog(wallet: SolanaWallet?) {
        try {
            val now = System.currentTimeMillis()
            var clearedCount = 0
            var phantomCount = 0
            val isLive = !com.lifecyclebot.data.ConfigStore.load(applicationContext).paperMode
            val w = wallet
            val onChainBalances: Map<String, Pair<Double, Int>>? = if (isLive && w != null) {
                try { w.getTokenAccountsWithDecimalsBounded() } catch (e: Exception) {
                    ErrorLogger.warn("BotService", "рҹ”§ [VERIFY_WATCHDOG] RPC failed; will retry next tick: ${e.message}")
                    null
                }
            } else null
            val mapLooksEmpty = isLive && onChainBalances != null && onChainBalances.isEmpty()
            if (mapLooksEmpty) {
                ErrorLogger.warn(
                    "BotService",
                    "рҹ”§ [VERIFY_WATCHDOG] RPC returned EMPTY map вҖ” treating as inconclusive (not wiping)."
                )
            }
            status.tokens.values.forEach { ts ->
                val pos = ts.position
                if (pos.pendingVerify && pos.qtyToken > 0.0 && pos.entryTime > 0L) {
                    val ageMs = now - pos.entryTime
                    if (ageMs >= 120_000L) {
                        if (isLive) {
                            if (onChainBalances == null) {
                                return@forEach
                            }
                            val onChainQty = onChainBalances[ts.mint]?.first ?: 0.0
                            if (onChainQty > 0.0) {
                                ErrorLogger.warn("BotService",
                                    "рҹ”§ [VERIFY_WATCHDOG] ${ts.symbol} | ${ageMs / 1000}s вҖ” tokens VERIFIED on-chain (qty=$onChainQty). Promoting to open.")
                                synchronized(ts) {
                                    ts.position = pos.copy(qtyToken = onChainQty, pendingVerify = false)
                                }
                                try { com.lifecyclebot.engine.PositionPersistence.savePosition(ts) } catch (_: Exception) {}
                                clearedCount++
                            } else if (mapLooksEmpty) {
                                val perMintQty: Double = try {
                                    w?.getTokenAccountsWithDecimalsBounded()?.get(ts.mint)?.first ?: 0.0
                                } catch (_: Exception) { 0.0 }
                                if (perMintQty > 0.0) {
                                    ErrorLogger.warn("BotService",
                                        "рҹ”§ [VERIFY_WATCHDOG] ${ts.symbol} | ${ageMs / 1000}s вҖ” tokens VERIFIED via per-mint RETRY (qty=$perMintQty) after empty bulk map. Promoting.")
                                    synchronized(ts) {
                                        ts.position = pos.copy(qtyToken = perMintQty, pendingVerify = false)
                                    }
                                    try { com.lifecyclebot.engine.PositionPersistence.savePosition(ts) } catch (_: Exception) {}
                                    clearedCount++
                                } else {
                                    ErrorLogger.warn("BotService",
                                        "рҹ”§ [VERIFY_WATCHDOG] ${ts.symbol} | ${ageMs / 1000}s вҖ” empty bulk + per-mint retry inconclusive. Keeping pendingVerify; will retry next tick.")
                                }
                            } else {
                                ErrorLogger.warn("BotService",
                                    "рҹ‘» [VERIFY_WATCHDOG] ${ts.symbol} | ${ageMs / 1000}s вҖ” GHOST POSITION confirmed (non-empty wallet map, mint absent). Wiping.")
                                synchronized(ts) {
                                    ts.position = com.lifecyclebot.data.Position()
                                    ts.lastExitTs = now
                                }
                                try { com.lifecyclebot.engine.PositionPersistence.savePosition(ts) } catch (_: Exception) {}
                                phantomCount++
                            }
                        } else {
                            synchronized(ts) {
                                ts.position = pos.copy(pendingVerify = false)
                            }
                            clearedCount++
                        }
                    }
                }
            }
            if (clearedCount > 0 || phantomCount > 0) {
                ErrorLogger.warn("BotService",
                    "рҹ”§ [VERIFY_WATCHDOG] Promoted=$clearedCount, Wiped(ghosts)=$phantomCount")
                if (clearedCount > 0) addLog("рҹ”§ Watchdog: promoted $clearedCount verified position(s)")
                if (phantomCount > 0) addLog("рҹ‘» Watchdog: wiped $phantomCount ghost position(s) вҖ” no tokens on-chain")
            }
        } catch (wdEx: Exception) {
            ErrorLogger.warn("BotService", "PendingVerify watchdog error: ${wdEx.message}")
        }
    }

    /**
     * V5.9.1036 вҖ” Extracted from botLoop() to reduce JVM bytecode (was 109
     * lines of inline scope.launch lambda body). Runs the every-180-ticks
     * (~15min) telemetry refresh: TokenWinMemory force-save + pattern
     * summary, hivemind reconnect/upload, throughput floor heartbeat,
     * CollectiveLearning sync, CollectiveIntelligenceAI refresh, and V3
     * vs FDG comparison log. Fire-and-forget on the service scope so
     * botLoop sees only a function-call overhead.
     */
    private fun run180TickTelemetry(cfg: BotConfig) {
        scope.launch {
            try {
                TokenWinMemory.forceSave()
                val summary = TokenWinMemory.getPatternSummary()
                if (summary.isNotBlank()) {
                    addLog("рҹ“Ҡ Pattern refresh: $summary")
                    ErrorLogger.info("TokenWinMemory", "рҹ“Ҡ 15min refresh: $summary")
                }
                if (!com.lifecyclebot.collective.CollectiveLearning.isEnabled()) {
                    try {
                        val reconnected = com.lifecyclebot.collective.CollectiveLearning.ensureConnected()
                        if (reconnected) {
                            addLog("рҹҢҗ Hivemind reconnected")
                            ErrorLogger.info("BotService", "CollectiveLearning auto-reconnect succeeded")
                        } else {
                            addLog("рҹҢҗ Hivemind offline вҖ” running solo")
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "Hivemind reconnect attempt failed: ${e.message}")
                    }
                }
                try {
                    val throughputMsg = com.lifecyclebot.v3.scoring.MemeEdgeAI.throughputStatus()
                    ErrorLogger.info("BotService", "рҹ“Ҡ $throughputMsg")
                    if (throughputMsg.startsWith("ALERT")) {
                        addLog("рҹ“Ҡ $throughputMsg")
                    }
                } catch (_: Exception) {}
                if (com.lifecyclebot.collective.CollectiveLearning.isEnabled()) {
                    try {
                        val botPrefs = getSharedPreferences("bot_service", android.content.Context.MODE_PRIVATE)
                        val instanceId = botPrefs.getString("instance_id", null)
                            ?: java.util.UUID.randomUUID().toString().also {
                                botPrefs.edit().putString("instance_id", it).apply()
                            }
                        val localStats = TradeHistoryStore.getStats()
                        val pnl24hPct = if (localStats.trades24h > 0) {
                            (localStats.pnl24hSol / (localStats.trades24h * 0.1).coerceAtLeast(0.01)) * 100
                        } else 0.0
                        val currentConfig = com.lifecyclebot.data.ConfigStore.load(applicationContext)
                        com.lifecyclebot.collective.CollectiveLearning.uploadHeartbeat(
                            instanceId = instanceId,
                            appVersion = com.lifecyclebot.BuildConfig.VERSION_NAME,
                            paperMode = currentConfig.paperMode,
                            trades24h = localStats.trades24h,
                            pnl24hPct = pnl24hPct
                        )
                        try {
                            val regionCode = java.util.Locale.getDefault().country.ifBlank { "UNKNOWN" }
                            val deviceModel = "${android.os.Build.MANUFACTURER}/${android.os.Build.MODEL}".take(80)
                            com.lifecyclebot.engine.ApiHealthMonitor.snapshot().forEach { (host, st) ->
                                com.lifecyclebot.collective.CollectiveLearning.uploadEndpointHealth(
                                    appVersion = com.lifecyclebot.BuildConfig.VERSION_NAME,
                                    regionCode = regionCode,
                                    deviceModel = deviceModel,
                                    host = host,
                                    successRate = st.successRate(),
                                    avgLatencyMs = st.avgLatencyMs(),
                                    successes = st.successes.get(),
                                    failures4xx = st.failures4xx.get(),
                                    failures5xx = st.failures5xx.get(),
                                    networkErrors = st.networkErrors.get(),
                                    lastSuccessMs = st.lastSuccessMs.get(),
                                    lastFailureMs = st.lastFailureMs.get(),
                                    lastError = st.lastErrorMessage.get() ?: "",
                                )
                            }
                        } catch (e: Exception) {
                            ErrorLogger.debug("BotService", "Endpoint health hive upload error: ${e.message}")
                        }
                        val modeStats = ModeLearning.getAllModeStats()
                        val snapshots = modeStats.mapValues { (_, stats) ->
                            com.lifecyclebot.collective.CollectiveLearning.ModeStatSnapshot(
                                totalTrades = stats.totalTrades,
                                wins = stats.wins,
                                losses = stats.losses,
                                avgPnlPct = stats.avgPnlPct,
                                avgHoldMins = stats.avgHoldMins,
                                marketCondition = "NEUTRAL",
                                liquidityBucket = "MID"
                            )
                        }
                        com.lifecyclebot.collective.CollectiveLearning.syncModeLearning(snapshots)
                        val collectiveInsights = com.lifecyclebot.collective.CollectiveLearning.getInsightsSummary()
                        addLog("рҹҢҗ $collectiveInsights")
                        if (cfg.v3EngineEnabled) {
                            val v3Comparison = com.lifecyclebot.v3.V3EngineManager.getComparisonSummary()
                            addLog("вҡЎ $v3Comparison")
                            ErrorLogger.info("V3Comparison", v3Comparison)
                        }
                        try {
                            com.lifecyclebot.v3.scoring.CollectiveIntelligenceAI.refresh()
                        } catch (e: Exception) {
                            ErrorLogger.debug("BotService", "CollectiveAI refresh error: ${e.message}")
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "Collective sync error: ${e.message}")
                    }
                }
            } catch (e: Exception) {
                ErrorLogger.debug("BotService", "TokenWinMemory refresh error: ${e.message}")
            }
        }
    }


    private suspend fun botLoop() {
        if (botLoopStartedAtMs == 0L) botLoopStartedAtMs = System.currentTimeMillis()
        // V5.9.919 вҖ” FIRST ACTION on botLoop entry: clear RESCUE_LAUNCHING
        // phase by stamping progress. Operator V5.9.916 freeze showed phase
        // stuck at RESCUE_LAUNCHING for 4+ minutes because the 78 lines of
        // setup before the first markProgress("ENTER") could be delayed by
        // IO-pool saturation вҖ” heartbeat alarm then saw no progress AND
        // unknown phase вҶ’ SLOW_NO_RESCUE forever.
        markProgress("BOTLOOP_BOOT")
        ErrorLogger.info("BotService", "botLoop() started")
        ForensicLogger.lifecycle("BOTLOOP_STARTED", "scope.active=${scope.coroutineContext[kotlinx.coroutines.Job]?.isActive}")

        // V5.9.1027 вҖ” orphan exit. See checkBotLoopOrphan() doc.
        val myJob: kotlinx.coroutines.Job? = try {
            currentCoroutineContext()[kotlinx.coroutines.Job]
        } catch (_: Throwable) { null }
        
        startSingletonRuntimeMonitors()

        // V5.9.251: PERIODIC WALLET RECONCILIATION
        // Re-run StartupReconciler every 90s during a live session so
        // positions that drift mid-session get caught fast:
        //   - pendingVerify positions whose 30s window expired but tokens landed
        //   - External sells (manual Phantom/Jupiter sells) вҖ” stamps recentlyClosedMs
        //     to prevent immediate re-buy (was 5 min, too slow for meme tokens)
        //   - Orphaned tokens from silent buy confirmations
        var lastReconcileAt = System.currentTimeMillis()
        val reconcileIntervalMs = 90 * 1000L  // V5.9.251: 90s (was 5 min вҖ” too slow)

        // V5.9.290: PendingVerify Watchdog вҖ” sweeps every 60s for any position stuck in
        // pendingVerify for > 120s and force-clears it so exit management can fire.
        // This is an additional proactive layer on top of the per-tick check in the
        // exit management block. Belt AND suspenders.
        // lastPendingVerifyWatchdogAt now a companion @Volatile (V5.9.714) вҖ” removed local var
        val pendingVerifyWatchdogIntervalMs = 60_000L

        // V5.9.362 вҖ” REGIME PULSE
        // CrossMarketRegimeAI is only ever fed by CryptoAltTrader / TokenizedStockTrader.
        // When Perps is OFFLINE the regime stays on its boot default forever, so the
        // meme trader runs full-throttle even in obvious chop / risk-off conditions.
        // This 60s pulse pushes SOL/BTC/ETH from PerpsMarketDataFetcher (Pyth/Jupiter/
        // CoinGecko, already cached) into the regime engine and re-evaluates so the
        // entire universe sees a live regime no matter which traders are active.
        var lastRegimePulseAt = 0L
        val regimePulseIntervalMs = 60_000L

        // V5.9.634c вҖ” freeze-detector state moved to class fields and the
        // detector body extracted into runFreezeDetectorTick() because the
        // inline version pushed botLoop past the JVM 64KB per-method limit.
        if (freezeLastExecCount < 0L) {
            freezeLastExecCount = com.lifecyclebot.engine.CanonicalLearningCounters.executedTradesTotal.get()
            freezeLastExecChangeMs = System.currentTimeMillis()
        }

        var loopCount = 0
        // V5.9.660 вҖ” lastTickStartMs removed; emitBotLoopTick tracks its
        // own prev-cycle delta via class field lastBotLoopTickMs.
        while (status.running) {
          // V5.9.1027 вҖ” orphan exit (see checkBotLoopOrphan doc).
          if (checkBotLoopOrphan(myJob, loopCount)) return
          try {
            loopCount++
            try { RuntimeDoctor.requestTick(uiRunning = status.running) } catch (_: Throwable) {}

            // V5.9.660 вҖ” BOT_LOOP_TICK heartbeat. emitBotLoopTick now
            // tracks prev-cycle delta via its own class field (saves a
            // few bytes of botLoop bytecode).
            emitBotLoopTick(loopCount)

            // V5.9.676 вҖ” CYCLE_PHASE forensic markers. Operator's V5.9.675
            // dump showed cycle #2 wedged at 91s and then died silently
            // for the next 14 minutes. botLoop is at the JVM 64KB method
            // cap so we can't wrap the body in withTimeoutOrNull (the
            // exception flow expansion would blow the method size). The
            // surgical alternative is a short forensic breadcrumb at the
            // start of each cycle and at each major phase boundary, so
            // when the heartbeat next detects a stall we can see exactly
            // which phase the cycle died inside. Phase markers are added
            // at: ENTER, REGIME_PULSE_DONE, SENTIENCE_DONE, LAB_DONE,
            // FEE_DRAIN_DONE, PRE_SUPERVISOR, POST_SUPERVISOR, EXIT_SWEEP_DONE.
            // Total breadcrumb cost ~8 forensic events per cycle ~120 bytes.
            val _cycleStartMs = System.currentTimeMillis()
            try {
              markProgress("ENTER")
              ForensicLogger.lifecycle(
                "CYCLE_PHASE",
                "loop=$loopCount phase=ENTER"
              )
            } catch (_: Throwable) {}

            // V5.9.652 вҖ” extracted to emitLoopTopSnapshot() to keep botLoop
            // under the JVM 64KB method size limit. Same content, different
            // method, no behavior change.
            if (loopCount % 6 == 0) {
                emitLoopTopSnapshot(loopCount)
            }

            // V5.9.454 вҖ” WALLET RE-SYNC FIX.
            // BotService's local `wallet` var previously only updated
            // from inside launchWalletConnect's callback. When
            // Executor.doSell successfully reconnected the WalletManager
            // singleton via attemptReconnect(), the new wallet was never
            // propagated back to this local var вҖ” so the NEXT tick still
            // passed `wallet=null` to the Executor and the sell hit
            // "CRITICAL: Live mode sell attempted but WALLET IS NULL!"
            // again, forever.
            //
            // Fix: in live mode, re-sync from the singleton every tick.
            // Cheap read (returns a cached ref), no network call.
            if (!ConfigStore.load(applicationContext).paperMode) {
                val fresh = walletManager.getWallet()
                if (fresh != null && fresh !== wallet) {
                    wallet = fresh
                    ErrorLogger.info("BotService", "рҹ”„ wallet re-synced from singleton вҖ” sells unblocked")
                }
            }

            // V5.9.362 вҖ” Regime pulse (every 60s, side-effect-only, never blocks)
            if (System.currentTimeMillis() - lastRegimePulseAt > regimePulseIntervalMs) {
                lastRegimePulseAt = System.currentTimeMillis()
                kotlinx.coroutines.GlobalScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    try { runRegimePulse() } catch (_: Throwable) {}
                }
            }

            // V5.9.401 вҖ” Sentience auto-tune + distrust nomination (rate-limited internally)
            try { runSentienceAutoTune() } catch (_: Throwable) {}

            // V5.9.402 вҖ” LLM Lab tick (creation + paper exec + cull, all internally gated).
            try { runLabUniverseTick() } catch (_: Throwable) {}

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.2: PIPELINE TRACE - Snapshot loop state at start
            // Freeze aggression for this loop cycle to prevent mid-loop mutations
            // V5.2 FIX: Use correct balance based on paper/live mode
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            val cfg = ConfigStore.load(applicationContext)

            // V5.9.226: Bug #7 вҖ” Drain failed fee retry queue at cycle start (live mode only)
            // V5.0.3920 вҖ” also flush the FeeAccumulator (batched per-destination fees).
            if (!cfg.paperMode) {
                val liveWallet = wallet
                if (liveWallet != null) {
                    try { FeeRetryQueue.drainFeeQueue(liveWallet) }
                    catch (e: Exception) { ErrorLogger.warn("BotService", "FeeRetryQueue drain error: ${e.message}") }
                    try { FeeAccumulator.tryFlush(liveWallet) }
                    catch (e: Exception) { ErrorLogger.warn("BotService", "FeeAccumulator flush error: ${e.message}") }
                }
            }

            // V5.9.290: PendingVerify Watchdog вҖ” proactively sweep for stuck pendingVerify positions.
            // Runs every 60s. Clears any position where qtyToken>0 && pendingVerify=true && age>120s.
            // This runs BEFORE the per-token loop so that stuck positions are already cleared when
            // the exit management block evaluates them, rather than relying on the per-tick check alone.
            // V5.9.315: Watchdog now does on-chain RE-CHECK before deciding (live mode only).
            //   - Tokens present on-chain вҶ’ adopt real qty + clear pendingVerify (becomes open).
            //   - Tokens NOT present (RPC succeeded with 0) вҶ’ wipe position as confirmed phantom.
            //   - RPC failed вҶ’ leave pendingVerify=true; retry next watchdog tick.
            // This eliminates GHOST POSITIONS (Models.kt isOpen no longer auto-promotes after 120s).
            if (System.currentTimeMillis() - lastPendingVerifyWatchdogAt > pendingVerifyWatchdogIntervalMs) {
                lastPendingVerifyWatchdogAt = System.currentTimeMillis()
                // V5.9.1036 вҖ” extracted to runPendingVerifyWatchdog(wallet)
                // to reduce botLoop bytecode (was 110 lines of inline body).
                runPendingVerifyWatchdog(wallet)
            }

            // V5.9.103: periodic reconcile (was live-mode-only)
            //
            // V5.9.750 вҖ” also fire in paper mode when:
            //   (a) the live wallet is still connected via WalletManager
            //       singleton (paper mode just nulls the local cfg-driven
            //       wallet field вҖ” the singleton survives the flip), AND
            //   (b) at least one pendingVerify position exists in
            //       status.tokens (i.e. a prior live session left stuck
            //       buys behind).
            //
            // Operator screenshot 23:36: Fartcoin / IO / MEMELON / Taylur
            // all show BUY_CONFIRMED (tx mined on-chain) but no
            // BUY_VERIFIED_LANDED. Then operator flipped to paper to
            // inspect вҶ’ cfg.paperMode=true вҶ’ the existing live-mode-only
            // gate locked out any further reconcile attempt вҶ’ V5.9.748
            // RECONCILE-PROMOTE never had a chance to fire вҶ’ positions
            // stayed pendingVerify forever and remained invisible in the
            // Open Positions card even though tokens were sitting in the
            // host wallet (+59% on CwhP вҖ” pure leaked alpha).
            //
            // This branch keeps the original live-mode behaviour intact
            // and ADDS a paper-mode rescue branch that runs the same
            // reconcile() (V5.9.748 promote-pending path handles it) but
            // explicitly only when there's something to rescue.
            val nowMs = System.currentTimeMillis()
            val intervalElapsed = nowMs - lastReconcileAt > reconcileIntervalMs
            val hasPendingVerify = try {
                synchronized(status.tokens) {
                    status.tokens.values.any { it.position.pendingVerify && it.position.costSol > 0 }
                }
            } catch (_: Throwable) { false }
            val singletonWallet = try { WalletManager.getWallet() } catch (_: Throwable) { null }
            val paperRescueEligible = cfg.paperMode && hasPendingVerify &&
                singletonWallet != null && singletonWallet.publicKeyB58.isNotEmpty()
            val liveTickEligible = !cfg.paperMode
            if ((liveTickEligible || paperRescueEligible) && intervalElapsed) {
                lastReconcileAt = nowMs
                // V5.9.1470d вҖ” extracted to keep botLoop under the JVM 64KB method limit
                // (CI run#3473-3475 hit "Couldn't transform method node: botLoop"). The
                // already-2000-line botLoop was at the bytecode ceiling; this frees room.
                launchPeriodicReconcile(rescueOnly = paperRescueEligible, wallet = wallet)
            }

            // V5.9.631 вҖ” Meme lane must not silently disappear while the bot is running.
            // Operator forensic log: CryptoAlt/Markets/Commodities/Metals/Forex all ran
            // for an hour, but Meme showed no scanner/search/display/trades. Root cause:
            // V5.9.708 FIX вҖ” The Meme Trader toggle must be authoritative.
            // Previous formula included `status.running` (always true) which made
            // memeTraderEnabled=false completely ineffective. Also, tradingMode=2
            // (BOTH) was in the OR chain, overriding the sub-toggle.
            //
            // Correct semantics:
            //   - tradingMode 0 (MEME_ONLY): meme runs regardless of sub-toggle
            //   - tradingMode 1 (MARKETS_ONLY): meme never runs
            //   - tradingMode 2 (BOTH): meme runs ONLY IF memeTraderEnabled=true
            //
            // Scanner intake (admitProtectedMemeIntake) is infrastructure and
            // remains always-on while the bot is running вҖ” that is separate from
            // this execution gate.
            val memeEnabled = when (cfg.tradingMode) {
                0 -> true                      // MEME_ONLY: always run meme
                1 -> false                     // MARKETS_ONLY: never run meme
                else -> cfg.memeTraderEnabled  // BOTH: respect the toggle
            }
            if (!memeEnabled) {
                // Meme trader disabled вҖ” still run markets watchdog before sleeping
                try {
                    // V5.9.469 вҖ” AND-semantics gate (was OR-semantics; tradingMode=2
                    // bypassed the toggle, restarting markets every 10 ticks even
                    // when the user had toggled the master Markets switch off).
                    val marketsEnabled = isMarketsLaneEnabled(cfg)

                    // V5.9.469 вҖ” if user just toggled Markets off mid-session,
                    // STOP the engine instead of letting it run unattended.
                    if (!marketsEnabled && com.lifecyclebot.perps.PerpsExecutionEngine.isRunning()) {
                        ErrorLogger.info("BotService", "рҹ“ҙ [meme-off] Markets toggled OFF mid-session вҖ” stopping PerpsExecutionEngine")
                        addLog("рҹ“ҙ Markets toggled OFF вҖ” stopping engine")
                        try { com.lifecyclebot.perps.PerpsExecutionEngine.stop() } catch (_: Exception) {}
                    }

                    if (marketsEnabled && loopCount % 10 == 0) {
                        val healthy = com.lifecyclebot.perps.PerpsExecutionEngine.isHealthy()
                        if (!healthy) {
                            ErrorLogger.warn("BotService", "вҡ пёҸ [meme-off] PerpsExecutionEngine unhealthy вҖ” restartingвҖҰ")
                            addLog("вҡЎ Markets engine watchdog (meme-off): restartingвҖҰ")
                            com.lifecyclebot.perps.PerpsExecutionEngine.stop()
                            delay(500)
                            com.lifecyclebot.perps.PerpsExecutionEngine.start(applicationContext)
                        }
                    }
                    // CryptoAltTrader watchdog (meme-off) вҖ” only if enabled
                    if (loopCount % 10 == 0 && cfg.cryptoAltsEnabled && !com.lifecyclebot.perps.CryptoAltTrader.isHealthy()) {
                        ErrorLogger.warn("BotService", "вҡ пёҸ [meme-off] CryptoAltTrader unhealthy вҖ” restartingвҖҰ")
                        com.lifecyclebot.perps.CryptoAltTrader.start()
                    }
                    // TokenizedStockTrader watchdog (meme-off) вҖ” only if stocks enabled
                    if (marketsEnabled && cfg.stocksEnabled && loopCount % 10 == 0 && !com.lifecyclebot.perps.TokenizedStockTrader.isHealthy()) {
                        ErrorLogger.warn("BotService", "вҡ пёҸ [meme-off] TokenizedStockTrader unhealthy вҖ” restartingвҖҰ")
                        com.lifecyclebot.perps.TokenizedStockTrader.start()
                    }
                    // CommoditiesTrader watchdog (meme-off) вҖ” only if commodities enabled
                    if (marketsEnabled && cfg.commoditiesEnabled && loopCount % 10 == 0 && !com.lifecyclebot.perps.CommoditiesTrader.isHealthy()) {
                        ErrorLogger.warn("BotService", "вҡ пёҸ [meme-off] CommoditiesTrader unhealthy вҖ” restartingвҖҰ")
                        com.lifecyclebot.perps.CommoditiesTrader.start()
                    }
                    // MetalsTrader watchdog (meme-off) вҖ” only if metals enabled
                    if (marketsEnabled && cfg.metalsEnabled && loopCount % 10 == 0 && !com.lifecyclebot.perps.MetalsTrader.isHealthy()) {
                        ErrorLogger.warn("BotService", "вҡ пёҸ [meme-off] MetalsTrader unhealthy вҖ” restartingвҖҰ")
                        com.lifecyclebot.perps.MetalsTrader.start()
                    }
                    // ForexTrader watchdog (meme-off) вҖ” only if forex enabled
                    if (marketsEnabled && cfg.forexEnabled && loopCount % 10 == 0 && !com.lifecyclebot.perps.ForexTrader.isHealthy()) {
                        ErrorLogger.warn("BotService", "вҡ пёҸ [meme-off] ForexTrader unhealthy вҖ” restartingвҖҰ")
                        com.lifecyclebot.perps.ForexTrader.start()
                    }
                } catch (e: Exception) {
                    ErrorLogger.error("BotService", "Markets watchdog (meme-off) error: ${e.message}", e)
                }
                delay(cfg.pollSeconds * 1000L)
                continue
            }
            
            // V5.2 FIX: Completely isolate paper vs live wallet for balance display
            val displayBalance = if (cfg.paperMode) {
                // In paper mode, show paper wallet balance from FluidLearning
                FluidLearning.getPaperBalance()
            } else {
                // In live mode, show real wallet balance
                walletManager.state.value.solBalance
            }
            
            val loopSnapshot = PipelineTracer.startLoop(
                loopId = loopCount,
                aggression = BehaviorAI.getAggressionLevel(),
                paperMode = cfg.paperMode,
                liveMode = !cfg.paperMode,
                walletBalance = displayBalance,
                openPositions = status.openPositionCount,
                watchlistSize = GlobalTradeRegistry.size()
            )
            val frozenAggression = loopSnapshot.aggression

            // V5.9.495z32 вҖ” sweep stale watchlist candidates per loop.
            // Snipe-mode TTL = 5min, normal = 30min. Operator z32 directive:
            // we MUST NOT purge fresh candidates aggressively, only stale.
            try {
                val snipeMode = false  // BotConfig has no snipeMode flag yet вҖ” passive sweep
                val expired = com.lifecyclebot.engine.WatchlistTtlPolicy.sweepStale(snipeMode)
                if (expired > 0) {
                    ErrorLogger.debug("BotService",
                        "вҷ»пёҸ WatchlistTtlPolicy: expired=$expired (size=${com.lifecyclebot.engine.WatchlistTtlPolicy.size()})")
                }
            } catch (_: Throwable) { /* best-effort */ }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.0: Clear FinalExecutionPermit state at start of each cycle
            // This allows tokens to be re-evaluated fresh each loop
            // V5.2.6: Set paper mode flag for bypass logic
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            FinalExecutionPermit.isPaperMode = cfg.paperMode
            FinalExecutionPermit.clearCycleState()
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.0: GlobalTradeRegistry cleanup
            // Clean expired rejections and cooldowns
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            GlobalTradeRegistry.cleanup()
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.20: EfficiencyLayer cleanup
            // Clean stale seen tokens, expired liquidity rejections, etc.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            EfficiencyLayer.cleanup()
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.0: TradeAuthorizer cleanup
            // Clean stale shadow tracking entries
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            TradeAuthorizer.cleanup()
            
            val watchlist = cfg.watchlist.toMutableList()
            if (cfg.activeToken.isNotBlank() && cfg.activeToken !in watchlist)
                watchlist.add(cfg.activeToken)
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // WALLET HEALTH CHECK - Critical for live mode sells
            // If wallet is null in live mode, sells will fail silently!
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (!cfg.paperMode && wallet == null) {
                // V5.9.73 FIX: fire-and-forget reconnect so the bot loop
                // doesn't stall for up to 90s when RPCs are slow. Previously
                // this called walletManager.connect() synchronously and
                // blocked every live-mode tick where wallet was null until
                // all fallback RPCs timed out.
                val existing = walletConnectJob
                if (existing == null || !existing.isActive) {
                    if (cfg.privateKeyB58.isNotBlank()) {
                        ErrorLogger.warn("BotService", "рҹҡЁ LIVE MODE wallet null вҖ” launching background reconnect")
                        addLog("рҹҡЁ WALLET NULL in live mode вҖ” reconnecting in backgroundвҖҰ")
                        val rpcUrl = cfg.rpcUrl.ifBlank { "https://api.mainnet-beta.solana.com" }
                        launchWalletConnect(cfg.privateKeyB58, rpcUrl, runReconciliation = false)
                    } else {
                        ErrorLogger.warn("BotService", "рҹҡЁ LIVE MODE but no private key configured")
                        addLog("рҹҡЁ Live mode: no private key configured вҖ” cannot reconnect")
                    }
                }
            }
            
            // Update FinalDecisionGate mode for veto cooldown timing
            FinalDecisionGate.setModeForVeto(cfg.paperMode)
            
            // V5.6 FIX: Sync CashGenerationAI mode so checkExit finds positions in correct map!
            // Without this, positions entered in paper mode won't be found when checking exits
            com.lifecyclebot.v3.scoring.CashGenerationAI.setTradingMode(cfg.paperMode)
            
            // V5.6.11: Sync ALL trading AI modes - this transfers learning from paper to live
            com.lifecyclebot.v3.scoring.ShitCoinTraderAI.setTradingMode(cfg.paperMode)
            com.lifecyclebot.v3.scoring.BlueChipTraderAI.setTradingMode(cfg.paperMode)
            com.lifecyclebot.v3.scoring.MoonshotTraderAI.setTradingMode(cfg.paperMode)
            com.lifecyclebot.v3.scoring.QualityTraderAI.setTradingMode(cfg.paperMode)

            // V5.9.761 вҖ” Sync the FOUR meme sub-traders that were silently
            // stuck in their init-time paper mode. init() is one-shot
            // (guarded by `initialized`), so toggling PaperвҶ”Live in the UI
            // never reached these layers вҖ” they kept placing paper trades
            // while ShitCoin/BlueChip/Moonshot/Quality moved to live, which
            // is exactly the operator regression ("meme trader running live,
            // sub-traders still paper"). These setTradingMode() helpers were
            // added in V5.9.761 and just write the volatile isPaperMode.
            com.lifecyclebot.v3.scoring.ShitCoinExpress.setTradingMode(cfg.paperMode)
            com.lifecyclebot.v3.scoring.ManipulatedTraderAI.setTradingMode(cfg.paperMode)
            com.lifecyclebot.v3.scoring.DipHunterAI.setTradingMode(cfg.paperMode)
            com.lifecyclebot.v3.scoring.SolanaArbAI.setTradingMode(cfg.paperMode)
            
            // V5.6.6: Update Treasury with actual wallet balance for proper position sizing
            val walletBalanceForTreasury = if (cfg.paperMode) {
                // Paper mode: use paper wallet balance (starts at 6 SOL, compounds)
                status.paperWalletSol
            } else {
                // Live mode: use actual SOL balance
                status.getEffectiveBalance(cfg.paperMode)
            }
            com.lifecyclebot.v3.scoring.CashGenerationAI.updateWalletBalance(walletBalanceForTreasury)
            try {
                val arbTreasurySol4335 = com.lifecyclebot.v3.scoring.CashGenerationAI.getTreasuryBalance(cfg.paperMode)
                val arbSolPrice4335 = WalletManager.lastKnownSolPrice.takeIf { it > 0.0 } ?: 150.0
                com.lifecyclebot.v3.scoring.SolanaArbAI.syncTreasuryUsd(cfg.paperMode, arbTreasurySol4335 * arbSolPrice4335)
            } catch (_: Throwable) { }
            
            // V5.0: Advance TradeAuthorizer epoch for decision tracking
            TradeAuthorizer.advanceEpoch()
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.0 CRITICAL FIX: ONLY INITIALIZE TRADING MODES ONCE
            // Previously this was called every loop, causing state resets!
            // Services are singletons - they should init once per session.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (!tradingModesInitialized) {
                initTradingModes(cfg)
                tradingModesInitialized = true
            }

            // Log watchlist status every 5 loops for better visibility
            // V4.0: Use GlobalTradeRegistry for accurate count
            if (loopCount % 5 == 1) {
                val registrySize = GlobalTradeRegistry.size()
                ErrorLogger.info("BotService", "Bot loop #$loopCount - Watchlist size: $registrySize (GlobalTradeRegistry)")
                addLog("рҹ”„ Loop #$loopCount | Watchlist: $registrySize tokens | Scanner: ${if(marketScanner != null) "ACTIVE" else "INACTIVE"}")
                if (registrySize == 0) {
                    addLog("вҡ пёҸ Watchlist empty - waiting for scanner to discover tokens...")
                } else {
                    // Log first 3 tokens being processed
                    val firstTokens = GlobalTradeRegistry.getWatchlist().take(3).joinToString(", ") { it.take(8) + "..." }
                    addLog("рҹ“Ҡ Processing: $firstTokens")
                }
                
                // Record healthy status for watchdog (every 5 loops ~ 25 seconds)
                ServiceWatchdog.recordHealthy(applicationContext)
            }

            // V5.9.633 вҖ” periodic Reject-Reason Aggregator dump (~60s cadence).
            // Operator-facing visibility for "1518 mints scanned but only 85
            // executed" forensics: tells you which gate is the loudest dampener
            // right now (e.g. "MOONSHOT:low_buy_pressure=423(42%)").
            if (loopCount % 12 == 0) {
                try {
                    val line = RejectionTelemetry.summaryLine(top = 5)
                    if (RejectionTelemetry.totalWindowCount() > 0L) {
                        ErrorLogger.info("BotService", line)
                        addLog(line)
                    }
                } catch (_: Throwable) {}
            }

            // V5.9.634 вҖ” FREEZE DETECTOR + CAP DIAGNOSTICS (~60s cadence).
            // See runFreezeDetectorTick() for full description. Extracted to
            // a separate suspend function in V5.9.634c because botLoop hit the
            // JVM 64KB per-method bytecode limit.
            if (loopCount % 12 == 0) {
                runFreezeDetectorTick(loopCount, cfg)
            }
            
            // AGGRESSIVE WATCHLIST CLEANUP - every 5 loops (about 25 seconds)
            // V4.0: Use GlobalTradeRegistry.size() for check
            if (loopCount % 5 == 0 && GlobalTradeRegistry.size() > 3) {
                scope.launch {
                    try {
                        cleanupWatchlist()
                    } catch (e: Exception) {
                        ErrorLogger.error("BotService", "Watchlist cleanup error: ${e.message}")
                    }
                }
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.0: SYNC GLOBALTRADEREGISTRY TO CONFIG - every 10 loops (~50 seconds)
            // Persists the thread-safe watchlist to ConfigStore for restart recovery
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (loopCount % 10 == 0) {
                try {
                    GlobalTradeRegistry.syncToConfig(applicationContext)
                    ErrorLogger.debug("BotService", GlobalTradeRegistry.getStats())
                } catch (e: Exception) {
                    ErrorLogger.error("BotService", "GlobalTradeRegistry sync error: ${e.message}")
                }
                // V5.9.8: Persist paper wallet balance every 10 loops (~50s)
                if (cfg.paperMode && status.paperWalletSol > 0.01) {
                    try {
                        PaperWalletStore.persist(applicationContext, status.paperWalletSol)
                    } catch (_: Exception) {}
                }
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // SCANNER STALENESS CHECK - every 6 loops (~30 seconds)
            // If no new tokens found for 2 minutes, reset scanner maps
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (loopCount % 6 == 0 && marketScanner != null) {
                marketScanner?.checkAndResetIfStale()
            }

            // V5.9.660 вҖ” extracted to runScannerHeartbeat() to keep
            // botLoop under the JVM 64KB method size limit.
            if (loopCount % 6 == 0) {
                runScannerHeartbeat()
            }

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.621 вҖ” INERT-LOOP WATCHDOG (every ~60s)
            //
            // Operator: "its been sitting now 'started' and absolutely nothing
            // вҖ” no trades no Scanner nothing". Detected pathology: BotService
            // is running, status.running=true, but the scanner's onTokenFound
            // callback hasn't fired in N minutes despite PumpPortal showing
            // 2000+ mints. This means either:
            //   вҖў SolanaMarketScanner died silently (coroutine cancelled)
            //   вҖў DataOrchestrator stream feeds disconnected
            //   вҖў PumpPortal WS dropped without onLost firing
            //
            // First trip (3min silence): force scanner soft-reset + stream
            // reconnect. Second trip (5min silence): nuke + recreate the
            // market scanner from scratch. Always logs loudly so the
            // operator sees the recovery action.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.692 вҖ” purge Sniper ghost missions every ~30s (loopCount % 6 = every 5*6=30s)
            if (loopCount % 6 == 0) {
                try { com.lifecyclebot.v3.scoring.ProjectSniperAI.sweepStaleMissions(300L) } catch (_: Throwable) {}
            }

            if (loopCount % 12 == 0) {  // ~60s cadence
                try {
                    val now = System.currentTimeMillis()
                    val silenceMs = now - lastScannerDiscoveryMs
                    when {
                        silenceMs > 5 * 60_000L -> {
                            ErrorLogger.error("BotService",
                                "рҹҡЁ INERT-LOOP WATCHDOG (HARD): no scanner activity in ${silenceMs/1000}s вҖ” restarting scanner")
                            addLog("рҹҡЁ INERT WATCHDOG: ${silenceMs/1000}s of scanner silence вҖ” restarting Solana scanner")
                            try { marketScanner?.stop() } catch (_: Throwable) {}
                            delay(500)
                            try { orchestrator?.reconnectStreams() } catch (_: Throwable) {}
                            val sc = marketScanner
                            if (sc != null) {
                                try {
                                    sc.start()
                                    addLog("вң… Solana scanner restarted by inert watchdog")
                                    ErrorLogger.warn("BotService", "вң… Inert watchdog restarted existing SolanaMarketScanner")
                                } catch (t: Throwable) {
                                    ErrorLogger.error("BotService", "Scanner restart failed: ${t.message}", t)
                                    addLog("вқҢ Scanner restart failed: ${t.message}")
                                }
                            } else {
                                // V5.9.645 вҖ” never silently swallow a null scanner.
                                // Self-heal the scanner instead of telling the operator
                                // to restart. The construction is now wrapped in
                                // bootMemeScanner() so we can call it idempotently from
                                // any recovery path.
                                ErrorLogger.error("BotService", "рҹҡЁ INERT WATCHDOG: marketScanner is NULL вҖ” auto-recovering via bootMemeScanner")
                                addLog("рҹҡЁ Scanner missing вҖ” auto-recovering via self-heal")
                                bootMemeScanner(reason = "INERT_WATCHDOG_NULL")
                            }
                            // Reset clock so the restart gets ~3min before another hard-reset
                            lastScannerDiscoveryMs = now
                            inertWatchdogFiredOnce = false
                        }
                        silenceMs > 3 * 60_000L && !inertWatchdogFiredOnce -> {
                            ErrorLogger.warn("BotService",
                                "вҡ пёҸ INERT-LOOP WATCHDOG (SOFT): ${silenceMs/1000}s of scanner silence вҖ” reconnecting streams")
                            addLog("вҡ пёҸ INERT WATCHDOG: ${silenceMs/1000}s of scanner silence вҖ” reconnect attempted")
                            try { orchestrator?.reconnectStreams() } catch (_: Throwable) {}
                            try { marketScanner?.checkAndResetIfStale() } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.AntiChokeManager.tick(
                                isPaperMode = cfg.paperMode,
                                wallet = wallet,
                                tokens = status.tokens,
                                loopCount = loopCount,
                            ) } catch (_: Throwable) {}
                            inertWatchdogFiredOnce = true
                        }
                    }
                } catch (e: Exception) {
                    ErrorLogger.debug("BotService", "Inert watchdog tick error: ${e.message}")
                }
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // PERIODIC ORPHAN SCAN - every 10 loops (~50 seconds) in live mode
            // Catches tokens that failed to sell and are stuck in wallet
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (!cfg.paperMode && loopCount % 10 == 0 && wallet != null) {
                scope.launch {
                    try {
                        addLog("рҹ”Қ Periodic orphan scan starting...")
                        scanAndSellOrphans(wallet!!)
                    } catch (e: Exception) {
                        ErrorLogger.error("BotService", "Periodic orphan scan error: ${e.message}")
                    }
                }
            }
            
            // V5.9.660 вҖ” extracted to runMarketsEngineWatchdog() to keep
            // botLoop under the JVM 64KB method size limit. Same cadence
            // (every 10 loops), same behavior. See helper for full body.
            if (loopCount % 10 == 0) {
                runMarketsEngineWatchdog(loopCount, cfg)
            }

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // PENDING SELL QUEUE PROCESSING вҖ” every loop tick (~5s) in live mode
            // V5.9.478: bumped from `% 10` (50-80s) вҶ’ `% 1` (every tick).
            // Operator: '80 seconds is dumb and way to long the price will
            // always have moved plus we will miss quick pump spikes вҖ” it
            // needs to be as fast as the buys are aka instant.'
            //
            // Concurrency safety: liveSell's per-mint `sellInProgress` guard
            // + the `getAndClear()` semantics (queue is drained, processed,
            // failures are re-added) prevent double-fire on the same mint.
            // V5.9.478 also adds an in-line slippage escalation ladder
            // (200вҶ’400вҶ’600вҶ’1000bps within ONE liveSell call) so most retries
            // resolve before this loop iteration even completes; this fast
            // tick is the safety net for non-slippage failures (RPC blips,
            // rate-limits, RFQ outages).
            //
            // Historical context (V5.9.321): the previous %10 was set to
            // avoid double SELL_START / PENDING_RETRY_1 patterns when the
            // first liveSell hadn't yet received its on-chain confirmation.
            // With sellInProgress, this cannot happen вҖ” the second tick
            // sees the guard set and skips re-entry.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (!cfg.paperMode && loopCount % 1 == 0 && wallet != null && PendingSellQueue.hasPending()) {
                scope.launch {
                    try {
                        val pendingSells = PendingSellQueue.getAndClear()
                        if (pendingSells.isNotEmpty()) {
                            addLog("Processing ${pendingSells.size} pending sells...")
                            for (sell in pendingSells) {
                                try {
                                    // Find the token state if still tracked
                                    val ts = synchronized(status.tokens) { 
                                        status.tokens[sell.mint]
                                    }
                                    
                                    if (ts != null && ts.position.isOpen) {
                                        // V5.9.291 FIX: CRITICAL вҖ” never fake-close a position.
                                        // Old code called tradeId.closed(-100%) after 3 retries
                                        // WITHOUT clearing ts.position or executing any swap.
                                        // Result: bot "forgot" the position, tokens stayed in
                                        // wallet forever, -100% PnL wrongly booked.
                                        //
                                        // New behaviour:
                                        //   retryCount < 20 вҶ’ keep retrying (Jupiter lag is real)
                                        //   retryCount >= 20 вҶ’ LOUD notification to user, keep
                                        //     retrying anyway, NEVER fake-close without a real sig.
                                        //     StartupReconciler will adopt the position on restart.
                                        if (sell.retryCount >= 20 && sell.retryCount % 5 == 0) {
                                            // Escalating alert every 5 attempts after threshold
                                            addLog("рҹҡЁ STUCK SELL (${sell.retryCount} attempts): ${sell.symbol} вҖ” still retrying. Tokens in wallet.")
                                            sendTradeNotif(
                                                "рҹҡЁ Stuck Sell вҖ” Action Required",
                                                "${sell.symbol}: ${sell.retryCount} sell attempts failed. " +
                                                "Tokens are still in your wallet. Bot will keep retrying. " +
                                                "If persistent, use the positions panel to force-release.",
                                                com.lifecyclebot.engine.NotificationHistory.NotifEntry.NotifType.INFO
                                            )
                                            ErrorLogger.error("BotService",
                                                "рҹҡЁ STUCK_SELL: ${sell.symbol} | retryCount=${sell.retryCount} | " +
                                                "reason=${sell.reason} | tokens STILL in wallet, NOT fake-closed")
                                        }
                                        addLog("Retrying sell: ${sell.symbol} (attempt ${sell.retryCount + 1})")
                                        // V5.9.1527 (spec item 4) вҖ” pass the CANONICAL (de-polluted)
                                        // exit reason. CloseLease.canonicalReason strips any nested
                                        // PENDING_RETRY_n: prefixes so the reason never recurses. The
                                        // attempt count is carried by the CloseLease, NOT baked into the
                                        // reason string (originalExitReason is immutable).
                                        val canonicalReason = com.lifecyclebot.engine.sell.CloseLease.canonicalReason(sell.reason)
                                        executor.requestSell(ts, canonicalReason, wallet, wallet!!.getSolBalance())
                                    } else {
                                        // Token no longer tracked вҖ” might be orphaned or already sold
                                        addLog("Pending sell for untracked/closed token: ${sell.symbol} вҖ” removing from queue")
                                        PendingSellQueue.remove(sell.mint)
                                    }
                                } catch (e: Exception) {
                                    addLog("Pending sell retry failed: ${sell.symbol} вҖ” ${e.message}")
                                    // V5.9.291 FIX: requeue unconditionally вҖ” never fake-close.
                                    // requestSell internally handles FAILED_RETRYABLE вҶ’ requeue,
                                    // so this outer catch is belt-and-suspenders for unexpected
                                    // exceptions thrown before requestSell is reached.
                                    val tsForRequeue = synchronized(status.tokens) { status.tokens[sell.mint] }
                                    if (tsForRequeue != null && tsForRequeue.position.isOpen) {
                                        PendingSellQueue.requeue(sell)
                                        ErrorLogger.warn("BotService",
                                            "рҹ”„ SELL_EXCEPTION_REQUEUE: ${sell.symbol} | attempt=${sell.retryCount} | ${e.message?.take(60)}")
                                    } else {
                                        // Token is gone / already sold вҖ” drop from queue cleanly
                                        PendingSellQueue.remove(sell.mint)
                                        addLog("Pending sell dropped (position closed): ${sell.symbol}")
                                    }
                                }
                                // Small delay between retries to avoid rate limits
                                kotlinx.coroutines.delay(500)
                            }
                        }
                    } catch (e: Exception) {
                        ErrorLogger.error("BotService", "Pending sell processing error: ${e.message}")
                    }
                }
            }

            // Currency rate refresh + feed SOL price to bonding curve tracker
            scope.launch {
                try {
                    currencyManager.refreshIfStale()
                    val sol = currencyManager.getSolUsd()
                    if (sol > 0) BondingCurveTracker.updateSolPrice(sol)
                } catch (_: Exception) {}
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // BEHAVIOR LEARNING MAINTENANCE - every 60 loops (~5 minutes)
            // Self-healing check and pattern pruning
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.33: Free-musing stream вҖ” sentient chat has more freedom.
            // Fires every 12 loops (~50-60s) so the window actually feels alive
            // even when no trades are happening. Talks about philosophy, memory,
            // the market, the user relationship, humor вҖ” not just trade outcomes.
            if (loopCount % 12 == 0 && loopCount % 60 != 0) {
                try { SentientPersonality.freeMusing() } catch (_: Exception) {}
            }
            if (loopCount % 60 == 0) {
                // V5.9.9: Sentient personality periodic reflection
                try { SentientPersonality.periodicReflection() } catch (_: Exception) {}

                scope.launch {
                    try {
                        // Self-healing check (clears data if poisoned)
                        val wasCleared = BehaviorLearning.selfHealingCheck()
                        if (wasCleared) {
                            addLog("рҹ§№ BehaviorLearning: Self-healed (cleared poisoned data)")
                        }
                        
                        // Prune stale patterns
                        BehaviorLearning.pruneStalePatterns()
                        // Log health status periodically
                        val health = BehaviorLearning.getHealthStatus()
                        if (health.goodCount + health.badCount >= 10) {
                            ErrorLogger.info("BehaviorLearn", "рҹ“Ҡ Health: ${health.summary()}")
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "BehaviorLearning maintenance error: ${e.message}")
                    }
                }

                // V5.9.318: InsiderWalletTracker delta scan (~every 5 min).
                // Detects NEW_POSITION/ACCUMULATION/DISTRIBUTION/SELL events on
                // tracked Trump/whale wallets and forwards them to the signal
                // callback wired in onCreate (notifications + log).
                scope.launch {
                    try {
                        val signals = com.lifecyclebot.perps.InsiderWalletTracker.scanForSignals()
                        if (signals.isNotEmpty()) {
                            ErrorLogger.info("BotService", "рҹ”Қ InsiderWalletTracker scan: ${signals.size} signal(s) detected")
                        }
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "InsiderWalletTracker scan error: ${e.message}")
                    }
                }

                // V5.9.318: TRADING COPILOT update вҖ” refresh the life-coach
                // directive from recent trade outcomes + layer health. Cheap
                // (O(window=30)). The coaching state then steers entries via
                // LifecycleStrategy.shouldTradeBase / FinalDecisionGate.
                try { com.lifecyclebot.engine.TradingCopilot.update() } catch (_: Exception) {}
                try {
                    val antiChoke = com.lifecyclebot.engine.AntiChokeManager.tick(
                        isPaperMode = cfg.paperMode,
                        wallet = wallet,
                        tokens = status.tokens,
                        loopCount = loopCount,
                    )
                    if (antiChoke != null && antiChoke.level != com.lifecyclebot.engine.AntiChokeManager.Level.CLEAR) {
                        addLog("рҹ«Ғ AntiChoke ${antiChoke.level.name}: ghosts=${antiChoke.ghostsCleared} pruned=${antiChoke.dormantPruned} trades24h=${antiChoke.trades24h}/${antiChoke.target24h}")
                    }
                } catch (e: Exception) {
                    ErrorLogger.debug("BotService", "AntiChoke tick error: ${e.message}")
                }

                // V5.9.439 вҖ” LEARNING TRANSPARENCY LOG (~every 5 min).
                // Surfaces the live snapshots of the three outcome-attribution
                // trackers so the user can see the brain narrowing toward
                // profitable buckets in real time. Fires only when the cheap
                // snapshot has at least one populated bucket.
                try {
                    val score = com.lifecyclebot.engine.ScoreExpectancyTracker.snapshot()
                    val hold  = com.lifecyclebot.engine.HoldDurationTracker.snapshot()
                    val exit  = com.lifecyclebot.engine.ExitReasonTracker.snapshot()
                    if (score != "no samples yet" || hold != "no samples yet" || exit != "no samples yet") {
                        ErrorLogger.info("BotService",
                            "рҹ§  LEARNING SNAPSHOT\n" +
                            "   score    : $score\n" +
                            "   hold     : $hold\n" +
                            "   exit     : $exit")
                    }
                } catch (_: Exception) {}

                // V5.0.4501 вҖ” flush learning state asynchronously. saveAll() exports
                // heavyweight brains (TradeLessonRecorder, RegimeTransitionAI, etc.);
                // doing this inline inflated loop cycles and showed up in ANR traces.
                try { com.lifecyclebot.engine.LearningPersistence.requestSaveAllAsync("periodic_loop_4501") } catch (_: Exception) {}

                // V5.9.318: LIVE WALLET RECONCILE SWEEP (~every 5 min, LIVE only).
                // ROOT CAUSE: Sub-traders (ShitCoin/Moonshot/Quality/BlueChip
                // /Manip) closePosition() paths only update in-memory PnL вҖ”
                // they NEVER broadcast a Jupiter sell. Result: every V3 exit
                // leaks tokens into the wallet during normal operation. STOP
                // BOT sweep was the only fallback, and it was too late.
                // This periodic reconcile sweep liquidates ANY non-stable SPL
                // holdings the bot is no longer tracking as an open position.
                // Active V3 positions are passed as additionalPreservedMints so
                // currently-held trades are NOT prematurely liquidated.
                scope.launch {
                    try { runReconcileSweep() }
                    catch (e: Exception) { ErrorLogger.debug("BotService", "Reconcile sweep error: ${e.message}") }
                }
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // TOKEN WIN MEMORY REFRESH - every 180 loops (~15 minutes)
            // Recalculate pattern statistics and persist to storage
            // This ensures bad tokens and patterns are integrated into decisions
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (loopCount % 180 == 0) {
                // V5.9.1036 вҖ” extracted from botLoop to reduce JVM bytecode
                // (was 109 lines of inline scope.launch body). Telemetry
                // is fire-and-forget; this returns immediately.
                run180TickTelemetry(cfg)
            }
            
            // Decay pattern weights every 720 loops (~1 hour)
            if (loopCount % 720 == 0) {
                scope.launch {
                    try {
                        BehaviorLearning.decayPatternWeights()
                    } catch (_: Exception) {}
                }
                
                // Run CollectiveIntelligenceAI maintenance (prune, dedupe, anomaly scan)
                scope.launch {
                    try {
                        com.lifecyclebot.v3.scoring.CollectiveIntelligenceAI.runMaintenance()
                    } catch (_: Exception) {}
                }
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // UPDATE ADAPTIVE CONFIDENCE MARKET CONDITIONS
            // 
            // This feeds the fluid confidence layer with current market data:
            // - Average volatility across watched tokens
            // - Average buy pressure trend
            // - Recent win rate from SmartSizer
            // - Time since last loss
            // - Session P&L percentage
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            scope.launch {
                try {
                    // Calculate average volatility and buy pressure from watched tokens
                    val tokenList = synchronized(status.tokens) { status.tokens.values.toList() }
                    
                    val avgVolatility = if (tokenList.isNotEmpty()) {
                        tokenList.mapNotNull { ts ->
                            if (ts.meta.avgAtr > 0) ts.meta.avgAtr else null
                        }.takeIf { it.isNotEmpty() }?.average() ?: 5.0
                    } else 5.0
                    
                    val avgBuyPressure = if (tokenList.isNotEmpty()) {
                        tokenList.map { it.meta.pressScore }.average()
                    } else 50.0
                    
                    // Get performance stats from SmartSizer
                    val effectiveBalance = status.getEffectiveBalance(cfg.paperMode)
                    
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    // FIX: Use FluidLearning.getTradeCount() for paper mode
                    // 
                    // BUG: Previously used tokenList.flatMap { it.trades }.size which
                    // resets to 0 when tokens are removed or bot restarts.
                    // FluidLearning.getTradeCount() is PERSISTED and accurate.
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    val sessionTradeCount = tokenList.flatMap { it.trades }.size  // In-memory trades (for session stats)
                    // V5.9.291 FIX: Live mode must also use the PERSISTED trade count.
                    // Previously live fell back to sessionTradeCount (in-memory only) which
                    // resets to 0 on every bot restart. This made learningProgress = 0 in
                    // live вҶ’ FDG thought it was a brand-new virgin bot вҶ’ confidence floors
                    // bottomed out and barely any trade passed through.
                    // FluidLearning.getTradeCount() is persisted across restarts and shared
                    // between paper and live вҖ” all paper knowledge carries over seamlessly.
                    val persistedTradeCount = try {
                        FluidLearning.getTradeCount()
                    } catch (_: Exception) { sessionTradeCount }

                    // V5.9.683-FIX: Raw persisted count (FluidLearning) can be 10-70x
                    // inflated vs real canonical settled trades (e.g. 4956 vs 71).
                    // This made FDG treat the bot as expert-phase: learningProgress ~0.99
                    // вҶ’ isBootstrapPhase=false вҶ’ canBypassConfidenceFloors=false
                    // вҶ’ 22% hard floor always active вҶ’ most candidates hard-blocked.
                    // Fix: fdgBypassCount = min(legacy, canonical*10) so the bypass
                    // stays active until ~100 real canonical settled trades accumulate.
                    val canonicalSettled = try {
                        (com.lifecyclebot.engine.CanonicalLearningCounters.settledWins.get() +
                         com.lifecyclebot.engine.CanonicalLearningCounters.settledLosses.get()).toInt()
                    } catch (_: Exception) { 0 }
                    val fdgBypassCount = if (canonicalSettled > 0) {
                        minOf(maxOf(sessionTradeCount, persistedTradeCount), canonicalSettled * 10)
                    } else {
                        maxOf(sessionTradeCount, persistedTradeCount)
                    }
                    // effectiveTradeCount unchanged вҖ” drives sizing and all non-FDG callers
                    val effectiveTradeCount = maxOf(sessionTradeCount, persistedTradeCount)
                    
                    val perfContext = SmartSizer.getPerformanceContext(
                        walletSol = effectiveBalance,
                        totalTrades = effectiveTradeCount,
                        isPaperMode = cfg.paperMode
                    )
                    
                    // Calculate session P&L
                    val allTrades = tokenList.flatMap { it.trades }
                    val sessionPnlSol = allTrades.sumOf { it.pnlSol }
                    val sessionPnlPct = if (effectiveBalance > 0) {
                        (sessionPnlSol / effectiveBalance) * 100
                    } else 0.0
                    
                    // Estimate time since last loss
                    val lastLossTrade = allTrades
                        .filter { it.side == "SELL" && it.pnlSol < 0 }
                        .maxByOrNull { it.ts }
                    val timeSinceLastLossMs = if (lastLossTrade != null) {
                        System.currentTimeMillis() - lastLossTrade.ts
                    } else Long.MAX_VALUE
                    
                    // Update the adaptive confidence layer
                    FinalDecisionGate.updateMarketConditions(
                        avgVolatility = avgVolatility,
                        buyPressureTrend = avgBuyPressure,
                        recentWinRate = perfContext.recentWinRate,
                        timeSinceLastLossMs = timeSinceLastLossMs,
                        sessionPnlPct = sessionPnlPct,
                        totalSessionTrades = fdgBypassCount,  // V5.9.683-FIX: canonical-capped count so bypass gate uses real settled trades
                        // LEARNING LAYER DATA
                        entryAiWinRate = EntryIntelligence.getWinRate(),
                        exitAiAvgPnl = ExitIntelligence.getAveragePnl(),
                        edgeLearningAccuracy = EdgeLearning.getVetoAccuracy() * 100.0,
                    )
                    
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    // UPDATE MARKET REGIME AI
                    // Detects bull/bear/crab market conditions to adjust strategy
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    try {
                        val solPrice = WalletManager.lastKnownSolPrice
                        
                        // Calculate meme performance from recent trades
                        val recentTrades = allTrades.filter { 
                            System.currentTimeMillis() - it.ts < 24 * 60 * 60 * 1000L 
                        }
                        val avgMemePerf = if (recentTrades.isNotEmpty()) {
                            recentTrades.mapNotNull { it.pnlPct }.average()
                        } else 0.0
                        
                        // Count successful vs rugged tokens
                        val successCount = recentTrades.count { (it.pnlPct ?: 0.0) >= 100.0 }
                        val rugCount = recentTrades.count { (it.pnlPct ?: 0.0) <= -80.0 }
                        
                        MarketRegimeAI.updateMarketData(
                            solPrice = solPrice,
                            solChange24h = 0.0, // Not tracked currently
                            solChange7d = 0.0, // Not tracked currently
                            avgMemePerformance = avgMemePerf,
                            successfulLaunches = successCount,
                            ruggedLaunches = rugCount,
                            volatilityIndex = avgVolatility,
                        )
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "MarketRegimeAI update error: ${e.message}")
                    }
                    
                    // Log adaptive confidence status every 5 loops
                    if (loopCount % 5 == 1) {
                        val adaptiveInfo = FinalDecisionGate.getAdaptiveConfidenceExplanation(cfg.paperMode)
                        addLog("рҹҺҡпёҸ $adaptiveInfo")
                    }
                } catch (e: Exception) {
                    ErrorLogger.error("BotService", "Adaptive confidence update error: ${e.message}")
                }
            }
            
            // Periodic AI stats logging (every ~5 minutes = 6-7 loops at 45s intervals)
            if (loopCount % 7 == 0) {
                addLog("рҹӨ– AI STATUS: ${TradingMemory.getStats()}")
                // Also log BotBrain learning state
                val brainStatus = botBrain?.let { b ->
                    "рҹ§  Brain: entry_adj=${String.format("%+.0f", b.entryThresholdDelta)} " +
                    "regime=${b.currentRegime} " +
                    "size_mult=${String.format("%.0f%%", b.regimeBullMult * 100)} " +
                    "suppressed=${b.totalSuppressedPatterns}"
                } ?: "рҹ§  Brain not initialized"
                addLog(brainStatus)
                
                // Log adaptive learning status
                addLog("рҹ§¬ ${AdaptiveLearningEngine.getStatus()}")
                
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                // LOG NEW AI LAYERS STATUS
                // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                addLog("рҹҗӢ ${WhaleTrackerAI.getStats()}")
                addLog("рҹ“Ҡ ${MarketRegimeAI.getStats()}")
                addLog("рҹҡҖ ${MomentumPredictorAI.getStats()}")
                addLog("рҹ“– ${NarrativeDetectorAI.getStats()}")
                addLog("вҸ° ${TimeOptimizationAI.getStats()}")
                addLog("рҹ’§ ${LiquidityDepthAI.getStats()}")
                addLog("рҹ”— ${AICrossTalk.getStats()}")
                
                // Clean up old momentum data
                MomentumPredictorAI.cleanup()
                WhaleTrackerAI.cleanup()
                NarrativeDetectorAI.cleanup()
                TimeOptimizationAI.cleanup()
                LiquidityDepthAI.cleanup()
                AICrossTalk.cleanup()
                
                // Refresh time-based stats
                TimeOptimizationAI.refreshStats()
                NarrativeDetectorAI.refreshHeat()
                
                // Log cloud sync status (every ~35 mins = 5x7 loops)
                if (loopCount % 35 == 0) {
                    addLog("вҳҒпёҸ ${CloudLearningSync.getStatus()}")
                    
                    // Auto-discover top whale wallets
                    scope.launch {
                        try {
                            val added = copyTradeEngine.autoDiscoverTopWallets(maxWallets = 3, minPnlSol = 20.0)
                            if (added > 0) {
                                val stats = copyTradeEngine.getStats()
                                addLog("рҹҗӢ Whale discovery: +$added | tracking ${stats.activeWallets}")
                            }
                        } catch (_: Exception) {}
                    }
                }
            }
            
            // Pattern Backtest - Run daily (every ~1440 loops at 1min intervals, or ~320 at 45s)
            // This analyzes historical trades to find which patterns work best
            if (loopCount % 300 == 0 && loopCount > 0) {
                scope.launch {
                    try {
                        tradeDb?.let { db ->
                            val report = PatternBacktester.runBacktest(db)
                            if (report.totalTrades >= 10) {
                                addLog("в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ")
                                addLog("рҹ“Ҡ PATTERN BACKTEST (${report.totalTrades} trades)")
                                addLog("Overall Win Rate: ${report.overallWinRate.toInt()}%")
                                
                                // Log top insights
                                report.insights.take(5).forEach { addLog(it) }
                                
                                // Log pattern recommendations
                                report.patterns.filter { it.recommendation in listOf("BOOST", "DISABLE") }
                                    .take(3).forEach { p ->
                                        addLog("${p.recommendation}: ${p.patternName} " +
                                            "(${p.winRate.toInt()}% win, PF=${String.format("%.1f", p.profitFactor)})")
                                    }
                                addLog("в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ")
                                
                                // AUTO-TUNE: Apply backtest results to pattern weights
                                PatternAutoTuner.updateFromBacktest(report)
                                addLog("рҹҺӣпёҸ ${PatternAutoTuner.getStatus()}")
                                
                                // CLOUD SYNC: Upload learnings to community database
                                try {
                                    val weights = AdaptiveLearningEngine.getDetailedWeights()
                                    val uploaded = CloudLearningSync.uploadLearnings(
                                        tradeCount = report.totalTrades,
                                        winRate = report.overallWinRate,
                                        featureWeights = weights,
                                        patternStats = report.patterns,
                                    )
                                    if (uploaded) {
                                        addLog("вҳҒпёҸ Shared learnings with community!")
                                    }
                                    
                                    // V5.6.12: Download community weights after upload
                                    val communityWeights = CloudLearningSync.downloadCommunityWeights()
                                    if (communityWeights != null && communityWeights.totalContributors > 0) {
                                        addLog("вҳҒпёҸ Synced: ${communityWeights.totalContributors} contributors, ${communityWeights.totalTrades} collective trades")
                                        // Apply community weights to local learning engine
                                        AdaptiveLearningEngine.applyCommunityWeights(communityWeights.featureWeights, communityWeights.totalTrades)
                                    }
                                } catch (e: Exception) {
                                    ErrorLogger.debug("CloudSync", "Upload error: ${e.message}")
                                }
                            }
                        }
                    } catch (e: Exception) {
                        ErrorLogger.error("Backtest", "Pattern backtest error: ${e.message}")
                    }
                }
            }

            // Balance + P&L refresh
            scope.launch {
                try {
                    walletManager.refreshBalance()
                    val freshSol = walletManager.state.value.solBalance
                    status.walletSol = freshSol

                    // V5.0.4586 вҖ” DAILY COMPOUND RULE 4 tracker feed. Read-only
                    // shaper: snapshots UTC-day-open wallet balance so
                    // LiveStrategyTuner can lift winner ceilings when we're
                    // behind the operator's 2x/day compound floor. Fail-open.
                    if (freshSol > 0.0) {
                        try { DailyCompoundingTracker.update(freshSol) } catch (_: Throwable) {}
                    }

                    // V5.0.4588 вҖ” LANE AUTO-PAUSE evaluation. Cheap; internally
                    // rate-limited to every 30s. Auto-pauses proven-toxic lanes
                    // (n>=15 && wins=0) OR (n>=20 && wr<20% && ev<=-40%).
                    try { LaneAutoPauseGuard.evaluateLive() } catch (_: Throwable) {}

                    // V5.0.4590 вҖ” LANE SHADOW-PROOF LOOP. Cheap; internally
                    // rate-limited to every 5min. Auto-resumes paused lanes
                    // when the LLM Lab has proven a strategy in that asset
                    // class (>=20 paper trades, >=30% WR, positive SOL PnL).
                    try { LaneShadowProofLoop.evaluate() } catch (_: Throwable) {}

                    // в”Җв”Җ Shared wallet: broadcast live SOL balance to all traders в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                    if (freshSol > 0.0) {
                        try { com.lifecyclebot.perps.CryptoAltTrader.updateLiveBalance(freshSol) } catch (_: Exception) {}
                        try { com.lifecyclebot.perps.TokenizedStockTrader.updateLiveBalance(freshSol) } catch (_: Exception) {}
                        try { com.lifecyclebot.perps.PerpsTraderAI.setLiveBalance(freshSol) } catch (_: Exception) {}
                        // V5.9.283: Auto-untrip STARTUP_FLOOR CB if wallet grew above minimum
                        if (!cfg.paperMode) {
                            LiveSafetyCircuitBreaker.updateBalance(freshSol)

                            // V5.9.736 вҖ” LOW-BALANCE EARLY WARNING.
                            // LiveSafetyCircuitBreaker.MIN_LIVE_SOL is 0.10 вҖ” at that
                            // point all live trades are already blocked. Operator
                            // dump showed wallet at 0.1904 SOL trying to go live,
                            // which is one Jupiter swap + slippage + priority fee
                            // away from the breaker floor. Surface a warning in
                            // logs + UI as soon as we drop under 2Г— the floor so
                            // the operator sees it coming, not after the breaker
                            // trips silently mid-session.
                            val warnFloor = LiveSafetyCircuitBreaker.MIN_LIVE_SOL * 2.0  // 0.20 SOL
                            if (freshSol < warnFloor && !LiveSafetyCircuitBreaker.isTripped()) {
                                val solPx = WalletManager.lastKnownSolPrice.takeIf { it > 0 } ?: 0.0
                                val usdNote = if (solPx > 0) " (~\$${(freshSol * solPx).toInt()})" else ""
                                ErrorLogger.warn("BotService",
                                    "вҡ пёҸ LIVE_BALANCE_LOW: wallet=${"%.4f".format(freshSol)} SOL$usdNote вҖ” " +
                                    "approaching circuit-breaker floor ${LiveSafetyCircuitBreaker.MIN_LIVE_SOL} SOL. " +
                                    "Top up to avoid mid-session trade halt.")
                                addLog("вҡ пёҸ Live wallet low: ${"%.4f".format(freshSol)} SOL$usdNote вҖ” top up to avoid halt at ${LiveSafetyCircuitBreaker.MIN_LIVE_SOL}")
                            }
                        }
                    }
                    

                    // в”Җв”Җ Shared paper wallet: broadcast paper balance to all traders в”Җв”Җв”Җв”Җв”Җв”Җ

                    // Treasury milestone check вҖ” live mode uses real wallet; paper uses paper balance
                    // V5.5 FIX: Paper mode now also triggers milestones so scaling tiers work in testing
                    run {
                        val solPx = WalletManager.lastKnownSolPrice.takeIf { it > 0 } ?: 150.0
                        val balanceSol = if (cfg.paperMode) status.paperWalletSol else freshSol
                        TreasuryManager.onWalletUpdate(
                            walletSol    = balanceSol,
                            solPrice     = solPx,
                            onMilestone  = { milestone, walletUsd ->
                                val modeTag = if (cfg.paperMode) " [PAPER]" else ""
                                addLog("рҹҸҰ MILESTONE$modeTag: ${milestone.label} hit @ \$${walletUsd.toLong()}", "treasury")
                                if (milestone.celebrateOnHit) {
                                    sendTradeNotif("рҹҺү ${milestone.label}!",
                                        "Treasury now locking ${(milestone.lockPct*100).toInt()}% of profits",
                                        NotificationHistory.NotifEntry.NotifType.INFO)
                                }
                                TreasuryManager.save(applicationContext)
                                // V5.9.212: MILESTONE HANDOFF вҖ” signal TreasuryOpportunityEngine to
                                // actively seek re-deployment of newly locked capital. Previously
                                // the milestone callback was a no-op for deployment вҖ” capital sat idle.
                                if (TreasuryOpportunityEngine.isEnabled()) {
                                    TreasuryOpportunityEngine.onMilestoneHit(
                                        milestone = milestone.label,
                                        walletUsd = walletUsd,
                                        treasurySol = TreasuryManager.treasurySol,
                                    )
                                    addLog("рҹҸҰ Treasury deployment unlocked вҖ” seeking high-conviction opportunity post-milestone", "treasury")
                                }
                            }
                        )
                        
                        // V5.6.15: Sync RunTracker30D balance with actual paper wallet every 10 loops
                        if (cfg.paperMode && loopCount % 10 == 0) {
                            RunTracker30D.syncBalance(balanceSol)
                        }

                        // V5.9.399 вҖ” back-fund the paper wallet from treasury
                        // when it dries up. Only paper mode (live treasury is
                        // on-chain locked, not auto-pullable). Floor = 10% of
                        // configured starting capital. Runs every 5 loops to
                        // smooth out churn.
                        if (cfg.paperMode && loopCount % 5 == 0) {
                            try {
                                val floor = (cfg.paperSimulatedBalance * 0.10).coerceAtLeast(1.0)
                                val pulled = TreasuryManager.backFundPaperWalletIfLow(
                                    walletSol = balanceSol,
                                    floorSol  = floor,
                                    solPrice  = solPx,
                                )
                                if (pulled > 0.0) {
                                    executor.onPaperBalanceChange?.invoke(pulled)
                                    addLog("рҹ’ё Treasury back-fund вҶ’ +${"%.4f".format(pulled)} SOL credited to paper wallet (floor=${"%.2f".format(floor)})", "treasury")
                                    TreasuryManager.save(applicationContext)
                                }
                            } catch (e: Exception) {
                                ErrorLogger.debug("BotService", "Treasury back-fund check error: ${e.message}")
                            }
                        }

                        // V5.9.220: Wire DrawdownCircuitAI вҖ” feed it real balance every loop.
                        // Paper mode: aggression penalties only kick in above a 15% drawdown threshold
                        // (the circuit's own thresholds are 3/6/10%, but paper is noisy early).
                        // Live mode: full sensitivity from day one.
                        if (!cfg.paperMode) {
                            com.lifecyclebot.v3.scoring.DrawdownCircuitAI.recordBalance(balanceSol)
                        } else if (loopCount % 5 == 0) {
                            // Paper: sample every ~5 loops to smooth noise; circuit still activates but
                            // only at higher DD because paper losses are expected in proof runs.
                            com.lifecyclebot.v3.scoring.DrawdownCircuitAI.recordBalance(balanceSol)
                        }
                    }
                    // Gather all trades across all tokens for P&L - use synchronized copy
                    val allTrades = synchronized(status.tokens) {
                        status.tokens.values.toList().flatMap { it.trades.toList() }
                    }
                    walletManager.updatePnl(allTrades)
                    
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    // CLOSED-LOOP FEEDBACK: Update FDG with wallet performance
                    // 
                    // The bot's LIFETIME win rate influences confidence thresholds.
                    // Winning = more aggressive, Losing = more defensive.
                    // Uses EMA smoothing (damping) to prevent whipsawing.
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    val walletStats = walletManager.state.value
                    FinalDecisionGate.updateClosedLoopFeedback(
                        lifetimeWinRate = walletStats.winRate.toDouble(),
                        lifetimeTrades = walletStats.totalTrades,
                    )
                } catch (_: Exception) {}
            }


            var lastSuccessfulPollMs = System.currentTimeMillis()

            // V5.2: Prioritization moved AFTER TokenMergeQueue.processQueue()
            // See the prioritizedWatchlist definition after MergeQueue processing

            // Process all tokens in parallel вҖ” each gets its own coroutine.
            // This reduces per-cycle latency from (NГ—50ms + pollSeconds) to just pollSeconds.
            // V4.1: Lambda body extracted to processTokenCycle() to reduce compiler complexity
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.0: CHECK TRADING LAYER READINESS
            // Block all trading until AI layers are fully initialized
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (!allTradingLayersReady && loopCount > 1) {
                addLog("вҸі Waiting for trading layers to initialize...")
                kotlinx.coroutines.delay(1000)
                continue  // Skip this cycle, try again
            }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.20: PROCESS MERGE QUEUE - Full Lifecycle Integration
            // 
            // This is where tokens actually get added to the watchlist.
            // MergeQueue batches scanner discoveries and deduplicates:
            //   - Token found by DEX_BOOSTED + PUMP_FUN = 1 add with confidence boost
            //   - Processes every 2 seconds after 5-second merge window
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            try { processTokenMergeQueue(loopCount) }
            catch (e: Exception) { ErrorLogger.debug("BotService", "MergeQueue error: ${e.message}") }
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.2 FIX: GET EFFECTIVE WATCHLIST FROM GLOBALTRADEREGISTRY
            // This MUST happen AFTER TokenMergeQueue.processQueue() which adds tokens!
            // Previously this was done BEFORE merge queue, causing newly added tokens
            // to be skipped until the next loop iteration.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            val registryWatchlist = GlobalTradeRegistry.getWatchlist()
            val effectiveWatchlist = if (registryWatchlist.isNotEmpty()) {
                registryWatchlist
            } else {
                // Fallback to config watchlist if registry is empty
                watchlist
            }
    

            // V5.2: Prioritize tokens for processing
val prioritizedWatchlist = if (cfg.v3EngineEnabled) {
    val nowMs = System.currentTimeMillis()
    effectiveWatchlist.sortedByDescending { mint ->
        val ts = status.tokens[mint]
        if (ts == null) {
            // V5.9.624 вҖ” unknown freshly-enqueued mints should get hydrated,
            // not buried. Also add a fair-coverage boost using registry metadata
            // so the protected 500-token bench actually reaches qualification.
            val entry = try { GlobalTradeRegistry.getEntry(mint) } catch (_: Throwable) { null }
            val neverProcessedBoost = if ((entry?.processCount ?: 0) == 0) 120.0 else 0.0
            val lrpBoost = entry?.lastProcessedAt?.let { last ->
                if (last <= 0L) 160.0 else ((nowMs - last).coerceAtLeast(0L) / 1_000.0).coerceAtMost(180.0)
            } ?: 80.0
            45.0 + neverProcessedBoost + lrpBoost
        } else {
            var priority = 0.0
            if (ts.position.isOpen) priority += 10_000.0 // Open positions always first

            // V5.9.624 вҖ” fair-coverage layer for the protected intake bench.
            // Never/least-recently processed candidates get a bounded boost.
            // This improves the AMOUNT of tokens that arrive to qualification
            // without pruning the watchlist or starving open-position exits.
            val entry = try { GlobalTradeRegistry.getEntry(mint) } catch (_: Throwable) { null }
            val neverProcessedBoost = if ((entry?.processCount ?: 0) == 0) 140.0 else 0.0
            val lrpBoost = entry?.lastProcessedAt?.let { last ->
                if (last <= 0L) 180.0 else ((nowMs - last).coerceAtLeast(0L) / 1_000.0).coerceAtMost(160.0)
            } ?: 90.0
            priority += neverProcessedBoost + lrpBoost

            // Deprioritize obvious shadow-only zombies, but never remove them.
            // Quality/freshness can still lift a candidate back up when data changes.
            if (ts.lastLiquidityUsd <= 0.0 && ts.phase in listOf("dying", "dead", "rug_likely", "distribution", "distributing")) {
                priority -= 120.0
            }

            // V5.9.602 вҖ” freshness/source boost for the meme snipe lane.
            // Previous ordering was liquidity-heavy, so old $2M+ tokens like
            // ZEREBRO stayed ahead while 0-2min PumpPortal launches were
            // deferred (processed=48 total=141). Fresh pump candidates are
            // where the edge lives; process them right after open positions.
            val ageMs = (nowMs - ts.addedToWatchlistAt).coerceAtLeast(0L)
            val freshBoost = when {
                ageMs < 60_000L -> 350.0
                ageMs < 180_000L -> 220.0
                ageMs < 300_000L -> 120.0
                else -> 0.0
            }
            val sourceBoost = when {
                ts.source.contains("PUMP", ignoreCase = true) -> 160.0
                ts.source.contains("DEX_BOOST", ignoreCase = true) -> 90.0
                ts.source.contains("TREND", ignoreCase = true) -> 55.0
                else -> 0.0
            }
            priority += freshBoost + sourceBoost

            // Keep quality signals, but cap liquidity so giant older pools do
            // not starve fresh memes. Fluid sizing/learning remains untouched.
            // V5.9.794 вҖ” operator audit Item 6: priority queue now reads REAL
            // pool liquidity from LiquidityClassifier (not the raw value that
            // conflates pump.fun BC estimates with executable depth). BC-only
            // tokens still get a small bump (so discovery isn't starved) but
            // confirmed-pool tokens dominate the head of the queue where the
            // bot can actually trade them.
            val realPoolUsd = try {
                com.lifecyclebot.engine.LiquidityClassifier.realPoolLiquidityUsd(ts)
            } catch (_: Throwable) { ts.lastLiquidityUsd }
            val bcEstUsd = try {
                com.lifecyclebot.engine.LiquidityClassifier.bondingCurveLiquidityEstUsd(ts)
            } catch (_: Throwable) { 0.0 }
            priority += (realPoolUsd / 2_000.0).coerceAtMost(60.0)
            priority += (bcEstUsd / 8_000.0).coerceAtMost(15.0)
            priority += ts.entryScore
            priority += ts.meta.momScore * 0.8
            priority += ts.meta.volScore * 0.5
            priority += (ts.lastBuyPressurePct - 50.0).coerceIn(0.0, 35.0)
            // V5.9.794 вҖ” operator audit Item 6 priority signals: volume,
            // safety-freshness, source-reliability.
            // Volume: real volume proxy вҖ” bias toward tokens with active
            // turnover so dead pools don't stay top-of-queue on liquidity
            // depth alone.
            val volumeUsd = (ts.lastLiquidityUsd * 0.05).coerceAtLeast(0.0)
            priority += (volumeUsd / 3_000.0).coerceAtMost(35.0)
            // Safety freshness: tokens whose rugcheck/safety report was
            // refreshed in the last 2 minutes are more trustworthy to act
            // on. Stale safety = small de-prioritisation.
            val safetyAgeSec = if (ts.lastSafetyCheck > 0L)
                ((nowMs - ts.lastSafetyCheck) / 1_000L).coerceAtLeast(0L) else Long.MAX_VALUE
            val safetyFreshBoost = when {
                safetyAgeSec < 120L -> 30.0
                safetyAgeSec < 600L -> 10.0
                safetyAgeSec == Long.MAX_VALUE -> -5.0
                else -> 0.0
            }
            priority += safetyFreshBoost
            // Source reliability: confirmed-pool sources rank above BC-only
            // sources rank above UNKNOWN. Distinct from the freshness boost
            // вҖ” this is about how trustworthy the price/liquidity reading is.
            val hasConfirmedPool = try {
                com.lifecyclebot.engine.LiquidityClassifier.hasConfirmedExitPool(ts)
            } catch (_: Throwable) { false }
            priority += if (hasConfirmedPool) 25.0 else 0.0
            priority
        }
    }
} else {
    effectiveWatchlist
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// PATCH: chunked watchlist processing with per-token timeout
// Prevent one overloaded loop from timing out the entire batch.
// Keeps open positions first, then processes the rest in small waves.
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
val openPositionMints = prioritizedWatchlist.filter { mint ->
    val ts = status.tokens[mint]
    isCapCountableLiveToken(mint, ts) || GlobalTradeRegistry.hasOpenPosition(mint)
}

// V5.9.494 вҖ” UNIVERSAL OPEN-POSITION COVERAGE.
// Operator forensics: VENIS Treasury sat at +161% (target +4%) and
// V3 VENIS at +29% with lock at +23% вҖ” neither sold because the
// scanner had stopped returning fresh data for those mints, so
// processTokenCycle never fired the exit checks. Treasury / ShitCoin /
// Quality / Moonshot / BlueChip all hold positions in their OWN
// stores; their mints can drop off the scanner radar even while
// those positions are still ACTIVELY losing money.
//
// Force-include every open position from sub-trader stores PLUS the
// V3 lane (status.tokens). Any mint with a live position somewhere
// is processed every tick, irrespective of scanner visibility.
val subTraderOpenMints: List<String> = collectSubTraderOpenMints()

val v3OpenMints: List<String> = synchronized(status.tokens) {
    status.tokens.values.filter { isCapCountableLiveToken(it.mint, it) }.map { it.mint }
}

// V5.9.1470 (spec items 8+9) вҖ” GHOST REAPER + forcedOpen sanitization.
// Before the supervisor runs, drop any mint that the close ledger marks CLOSED from
// the forcedOpen set. This guarantees forcedOpen only ever contains GENUINELY open
// positions, so closed/closing mints stop consuming watchlist selection priority and
// holding slots (operator: "forcedOpen=28 keeps consuming watchlist selection",
// "forcedOpen must not exceed actual open position count"). Reaping here = before
// PRE_SUPERVISOR, exactly as the spec requires. Metadata-only filter; held positions
// are never in the close ledger so they are never reaped.
val paperRuntimeForSlotTruth = try { RuntimeModeAuthority.isPaper() } catch (_: Throwable) { cfg.paperMode }
val forcedOpenRaw = if (paperRuntimeForSlotTruth) {
    // V5.0.3810 вҖ” PAPER slot truth is the simulator ledger only. Do not union
    // stale sub-trader forced rows or live wallet/tracker state into paper slots.
    rebuildPaperForcedOpenFromLedger()
} else {
    (openPositionMints + subTraderOpenMints + v3OpenMints).distinct()
}
val forcedOpenMints = if (paperRuntimeForSlotTruth) reapPaperForcedOpen(forcedOpenRaw) else reapGhostForcedOpen(forcedOpenRaw)

// V5.9.1470b (spec item 7) вҖ” publish slot-health via helper (keeps botLoop bytecode
// under the JVM method-size limit; CI run#3474 hit 'Couldn't transform method node').
try { publishSlotHealth(forcedOpenMints, forcedOpenMints.size) } catch (_: Throwable) {}

val otherMints = prioritizedWatchlist.filterNot { mint ->
    mint in openPositionMints || mint in subTraderOpenMints || mint in v3OpenMints
}

// V5.9.663d вҖ” V5.9.663c reverted: gating watchlist to every-3rd-tick
// stopped the bot from trading and didn't help ANR. Operator: 'remove
// the last change. let's lower the watchlist size to 250.'
// Watchlist cap dropped from 300 вҶ’ 250 in the next block.
// V5.9.1319 (Item 7) вҖ” collapse same-symbol families on the per-cycle slice BEFORE the
// expensive supervisor/V3/lane work. Protected 500-token intake pool is untouched.
val otherMintsDeduped = dedupeWatchlistByFamily(otherMints)
val orderedMintsRaw = (forcedOpenMints + otherMintsDeduped).distinct()

// V5.9.960 вҖ” SMART WATCHLIST ROUND-ROBIN.
//
// Operator (2026-05-19): 'bot cycle should be every 5 seconds.' With
// 250 mints Г— ~250ms per processTokenCycle network call and 100-range
// parallelism, the SUPERVISOR floor is ~7s even with V5.9.958 chunk
// timeouts. To hit a real 5s round-trip we must EVALUATE FEWER MINTS
// PER CYCLE вҖ” but not blindly: meme alpha lives in the freshly-listed
// tokens, so those must be evaluated every tick. The cold tail
// rotates so it gets covered every 2-3 cycles instead of every cycle.
//
// Selection priority (in order, capped at 100 = one supervisor range = ~2.4s):
//   1. forcedOpenMints вҖ” ALL open positions always evaluated (was
//      already true). These are the mints with skin in the game.
//   2. Fresh mints (addedAt < 60s ago) вҖ” pump.fun graduations and
//      newly-trending tokens. This is where the entry alpha lives.
//   3. Never-processed mints (processCount == 0) вҖ” first-evaluation
//      priority so we don't sit on stale candidates.
//   4. Stale mints (oldest lastProcessedAt) вҖ” round-robin coverage of
//      the cold tail. ~1/3 of the tail per cycle.
//
// Result: ~5-8s round-trip cycle, fresh mints every tick, full
// watchlist covered every 2-3 ticks.
val orderedMints: List<String> = selectOrderedMintsForCycle(forcedOpenMints, otherMintsDeduped, orderedMintsRaw)

val maxBatchMillis = if (cfg.paperMode) 15_000L else 25_000L
val perTokenTimeoutMs = if (cfg.paperMode) 1_200L else 2_500L
// V5.9.106: widen concurrency for fat watchlists. User logs showed
// processed=20 / total=64 (44 deferred per tick) вҖ” the existing caps
// couldn't keep up with the user's 50вҖ“100 token universe, so trades
// were being evaluated once every 2вҖ“3 ticks instead of every tick,
// slowing exits on fast-moving micro-caps.
// V5.9.162 вҖ” doubled again during bootstrap because the meme-trader
// volume test showed ~50% of tokens still deferred per tick at the
// V5.9.106 caps. On a ~100-token watchlist we want EVERY token
// evaluated EVERY tick, not every 2-3 ticks.
// V5.9.291 FIX: memeBootstrap must reflect the PERSISTED learning state, not just
// in-memory. In live mode after paper learning, getLearningProgress() uses the
// persisted trade count so this is now accurate. We also use ModeLeniency: if we
// have a proven edge we treat live the same as paper (wide-open concurrency) so
// the scanner doesn't get starved to a single token per cycle.
val memeBootstrap = try {
    val progress = com.lifecyclebot.v3.scoring.FluidLearningAI.getLearningProgress()
    val lenient = com.lifecyclebot.engine.ModeLeniency.useLenientGates(cfg.paperMode)
    // Use bootstrap-level concurrency whenever:
    //   a) We are in bootstrap phase (< 40% progress), OR
    //   b) We have a proven edge (lenient=true) вҖ” treat like paper, use wider parallelism
    progress < 0.40 || lenient
} catch (_: Exception) { false }
// V5.9.175 вҖ” doubled the concurrency caps AGAIN because user logs still showed
// "processed=24 total=70" (46 deferred). At 70 watchlist tokens the previous
// 24-parallel cap meant 3 batches Г— 2.5s вүҲ 7.5s, but with per-token timeouts
// and the 25s deadline a single slow fetch was burning whole batches. The
// new caps target EVERY token evaluated EVERY tick so fluid exits don't miss
// intra-tick moves on fast-moving micro-caps.
val maxParallel = if (memeBootstrap) {
    // V5.9.1026 вҖ” CAP AT 32 IN BOOTSTRAP MODE.
    //
    // V5.9.1073 uses 100 as the canonical supervisor range for a 50-100 token
    // watchlist. Operator V5.9.1025 snapshot showed the watchlist had
    // exploded to 1056 tokens (PumpPortal spam вҖ” e.g. 14Г— "egg" intaken
    // in 7 seconds, EGG 12Г—, Sharpton 9Г—) and EVERY supervisor chunk
    // reported processed=0 deferred=100.
    //
    // Root cause: 100-range async workers on Dispatchers.IO contend
    // for only 64 default IO threads, plus OkHttp's per-host connection
    // pool (~10). Many workers never even start running before the
    // 2.5s chunk budget expires вҖ” the harvest fix in V5.9.1025 confirmed
    // active=100 at every timeout (none completed).
    //
    // 32 parallel is plenty: 32 fits inside the IO pool, fits inside
    // typical OkHttp connection budgets, and lets each worker complete
    // a real processTokenCycle (Birdeye+Helius+V3+lane evals вүҲ 1.5-2s)
    // inside the chunk budget. 100 tokens вҶ’ bounded 100-slot supervisor = ~7.5s,
    // well within the 15s paper-mode batch deadline.
    when {
        orderedMints.size >= 80 -> 32
        orderedMints.size >= 60 -> 28
        orderedMints.size >= 40 -> 24
        orderedMints.size >= 20 -> 20
        orderedMints.size >= 12 -> 16
        orderedMints.size >= 6  -> 12
        else -> 6
    }
} else {
    when {
        orderedMints.size >= 60 -> 20
        orderedMints.size >= 40 -> 16
        orderedMints.size >= 20 -> 10
        orderedMints.size >= 12 -> 8
        orderedMints.size >= 6  -> 6
        else -> 4
    }
}

val batchDeadline = System.currentTimeMillis() + maxBatchMillis
var processedCount = 0
var deferredCount = 0

// V5.9.676 вҖ” phase breadcrumb before the parallel-supervisor scope. If
// the loop wedges INSIDE the supervisorScope, the heartbeat will see
// the last lifecycle event as PRE_SUPERVISOR and we know it's a
// per-token/network problem, not a regime/sentience/lab issue.
try {
  markProgress("PRE_SUPERVISOR")
  ForensicLogger.lifecycle(
    "CYCLE_PHASE",
    "loop=$loopCount phase=PRE_SUPERVISOR mints=${orderedMints.size}"
  )
} catch (_: Throwable) {}

// V5.9.1020 вҖ” HARD OUTER TIMEOUT WRAPPER + KILL THE LYING PROGRESS TICKER.
//
// Operator V5.9.1018c+V5.9.1019 snapshot (build 2974, uptime 563 s) STILL
// showed botLoop wedged in phase=SUPERVISOR for 652 s straight вҖ” no full
// cycle in 10+ minutes, no trades despite 350+ tokens in the watchlist
// and intake firing every few seconds.
//
// Root cause (triage agent confirmed):
//   1. The V5.9.935 progressTicker fires markProgress("SUPERVISOR") every
//      10 s UNCONDITIONALLY. This kept heartbeat's progressGap pinned at
//      5-9 s while the ACTUAL cycle stalled for 600+ s. The freeze
//      detector was LIED TO by the ticker вҖ” heartbeat rescue never fired
//      because by its measurement the loop looked alive.
//   2. The supervisorAbort check at the OLD line 9489 (`if elapsedMs >
//      maxBatchMillis + 2000 вҶ’ abort`) lived INSIDE the chunk forEach.
//      If the FIRST chunk hangs (which it does when Helius is 403'ed and
//      OkHttp blocks in JNI socket-read вҖ” withTimeoutOrNull cannot
//      interrupt native blocking calls), the forEach never advances to
//      the second iteration, so the abort check NEVER runs again.
//   3. V5.9.1012's detached GlobalScope.async workers don't help here:
//      jobs.awaitAll() inside withTimeoutOrNull DOES wake up on chunk
//      timeout BUT the cleanup path returns and the outer forEach
//      iterates to the next chunk only after the chunk's own try/finally
//      completes. If processTokenCycle is stuck in a non-cancellable
//      OkHttp socketRead, the Deferred's cancel() is a no-op until the
//      JVM gives up the native call. Net result: the forEach iteration
//      itself is blocked.
//
// Fix:
//   a. Wrap the entire SUPERVISOR run block in withTimeoutOrNull
//      (maxBatchMillis + 5_000L). This is a HARD UPPER BOUND вҖ” no matter
//      what happens inside, the bot loop is GUARANTEED to advance to
//      POST_SUPERVISOR within ~20 s. When the timeout fires, the
//      progressTicker is cancelled and the abandoned in-flight token
//      workers finish whenever they finish (they're detached, no
//      structured concurrency dependency).
//   b. Kill the progressTicker entirely. With (a) in place, heartbeat's
//      2-minute rescue ceiling now becomes the AUTHORITATIVE freeze
//      detector вҖ” if SUPERVISOR genuinely wedges, progressGap will
//      climb and heartbeat will fire rescue. No more lying.
//   c. Move the supervisorAbort elapsed check to the TOP of each
//      forEach iteration so it fires even if previous chunks took
//      multiple seconds each.
val supervisorOuterBudget = maxBatchMillis + 5_000L
// V5.9.1021 вҖ” SUPERVISOR phase extracted into runSupervisorPhase() to free
// botLoop's JVM 64 KB method-size budget. V5.9.1020's inline withTimeoutOrNull
// + hard-timeout-log pushed botLoop OVER the cap (release compile failed
// 'Method code too large'). The whole SUPERVISOR body now lives in a
// separate JVM method so its bytecode doesn't count toward botLoop's quota.
// V5.9.1037 вҖ” SILENT SUPERVISOR. The legacy runSupervisorPhase awaits
// per-chunk withTimeoutOrNull which was burning ~14s per cycle on
// SUPERVISOR_CHUNK_TIMEOUT (operator V5.9.1036 snapshot: 23 chunk timeouts
// in 150s, processed=0 deferred=100 every cycle). Workers ALREADY run on
// detached GlobalScope.async(Dispatchers.IO) вҖ” the bot loop's await was
// pure dead waiting, since `processed/deferred` only feed log strings and
// no downstream control flow depends on them. fireSupervisorWorkers spawns
// workers via GlobalScope.launch (no await), bounds in-flight concurrency
// via supervisorActive counter, and returns immediately. Workers complete
// in their own time silently. The bot loop now sees ~0ms supervisor cost.
val supRes = fireSupervisorWorkers(
    orderedMints = orderedMints,
    cfg = cfg,
    wallet = wallet,
    lastSuccessfulPollMs = lastSuccessfulPollMs,
    loopCount = loopCount,
)
processedCount += supRes.processed
deferredCount += supRes.deferred

if (deferredCount > 0) {
    addLog("вҸ° Watchlist load high - deferred $deferredCount token(s) to next cycle")
    ErrorLogger.warn(
        "BotService",
        "Watchlist processing deferred $deferredCount token(s); processed=$processedCount total=${orderedMints.size}"
    )
}

// V5.9.682 вҖ” POST_SUPERVISOR breadcrumb. Operator dump V5.9.681 showed
// cycle 2 took 33s and cycle 3 wedged. With only PRE_SUPERVISOR and
// CYCLE_EXIT we cannot tell whether the freeze is inside the
// supervisorScope (per-token network) or in the EXIT_SWEEP /
// reconciler / mode-switch / persistence saves afterwards. This
// breadcrumb separates the two halves.
try {
    markProgress("POST_SUPERVISOR")
    ForensicLogger.lifecycle(
        "CYCLE_PHASE",
        "loop=$loopCount phase=POST_SUPERVISOR processed=$processedCount deferred=$deferredCount total=${orderedMints.size}"
    )
} catch (_: Throwable) {}

// V5.9.1009 вҖ” UNIVERSAL EXIT SWEEP enqueue only.
// Main botLoop must never block on exits. The previous synchronous call here
// entered sweepUniversalExits() вҶ’ executor.requestSell()/runManageOnly() вҶ’
// paperSell() heavy learning fanout, parking the cycle in POST_SUPERVISOR.
// openPositionTickLoop owns exit management; botLoop only requests a
// single-flight async sweep and immediately continues toward CYCLE_EXIT.
val postSupervisorOpenCount = try {
    synchronized(status.tokens) { status.tokens.values.count { isCapCountableLiveToken(it.mint, it) } }
} catch (_: Throwable) { 0 }
val postSupervisorNowMs = System.currentTimeMillis()
val postSupervisorBackupDue = (postSupervisorNowMs - lastPostSupervisorExitBackupMs) >= POST_SUPERVISOR_EXIT_BACKUP_MS
val tickExitSweepFresh = postSupervisorOpenCount > 0
// V5.9.1313 вҖ” HOT-EXIT LIVENESS GUARD (the real "it doesn't keep trading" fix).
// Detect a dead/stale hotExit (the 2s manager that owns runManageOnly вҶ’
// STRICT_SL / partials / profit lock / STALE_FEED_EVICT). lastTickExitSweepMs
// is bumped ONLY by a live hotExit. Operator log a6f08d82: open=10 pinned, age
// 7sвҶ’58s, zero sells/entries because exits were deferred to a dead manager.
// The heavy resurrect+force-sweep logic lives in maybeHealHotExit() (a plain
// member fun) so botLoop's coroutine state-machine stays small enough for the
// JVM back-end to transform (1313a: inlining it overflowed botLoop's method).
val hotExitHandledSweep = maybeHealHotExit(loopCount, postSupervisorOpenCount, postSupervisorNowMs)
if (hotExitHandledSweep) {
    // hotExit was stale вҖ” maybeHealHotExit resurrected it and forced the sweep.
} else if (postSupervisorOpenCount > 0 && !postSupervisorBackupDue) {
    // V5.9.1318 (Item 1) вҖ” normal deferral to the live hot-exit manager (NOT a stall;
    // maybeHealHotExit ran just above and force-resets if hot exit was actually stale).
    // Demoted from a per-loop lifecycle log to debug to stop the snapshot spam.
    ErrorLogger.debug("BotService", "exit deferred to live hotExit loop=$loopCount open=$postSupervisorOpenCount")
} else if (exitSweepInFlight.get()) {
    try {
        ForensicLogger.lifecycle(
            "POST_SUPERVISOR/EXIT_SWEEP_DEFERRED_INFLIGHT",
            "loop=$loopCount open=$postSupervisorOpenCount reason=inflight_no_force_reset"
        )
    } catch (_: Throwable) {}
} else {
    lastPostSupervisorExitBackupMs = postSupervisorNowMs
    try {
        ForensicLogger.lifecycle(
            "POST_SUPERVISOR/EXIT_SWEEP_BACKUP_ENQUEUED",
            "loop=$loopCount open=$postSupervisorOpenCount reason=stale_backup"
        )
    } catch (_: Throwable) {}
    launchExitSweepAsync("POST_SUPERVISOR_BACKUP")
}

            // V5.9.495z6 вҖ” WALLET RECONCILIATION (operator spec May 2026).
            // After all sub-trader cycles + universal exit sweep, sync the
            // PositionStore with the on-chain wallet truth. Recovers orphan
            // mints (positions=0 + ALREADY_OPEN drift bug) and closes
            // zombies (open position with zero wallet balance). Throttled
            // to every ~15s internally so calling every loop is fine.
            if (!cfg.paperMode) {
                wallet?.let { w ->
                    try {
                        WalletReconciler.reconcileWalletHoldings(status, w, isPaperMode = false)
                    } catch (e: Exception) {
                        ErrorLogger.debug("BotService", "WalletReconciler error: ${e.message?.take(80)}")
                    }
                }
            }
            // This runs during LIVE mode to learn from background paper trades
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.0.6073 вҖ” SHADOW ALWAYS-ON: runs behind BOTH paper and live
            // modes (was live-only + toggle-gated). Constant learning state.
            run {
                try {
                    // Pass current token states so shadow positions can get price updates
                    val tokenStatesCopy = synchronized(status.tokens) {
                        status.tokens.toMap()
                    }
                    executor.checkShadowPositions(tokenStatesCopy)
                } catch (e: Exception) {
                    ErrorLogger.debug("BotService", "Shadow position check error: ${e.message}")
                }
            }
            
            // HOT MODE SWITCH: Detect paperMode changes and propagate to all subsystems
            // This fixes the ghost-town bug where switching PAPERвҶ’LIVE left all
            // singletons still believing they were in paper mode.
            try { markProgress("POST_SUPERVISOR/CONFIG_RELOAD") } catch (_: Throwable) {}
            val loopCfg = ConfigStore.load(applicationContext)
            RuntimeModeAuthority.publishConfig(loopCfg.paperMode, loopCfg.autoTrade)
            // V5.9.1360 вҖ” P0.1 LIVE-MODE TRANSFER AUDIT. One diagnostic line per
            // loop tick whenever the UI has selected LIVE, so the live handoff is
            // never invisible: it prints the exact firstLiveBlocker (or NONE).
            // Observe-only; reads existing authorities/counters. Never throws.
            try {
                val wConn = try { walletManager.state.value.connectionState == WalletConnectionState.CONNECTED } catch (_: Throwable) { false }
                val wSol  = try { walletManager.state.value.solBalance } catch (_: Throwable) { 0.0 }
                val liveEnabled = loopCfg.autoTrade || loopCfg.cyclicTradeLiveEnabled
                LiveTransferAudit.emit(applicationContext, loopCfg.paperMode, wConn, wSol, liveEnabled)
            } catch (_: Throwable) {}
            val loopIsPaper = loopCfg.paperMode
            if (GlobalTradeRegistry.isPaperMode != loopIsPaper) {
                ErrorLogger.info("BotService", "рҹ”„ HOT MODE SWITCH DETECTED: paper=${GlobalTradeRegistry.isPaperMode} вҶ’ $loopIsPaper")
                GlobalTradeRegistry.isPaperMode = loopIsPaper
                UnifiedModeOrchestrator.isPaperMode = loopIsPaper
                EfficiencyLayer.isPaperMode = loopIsPaper
                FinalExecutionPermit.isPaperMode = loopIsPaper
                // Re-initialize V3 engine with new mode (hot-swap, preserves learning)
                if (loopCfg.v3EngineEnabled) {
                    com.lifecyclebot.v3.V3EngineManager.updateMode(loopCfg)
                }
                addLog("рҹ”„ Mode switched to ${if (loopIsPaper) "рҹ“қ PAPER" else "рҹ”ҙ LIVE"} вҖ” all AI layers updated")
            }

        // V5.9.998 вҖ” POST_SUPERVISOR WEDGE FIX (Doctrine #5 вҖ” high-latency
        // DB queries on background threads). Operator snapshot V5.9.997
        // showed loopCount=2 with avgCycleMs=4585 and a 92-second
        // progressGap in phase=POST_SUPERVISOR. Root cause traced: this
        // block runs FIVE synchronous prefs/disk writes on the bot-loop
        // thread (SessionStore.save + PositionPersistence.saveAllPositions
        // + CashGenerationAI.save + SmartSizer.save + BehaviorAI.save).
        // After V5.9.984-991 amnesia close, the persistence blob writes
        // got heavier (TRADE_LESSONS alone = 3500 records). At loopCount=6
        // these all fire back-to-back during POST_SUPERVISOR with no
        // intermediate progress markers вҶ’ loop heartbeat alarm fires вҶ’
        // operator sees "bot trades once then idles forever".
        //
        // Fix: dispatch all five saves to Dispatchers.IO. Each save is
        // already idempotent + throttled internally. Bump position-persist
        // cadence from every 6 loops to every 12 (still <60s with avg
        // cycle ~5s, well within crash-recovery RTO). Add markProgress
        // breadcrumbs so if anything else in this region stalls in the
        // future we can localise it.
        //
        // SAFETY: all five callees handle null ctx (return early), throttle
        // by SAVE_THROTTLE_MS, and catch their own exceptions. Dispatching
        // to IO is safe вҖ” saveAll() in LearningPersistence uses the same
        // pattern (line 94: GlobalScope.launch(Dispatchers.IO)).
        try { markProgress("POST_SUPERVISOR/PERSIST_QUEUE") } catch (_: Throwable) {}
        // Periodically persist session state - use synchronized copy
            val tradeCount = synchronized(status.tokens) {
                status.tokens.values.toList().sumOf { it.trades.size }
            }
            val shouldSaveSession = tradeCount % 5 == 0 && status.running
            // V5.9.998 вҖ” bumped throttle from %6 to %12. PositionPersistence
            // additionally has MIN_SAVE_INTERVAL_MS internal throttle.
            val shouldSavePositions = loopCount % 12 == 0
            if (shouldSaveSession || shouldSavePositions) {
                val tokensCopy = if (shouldSavePositions) {
                    synchronized(status.tokens) { status.tokens.toMap() }
                } else emptyMap()
                val ctxSnap = applicationContext
                val paperSnap = cfg.paperMode
                kotlinx.coroutines.GlobalScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    if (shouldSaveSession) {
                        try { SessionStore.save(ctxSnap, paperSnap) } catch (_: Exception) {}
                    }
                    if (shouldSavePositions) {
                        try {
                            PositionPersistence.saveAllPositions(tokensCopy)
                            com.lifecyclebot.v3.scoring.CashGenerationAI.save(force = true)
                            SmartSizer.save(force = true)
                            com.lifecyclebot.v3.scoring.BehaviorAI.save(force = true)
                        } catch (e: Exception) {
                            ErrorLogger.debug("BotService", "Position persistence save error: ${e.message}")
                        }
                    }
                }
            }
            try { markProgress("POST_SUPERVISOR/PERSIST_DISPATCHED") } catch (_: Throwable) {}
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // CYCLIC TRADE ENGINE вҖ” $5000 USD wallet-gated compound ring
            // V5.9.780a вҖ” extracted into maybeTickCyclicTradeEngine() so the
            // botLoop suspend state machine stays under the JVM 64 KB method
            // size limit. Gate logic identical: PAPER вҶ’ tick if CYCLIC enabled;
            // LIVE вҶ’ tick only if CYCLIC enabled AND walletUsd >= $5000.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            if (loopCount % 10 == 0) {
                maybeTickCyclicTradeEngine(wallet)
            }
            try { markProgress("POST_SUPERVISOR/CYCLIC_CHECK") } catch (_: Throwable) {}

            // V5.9.676 вҖ” final phase breadcrumb. If the loop wedges
            // here we'll see the last lifecycle event was CYCLE_EXIT,
            // proving the cycle body itself completed but delay() got
            // suspended (Doze or scope cancellation).
            try {
              val _cycleElapsedMs = System.currentTimeMillis() - _cycleStartMs
              try { supervisorNoteCycleElapsedForThrottle(_cycleElapsedMs) } catch (_: Throwable) {}
              markProgress("CYCLE_EXIT")
              ForensicLogger.lifecycle(
                "CYCLE_PHASE",
                "loop=$loopCount phase=CYCLE_EXIT elapsedMs=$_cycleElapsedMs"
              )
            } catch (_: Throwable) {}

            // V5.9.678 вҖ” UNIVERSAL SL SAFETY-NET SWEEP (P0 bug fix).
            // Operator screenshot showed paper positions at -98% / -90% /
            // -71% / -33% вҖ” all 50-80 percentage points past the configured
            // -20% SL. Root cause: the SHITCOIN exit branch requires
            // tradingMode=="SHITCOIN" and the MOONSHOT exit branch requires
            // tradingMode.startsWith("MOONSHOT"); positions whose mode tag
            // is null/empty (orphans loaded from disk, paper positions
            // hydrated without a tag, mode flipped to "" during SCвҶ’MS
            // promotion) hit NEITHER branch and sit forever at -98%. The
            // existing runFallbackSafetyExit() does exactly the right
            // delegation (lane checkExit if registered, -20% hard floor for
            // orphans) but was only invoked when DexScreener was down.
            // The sweep below runs once per cycle on ALL open positions
            // regardless of feed state. Kept OUT of processTokenCycle to
            // avoid blowing that function's JVM 64KB method-size cap.
            // V5.9.1019 вҖ” UNIVERSAL SL SWEEP MOVED OFF BOT LOOP THREAD.
            // The previous synchronous call iterated all open positions and
            // could trigger executor.requestSell() per match, dragging in
            // paperSell's full learning fanout. With 5-10 open positions
            // this could burn 30-50s of bot loop time PER CYCLE, matching
            // exactly the alternation pattern in operator V5.9.1018 snapshot
            // ([237, 8, 11531, 179, 18790, 54, 22674, 14, 44108, 575]ms).
            // Launch async with the proven V5.9.1010 single-flight + hard-
            // timeout-watchdog pattern so a stuck sell can never wedge the
            // gate or the loop again.
            markProgress("EXIT_SWEEP")
            if (postSupervisorOpenCount > 0 && !postSupervisorBackupDue) {
                // V5.9.1318 (Item 1) вҖ” universal SL must NEVER be indefinitely deferred to a
                // stale hot exit. maybeHealHotExit (above) already routes an INDEPENDENT
                // universal sweep through the single-owner coordinator the moment hot exit is
                // stale >10s. So this branch is just the normal short backup-window deferral
                // while hot exit is healthy вҖ” demoted to debug to stop per-loop spam.
                ErrorLogger.debug("BotService", "universalSL deferred (hotExit live) loop=$loopCount open=$postSupervisorOpenCount")
            } else if (slSafetyNetInFlight.get()) {
                try {
                    ForensicLogger.lifecycle(
                        "UNIVERSAL_SL_SWEEP_DEFERRED_INFLIGHT",
                        "loop=$loopCount open=$postSupervisorOpenCount reason=inflight_no_force_reset"
                    )
                } catch (_: Throwable) {}
            } else {
                launchUniversalSlSweepAsync(cfg, wallet)
            }
            markProgress("IDLE")  // V5.9.762 вҖ” between cycles is idle/safe-to-rescue.

            delay(cfg.pollSeconds * 1000L)
          } catch (ce: kotlinx.coroutines.CancellationException) {
            // V5.9.676 вҖ” DO NOT swallow CancellationException. The previous
            // catch (e: Exception) caught it (CE extends Exception in older
            // Kotlin) and re-entered delay(5000) вҖ” which threw another CE
            // вҖ” which the catch swallowed вҶ’ infinite resurrection loop.
            // That was a major contributor to the V5.9.675 rescue failing:
            // our cancel(CE) was caught by the old `catch (e: Exception)`,
            // logged as "Loop error", and the loop kept resurrecting itself.
            // Now we explicitly rethrow CE so the heartbeat's cancel() can
            // actually kill the coroutine and the rescue's relaunch succeeds.
            try {
              ForensicLogger.lifecycle(
                "BOTLOOP_CANCELLED",
                "loop=$loopCount msg=${ce.message?.take(80)}"
              )
            } catch (_: Throwable) {}
            throw ce
          } catch (e: Exception) {
            // Catch any crash in the main loop and log it
            addLog("вқҢ Loop error: ${e.message}")
            delay(5000) // wait 5 seconds before retrying
          }
        }
    }

    // в”Җв”Җ logging в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    /**
     * Aggressively clean up the watchlist to make room for new opportunities.
     * Removes tokens that are:
     * - Blocked by safety checker (rugcheck failed)
     * - Stale (no price updates)
     * - Dead (zero liquidity or volume)
     * - IDLE too long without getting a buy signal
     * - Underperforming (flat price with no buys)
     */
    /**
     * V5.9.494 вҖ” UNIVERSAL EXIT SWEEP.
     *
     * Operator: 'where are the fluid stops and dynamic profit lockers?
     * nothing should rip 35% out of us! ensure all trading tools layers
     * etc are wired correctly for live trading.'
     *
     * Runs at the end of every main loop tick. Hits two coverage gaps
     * that processTokenCycle leaves open:
     *
     *   1) CashGenerationAI Treasury positions whose mints aren't in
     *      status.tokens (or whose ts.position.isTreasuryPosition is
     *      stale). The treasury exit signal at line ~9246 only fires
     *      when ts is found AND tagged as treasury вҖ” for older bot
     *      restarts or sub-trader-private positions, that gate misses.
     *
     *   2) V3 lane open positions (status.tokens with isOpen=true)
     *      where the scanner stopped returning fresh quotes. The
     *      V5.9.426 fallback path catches some of these but doesn't
     *      run profit-lock or partial-sell logic вҖ” only hard SL.
     *
     * For (1) we ask CashGenerationAI for any non-HOLD signals and
     * route them through executor.requestSell, synthesising a
     * TokenState if the mint isn't in status.tokens.
     *
     * For (2) we iterate every open V3 position and call
     * executor.runManageOnly() which executes:
     *      checkProfitLock вҶ’ checkPartialSell вҶ’ riskCheck (fluid stops)
     * once. Cheap on the happy path (returns immediately if no
     * trigger), and finally fires the sells we keep missing.
     */

    /**
     * V5.9.634 вҖ” Freeze Detector + Cap Diagnostics
     *
     * Symptom this fixes: bot ramps to ~85 trades / 13 open then halts
     * entirely for 30+ minutes while PumpPortal intake is still flowing
     * and the scanner is alive. Either:
     *   (a) all sub-traders are silently rejecting every candidate
     *       (RejectStats from V5.9.633 will tell us which one), OR
     *   (b) every open position is stuck pendingVerify / dead and the
     *       per-lane concurrent cap is thus saturated, OR
     *   (c) some boolean flag (paused, halted, distrusted) flipped on
     *       and never flipped back.
     *
     * We track [CanonicalLearningCounters.executedTradesTotal] вҖ” if it
     * has not advanced for 3 minutes WHILE marketScanner != null AND
     * we have at least one open meme position, fire one automated
     * unfreeze. All actions are cheap and idempotent. Self-rate-limited
     * to one fire per 5 minutes.
     *
     * Extracted from botLoop in V5.9.634c so the loop stays under the
     * JVM 64KB per-method bytecode ceiling.
     */
    private suspend fun runFreezeDetectorTick(
        loopCount: Int,
        cfg: com.lifecyclebot.data.BotConfig,
    ) {
        try {
            val now = System.currentTimeMillis()
            val curExec = maxOf(
                com.lifecyclebot.engine.CanonicalLearningCounters.executedTradesTotal.get(),
                try { com.lifecyclebot.engine.TradeHistoryStore.getTradeCount24h().toLong() } catch (_: Throwable) { 0L }
            )
            if (curExec != freezeLastExecCount) {
                freezeLastExecCount = curExec
                freezeLastExecChangeMs = now
            }

            // в”Җв”Җ Cap diagnostics: per-lane open count + caps в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            val memeOpen = status.tokens.values.count { ts ->
                try { isCapCountableLiveToken(ts.mint, ts) } catch (_: Throwable) { false }
            }
            val memePending = status.tokens.values.count { ts ->
                try { ts.position.pendingVerify && ts.position.qtyToken > 0.0 } catch (_: Throwable) { false }
            }
            val memeCap = if (cfg.paperMode) cfg.maxConcurrentPositions else cfg.maxConcurrentLivePositions
            val cbState = try {
                if (::securityGuard.isInitialized) securityGuard.getCircuitBreakerState() else null
            } catch (_: Throwable) { null }
            val haltedTag = when {
                cbState == null              -> ""
                cbState.isHalted             -> " В· HALTED:${cbState.haltReason.take(30)}"
                cbState.consecutiveLosses>=3 -> " В· streak=${cbState.consecutiveLosses}"
                else                         -> ""
            }
            val freezeAgeSec = (now - freezeLastExecChangeMs) / 1000
            val capLine = "рҹӘӘ caps: meme=$memeOpen/$memeCap (pending=$memePending) В· execAge=${freezeAgeSec}s В· execTotal=$curExec$haltedTag"
            ErrorLogger.info("BotService", capLine)
            addLog(capLine)

            // в”Җв”Җ Freeze detector в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            val staleMs = now - freezeLastExecChangeMs
            val scannerAlive = marketScanner != null
            val haveOpens = memeOpen > 0
            val canFireAgain = (now - freezeRecoveryFiredAt) > 5 * 60_000L
            val freezeStaleThresholdMs = 3 * 60_000L
            val antiChokeSoftening = try { com.lifecyclebot.engine.AntiChokeManager.isSoftening() } catch (_: Throwable) { false }
            val tradeCount24h = try { com.lifecyclebot.engine.TradeHistoryStore.getTradeCount24h() } catch (_: Throwable) { 0 }
            val projectedOk = tradeCount24h >= 500
            if (staleMs > freezeStaleThresholdMs && scannerAlive && haveOpens && canFireAgain && antiChokeSoftening && !projectedOk) {
                freezeRecoveryFiredAt = now
                ErrorLogger.error("BotService",
                    "рҹ”“ FREEZE_DETECTOR: 0 executions in ${staleMs/1000}s while scanner alive + memeOpen=$memeOpen вҖ” running auto-unfreeze")
                addLog("рҹ”“ FREEZE_DETECTOR fired (${staleMs/1000}s stale) вҖ” auto-unfreezing")

                // 1) Reset scanner staleness in case it's silently
                //    paused on a saturated cooldown map.
                try { marketScanner?.checkAndResetIfStale() } catch (_: Throwable) {}

                // 2) Reconnect external streams (PumpPortal /
                //    DataOrchestrator / Pyth Hermes), fail-open.
                try { orchestrator?.reconnectStreams() } catch (_: Throwable) {}

                // 3) If SecurityGuard is halted from a stale streak,
                //    clear it. The next loss will re-halt it; we just
                //    don't want a permanent stuck halt blocking buys.
                try {
                    if (::securityGuard.isInitialized) {
                        val cb = securityGuard.getCircuitBreakerState()
                        if (cb.isHalted) {
                            ErrorLogger.warn("BotService",
                                "рҹ”“ FREEZE_DETECTOR: SecurityGuard halted (${cb.haltReason}) вҖ” clearing halt")
                            securityGuard.clearHalt()
                        }
                    }
                } catch (_: Throwable) {}

                // 4) V5.9.1169 вҖ” do NOT clear FinalDecisionGate learning state here.
                // This detector was firing during high-throughput/low-close windows
                // and wiping FDG memory, making entry quality worse. Real freeze
                // recovery restores plumbing only.

                // 5) Bump the AntiChokeManager.
                try {
                    com.lifecyclebot.engine.AntiChokeManager.tick(
                        isPaperMode = cfg.paperMode,
                        wallet      = wallet,
                        tokens      = status.tokens,
                        loopCount   = loopCount,
                    )
                } catch (_: Throwable) {}

                addLog("рҹ”“ FREEZE_DETECTOR: scanner reset В· streams reconnected В· halt cleared В· FDG memory preserved")
            }
        } catch (e: Exception) {
            ErrorLogger.debug("BotService", "Freeze detector tick error: ${e.message}")
        }
    }


    private data class ExitSweepSnapshot(
        val cfg: com.lifecyclebot.data.BotConfig?,
        val wallet: com.lifecyclebot.network.SolanaWallet?,
        val balance: Double,
    )

    private fun buildExitSweepSnapshot(): ExitSweepSnapshot {
        val cfgSnapshot = try { ConfigStore.load(applicationContext) } catch (_: Throwable) { null }
        val walletSnapshot = try { walletManager.getWallet() } catch (_: Throwable) { null }
        val balanceSnapshot = try {
            cfgSnapshot?.let { status.getEffectiveBalance(it.paperMode) } ?: 0.0
        } catch (_: Throwable) { 0.0 }
        return ExitSweepSnapshot(cfgSnapshot, walletSnapshot, balanceSnapshot)
    }

    private fun requestExitSweepCoordinator(reason: String, full: Boolean, universal: Boolean) {
        try {
            // V5.9.1361 P0.6 вҖ” count requests that collapse into an already-pending
            // bit (no new work admitted) so the operator can see how much of the old
            // "skip pressure" was just benign request coalescing, not choked exits.
            if (full && fullExitSweepPending.get()) {
                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("EXIT_COORD_BACKUP_DEDUPE") } catch (_: Throwable) {}
            }
            if (universal && universalSlSweepPending.get()) {
                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("EXIT_COORD_BACKUP_DEDUPE") } catch (_: Throwable) {}
            }
            if (full) fullExitSweepPending.set(true)
            if (universal) universalSlSweepPending.set(true)
            ForensicLogger.lifecycle(
                "EXIT_COORDINATOR_REQUESTED",
                "reason=$reason full=$full universal=$universal pendingFull=${fullExitSweepPending.get()} pendingUniversal=${universalSlSweepPending.get()}"
            )
        } catch (_: Throwable) {}
        ensureExitSweepCoordinator()
    }

    private fun ensureExitSweepCoordinator() {
        val existing = exitSweepCoordinatorJob
        if (existing?.isActive == true) return
        synchronized(exitSweepCoordinatorLock) {
            val again = exitSweepCoordinatorJob
            if (again?.isActive == true) return
            exitSweepCoordinatorJob = scope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try { ForensicLogger.lifecycle("EXIT_COORDINATOR_STARTED", "thread=io") } catch (_: Throwable) {}
                while (status.running) {
                    try {
                        val now = System.currentTimeMillis()
                        // V5.9.1361 P0.6 вҖ” DEDUPE-PRESERVING DRAIN. The old code did
                        // getAndSet(false) on the pending flag BEFORE the rate-limit
                        // check, so a request arriving inside the 30s window cleared the
                        // pending bit and was silently DROPPED вҖ” a genuinely-needed sweep
                        // could be lost until the next unrelated request happened to land.
                        // Now we PEEK the pending flag; we only consume (clear) it when we
                        // actually service the sweep. If rate-limited, the pending bit
                        // stays set so the sweep fires the instant the window opens вҖ”
                        // deterministic, no lost requests. Repeated requests while one is
                        // already pending collapse into the single pending bit
                        // (EXIT_COORD_BACKUP_DEDUPE) instead of spamming skips.
                        val wantsFull = fullExitSweepPending.get()
                        val wantsUniversal = universalSlSweepPending.get()
                        var didWork = false

                        if (wantsFull) {
                            val age = now - exitCoordinatorLastFullMs.get()
                            if (age >= EXIT_COORDINATOR_FULL_MIN_MS) {
                                fullExitSweepPending.set(false)  // consume only on service
                                exitCoordinatorLastFullMs.set(now)
                                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("EXIT_COORD_LOCK_HELD_MS_FULL_${minOf(age/1000L,99L)}s") } catch (_: Throwable) {}
                                val snap = buildExitSweepSnapshot()
                                if (snap.cfg != null) {
                                    didWork = true
                                    try { ForensicLogger.lifecycle("EXIT_COORDINATOR_FULL_START", "ageMs=$age") } catch (_: Throwable) {}
                                    try { sweepUniversalExits(snap.cfg, snap.wallet, snap.balance) }
                                    catch (t: Throwable) { ErrorLogger.warn("BotService", "exit coordinator full sweep error: ${t.message}") }
                                    try { ForensicLogger.lifecycle("EXIT_COORDINATOR_FULL_DONE", "ageMs=$age") } catch (_: Throwable) {}
                                    // V5.9.1470 (spec item 4) вҖ” a successful coordinator sweep
                                    // IS exit protection running. Advance the hot-exit heartbeat
                                    // so maybeHealHotExit stops re-firing STALE_RESET when the
                                    // 2s hot manager is the wedged component (root of resets=10).
                                    lastTickExitSweepMs = System.currentTimeMillis()
                                } else {
                                    try { ForensicLogger.lifecycle("EXIT_COORDINATOR_FULL_SKIPPED", "reason=cfg_null") } catch (_: Throwable) {}
                                }
                            } else {
                                // V5.9.1361 P0.6 вҖ” rate-limited: pending bit STAYS set (the
                                // sweep will fire the instant the 30s window opens). Replace
                                // the per-tick lifecycle spam with a single skip-reason
                                // counter so the dump stays readable.
                                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("EXIT_COORD_SKIP_REASON_FULL_RATE_LIMITED") } catch (_: Throwable) {}
                            }
                        }

                        if (wantsUniversal) {
                            val age = now - exitCoordinatorLastUniversalMs.get()
                            if (age >= EXIT_COORDINATOR_UNIVERSAL_MIN_MS) {
                                universalSlSweepPending.set(false)  // consume only on service
                                exitCoordinatorLastUniversalMs.set(now)
                                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("EXIT_COORD_LOCK_HELD_MS_UNIVERSAL_${minOf(age/1000L,99L)}s") } catch (_: Throwable) {}
                                val snap = buildExitSweepSnapshot()
                                if (snap.cfg != null) {
                                    didWork = true
                                    try { ForensicLogger.lifecycle("EXIT_COORDINATOR_UNIVERSAL_START", "ageMs=$age") } catch (_: Throwable) {}
                                    try { runUniversalSlSafetyNetSweep(snap.cfg, snap.wallet) }
                                    catch (t: Throwable) { ErrorLogger.warn("BotService", "exit coordinator universal sweep error: ${t.message}") }
                                    try { ForensicLogger.lifecycle("EXIT_COORDINATOR_UNIVERSAL_DONE", "ageMs=$age") } catch (_: Throwable) {}
                                    // V5.9.1470 (spec item 4) вҖ” universal SL sweep also counts as
                                    // exit protection; advance the heartbeat (see FULL_DONE note).
                                    lastTickExitSweepMs = System.currentTimeMillis()
                                } else {
                                    try { ForensicLogger.lifecycle("EXIT_COORDINATOR_UNIVERSAL_SKIPPED", "reason=cfg_null") } catch (_: Throwable) {}
                                }
                            } else {
                                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("EXIT_COORD_SKIP_REASON_UNIVERSAL_RATE_LIMITED") } catch (_: Throwable) {}
                            }
                        }

                        kotlinx.coroutines.delay(if (didWork) 250L else 750L)
                    } catch (ce: kotlinx.coroutines.CancellationException) {
                        throw ce
                    } catch (t: Throwable) {
                        ErrorLogger.debug("BotService", "exit coordinator loop error: ${t.message}")
                        try { kotlinx.coroutines.delay(1_000L) } catch (_: Throwable) { break }
                    }
                }
                try { ForensicLogger.lifecycle("EXIT_COORDINATOR_STOPPED", "running=${status.running}") } catch (_: Throwable) {}
            }
        }
    }

    private fun launchExitSweepAsync(reason: String) {
        // V5.9.1198 вҖ” request-only shim. Heavy full sweeps are owned by the
        // off-loop coordinator above; callers never spawn/reset workers directly.
        requestExitSweepCoordinator(reason = reason, full = true, universal = false)
    }


    /**
     * V5.9.1021 вҖ” SUPERVISOR phase extracted from botLoop to free its
     * JVM 64 KB method-size budget. V5.9.1020's inline withTimeoutOrNull
     * + hard-timeout-log pushed botLoop OVER the cap (release compile
     * failed with 'Method code too large'). The whole SUPERVISOR body
     * now lives in a separate JVM method.
     *
     * Behaviour-equivalent to the V5.9.1020 inline block:
     *   вҖў Hard outer time fence via withTimeoutOrNull(supervisorOuterBudget)
     *     guarantees botLoop advances within ~maxBatchMillis+5s.
     *   вҖў Chunked iteration with detached GlobalScope.async per-token
     *     workers (V5.9.1012) and per-chunk withTimeoutOrNull (V5.9.914).
     *   вҖў Per-iteration supervisorAbort elapsed check (V5.9.1020 fix).
     *   вҖў markProgress("SUPERVISOR") between chunks (no lying progress
     *     ticker, V5.9.1020).
     *   вҖў Forensic events: SUPERVISOR_OUTER_TIMEOUT, SUPERVISOR_CHUNK_TIMEOUT,
     *     SUPERVISOR_HARD_TIMEOUT.
     *
     * Returns SupervisorPhaseResult(processed, deferred, hardTimedOut).
     */
    private suspend fun runSupervisorPhase(
        orderedMints: List<String>,
        maxParallel: Int,
        perTokenTimeoutMs: Long,
        maxBatchMillis: Long,
        supervisorOuterBudget: Long,
        batchDeadline: Long,
        cycleStartMs: Long,
        loopCount: Int,
        cfg: com.lifecyclebot.data.BotConfig,
        wallet: com.lifecyclebot.network.SolanaWallet?,
        lastSuccessfulPollMs: Long,
    ): SupervisorPhaseResult {
        var processed = 0
        var deferred = 0
        val completed = kotlinx.coroutines.withTimeoutOrNull(supervisorOuterBudget) {
            markProgress("SUPERVISOR")
            var supervisorAbort = false
            orderedMints.chunked(maxParallel).forEach inner@ { chunk ->
                if (supervisorAbort) return@inner
                val supervisorElapsedMs = System.currentTimeMillis() - cycleStartMs
                if (supervisorElapsedMs > maxBatchMillis + 2_000L) {
                    deferred += (orderedMints.size - processed - deferred).coerceAtLeast(0)
                    supervisorAbort = true
                    try {
                        ForensicLogger.lifecycle(
                            "SUPERVISOR_OUTER_TIMEOUT",
                            "loop=$loopCount elapsedMs=$supervisorElapsedMs processed=$processed deferred=$deferred total=${orderedMints.size}"
                        )
                    } catch (_: Throwable) {}
                    return@inner
                }
                if (!status.running) {
                    supervisorAbort = true
                    return@inner
                }
                val timeLeft = batchDeadline - System.currentTimeMillis()
                if (timeLeft <= 250L) {
                    deferred += (orderedMints.size - processed - deferred).coerceAtLeast(0)
                    supervisorAbort = true
                    return@inner
                }
                val jobs = chunk.map { mint ->
                    // V5.9.1557 вҖ” bounded structured workers. Detached GlobalScope
                    // supervisor workers could outlive the chunk timeout and keep
                    // mutating lane/FDG state after the cycle moved on.
                    async(kotlinx.coroutines.Dispatchers.IO) {
                        try {
                            if (!status.running) return@async false
                            if (orchestrator?.shouldPoll(mint) == false) return@async false
                            val cycleCfg = cfg.copy(paperMode = try { RuntimeModeAuthority.isPaper() } catch (_: Throwable) { cfg.paperMode })
                            processTokenCycle(mint, cycleCfg, wallet, lastSuccessfulPollMs)
                            try { GlobalTradeRegistry.markProcessed(mint) } catch (_: Throwable) {}
                            true
                        } catch (ce: kotlinx.coroutines.CancellationException) {
                            false
                        } catch (t: Throwable) {
                            ErrorLogger.debug("BotService", "Supervisor token worker failed ${mint.take(8)}: ${t.message}")
                            false
                        }
                    }
                }
                val chunkBudgetMs = minOf(
                    // V5.9.1029 вҖ” WIDEN CHUNK BUDGET to fix supervisor freeze.
                    // Operator V5.9.1028b snapshot showed processed=0 deferred=100
                    // on EVERY supervisor cycle (237Г— SUPERVISOR_CHUNK_TIMEOUT in
                    // 1041s) вҖ” the harvest fix from V5.9.1025 wasn't enough because
                    // the 2.5s floor was simply TOO TIGHT for 32 parallel workers
                    // each running processTokenCycle (V3 + safety + lane evals +
                    // sometimes a 300-700ms network call). Every chunk hit
                    // active=32 (no worker completed in 2.5s) вҶ’ harvest returned 0.
                    //
                    // Widened to 4.5s floor (was 2.5s). At maxBatchMillis=15s
                    // (paper) we still fit 3 chunks Г— 4.5s = 13.5s inside the
                    // batch deadline. perTokenTimeoutMs * 4 = 4800ms (paper) /
                    // 10000ms (live) as the multiplier-driven ceiling.
                    (perTokenTimeoutMs * 4L).coerceAtLeast(4_500L),
                    (batchDeadline - System.currentTimeMillis()).coerceAtLeast(750L)
                )
                // V5.9.1025 вҖ” HARVEST COMPLETED WORK ON CHUNK TIMEOUT.
                //
                // Operator V5.9.1024 snapshot showed processed=0 deferred=100
                // EVERY supervisor cycle, even though DexScreener was at 99%
                // SR and individual `processTokenCycle` calls were obviously
                // fast (trades were happening via the SCAN_CB direct path).
                //
                // Old failure path: `withTimeoutOrNull { jobs.awaitAll() } ?:
                // List(jobs.size) { false }` вҖ” if even ONE legacy job wedged
                // past the 2.5s budget, awaitAll() returned null and the whole legacy chunk
                // were marked deferred, throwing away the 95+ that actually
                // completed. With 720 tokens in the watchlist, NONE were
                // ever re-evaluated by the supervisor вҖ” every chunk lost
                // 100% of its work to a single straggler.
                //
                // New: still bound the chunk by withTimeoutOrNull, but after
                // it returns (success OR timeout) iterate jobs and harvest
                // each one's completion state independently. Completed jobs
                // contribute their bool result (processed++). Cancelled jobs
                // count as deferred. Stragglers still active after the
                // timeout get cancelled + marked deferred.
                val chunkTimedOut: Boolean = kotlinx.coroutines.withTimeoutOrNull(chunkBudgetMs) {
                    jobs.awaitAll()
                } == null
                if (chunkTimedOut) {
                    val activeStragglers = try { jobs.count { it.isActive } } catch (_: Throwable) { -1 }
                    ErrorLogger.warn(
                        "BotService",
                        "Supervisor detached chunk timeout after ${chunkBudgetMs}ms вҖ” abandoning $activeStragglers straggler(s); harvesting completed"
                    )
                    try {
                        ForensicLogger.lifecycle(
                            "SUPERVISOR_CHUNK_TIMEOUT",
                            "loop=$loopCount chunk=${chunk.size} active=$activeStragglers budgetMs=$chunkBudgetMs"
                        )
                    } catch (_: Throwable) {}
                }
                val chunkResults: List<Boolean> = jobs.map { j ->
                    when {
                        j.isCancelled -> false
                        j.isCompleted -> try { j.await() } catch (_: Throwable) { false }
                        else -> {
                            try { j.cancel(kotlinx.coroutines.CancellationException("supervisor chunk timeout")) } catch (_: Throwable) {}
                            false
                        }
                    }
                }
                chunkResults.forEach { ok ->
                    if (ok) processed++ else deferred++
                }
                try { markProgress("SUPERVISOR") } catch (_: Throwable) {}
            }
            Unit
        }
        val hardTimedOut = (completed == null)
        if (hardTimedOut) {
            val elapsed = System.currentTimeMillis() - cycleStartMs
            deferred += (orderedMints.size - processed - deferred).coerceAtLeast(0)
            try {
                ForensicLogger.lifecycle(
                    "SUPERVISOR_HARD_TIMEOUT",
                    "loop=$loopCount elapsedMs=$elapsed budgetMs=$supervisorOuterBudget processed=$processed deferred=$deferred total=${orderedMints.size}"
                )
            } catch (_: Throwable) {}
            ErrorLogger.warn(
                "BotService",
                "рҹҡЁ SUPERVISOR hard-timeout after ${elapsed}ms (budget=${supervisorOuterBudget}ms) вҖ” forcing cycle advance; ${orderedMints.size - processed} token(s) deferred"
            )
        }
        return SupervisorPhaseResult(processed, deferred, hardTimedOut)
    }

    /** V5.9.1021 вҖ” result of runSupervisorPhase. */
    private data class SupervisorPhaseResult(
        val processed: Int,
        val deferred: Int,
        val hardTimedOut: Boolean,
    )

    // V5.9.1037 вҖ” SILENT SUPERVISOR concurrency state. Workers tally
    // themselves via these atomics; the bot loop no longer awaits.
    private val supervisorActive = java.util.concurrent.atomic.AtomicInteger(0)
    private val supervisorLifetimeSpawned = java.util.concurrent.atomic.AtomicLong(0)
    private val supervisorLifetimeProcessed = java.util.concurrent.atomic.AtomicLong(0)
    private val supervisorLifetimeSkipped = java.util.concurrent.atomic.AtomicLong(0)
    // V5.9.1039 вҖ” added in response to operator V5.9.1038 4h-uptime dump
    // showing the silent supervisor pool permanently saturated by hung
    // workers. Counts workers that hit the per-worker withTimeoutOrNull
    // budget вҖ” surfaces stuck APIs at a glance.
    private val supervisorLifetimeWorkerTimeouts = java.util.concurrent.atomic.AtomicLong(0)

    // V5.9.1077 вҖ” supervisor slots are leases, not a blind counter.
    // Operator log showed the ghost-death pattern:
    //   SUPERVISOR_INFLIGHT_CAP loop=43 spawned=0 skipped=100 active=100 cap=100
    // even while BOT_LOOP_TICK continued. The old AtomicInteger counted acquired
    // slots but had no identity/age; if a watchdog/release coroutine was delayed,
    // or the next 5s loop arrived before the 5.5s release, the whole next cycle
    // saw cap-full and processed zero tokens. Leases expire by wall-clock before
    // acquire, so stale/dead workers cannot monopolize capacity.
    // V5.9.1470 (spec item 6) вҖ” leases now carry a ref to their worker job so a
    // force-release can CANCEL the underlying coroutine, not just drop the lease
    // record. A worker that keeps running after force-release can re-add stale state
    // and cause ghost opens вҖ” exactly the storm the operator observed.
    private data class SupervisorLease(
        val mint: String,
        val startedMs: Long,
        val jobRef: java.util.concurrent.atomic.AtomicReference<kotlinx.coroutines.Job?> =
            java.util.concurrent.atomic.AtomicReference(null),
    )
    private val supervisorLeaseSeq = java.util.concurrent.atomic.AtomicLong(0)
    private val supervisorLeases = java.util.concurrent.ConcurrentHashMap<Long, SupervisorLease>()
    private val supervisorLifetimeExpiredLeases = java.util.concurrent.atomic.AtomicLong(0)
    // Must be < 5s bot cadence so the next cycle is never fully starved by the
    // prior cycle's timed workers. processTokenCycle may continue in background,
    // but its supervisor slot lease has expired and capacity is returned.
    // V5.9.1415 вҖ” TTL must be a BACKSTOP above the worker timeout, not a racer
    // below it. The old 4750ms TTL fired before the 5000ms worker budget, so the
    // acquire-time prune released slots whose workers were still legitimately
    // running inside budget вҖ” re-creating the over-admission the watchdog fix
    // closes. Set TTL = worker timeout + grace so a lease is only TTL-pruned if
    // its worker has genuinely overrun (and the safety-net watchdog will have
    // cancelled it). Slots still free within ~5.75s worst case; the bot loop
    // (5s cadence) is never starved because admission is per-cycle and the cap
    // is 32 of a ~300 universe.
    private val SUPERVISOR_LEASE_TTL_MS: Long = 6_000L
    // Back-pressure: if the underlying IO is wedged, don't launch another full
    // 100 workers every 5s forever. This still preserves throughput while avoiding
    // runaway thread/network pressure.
    // V5.9.1319 (Item 3) вҖ” bounded supervisor worker pool. The old 140 firehose
    // admitted far more work than the IO layer could drain (operator: workerTimeout=351,
    // expiredLeases=24, maxCycleMs=57807). Base cap lowered to 32 (bounded but still well
    // above the spec's 16 floor, so the 500-1000/day doctrine is preserved on a ~300 watchlist).
    // V5.9.1445 вҖ” 32->48. THIS is the real enforced supervisor cap (returned by
    // supervisorEffectiveCap); SUPERVISOR_MAX_INFLIGHT=96 is cosmetic/unused (only
    // printed in logs). 5.0.3447 snapshot: mints=96 every cycle, spawned=32
    // skipped=64 вҖ” exactly 64 mints DEFERRED every cycle because the real cap was
    // 32, parking throughput at ~140 trades. 48 still fits inside the 64-thread
    // Dispatchers.IO pool (+OkHttp per-host pool) with headroom, lifting per-cycle
    // coverage 50% without the 100-worker IO-starvation the V5.9.1026 cap guarded
    // against. Paired with the 5s->8s worker-timeout widen so admitted workers
    // actually complete instead of being force-released mid-flight.
    private val SUPERVISOR_BASE_MAX_WORKERS: Int = 48
    // Emergency throttle target вҖ” effective cap drops to this on sustained overload.
    private val SUPERVISOR_EMERGENCY_MAX_WORKERS: Int = 16
    @Volatile private var supervisorEmergencyThrottleUntilMs: Long = 0L
    // V5.9.1470 (spec item 5) вҖ” BOUNDED BACKPRESSURE + COOLING (replaces observation-only).
    // The operator snapshot shows worker_timeout >2000/10min while the throttle was pure
    // observation, so a lease-storm could run unbounded (FORCE_RELEASED=5620). The 1332
    // removal was right to kill the BLUNT cap=16 pin, but the correct answer is GRADUATED
    // backpressure that scales with the actual timeout rate and self-heals fast вҖ” NOT a
    // 5-minute hard pin. COOLING never disables lanes/learning/probing; it only trims the
    // CONCURRENT worker cap so wedged IO stops compounding, and exits run on their own
    // dispatcher (unaffected). Floor is 8 so the pool never fully stalls.
    @Volatile private var supervisorCoolingUntilMs: Long = 0L
    // V5.9.1470b (spec item 7) вҖ” extracted from botLoop to keep that coroutine method
    // under the JVM bytecode size limit. Publishes live slot-health for SlotHealthGate
    // so TradeAuthorizer can defer (not block) new buys while slots are dirty. Pure
    // telemetry: never gates here, never touches positions/balances/exits.
    // V5.9.1470b вҖ” extracted ghost reaper (keeps botLoop under JVM method-size limit).
    // Reaps mints the close ledger marks CLOSED from forcedOpen BEFORE PRE_SUPERVISOR so
    // closed positions stop holding slots/priority, and releases their sell/supervisor
    // locks. Held positions are never in the close ledger, so they are never reaped.
    // V5.9.1470d вҖ” extracted periodic-reconcile + phantom-sweep from botLoop to free
    // bytecode (botLoop was at the JVM 64KB per-method ceiling). Behaviour unchanged:
    // rescueOnly uses the live singleton wallet for paper-mode pending-verify rescue;
    // otherwise the live-session wallet. Runs off-loop on Dispatchers.IO. Never mutates
    // balances/positions here beyond what StartupReconciler/phantom-sweep already did.
    private fun launchPeriodicReconcile(rescueOnly: Boolean, wallet: SolanaWallet?) {
        val singletonWallet = try { WalletManager.getWallet() } catch (_: Throwable) { null }
        kotlinx.coroutines.GlobalScope.launch(kotlinx.coroutines.Dispatchers.IO) {
            try {
                val w = if (rescueOnly) singletonWallet else wallet
                if (w != null && w.publicKeyB58.isNotEmpty()) {
                    if (rescueOnly) {
                        addLog("рҹӣҹ PAPER-MODE PENDING-VERIFY RESCUE вҖ” running reconcile against live wallet to promote stuck positions")
                    }
                    val r = com.lifecyclebot.engine.StartupReconciler(
                        wallet = w,
                        status = status,
                        onLog = { msg -> addLog("[reconcile] $msg") },
                        onAlert = { title, body ->
                            ErrorLogger.info("BotService", "вҡ пёҸ $title вҖ” $body")
                        },
                        executor = executor,
                        autoSellOrphans = false,
                    )
                    r.reconcile()
                    // V5.9.493 вҖ” PHANTOM SWEEP for sub-trader stores (Treasury/ShitCoin/
                    // Quality/BlueChip/Moonshot keep positions in their own maps).
                    try {
                        val accounts = w.getTokenAccountsWithDecimalsBounded()
                        val walletMints = accounts
                            .filter { (_, v) -> v.first > 0.0 }
                            .keys
                        val cleared = com.lifecyclebot.v3.scoring.CashGenerationAI
                            .sweepPhantoms(walletMints)
                        if (cleared > 0) {
                            addLog("рҹ§№ Treasury phantom sweep: cleared $cleared stale position(s)")
                        }
                    } catch (e: Exception) {
                        ErrorLogger.warn("BotService", "Phantom sweep error: ${e.message}")
                    }
                }
            } catch (e: Exception) {
                ErrorLogger.warn("BotService", "Periodic reconcile error: ${e.message}")
            }
        }
    }

    /**
     * V5.9.1475 (spec item 3) вҖ” CANONICAL GHOST PREDICATE. A mint in the
     * forcedOpen set is a GHOST (not a real open slot) when ANY of:
     *   - close ledger marks it CLOSED, OR
     *   - no live TokenState position is open AND it is not held in any
     *     sub-trader store (i.e. the open record has vanished but the slot
     *     is still pinned).
     * This is stricter than the old isClosed-only check, which let
     * sell-completed / sell-lock-released / vanished-open mints keep
     * counting as ghosts forever (ghost=11 while forced=4). Held positions
     * (real open in a store) are NEVER ghosts.
     */
    private fun isGhostMint(mint: String, liveOpenSet: Set<String>): Boolean {
        if (com.lifecyclebot.engine.PositionCloseLedger.isClosed(mint)) return true
        // If nothing anywhere reports this mint as a live open, the slot is stale.
        if (mint !in liveOpenSet) return true
        return false
    }

    private fun currentPaperOpenMintsFromLedger(): Set<String> {
        return try {
            val out = HashSet<String>()
            synchronized(status.tokens) {
                status.tokens.values.forEach { ts ->
                    val p = ts.position
                    if (p.isPaperPosition) {
                        val dust = p.qtyToken <= 1e-12 || p.costSol <= 0.000_001
                        if (dust && (p.qtyToken > 0.0 || p.costSol > 0.0)) {
                            try { ts.position = com.lifecyclebot.data.Position() } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.PositionPersistence.removePosition(ts.mint) } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.PositionCloseLedger.markClosed(ts.mint, "PAPER_SLOT_DUST_CLOSED", 0) } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.PaperPositionCloseAuthority.markClosed("PAPER", ts.mint, ts.symbol, "PAPER_SLOT_DUST_CLOSED") } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("PAPER_FORCED_ROW_CLEARED_DUST") } catch (_: Throwable) {}
                            try { ForensicLogger.lifecycle("PAPER_FORCED_ROW_CLEARED_DUST", "mint=${ts.mint.take(10)} symbol=${ts.symbol} qty=${p.qtyToken} cost=${p.costSol}") } catch (_: Throwable) {}
                        } else if (p.qtyToken > 1e-12 && p.costSol > 0.0 && p.isOpen && !com.lifecyclebot.engine.PositionCloseLedger.isClosed(ts.mint)) {
                            out.add(ts.mint)
                        }
                    }
                }
            }
            out
        } catch (_: Throwable) { emptySet() }
    }

    private fun rebuildPaperForcedOpenFromLedger(): List<String> {
        val open = currentPaperOpenMintsFromLedger()
        try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("PAPER_SLOT_HEALTH_REBUILT_FROM_LEDGER") } catch (_: Throwable) {}
        try { ForensicLogger.lifecycle("PAPER_SLOT_HEALTH_REBUILT_FROM_LEDGER", "open=${open.size} mints=${open.take(8).joinToString(",") { it.take(8) }}") } catch (_: Throwable) {}
        return open.toList()
    }

    private fun reapPaperForcedOpen(forcedOpenRaw: List<String>): List<String> {
        try { com.lifecyclebot.engine.PositionCloseLedger.prune() } catch (_: Throwable) {}
        val paperOpen = currentPaperOpenMintsFromLedger()
        val clean = forcedOpenRaw.filter { mint ->
            val closed = try { com.lifecyclebot.engine.PositionCloseLedger.isClosed(mint) } catch (_: Throwable) { false }
            val isOpen = mint in paperOpen
            if (closed) {
                try { ForensicLogger.lifecycle("PAPER_FORCED_ROW_CLEARED_CLOSED_LEDGER", "mint=${mint.take(10)}") } catch (_: Throwable) {}
                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("PAPER_FORCED_ROW_CLEARED_CLOSED_LEDGER") } catch (_: Throwable) {}
                false
            } else if (!isOpen) {
                try { ForensicLogger.lifecycle("PAPER_FORCED_ROW_CLEARED_NOT_OPEN", "mint=${mint.take(10)}") } catch (_: Throwable) {}
                try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("PAPER_FORCED_ROW_CLEARED_NOT_OPEN") } catch (_: Throwable) {}
                try { com.lifecyclebot.engine.Executor.releasePaperSellLock(mint) } catch (_: Throwable) {}
                try { supervisorForceReleaseLeaseAndCancel(mint, "PAPER_FORCED_ROW_NOT_OPEN") } catch (_: Throwable) {}
                false
            } else true
        }
        if (clean.size != forcedOpenRaw.size || clean.size == paperOpen.size) {
            try { ForensicLogger.lifecycle("PAPER_SLOT_OPEN_RECONCILED", "raw=${forcedOpenRaw.size} clean=${clean.size} ledger=${paperOpen.size}") } catch (_: Throwable) {}
            try { com.lifecyclebot.engine.PipelineHealthCollector.labelInc("PAPER_SLOT_OPEN_RECONCILED") } catch (_: Throwable) {}
        }
        lastReapLiveOpenSet = paperOpen
        return clean.distinct()
    }


    /** V5.9.1567 вҖ” keep sub-trader forced-open collection out of botLoop bytecode. */
