        return try {
            val out = mutableSetOf<String>()
            // V5.9.610/1565 вҖ” universal open-position coverage across all sub-trader stores.
            try { out.addAll(com.lifecyclebot.v3.scoring.CashGenerationAI.getActivePositionsSnapshot().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.MoonshotTraderAI.getActivePositions().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.ShitCoinTraderAI.getActivePositions().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.QualityTraderAI.getActivePositions().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.BlueChipTraderAI.getActivePositions().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.ManipulatedTraderAI.getActivePositions().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.DipHunterAI.getActiveDips().map { it.mint }) } catch (_: Throwable) {}
            try { out.addAll(com.lifecyclebot.v3.scoring.ShitCoinExpress.getActiveRides().map { it.mint }) } catch (_: Throwable) {}
            out.toList()
        } catch (_: Throwable) { emptyList() }
    }

    /** V5.9.1567 вҖ” keep forced-open ghost eviction out of botLoop/reaper transform bulk. */
    private fun evictSubTraderGhost(mint: String) {
        try { com.lifecyclebot.v3.scoring.CashGenerationAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.MoonshotTraderAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.ShitCoinTraderAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.QualityTraderAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.BlueChipTraderAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.ManipulatedTraderAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.DipHunterAI.evictGhost(mint) } catch (_: Throwable) {}
        try { com.lifecyclebot.v3.scoring.ShitCoinExpress.evictGhost(mint) } catch (_: Throwable) {}
    }

    private fun isCapCountableLiveToken(mint: String, ts: com.lifecyclebot.data.TokenState? = null): Boolean {
        return try {
            if (mint.isBlank()) return false
            val hostTracked = com.lifecyclebot.engine.HostWalletTokenTracker.hasTrackedPosition(mint)
            if (hostTracked) return com.lifecyclebot.engine.HostWalletTokenTracker.isCapCountable(mint)
            val pos = ts?.position ?: status.tokens[mint]?.position ?: return false
            !pos.isPaperPosition && pos.qtyToken > 0.0 && pos.isOpen
        } catch (_: Throwable) { false }
    }

    private fun reapGhostForcedOpen(forcedOpenRaw: List<String>): List<String> {
        try { com.lifecyclebot.engine.PositionCloseLedger.prune() } catch (_: Throwable) {}
        // Build the authoritative live-open set ONCE (close ledger + live TokenState
        // + sub-trader stores were already unioned into forcedOpenRaw, but a mint can
        // be in forcedOpenRaw yet no longer report open anywhere вҖ” that's a ghost).
        val liveOpenSet: Set<String> = try {
            val out = HashSet<String>()
            synchronized(status.tokens) {
                status.tokens.values.forEach { if (isCapCountableLiveToken(it.mint, it)) out.add(it.mint) }
            }
            forcedOpenRaw.forEach { m -> if (com.lifecyclebot.engine.GlobalTradeRegistry.hasOpenPosition(m)) out.add(m) }
            out
        } catch (_: Throwable) { forcedOpenRaw.toSet() }

        val reaped = forcedOpenRaw.filter { isGhostMint(it, liveOpenSet) }
        if (reaped.isNotEmpty()) {
            try {
                ForensicLogger.lifecycle("GHOST_POSITION_REAPED", "count=${reaped.size} mints=${reaped.take(8).joinToString(",") { it.take(8) }}")
                com.lifecyclebot.engine.PipelineHealthCollector.labelInc("GHOST_POSITION_REAPED")
            } catch (_: Throwable) {}
            for (m in reaped) {
                try { com.lifecyclebot.engine.Executor.releasePaperSellLock(m) } catch (_: Throwable) {}
                try { supervisorForceReleaseLeaseAndCancel(m, "GHOST_REAP") } catch (_: Throwable) {}
                // V5.9.1498 вҖ” ROOT-CAUSE: evict the stale entry from the sub-trader
                // stores so getActivePositions()/getActiveDips()/getActiveRides()
                // stop re-emitting it into forcedOpenRaw next cycle. WITHOUT this,
                // a closed mint is reaped (lease released) but immediately re-added
                // from the store on the very next cycle вҶ’ ghost>0 forever вҶ’ every
                // buy defers (the 6h-dead park). Pure map removal, no PnL/learning.
                evictSubTraderGhost(m)
            }
        }
        // Stash the clean list + live set so publishSlotHealth counts the SAME truth.
        lastReapLiveOpenSet = liveOpenSet
        return forcedOpenRaw.filterNot { isGhostMint(it, liveOpenSet) }
    }

    @Volatile private var lastReapLiveOpenSet: Set<String> = emptySet()

    private fun publishSlotHealth(forcedOpenClean: Collection<String>, forcedOpenCount: Int) {
        // V5.9.1475 (spec item 3) вҖ” count ghosts from the CLEANED forcedOpen list
        // using the SAME canonical predicate the reaper used. Previously this was
        // passed the RAW (pre-reap) list and re-counted just-reaped mints as ghosts,
        // so ghost never fell to 0 even though reaping happened. After reaping, a
        // healthy steady state has ghost=0.
        val live = lastReapLiveOpenSet
        val paperRuntime = try { RuntimeModeAuthority.isPaper() } catch (_: Throwable) { try { ConfigStore.load(applicationContext).paperMode } catch (_: Throwable) { false } }
        val ghostOpenNow = if (paperRuntime) 0 else forcedOpenClean.count { isGhostMint(it, live) }
        val paperOpenNow = if (paperRuntime) currentPaperOpenMintsFromLedger().size else forcedOpenCount
        val exitInFlight = try { fullExitSweepPending.get() || universalSlSweepPending.get() } catch (_: Throwable) { false }
        com.lifecyclebot.engine.SlotHealthGate.publish(
            ghostOpen = ghostOpenNow,
            forcedOpen = if (paperRuntime) paperOpenNow else forcedOpenCount,
            openPositions = if (paperRuntime) paperOpenNow else forcedOpenCount,
            supActive = supervisorActive.get(),
            supCap = supervisorEffectiveCap(),
            exitInFlight = exitInFlight,
        )
    }

    private fun supervisorEffectiveCap(): Int {
        val base = SUPERVISOR_BASE_MAX_WORKERS
        val now = System.currentTimeMillis()
        // Count timeouts in the current 10-min window (maintained by the throttle note fn).
        val windowFresh = (now - supervisorTimeoutWindowStartMs) < 600_000L
        val timeouts = if (windowFresh) supervisorTimeoutWindowCount else 0
        // COOLING latch: >500/10min trips a 60s cooling window (concurrent cap halved, min 8).
        if (timeouts >= 150) supervisorCoolingUntilMs = now + 90_000L
        val cooling = now < supervisorCoolingUntilMs
        val cap = when {
            cooling           -> maxOf(8, base / 3)   // 90s cooling floor
            timeouts >= 150   -> maxOf(8, base / 3)   // heavy: drain debt first
            timeouts >= 30    -> maxOf(12, base / 2)  // moderate: report 3717 had 50 and was parked
            else              -> base                 // healthy: full pool
        }
        return cap
    }
    // V5.9.1319 (Item 3) вҖ” emergency-throttle arming. When sustained overload is detected
    // (a cycle exceeding 30s, OR >20 worker timeouts inside a 10-minute window) we clamp the
    // effective worker cap to 16 and shorten cycle pressure for the next 5 minutes. Exit
    // protection (ExitCoordinator) is unaffected вҖ” it runs on its own dispatcher.
    @Volatile private var supervisorTimeoutWindowStartMs: Long = 0L
    @Volatile private var supervisorTimeoutWindowCount: Int = 0
    private fun supervisorArmEmergencyThrottle(reason: String, detail: String) {
        // V5.9.1332 вҖ” disarmed. supervisorEffectiveCap() no longer reads
        // supervisorEmergencyThrottleUntilMs; keeping the function as a no-op
        // observation log so we can still see when the OLD trip would have
        // fired (useful telemetry without the destructive cap clamp).
        try {
            ForensicLogger.lifecycle(
                "SUPERVISOR_EMERGENCY_THROTTLE_OBSERVED_DISARMED",
                "reason=$reason $detail (V5.9.1332: clamp removed; observation-only)",
            )
        } catch (_: Throwable) {}
    }
    private fun supervisorNoteWorkerTimeoutForThrottle() {
        val now = System.currentTimeMillis()
        if (now - supervisorTimeoutWindowStartMs >= 600_000L) {
            supervisorTimeoutWindowStartMs = now
            supervisorTimeoutWindowCount = 0
        }
        supervisorTimeoutWindowCount += 1
        // V5.9.1331 вҖ” STALL FIX (operator: "still trade stalls. it should never not be intake tokens").
        // The 20-timeout-in-10min trip was over-firing under the new ~2800/day throughput
        // (each cycle touches 32 tokens Г— 6/min = 192/min; even a 1% slow-API rate yields
        // ~2 timeouts/min = 120/10min вҖ” way above 20). Result: emergency throttle cap=16
        // pins for 5min repeatedly, cutting effective throughput in half during the
        // exact window when intake should be highest. Raise threshold 20вҶ’60 so the
        // throttle only kicks in on REAL pool exhaustion, not normal API tail latency.
        if (supervisorTimeoutWindowCount >= 30) {
            supervisorArmEmergencyThrottle("worker_timeouts", "count=$supervisorTimeoutWindowCount/10min")
        }
    }
    fun supervisorNoteCycleElapsedForThrottle(cycleMs: Long) {
        // V5.0.6072 вҖ” throttle arms at 15s (was 30s). Operator report showed
        // avgCycle=9552ms max=77422ms; waiting for 6Г— the 5s cycle budget
        // before cooling let wedged-IO bursts compound for multiple cycles.
        if (cycleMs > 15_000L) supervisorArmEmergencyThrottle("max_cycle_ms", "cycleMs=$cycleMs")
    }
    @Suppress("unused") private val SUPERVISOR_MAX_LIVE_WORKERS: Int = 32

    // V5.9.1073 вҖ” SUPERVISOR ACCOUNTING REWRITE.
    // Operator directive: give supervisor a range of 100 and stop the repeated
    // active=48/cap=48 weirdness. The old design selected 96 mints but allowed
    // only 48 in-flight workers, guaranteeing deferred work on a normal ~100-token
    // universe. Worse, the old stall watchdog "fixed" saturation by setting
    // supervisorActive=0 while workers were still alive; late releases could then
    // push the counter negative/phantom and the next cycle would oscillate between
    // false headroom and cap saturation.
    //
    // V5.9.1149 вҖ” align lease cap with the existing live-worker ceiling.
    // Runtime 5.0.3115 showed WATCHLIST_RR picked=199, supervisor spawned=120,
    // skipped=80, active=100 cap=100 liveCap=140. That means admission was still
    // being throttled by the older lease cap while the explicit runaway guard
    // already allowed 140 live workers. Raising the lease cap to 140 restores
    // throughput without scanner pruning, lane disabling, or increasing the
    // selected watchlist pool.
    // Saturation is telemetry only (SUPERVISOR_POOL_SATURATED_NO_RESET); we never
    // destructively reset the active counter again, and stale leases expire before
    // the next 5s loop cadence.
    private val supervisorLastSpawnAt = java.util.concurrent.atomic.AtomicLong(System.currentTimeMillis())
    private val supervisorLifetimeSaturationEvents = java.util.concurrent.atomic.AtomicLong(0) // saturation telemetry counter
    private val SUPERVISOR_POOL_STALL_MS: Long = 8_000L  // telemetry threshold only; no destructive counter reset
    // V5.9.1424 вҖ” DOUBLE SUPERVISOR CONCURRENCY 32 вҶ’ 64 (operator: "its really
    // only trading 1 token at a time ... it'll take months just to bootstrap").
    // Root cause of low concurrent opens: only 32 mints/cycle reached a worker, and
    // a large share of those were blocked (FDG/PROBE_ONLY, REENTRY_LOCKOUT) or
    // open-then-die, so distinct survivable opens per tick were a trickle. Doubling
    // the per-cycle worker pool widens the funnel so more NON-locked, FDG-passing
    // candidates reach EXEC each cycle and can coexist as concurrent positions вҖ”
    // the sample-size lever the bootstrap maturity curve needs (doctrine: throughput
    // before cleverness). Does NOT touch the protected 500-token intake pool, the
    // 10-min re-entry lockout, or any safety floor; it only processes more of the
    // already-admitted watchlist per tick. Workers remain bounded + leased, so this
    // cannot leak capacity (hard-expiry cleanup still applies).
    @Suppress("unused") private val SUPERVISOR_MAX_INFLIGHT: Int = 24  // V5.0.3676 вҖ” pressure-safe floor. Kept for overloaded/cooling windows.
    private val SUPERVISOR_HEALTHY_MEME_MAX_INFLIGHT: Int = 48  // V5.0.3723 вҖ” source fix: when workerTimeout/lease debt is clean, sample the meme hot pool at the real healthy worker cap instead of the old pressure floor.
    // Worker slot budget is one bot-loop cadence: long enough for normal
    // processTokenCycle, short enough that stuck IO cannot hold a supervisor
    // slot across multiple 5s cycles.
    // V5.9.1445 вҖ” 5s->8s. 5.0.3447 showed 668 SUPERVISOR_LEASE_FORCE_RELEASED in
    // 302s, nearly all at afterMs=5750 (timeout+watchdog grace) вҖ” admitted workers
    // were being force-killed at the 5s wall before processTokenCycle finished,
    // because current API latency (groq 944ms rate-limited, geckoterminal 372ms,
    // pumpfun 766ms) pushes per-token p95 past 5s. 8s lets real work complete while
    // still bounding stuck IO well inside the cycle cadence. workerTimeout=15 (real
    // timeouts) vs 668 force-releases proves most workers were NOT genuinely stuck.
    private val SUPERVISOR_WORKER_TIMEOUT_MS: Long = 9_000L
    // V5.9.1180 вҖ” timeout quarantine is per-mint, not global scanner pruning.
    // 3145 showed workerTimeout=239 while WATCHLIST_RR kept reselecting the
    // same slow/no-pair/API-wedged mints. Re-spawning those mints every 5s burns
    // supervisor slots and creates INFLIGHT_CAP without increasing FDG/EXEC.
    // Non-open timed-out mints cool briefly; open positions bypass this so exits
    // and hard-floor protection remain unconditional.
    private val supervisorTimeoutCooldownUntil = java.util.concurrent.ConcurrentHashMap<String, Long>()
    private val SUPERVISOR_TIMEOUT_COOLDOWN_MS: Long = 90_000L

    private fun supervisorMintIsOpen(mint: String): Boolean = try {
        isCapCountableLiveToken(mint, status.tokens[mint]) ||
            status.openPositions.any { it.mint == mint && isCapCountableLiveToken(it.mint, it) }
    } catch (_: Throwable) { false }

    private fun supervisorTimeoutCooldownActive(mint: String, now: Long = System.currentTimeMillis()): Boolean {
        // V5.9.1572 вҖ” open mints no longer bypass supervisor timeout cooldown.
        // Exits are handled by ExitCoordinator/open-position tick, so skipping full
        // supervisor re-poll for a chronic open mint does NOT weaken hard-floor exits.
        // It prevents the same open mints from monopolising every worker slot.
        val until = supervisorTimeoutCooldownUntil[mint] ?: return false
        if (until <= now) {
            supervisorTimeoutCooldownUntil.remove(mint, until)
            return false
        }
        return true
    }

    private fun supervisorArmTimeoutCooldown(mint: String) {
        val open = supervisorMintIsOpen(mint)
        val cooldownMs = if (open) 45_000L else SUPERVISOR_TIMEOUT_COOLDOWN_MS
        val until = System.currentTimeMillis() + cooldownMs
        supervisorTimeoutCooldownUntil[mint] = until
        if (supervisorTimeoutCooldownUntil.size > 2048) {
            val now = System.currentTimeMillis()
            try {
                val it = supervisorTimeoutCooldownUntil.entries.iterator()
                while (it.hasNext()) {
                    val e = it.next()
                    if (e.value <= now) it.remove()
                }
            } catch (_: Throwable) {}
        }
    }

    private fun supervisorPruneExpiredLeases(reason: String = "cycle"): Int {
        val now = System.currentTimeMillis()
        var expired = 0
        try {
            val it = supervisorLeases.entries.iterator()
            while (it.hasNext()) {
                val e = it.next()
                val age = now - e.value.startedMs
                if (age >= SUPERVISOR_LEASE_TTL_MS) {
                    if (supervisorLeases.remove(e.key, e.value)) expired++
                }
            }
        } catch (_: Throwable) {}
        if (expired > 0) {
            supervisorLifetimeExpiredLeases.addAndGet(expired.toLong())
            supervisorActive.set(supervisorLeases.size)
            try {
                ForensicLogger.lifecycle(
                    "SUPERVISOR_LEASE_EXPIRED",
                    "reason=$reason expired=$expired active=${supervisorLeases.size} ttlMs=$SUPERVISOR_LEASE_TTL_MS total=${supervisorLifetimeExpiredLeases.get()}",
                )
            } catch (_: Throwable) {}
        }
        return expired
    }

    private fun supervisorTryAcquireSlot(mint: String): Long {
        supervisorPruneExpiredLeases("acquire")
        val live = supervisorLeases.size
        // Lease cap controls cycle coverage; live-worker cap prevents runaway
        // non-cooperative processTokenCycle calls if APIs wedge.
        // V5.9.1319 (Item 3) вҖ” admit against the EFFECTIVE adaptive cap (base 32, or 16
        // during an emergency-throttle window). Replaces the old fixed 140 firehose.
        if (live >= supervisorEffectiveCap()) return -1L
        val id = supervisorLeaseSeq.incrementAndGet()
        supervisorLeases[id] = SupervisorLease(mint = mint, startedMs = System.currentTimeMillis())
        supervisorActive.set(supervisorLeases.size)
        return id
    }

    private fun supervisorReleaseSlot(leaseId: Long): Int {
        if (leaseId > 0L) supervisorLeases.remove(leaseId)
        val active = supervisorLeases.size.coerceAtLeast(0)
        supervisorActive.set(active)
        return active
    }

    /**
     * V5.9.1470 (spec item 6) вҖ” force-release every lease for a mint AND cancel its
     * worker coroutine. Used by the ghost reaper so reaped/closed mints cannot leave a
     * wedged worker running that re-adds stale state. Idempotent + fail-open. NEVER
     * touches positions/balances вҖ” it only cancels a stuck IO coroutine and frees slots.
     */
    private fun supervisorForceReleaseLeaseAndCancel(mint: String, reason: String) {
        if (mint.isBlank()) return
        var cancelled = 0
        try {
            val it = supervisorLeases.entries.iterator()
            while (it.hasNext()) {
                val e = it.next()
                if (e.value.mint == mint) {
                    try { e.value.jobRef.get()?.cancel() } catch (_: Throwable) {}
                    if (supervisorLeases.remove(e.key, e.value)) cancelled++
                }
            }
        } catch (_: Throwable) {}
        if (cancelled > 0) {
            supervisorActive.set(supervisorLeases.size.coerceAtLeast(0))
            try {
                ForensicLogger.lifecycle("SUPERVISOR_LEASE_FORCE_RELEASED", "mint=${mint.take(10)} reason=$reason cancelledJobs=$cancelled active=${supervisorLeases.size} cooled=true")
                com.lifecyclebot.engine.PipelineHealthCollector.labelInc("SUPERVISOR_LEASE_FORCE_RELEASED")
            } catch (_: Throwable) {}
        }
    }

    private fun supervisorClampIfNegative(reason: String) {
        val cur = supervisorActive.get()
        if (cur < 0 && supervisorActive.compareAndSet(cur, 0)) {
            try {
                ForensicLogger.lifecycle(
                    "SUPERVISOR_ACTIVE_CLAMPED",
                    "reason=$reason prevActive=$cur cap=$SUPERVISOR_MAX_INFLIGHT",
                )
            } catch (_: Throwable) {}
        }
        supervisorPruneExpiredLeases(reason)
        supervisorActive.set(supervisorLeases.size.coerceAtLeast(0))
    }

    /**
     * V5.9.1037 вҖ” fire-and-forget supervisor. Replaces the chunk-await
     * loop in runSupervisorPhase. Each mint that fits within the
     * SUPERVISOR_MAX_INFLIGHT budget gets a detached GlobalScope.launch
     * worker on Dispatchers.IO; the rest are dropped (re-attempted next
     * cycle's fresh ordering). The bot loop returns immediately вҖ” no
     * chunked await, no per-chunk timeout, no SUPERVISOR_CHUNK_TIMEOUT
     * forensic noise. Worker admission is bounded by expiring lease slots
     * plus the existing OkHttp dispatcher (maxRequestsPerHost=16 per
     * V5.9.1032), so we cannot permanently starve the next cycle.
     *
     * The returned SupervisorPhaseResult.processed is "spawned this tick",
     * not "completed this tick". For long-tail telemetry, audit
     * supervisorLifetimeProcessed / supervisorLifetimeSpawned counters.
     */
    private fun fireSupervisorWorkers(
        orderedMints: List<String>,
        cfg: com.lifecyclebot.data.BotConfig,
        wallet: com.lifecyclebot.network.SolanaWallet?,
        lastSuccessfulPollMs: Long,
        loopCount: Int,
    ): SupervisorPhaseResult {
        if (!status.running) return SupervisorPhaseResult(0, orderedMints.size, false)
        // V5.9.1073 вҖ” saturation is OBSERVATION ONLY.
        // The old pool reset path force-set supervisorActive=0 at cap, which
        // created phantom/negative accounting when late workers released. Do not
        // reset here. Clamp any historical negative value, log sustained full-cap
        // saturation, and let timed slot releases drain naturally.
        run {
            val now = System.currentTimeMillis()
            supervisorClampIfNegative("pre_cycle")
            val currentActive = supervisorLeases.size
            if (currentActive >= supervisorEffectiveCap()) {
                val stallMs = now - supervisorLastSpawnAt.get()
                if (stallMs >= SUPERVISOR_POOL_STALL_MS) {
                    supervisorLifetimeSaturationEvents.incrementAndGet()
                    supervisorLastSpawnAt.set(now)
                    try {
                        ForensicLogger.lifecycle(
                            "SUPERVISOR_POOL_SATURATED_NO_RESET",
                            "stallMs=$stallMs cap=$SUPERVISOR_MAX_INFLIGHT active=$currentActive events=${supervisorLifetimeSaturationEvents.get()}",
                        )
                    } catch (_: Throwable) {}
                }
            }
        }
        var spawned = 0
        var skipped = 0
        var cooldownSkipped = 0
        var shouldPollSkipped = 0
        try { markProgress("SUPERVISOR") } catch (_: Throwable) {}
        for (mint in orderedMints) {
            if (!status.running) break
            // V5.9.1180 вҖ” pre-admission filters. Do not acquire a lease or spawn
            // watchdog/IO coroutines for mints that are temporarily cooled after a
            // worker timeout, or that the orchestrator already says should not be
            // polled this tick. Open positions bypass timeout cooldown above.
            if (supervisorTimeoutCooldownActive(mint)) {
                skipped++
                cooldownSkipped++
                continue
            }
            if (orchestrator?.shouldPoll(mint) == false) {
                skipped++
                shouldPollSkipped++
                continue
            }
            val leaseId = supervisorTryAcquireSlot(mint)
            if (leaseId <= 0L) {
                skipped++
                continue
            }
            supervisorLifetimeSpawned.incrementAndGet()
            // V5.9.1042 вҖ” record last-successful-spawn timestamp so the
            // watchdog above can detect prolonged pool stalls.
            supervisorLastSpawnAt.set(System.currentTimeMillis())
            // V5.9.1046 вҖ” SLOT-RELEASE DECOUPLE. Operator V5.9.1045 dump
            // showed SUPERVISOR_WORKER_TIMEOUTs firing but slots still held; V5.9.1073 uses 5s
            // timeout working) but ~36 slots still held between resets.
            // Root cause: withTimeoutOrNull SUSPENDS the outer coroutine
            // until runInterruptible's inner block returns вҖ” and
            // processTokenCycle's outer try/catch SWALLOWS
            // InterruptedException ("Error [\$mint]" log), so the runaway
            // thread keeps running and the slot stays held until it
            // organically exits. Fix: spawn a separate watchdog coroutine
            // that delays for timeout+500ms then unconditionally releases
            // the slot via AtomicBoolean.compareAndSet. The main worker's
            // finally block also calls release(), but the CAS ensures
            // only one of them actually decrements. Bound: slot is now
            // guaranteed to free within timeout+0.5s regardless of whether
            // the inner thread ever returns.
            // V5.9.1415 вҖ” LEASE/WORKER ACCOUNTING FIX. The old watchdog released
            // the slot at SUPERVISOR_LEASE_TTL_MS (4750ms) вҖ” BEFORE the worker's
            // own 5000ms timeout could fire вҖ” while the worker coroutine kept
            // running. That freed the lease (active=leases.size shrank) while real
            // in-flight work exceeded the lease count, so new workers were admitted
            // over the real cap, IO saturated, workerTimeout climbed, and because
            // the timer (not the TTL prune) did the release, expiredLeases stayed 0:
            // the operator's exact "cap hit without lease expiry" signature.
            // FIX: hold a reference to the worker job; the safety-net watchdog now
            // fires AFTER the worker timeout + 750ms grace and CANCELS the job
            // before releasing the slot, so a lease is freed only when its worker
            // is genuinely done (normal finally) or has been force-killed. The
            // AtomicBoolean still guarantees exactly one decrement.
            val released = java.util.concurrent.atomic.AtomicBoolean(false)
            val workerJobRef = java.util.concurrent.atomic.AtomicReference<kotlinx.coroutines.Job?>(null)
            val releaseSlot = {
                if (released.compareAndSet(false, true)) supervisorReleaseSlot(leaseId)
                Unit
            }
            val workerJob = kotlinx.coroutines.GlobalScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    if (!status.running) return@launch
                    // V5.9.1180 вҖ” orchestrator.shouldPoll was moved before lease
                    // acquisition so non-pollable mints do not consume supervisor
                    // slots/watchdog coroutines.
                    // V5.9.1039 вҖ” PER-WORKER TIMEOUT. V5.9.1037 removed the
                    // chunk-level awaitAll timeout but forgot to add a
                    // per-worker safety net. Operator V5.9.1038 4h dump
                    // showed SUPERVISOR_INFLIGHT_CAP firing 2238 times with
                    // active=cap spawned=0 EVERY cycle вҖ” workers stuck
                    // on slow Birdeye/DexScreener responses never decremented
                    // supervisorActive, permanently saturating the pool.
                    // Result: bot loop spawned 0 new workers per cycle for
                    // 4h straight вҶ’ EXEC=2 only, projected 166 execs/day
                    // (target 500+). 20s budget is generous (~3x normal
                    // processTokenCycle p95) so legitimate work completes;
                    // stuck workers get cancelled and free their slot.
                    // V5.9.1044 вҖ” wrap the call in runInterruptible so the
                    // cooperative withTimeoutOrNull cancellation is upgraded
                    // to a REAL Thread.interrupt() on the IO dispatcher
                    // thread. processTokenCycle is a plain (non-suspend)
                    // function whose blocking ops (OkHttp socket reads,
                    // synchronized SQLite writes, Birdeye/DexScreener
                    // calls) never observe coroutine cancellation вҖ”
                    // explaining V5.9.1042's snapshot showing
                    // old destructive pool reset firing 29Г— in 20min: workers
                    // launched, hung non-cooperatively, and never
                    // released their slot, forcing the watchdog band-aid
                    // to kick in every ~42s. runInterruptible converts
                    // cancellation into JVM thread interrupt, which the
                    // vast majority of blocking I/O honors вҖ” so the
                    // worker actually dies and the finally block fires.
                    val ok = kotlinx.coroutines.withTimeoutOrNull(SUPERVISOR_WORKER_TIMEOUT_MS) {
                        kotlinx.coroutines.runInterruptible(kotlinx.coroutines.Dispatchers.IO) {
                            val cycleCfg = cfg.copy(paperMode = try { RuntimeModeAuthority.isPaper() } catch (_: Throwable) { cfg.paperMode })
                            processTokenCycle(mint, cycleCfg, wallet, lastSuccessfulPollMs)
                            try { GlobalTradeRegistry.markProcessed(mint) } catch (_: Throwable) {}
                        }
                    }
                    if (ok != null) {
                        supervisorLifetimeProcessed.incrementAndGet()
                    } else {
                        supervisorLifetimeWorkerTimeouts.incrementAndGet()
                        supervisorArmTimeoutCooldown(mint)
                        try { supervisorNoteWorkerTimeoutForThrottle() } catch (_: Throwable) {}
                        try {
                            ForensicLogger.lifecycle(
                                "SUPERVISOR_WORKER_TIMEOUT",
                                "mint=${mint.take(10)} budgetMs=$SUPERVISOR_WORKER_TIMEOUT_MS cooldownMs=$SUPERVISOR_TIMEOUT_COOLDOWN_MS open=${supervisorMintIsOpen(mint)}",
                            )
                        } catch (_: Throwable) {}
                        // V5.9.1324 вҖ” P1-6 surgical: structured timeout reason +
                        // NoTradeObservation row so timed-out candidates remain trainable.
                        try {
                            com.lifecyclebot.engine.PipelineHealthCollector.labelInc("SUPERVISOR_WORKER_TIMEOUT_REASON_BUDGET_EXCEEDED")
                            com.lifecyclebot.engine.PipelineHealthCollector.labelInc("SUPERVISOR_TIMEOUT_PER_MINT|${mint.take(10)}")
                            val ts2 = synchronized(status.tokens) { status.tokens[mint] }
                            if (ts2 != null && ts2.lastPrice > 0.0) {
                                com.lifecyclebot.engine.learning.NoTradeObservationStore.recordBlock(
                                    mint = mint,
                                    symbol = ts2.symbol,
                                    lane = "SUPERVISOR",
                                    scoreBand = "",
                                    score = 0,
                                    confidence = 0,
                                    entryLiqUsd = ts2.lastLiquidityUsd,
                                    entryMcapUsd = ts2.lastMcap,
                                    entryPrice = ts2.lastPrice,
                                    source = ts2.source.ifEmpty { "SUPERVISOR" },
                                    blockReason = "SUPERVISOR_WORKER_TIMEOUT_BUDGET_EXCEEDED",
                                    verdictTag = "BLOCK_SUPERVISOR_TIMEOUT",
                                )
                            }
                        } catch (_: Throwable) {}
                    }
                } catch (_: kotlinx.coroutines.CancellationException) {
                    // benign вҖ” service shutting down
                } catch (t: Throwable) {
                    ErrorLogger.debug(
                        "BotService",
                        "Silent supervisor worker failed ${mint.take(8)}: ${t.message}",
                    )
                } finally {
                    releaseSlot()
                }
            }
            workerJobRef.set(workerJob)
            // V5.9.1470 (spec item 6) вҖ” register the worker job on its lease so a
            // by-mint force-release (ghost reaper / dirty-slot cleanup) can cancel it.
            try { supervisorLeases[leaseId]?.jobRef?.set(workerJob) } catch (_: Throwable) {}
            // Safety-net watchdog: fires only AFTER the worker timeout + grace.
            // If the worker is still alive (non-cooperative blocking IO that
            // ignored the withTimeoutOrNull interrupt), cancel it and free the
            // slot. Never races ahead of the worker's own timeout/finally.
            kotlinx.coroutines.GlobalScope.launch(kotlinx.coroutines.Dispatchers.Default) {
                try {
                    kotlinx.coroutines.delay(SUPERVISOR_WORKER_TIMEOUT_MS + 750L)
                    if (!released.get()) {
                        try { workerJobRef.get()?.cancel() } catch (_: Throwable) {}
                        // V5.9.1453 вҖ” THE LEASE-CHURN LEAK. A worker that had to be
                        // FORCE-released here was wedged in non-interruptible blocking
                        // IO (slow/429'd provider вҖ” Helius/Birdeye/pumpfun). The clean
                        // withTimeoutOrNull-null path arms the per-mint timeout cooldown
                        // so WATCHLIST_RR stops re-selecting it; the watchdog path did
                        // NOT вҖ” so the SAME wedged mint got re-picked every cycle, wedged
                        // again, and force-released again forever (snapshot 81e428fb:
                        // dozens of FORCE_RELEASED @ afterMs=8750 every loop while
                        // spawned=0/deferred=120 вҖ” full pool, zero real throughput).
                        // Arm the cooldown on the force path too so wedged mints rotate
                        // OUT and free their slot for fresh candidates. Open positions
                        // are exempt inside supervisorArmTimeoutCooldown (exits/-15%
                        // floor stay unconditional). Also count it as a real worker
                        // timeout so PipelineHealthCollector reflects the true stuck-IO
                        // rate instead of hiding it behind force-releases.
                        try { supervisorArmTimeoutCooldown(mint) } catch (_: Throwable) {}
                        try { supervisorLifetimeWorkerTimeouts.incrementAndGet() } catch (_: Throwable) {}
                        try { supervisorNoteWorkerTimeoutForThrottle() } catch (_: Throwable) {}
                        try {
                            ForensicLogger.lifecycle(
                                "SUPERVISOR_LEASE_FORCE_RELEASED",
                                "mint=${mint.take(10)} afterMs=${SUPERVISOR_WORKER_TIMEOUT_MS + 750L} active=${supervisorLeases.size} cooled=true",
                            )
                        } catch (_: Throwable) {}
                        releaseSlot()
                    }
                } catch (_: Throwable) {}
            }
            spawned++
        }
        if (skipped > 0) supervisorLifetimeSkipped.addAndGet(skipped.toLong())
        if (skipped > 0) {
            val expiredAtCapReport = supervisorPruneExpiredLeases("cap_report")
            try {
                ForensicLogger.lifecycle(
                    "SUPERVISOR_INFLIGHT_CAP",
                    "loop=$loopCount spawned=$spawned skipped=$skipped cooldown=$cooldownSkipped shouldPoll=$shouldPollSkipped active=${supervisorLeases.size} cap=$SUPERVISOR_MAX_INFLIGHT liveCap=$SUPERVISOR_MAX_LIVE_WORKERS expiredLeases=$expiredAtCapReport",
                )
            } catch (_: Throwable) {}
        }
        return SupervisorPhaseResult(processed = spawned, deferred = skipped, hardTimedOut = false)
    }

    /**
     * V5.9.1019 вҖ” UNIVERSAL SL SWEEP, async + single-flight.
     *
     * Mirrors launchExitSweepAsync (V5.9.1010) for the OTHER per-cycle sweep
     * the bot loop used to run synchronously at the end of every cycle
     * (runUniversalSlSafetyNetSweep). With multiple open positions, that
     * sync version blocked the bot loop for 30-50s per call.
     *
     * Contract:
     *   вҖў Single-flight: a second call while still running is dropped with
     *     UNIVERSAL_SL_SWEEP_SKIPPED. Coalescing is correct because the
     *     sweep is idempotent (re-evaluating the same position cycle later
     *     is fine вҖ” exit signals are recomputed from live state).
     *   вҖў Hard 3s watchdog: if paperSell's non-cancellable IO blocks an
     *     IO worker, we release the single-flight gate after 3s so the
     *     next cycle can request another sweep. Stuck worker is best-effort
     *     cancelled and may finish late (UNIVERSAL_SL_SWEEP_LATE_DONE).
     *   вҖў Budget higher than launchExitSweepAsync's 2.5s because this sweep
     *     iterates ALL open positions (not just exit-managed ones).
     */
    private fun launchUniversalSlSweepAsync(
        cfg: com.lifecyclebot.data.BotConfig,
        wallet: com.lifecyclebot.network.SolanaWallet?,
    ) {
        // V5.9.1198 вҖ” request-only shim. The cfg/wallet params are kept for
        // call-site compatibility; coordinator snapshots fresh state off-loop.
        requestExitSweepCoordinator(reason = "UNIVERSAL_SL", full = false, universal = true)
    }


    private fun sweepUniversalExits(
        cfg: com.lifecyclebot.data.BotConfig,
        wallet: com.lifecyclebot.network.SolanaWallet?,
        effectiveBalance: Double,
    ) {
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.9.1069 вҖ” UNIVERSAL HARD FLOOR + PEAK BACKSTOP (Part 0)
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // Operator screenshot evidence (V5.9.1068, 04:25):
        //   VGRD card displayed SL -14% but position sat at -83.8% (never sold)
        //   GG card displayed lock +276% on +283% peak вҖ” still open at +283%
        //   17 positions accumulated, cap=8 exceeded, bot effectively frozen
        //     on entry because exits stopped firing per-lane.
        //
        // This Part-0 runs BEFORE Treasury + V3 manage and is a pure safety
        // net: regardless of which lane owns the position, force-close when
        // (a) pnl% has fallen below the universal hard floor (-20%), OR
        // (b) the position peaked enough to expose a positive FluidLearningAI
        //     high-lock floor and current executable PnL is at/through that floor.
        //
        // No new pause/disable/cap. Just enforces faster EXIT on positions
        // that the per-lane SL/trail demonstrably failed to close.
        //
        // 45s post-buy grace honored (consistent with Part 1) so we never
        // clip a position before the first scanner refresh has populated it.
        try {
            val openTokensForFloor = synchronized(status.tokens) {
                status.tokens.values.filter { it.position.isOpen }.toList()
            }
            val nowMs = System.currentTimeMillis()
            openTokensForFloor.forEach { ts ->
                try {
                    val posAgeMs = nowMs - ts.position.entryTime
                    if (posAgeMs < 45_000L) return@forEach
                    val entry = ts.position.entryPrice
                    if (entry <= 0.0) return@forEach
                    val last = ts.lastPrice
                    if (last <= 0.0) return@forEach
                    val rawPnlPct = ((last - entry) / entry) * 100.0
                    val execPx = try { executor.getActualPricePublic(ts).takeIf { it.isFinite() && it > 0.0 } } catch (_: Throwable) { null }
                    val exitPx4481 = walletCorrespondentOpenPrice4481(ts, execPx ?: last, "UNIVERSAL_EXIT_SWEEP")
                    val entryForExec = ts.position.entryPrice.takeIf { it.isFinite() && it > 0.0 } ?: entry
                    val pnlPct = if (exitPx4481 > 0.0 && entryForExec > 0.0) ((exitPx4481 - entryForExec) / entryForExec) * 100.0 else rawPnlPct
                    val peakPct = kotlin.math.max(ts.position.peakGainPct, pnlPct)
                    val hardFloor = pnlPct <= -20.0
                    val fluidLockFloor = try {
                        com.lifecyclebot.v3.scoring.FluidLearningAI.getDynamicFluidStop(
                            modeDefaultStop = 20.0,
                            currentPnlPct = pnlPct,
                            peakPnlPct = peakPct,
                            holdTimeSeconds = (posAgeMs / 1000.0).coerceAtLeast(0.0),
                            volatility = ts.volatility ?: 50.0,
                        )
                    } catch (_: Throwable) { Double.NaN }
                    val highLockImmediate = peakPct >= 200.0 && fluidLockFloor.isFinite() && fluidLockFloor > 0.0 && pnlPct >= fluidLockFloor
                    val lockBreached = peakPct >= 30.0 && fluidLockFloor.isFinite() && fluidLockFloor > 0.0 && pnlPct < fluidLockFloor && pnlPct > 0.0
                    val peakDrawdown = highLockImmediate || lockBreached
                    if (!hardFloor && !peakDrawdown) return@forEach
                    val reason = if (hardFloor)
                        "UNIVERSAL_HARD_FLOOR_${pnlPct.toInt()}PCT"
                    else
                        "UNIVERSAL_PEAK_LOCK_peak${peakPct.toInt()}_now${pnlPct.toInt()}"
                    ErrorLogger.warn(
                        "BotService",
                        "рҹӣЎ UNIVERSAL_EXIT: ${ts.symbol} | pnl=${pnlPct.toInt()}% peak=${peakPct.toInt()}% | $reason",
                    )
                    try {
                        ForensicLogger.lifecycle(
                            "UNIVERSAL_EXIT_FORCE",
                            "symbol=${ts.symbol} pnl=${pnlPct.toInt()} peak=${peakPct.toInt()} reason=$reason",
                        )
                    } catch (_: Throwable) {}
                    val r = executor.requestSell(
                        ts = ts,
                        reason = reason,
                        wallet = wallet,
                        walletSol = effectiveBalance,
                    )
                    if (r == com.lifecyclebot.engine.Executor.SellResult.CONFIRMED ||
                        r == com.lifecyclebot.engine.Executor.SellResult.PAPER_CONFIRMED
                    ) {
                        addLog("рҹӣЎ [UNIVERSAL] ${ts.symbol}: $reason pnl=${pnlPct.toInt()}% peak=${peakPct.toInt()}%")
                    }
                } catch (e: Exception) {
                    ErrorLogger.debug("BotService", "Universal exit ${ts.symbol}: ${e.message}")
                }
            }
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "Universal exit sweep error: ${e.message}")
        }

        // Part 1 вҖ” Treasury sub-trader exits (any mint, with or without ts).
        try {
            val treasuryExits = com.lifecyclebot.v3.scoring.CashGenerationAI
                .checkAllPositionsForExit()
            treasuryExits.forEach { (mint, signal) ->
                if (signal == com.lifecyclebot.v3.scoring.CashGenerationAI.ExitSignal.HOLD) return@forEach
                val ts = synchronized(status.tokens) { status.tokens[mint] }
                    ?: synthesizeTreasuryTokenState(mint) ?: return@forEach
                // V5.9.495i вҖ” POST-BUY SETTLE-IN GRACE for treasury sweeps
                // too. Operator: "it buys them then 5 seconds later it
                // sells them". 45s breathing room before any exit fires.
                val posAgeMs = System.currentTimeMillis() - ts.position.entryTime
                if (posAgeMs < 45_000L) return@forEach
                val sweepPnlVerdict = com.lifecyclebot.engine.OpenPnlSanity.inspect(ts, "BotService.treasurySweep/${ts.symbol}/${mint.take(8)}")
                val pnlPct = if (sweepPnlVerdict.ok) sweepPnlVerdict.pnlPct else 0.0
                ErrorLogger.warn(
                    "BotService",
                    "рҹ§№ SWEEP TREASURY-EXIT: ${ts.symbol} | $signal | pnl=${pnlPct.toInt()}% вҖ” mint missed processTokenCycle",
                )
                try {
                    val r = executor.requestSell(
                        ts        = ts,
                        reason    = "TREASURY_${signal.name}_SWEEP",
                        wallet    = wallet,
                        walletSol = effectiveBalance,
                    )
                    if (r == com.lifecyclebot.engine.Executor.SellResult.CONFIRMED ||
                        r == com.lifecyclebot.engine.Executor.SellResult.PAPER_CONFIRMED) {
                        com.lifecyclebot.v3.scoring.CashGenerationAI.closePosition(
                            mint, ts.lastPrice, signal,
                        )
                        addLog("рҹ§№ [SWEEP] TREASURY ${ts.symbol}: ${signal.name} +${pnlPct.toInt()}% | result=$r")
                    }
                } catch (e: Exception) {
                    ErrorLogger.warn("BotService", "Sweep treasury sell error: ${e.message}")
                }
            }
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "Sweep treasury error: ${e.message}")
        }

        // Part 2 вҖ” V3 lane: ensure profit-lock + partial + risk fire on
        // every open position, not just those with fresh scanner data.
        try {
            val openTokens = synchronized(status.tokens) {
                status.tokens.values.filter { it.position.isOpen }.toList()
            }
            openTokens.forEach { ts ->
                try { executor.runManageOnly(ts, wallet, effectiveBalance) }
                catch (e: Exception) {
                    ErrorLogger.debug("BotService", "Sweep manage(${ts.symbol}): ${e.message}")
                }
            }
        } catch (e: Exception) {
            ErrorLogger.warn("BotService", "Sweep V3-manage error: ${e.message}")
        }
    }

    // V5.9.1000 вҖ” synthesizeTreasuryTokenState() extracted to BotServiceLifecycleExt.kt

    private suspend fun cleanupWatchlist() {
        // V5.9.624 вҖ” PROTECTED MEME INTAKE: non-destructive shadow classifier.
        //
        // HARD OPERATOR RULE: the Meme Trader scanner/watchlist is a protected
        // 500-token Solana intake bench. We build around it; we do NOT prune,
        // choke, shrink, route around, reset, or delete candidates just because
        // they are idle/stale/flat/low-liq/waiting. Earlier cleanup versions
        // removed tokens from GlobalTradeRegistry/status.tokens and fed ordinary
        // non-entry states into scanner rejectedMints. That improved short-term
        // loop cleanliness but quietly reduced arrival volume and starved the
        // learning/trading stack.
        //
        // This function now only annotates/telemeters candidate state. Safety
        // decisions are handled by the entry gates; scheduler fairness handles
        // processing budget. Open-position protection remains absolute.
        val registryWatchlist = GlobalTradeRegistry.getWatchlist()
        if (registryWatchlist.isEmpty()) return

        val cfg = ConfigStore.load(applicationContext)
        val now = System.currentTimeMillis()
        val isPaperMode = cfg.paperMode

        val staleThresholdMs = if (isPaperMode) 300_000L else 180_000L
        val idleThresholdMs = if (isPaperMode) 600_000L else 300_000L
        val maxWatchlistAge = if (isPaperMode) 7_200_000L else 1_800_000L
        val waitTimeout = if (isPaperMode) 300_000L else 120_000L

        var shadowTagged = 0
        var hardSafetyTagged = 0
        var staleTagged = 0
        var idleTagged = 0
        var phaseTagged = 0
        var lowLiqTagged = 0
        var timeoutTagged = 0
        var waitTagged = 0
        var flatTagged = 0
        var missingStateTagged = 0

        fun intakePhaseForShadow(phase: String, message: String): LiveTradeLogStore.Phase {
            val text = (phase + "|" + message).uppercase()
            return when {
                text.contains("RUGCHECK") && (text.contains("PENDING") || text.contains("TIMEOUT") || text.contains("UNKNOWN")) -> LiveTradeLogStore.Phase.INTAKE_PENDING_RUGCHECK
                text.contains("LIQ") && !text.contains("ZERO") && !text.contains("NO VALID") -> LiveTradeLogStore.Phase.INTAKE_SIZE_REDUCED
                text.contains("BLACKLIST") || text.contains("BANNED") || text.contains("HONEYPOT") || text.contains("CANNOT_SELL") || text.contains("CONFIRMED RUG") -> LiveTradeLogStore.Phase.INTAKE_TRUE_HARD_BLOCK
                else -> LiveTradeLogStore.Phase.INTAKE_RISK_PENALTY
            }
        }

        fun shadow(ts: com.lifecyclebot.data.TokenState?, mint: String, phase: String, message: String, hardSafety: Boolean = false) {
            shadowTagged++
            if (hardSafety) {
                hardSafetyTagged++
                // Only hard-safety shadows get per-token forensic logs. Ordinary
                // stale/idle/wait/flat states are summarized below so a 500-token
                // bench does not create its own logging/IO choke.
                try {
                    // V5.9.765 вҖ” EMERGENT priority 6. Intake hard-shadow
                    // protection is NOT a wallet-held situation; route via
                    // the BLACKLISTED enum so the dump no longer claims
                    // the operator's wallet holds 276 of these.
                    LiveTradeLogStore.log(
                        tradeKey = "INTAKE_${mint.take(16)}",
                        mint = mint,
                        symbol = ts?.symbol ?: mint.take(6),
                        side = "INFO",
                        phase = intakePhaseForShadow(phase, message),
                        message = "рҹӣЎ protected intake shadow В· $phase В· $message",
                        traderTag = "INTAKE",
                    )
                } catch (_: Throwable) {}
            }
        }

        for (mint in registryWatchlist) {
            val ts = synchronized(status.tokens) { status.tokens[mint] }

            // Held bags are never cleanup candidates. Exit management and the
            // universal sweep own them, independent of scanner visibility.
            if (
                HostWalletTokenTracker.hasOpenPosition(mint) ||
                ts?.position?.isOpen == true ||
                GlobalTradeRegistry.hasOpenPosition(mint) ||
                com.lifecyclebot.v3.scoring.QualityTraderAI.hasPosition(mint) ||
                com.lifecyclebot.v3.scoring.BlueChipTraderAI.hasPosition(mint) ||
                com.lifecyclebot.v3.scoring.ShitCoinTraderAI.hasPosition(mint) ||
                com.lifecyclebot.v3.scoring.MoonshotTraderAI.hasPosition(mint) ||
                com.lifecyclebot.v3.scoring.ManipulatedTraderAI.hasPosition(mint) ||
                com.lifecyclebot.v3.scoring.CashGenerationAI.hasPosition(mint)
            ) continue

            if (ts == null) {
                missingStateTagged++
                shadow(null, mint, "MISSING_STATE", "registry mint awaiting TokenState hydrate")
                continue
            }

            val ageInWatchlist = now - ts.addedToWatchlistAt
            val lastUpdate = ts.history.lastOrNull()?.ts ?: ts.addedToWatchlistAt
            val dataAge = now - lastUpdate

            if (ts.safety.isBlocked) {
                val reason = ts.safety.hardBlockReasons.firstOrNull() ?: "Safety check failed"
                if (!TokenBlacklist.isSoftPenaltyOnlyReason(reason)) {
                    shadow(ts, mint, "SAFETY_SHADOW", reason, hardSafety = true)
                    try { ForensicLogger.lifecycle("BUY_GATE_DECISION", "mint=${mint.take(10)} symbol=${ts.symbol} decision=HARD_BLOCK reason=${reason.take(120)} source=BotService.SAFETY_SHADOW liveEligible=false") } catch (_: Throwable) {}
                    // Do not mark scanner rejected and do not remove from registry.
                    // Entry/FDG safety will block execution while the candidate
                    // remains observable for learning, telemetry, and rehydration.
                    continue
                } else {
                    try { ForensicLogger.lifecycle("BUY_GATE_DECISION", "mint=${mint.take(10)} symbol=${ts.symbol} decision=PENALTY_ONLY reason=${reason.take(120)} source=BotService.SAFETY_SHADOW liveEligible=true") } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("BUY_GATE_PENALTY_ONLY_SAFETY_SHADOW") } catch (_: Throwable) {}
                }
            }

            if (TokenBlacklist.isBlocked(mint)) {
                val reason = TokenBlacklist.getBlockReason(mint)
                shadow(ts, mint, "BLACKLIST_SHADOW", reason, hardSafety = true)
                continue
            }

            if (ageInWatchlist < 90_000L) {
                if (!isPaperMode && ts.lastLiquidityUsd in 0.0..0.5) {
                    lowLiqTagged++
                    shadow(ts, mint, "FRESH_ZERO_LIQ_SHADOW", "liq=${ts.lastLiquidityUsd}")
                }
                continue
            }

            // V5.9.640 вҖ” do NOT shadow ordinary idle candidates. "idle" is the
            // default pre-qualification phase for fresh protected-intake tokens,
            // not a failure state. Everything is meant to hit the watchlist bench
            // for upstream qualification; only explicit blocked/dead/stale states
            // should be side-lined. The old IDLE_SHADOW block is intentionally
            // removed.

            if (ts.phase in listOf("dying", "dead", "rug_likely", "distribution") && ts.history.size >= 3) {
                phaseTagged++
                shadow(ts, mint, "PHASE_SHADOW", "phase=${ts.phase} history=${ts.history.size}")
            }

            if (lastUpdate > 0 && dataAge > staleThresholdMs) {
                staleTagged++
                shadow(ts, mint, "STALE_SHADOW", "dataAge=${dataAge / 1000}s")
            }

            if (ts.lastLiquidityUsd < 200 && !isPaperMode) {
                lowLiqTagged++
                shadow(ts, mint, "LOW_LIQ_SHADOW", "liq=$${ts.lastLiquidityUsd.toInt()}")
            }

            if (ageInWatchlist > maxWatchlistAge && ts.trades.isEmpty()) {
                timeoutTagged++
                shadow(ts, mint, "TIMEOUT_SHADOW", "age=${ageInWatchlist / 60000}m no trade")
            }

            if (ts.signal == "WAIT" && ageInWatchlist > waitTimeout && ts.trades.isEmpty()) {
                waitTagged++
                shadow(ts, mint, "WAIT_SHADOW", "age=${ageInWatchlist / 1000}s")
            }

            if (!isPaperMode && ts.history.size >= 6) {
                val recentCandles = ts.history.takeLast(6)
                val priceRange = recentCandles.maxOf { it.priceUsd } - recentCandles.minOf { it.priceUsd }
                val avgPrice = recentCandles.map { it.priceUsd }.average()
                val priceChangePercent = if (avgPrice > 0) (priceRange / avgPrice) * 100 else 0.0
                val totalBuys = recentCandles.sumOf { it.buysH1 }
                if (priceChangePercent < 1.5 && totalBuys < 2) {
                    flatTagged++
                    shadow(ts, mint, "FLAT_SHADOW", "range=${"%.2f".format(priceChangePercent)}% buys=$totalBuys")
                }
            }
        }

        if (shadowTagged > 0) {
            ErrorLogger.info(
                "BotService",
                "Protected intake shadow pass: tagged=$shadowTagged hard=$hardSafetyTagged stale=$staleTagged idle=$idleTagged phase=$phaseTagged lowLiq=$lowLiqTagged timeout=$timeoutTagged wait=$waitTagged flat=$flatTagged missing=$missingStateTagged watchlist=${registryWatchlist.size} removed=0"
            )
            if (hardSafetyTagged > 0) {
                addLog("рҹӣЎ Intake protected: hardShadow=$hardSafetyTagged removed=0 watchlist=${registryWatchlist.size}")
            }
        }
    }

    /**
     * Initialize all trading modes/layers with current configuration.
     * Extracted from botLoop to reduce function complexity and avoid compiler stack overflow.
     */

    /**
     * Process a single token's full cycle - price fetch, evaluation, trading decisions.
     * V4.1: Extracted from botLoop to reduce compiler complexity (was causing StackOverflow).
     */
    private fun processTokenCycle(mint: String, cfg: BotConfig, wallet: SolanaWallet?, lastSuccessfulPollMs: Long) {
        // V5.9.657 вҖ” operator triage round 3: the outer try-catch at the
        // bottom of this 5000-line function does ONLY:
        //     ts.lastError = e.message
        //     addLog("Error [$mint]: ${e.message}", mint)
        // addLog() writes to status.logs (a 600-line in-memory UI buffer)
        // вҖ” it does NOT emit to logcat OR to ErrorLogger. Operator install
        // log of V5.9.655 showed 0 SAFETY/V3/LANE_EVAL forensic lines for
        // 392 tokens; if even ONE exception is being thrown anywhere
        // upstream of those forensic phases (synth-pair, candle history
        // sync, SymbolicContext refresh, BondingCurveTracker, etc.), the
        // entire pipeline is swallowed silently. We had no way to see it.
        //
        // This entry-marker log proves processTokenCycle is being called
        // for each mint. Paired with the loud catch at line ~11984, the
        // operator now sees EITHER `рҹ§¬[SCAN_CB] enter mint=вҖҰ` for every
        // tick OR a loud `рҹ§¬[SCAN_CB] EXCEPTION` line вҖ” never silent.
        //
        // The phase=SCAN_CB tag distinguishes this from INTAKE (which
        // fires once at admit time) and lets the operator grep for
        // "SCAN_CB enter" to count actual cycle invocations.
        try {
            ForensicLogger.phase(
                ForensicLogger.PHASE.SCAN_CB,
                status.tokens[mint]?.symbol ?: mint.take(6),
                "enter mint=${mint.take(8)} paper=${cfg.paperMode}",
            )
        } catch (_: Throwable) { /* never let logging stop the cycle */ }

        // V5.9.982 вҖ” z31/z32 SnipeAgeGate telemetry wire (was DORMANT).
        // Operator spec z32: "we shouldn't block at 39% confidence we should
        // wait to see if it changes. we block far too quickly and purge tokens
        // way too quickly". This call is TELEMETRY-ONLY вҖ” it records a
        // BACKGROUND_CLASSED event via DeferActivityTracker when a token
        // exceeds the 15-min snipe threshold AND snipeMode is on. It NEVER
        // purges or skips. Default snipeMode=false preserves current behavior;
        // the gate only fires when operator flips the flag.
        try {
            val ts = status.tokens[mint]
            if (ts != null && cfg.snipeMode) {
                val ageMin = if (ts.addedToWatchlistAt > 0) {
                    (System.currentTimeMillis() - ts.addedToWatchlistAt) / 60000L
                } else 0L
                com.lifecyclebot.engine.SnipeAgeGate.evaluateAndTrack(
                    symbol = ts.symbol,
                    ageMinutes = ageMin,
                    snipeModeOn = true,
                )
            }
        } catch (_: Throwable) { /* telemetry must never break the cycle */ }

        // V5.9.750 вҖ” keep PipelineHealthCollector.modeSnapshot fresh so
        // onGate/onExec can split per-mode counters. One @Volatile write
        // per cycle; negligible cost. Truth source: cfg.paperMode.
        try {
            PipelineHealthCollector.modeSnapshot = try { RuntimeModeAuthority.authority().name } catch (_: Throwable) { if (cfg.paperMode) "PAPER" else "LIVE" }
        } catch (_: Throwable) { /* never break the cycle */ }
        try {
            // V5.9.495z42 P1 вҖ” opportunistic recovery-lock unlock attempt at
            // the top of every per-token cycle. Covers all V3 sub-trader
            // sell paths (BlueChip / ShitCoin / Quality / Moonshot /
            // CashGen / Manipulated) that consult checkExit() further down
            // this function вҖ” without this the unlock side only fires from
            // Executor.liveSell + the treasury tick, missing positions
            // owned by other lanes. Rate-limited internally (30s/mint),
            // runs on Dispatchers.IO so this is safe to call every cycle.
            try {
                com.lifecyclebot.engine.sell.RecoveryLockUnlocker.maybeAttemptUnlock(
                    mint = mint,
                    symbol = status.tokens[mint]?.symbol ?: mint.take(6),
                    wallet = wallet,
                    jupiterApiKey = cfg.jupiterApiKey,
                )
            } catch (_: Throwable) { /* never break the cycle */ }

            // V5.9.1179 вҖ” remove per-token wallet reconcile from supervisor hot path.
            // 3145 showed SUPERVISOR_INFLIGHT_CAP=178 and WORKER_TIMEOUT=239 while
            // processTokenCycle was spawning across ~200 mints. LiveWalletReconciler
            // already runs on bot_start, after sell/buy confirmations, and a periodic
            // live-mode tick; firing reconcileNow once per watchlist mint only creates
            // hundreds of cooldown no-ops/RPC-pressure opportunities before price/V3.
            // Preserve chain truth via those coordinated paths; keep per-token workers
            // focused on pricing, safety, V3, lane eval, and exits.

            // Primary price source: Dexscreener
            // V5.9.615 вҖ” when DexScreener has no pair (pre-graduation pump.fun
            // tokens), try the fallback price providers (pump.fun API / Birdeye).
            // If they succeed, synthesize a PairInfo so the cycle can continue
            // into the V3 / ShitCoin entry path. ShitCoin is *designed* for
            // exactly these tokens; without this synthesize step we choke the
            // entire pre-graduation meme lane the operator wants us to trade.
            val pair = dex.getBestPair(mint) ?: run {
                val ts = status.tokens[mint] ?: return
                // V5.9.656 вҖ” operator triage round 2: fast path for tokens
                // that already have a usable lastPrice (set by the V5.9.655
                // intake-time mcap/1B seed for fresh PumpPortal mints). Skip
                // tryFallbackPriceData entirely вҖ” those four sequential HTTP
                // calls (Birdeye, DexScreenerOracle, BirdeyeOracle, pump.fun
                // frontend) consume up to 15-20s on cold cache, which blows
                // through the 1.2s/token paper budget and causes
                // withTimeoutOrNull to silently drop the token before we
                // reach the synth check. With a seeded price we don't need
                // oracle confirmation to start scoring/safety-checking.
                if (ts.lastPrice > 0.0) {
                    val fastSynth = synthesizeFallbackPair(ts)
                    if (fastSynth != null) {
                        // Continue with the seeded synth pair.
                        return@run fastSynth
                    }
                }
                val refreshed = tryFallbackPriceData(mint, ts)
                val synth = if (ts.lastPrice > 0.0) synthesizeFallbackPair(ts) else null
                if (synth == null) {
                    // V5.9.655 вҖ” operator triage: this silent return was the
                    // root cause of "0 trades from 392 watchlist tokens". The
                    // mcap/1B intake-time price seed (admitProtectedMemeIntake)
                    // should make ts.lastPrice > 0.0 before we ever reach this
                    // branch for PumpPortal mints, but if we still land here
                    // something is genuinely off вҖ” log loudly so the operator
                    // doesn't have to wait another debug cycle to see it.
                    ForensicLogger.gate(
                        ForensicLogger.PHASE.INTAKE,
                        ts.symbol,
                        allow = false,
                        reason = "NO_PAIR_NO_FALLBACK src=${ts.source} mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} lastPrice=${ts.lastPrice} oracleHit=$refreshed",
                    )
                    // No usable price вҖ” last-resort exit safety net.
                    if (ts.position.qtyToken > 0.0 && ts.position.entryPrice > 0.0) {
                        runFallbackSafetyExit(ts, cfg, wallet)
                    } else {
                        // V5.0.3913 вҖ” benchmark restore: 3868-3879 kept fresh
                        // no-pair pump/Raydium discoveries hot long enough for
                        // fallback price/pair hydration. 3891 demoted/removed them
                        // on the FIRST no-pair miss, producing tiny WL counts and no
                        // live trade opportunities. Demote only after repeated aged
                        // misses; fresh tokens stay in status.tokens/watchlist.
                        val entry = try { com.lifecyclebot.engine.GlobalTradeRegistry.getEntry(mint) } catch (_: Throwable) { null }
                        val ageMs = entry?.addedAt?.let { System.currentTimeMillis() - it } ?: 0L
                        val processCount = entry?.processCount ?: 0
                        val agedNoPair = processCount >= 4 && ageMs > 120_000L
                        if (!agedNoPair) {
                            try { PipelineHealthCollector.labelInc("INTAKE_NO_PAIR_HELD_HOT_FOR_HYDRATION") } catch (_: Throwable) {}
                            try { ForensicLogger.lifecycle("INTAKE_NO_PAIR_HELD_HOT_FOR_HYDRATION", "mint=${mint.take(10)} symbol=${ts.symbol} src=${ts.source} pc=$processCount ageMs=$ageMs mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} action=keep_hot") } catch (_: Throwable) {}
                        } else {
                            if (liveHeldOrManagedMint(mint)) {
                                try { PipelineHealthCollector.labelInc("LIVE_HELD_NO_PAIR_DEMOTE_REMOVE_BLOCKED_4550") } catch (_: Throwable) {}
                                try { ForensicLogger.lifecycle("LIVE_HELD_NO_PAIR_DEMOTE_REMOVE_BLOCKED_4550", "mint=${mint.take(10)} symbol=${ts.symbol} pc=$processCount ageMs=$ageMs action=keep_watchlist_and_registry") } catch (_: Throwable) {}
                                return
                            }
                            val demoted = try {
                                com.lifecyclebot.engine.GlobalTradeRegistry.demoteWatchlistToProbation(
                                    mint = mint,
                                    reason = "NO_PAIR_NO_FALLBACK_AGED",
                                    liquidityUsd = ts.lastLiquidityUsd,
                                    confidence = 0,
                                    price = 0.0,
                                    isEstimatedLiquidity = true,
                                )
                            } catch (_: Throwable) { false }
                            if (demoted) {
                                try { synchronized(status.tokens) { status.tokens.remove(mint) } } catch (_: Throwable) {}
                                try { PipelineHealthCollector.labelInc("INTAKE_NO_PAIR_DEMOTED_TO_PROBATION_AGED") } catch (_: Throwable) {}
                                try { ForensicLogger.lifecycle("INTAKE_NO_PAIR_DEMOTED_TO_PROBATION_AGED", "mint=${mint.take(10)} symbol=${ts.symbol} src=${ts.source} pc=$processCount ageMs=$ageMs mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()}") } catch (_: Throwable) {}
                            }
                        }
                    }
                    return
                }
                synth  // continue into the rest of the cycle with synthesized pair
            }

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.62: PRE-PIPELINE DECIMAL-CORRUPTION FILTER
            //
            // The scanner occasionally ingests quotes where the price is off
            // by 10^N (wrong decimal place reported by DexScreener), which
            // produces open positions with phantom +440,000,000% "wins".
            //
            // This filter runs BEFORE the token is added to status.tokens
            // and before any price update is persisted. It ONLY rejects
            // clearly broken feed data вҖ” it never blocks legitimate wins,
            // never touches the wallet, never closes open positions.
            //
            // Rules (all conservative):
            //   a) First-ingest: reject if price implies impossible supply
            //      (< 1 or > 1e15 tokens) OR if FDV/MCAP ratio > 1000.
            //   b) Already-tracked: reject the INCOMING tick if it would
            //      jump the price by more than 100Г— vs the last recorded
            //      ts.lastPrice (i.e. +9900% in a single poll вҖ” physically
            //      impossible in a normal meme candle unless the feed is
            //      misreporting decimals). The position stays open at its
            //      last valid price; a future healthy tick recovers it.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            val incomingPrice = pair.candle.priceUsd
            val incomingMcap  = pair.candle.marketCap
            val incomingFdv   = pair.fdv
            val existingTs    = status.tokens[mint]

            val firstIngest = existingTs == null
            if (firstIngest && incomingPrice > 0 && incomingMcap > 0) {
                val impliedSupply = incomingMcap / incomingPrice
                val badSupply     = impliedSupply < 1.0 || impliedSupply > 1e15
                val badFdvRatio   = incomingFdv > 0 && incomingMcap > 0 && incomingFdv / incomingMcap > 1000
                if (badSupply || badFdvRatio) {
                    ErrorLogger.warn("BotService",
                        "рҹҡ« DISCOVERY-FILTER rejected ${pair.baseSymbol.ifBlank { mint.take(6) }}: " +
                        "price=$incomingPrice mcap=$incomingMcap fdv=$incomingFdv impliedSupply=$impliedSupply " +
                        "(badSupply=$badSupply badFdv=$badFdvRatio) вҖ” decimal-corrupt feed, not adding to scanner"
                    )
                    return   // pre-pipeline вҖ” token never enters status.tokens
                }
            }
            if (!firstIngest && incomingPrice > 0 && existingTs!!.lastPrice > 0) {
                val jumpMult = incomingPrice / existingTs.lastPrice
                if (jumpMult > 100.0 || (jumpMult > 0 && jumpMult < 0.01)) {
                    ErrorLogger.warn("BotService",
                        "рҹҡ« TICK-FILTER rejected ${existingTs.symbol}: prev=${existingTs.lastPrice} вҶ’ new=$incomingPrice " +
                        "(jump=${"%.1f".format(jumpMult)}x) вҖ” decimal-shift artifact, keeping last valid price"
                    )
                    return   // drop this poll entirely; position stays at last good price
                }
            }


        synchronized(status.tokens) {
            if (!status.tokens.containsKey(mint)) {
                status.tokens[mint] = TokenState(
                    mint       = mint,
                    symbol     = pair.baseSymbol.ifBlank { mint.take(6) },
                    name       = pair.baseName,
                    pairAddress = pair.pairAddress,
                    pairUrl    = pair.url,
                    source     = "WATCHLIST",  // Tokens loaded from config
                    // V5.9.642 вҖ” no-logo watchlist hydrate. Do not make token
                    // surfacing depend on DexScreener image availability.
                    logoUrl    = "",
                )
            }
            val ts = status.tokens[mint] ?: return
            
            // Try to infer source if unknown
            if (ts.source.isEmpty() || ts.source == "UNKNOWN") {
                ts.source = when {
                    pair.url.contains("pump.fun") -> "PUMP_FUN_GRADUATE"
                    pair.url.contains("raydium") -> "RAYDIUM_NEW_POOL"
                    else -> "DEX_TRENDING"
                }
            }
            
            // Defense-in-depth: confirm the pair's base token is the mint we polled for.
            // getBestPair() already filters this, but guard here in case of stale cache hits.
            if (pair.baseTokenAddress.isNotBlank() && pair.baseTokenAddress != mint) {
                ErrorLogger.warn("BotService", "DATA POLLUTION GUARD: ${ts.symbol} pair baseToken=${pair.baseTokenAddress} != queried mint=$mint вҖ” skipping price update")
                return
            }

            // V5.9.62: decimal/price-sanity was hoisted above to act as a
            // discovery-gate + tick-gate. By the time we reach here the
            // quote is trusted enough to persist.
            val validatedPrice = incomingPrice
            
            ts.lastPrice        = validatedPrice
            ts.lastPriceSource  = "DEXSCREENER_PAIR_POLL"  // V5.9.744
            ts.lastPricePoolAddr = pair.pairAddress
            ts.lastPriceDex     = when {  // V5.9.744 вҖ” derive DEX from pair URL (PairInfo has no dexId field)
                pair.url.contains("raydium", ignoreCase = true) -> "RAYDIUM"
                pair.url.contains("pump.fun", ignoreCase = true) -> "PUMP_FUN"
                pair.url.contains("bonk", ignoreCase = true) -> "BONK"
                pair.url.contains("meteora", ignoreCase = true) -> "METEORA"
                pair.url.contains("orca", ignoreCase = true) -> "ORCA"
                else -> "UNKNOWN"
            }
            ts.lastMcap         = pair.candle.marketCap
            ts.lastLiquidityUsd = pair.liquidity
            ts.lastFdv          = pair.fdv

            // V5.9: Populate lastBuyPressurePct from polling candle data.
            // Previously only set by DexScreener WebSocket вҖ” tokens without an active
            // WS subscription were stuck at default 50.0, causing ShitCoinExpress (>=55)
            // and ManipulatedTraderAI to never trigger on polled tokens.
            val candleTxns = pair.candle.buysH1 + pair.candle.sellsH1
            if (candleTxns > 0) {
                ts.lastBuyPressurePct = pair.candle.buysH1.toDouble() / candleTxns * 100.0
            }

            // V3.2: Update shadow learning engine with price
            if (pair.candle.priceUsd > 0) {
                com.lifecyclebot.v3.learning.ShadowLearningEngine.updatePrice(
                    ts.mint, pair.candle.priceUsd
                )

                // V5.2: Update CashGenerationAI (Treasury) with independent price tracking
                // V5.9.188c: ALWAYS update so Treasury positions never show stale +0.0%
                com.lifecyclebot.v3.scoring.CashGenerationAI.updatePrice(
                    ts.mint, pair.candle.priceUsd
                )
                // V5.9.188c: CashGenerationAI.updatePrice() is the Treasury UI's price source
                // (PriceAggregator doesn't exist in this codebase)

                // V5.9.398 вҖ” push the same live price into the other 4 meme
                // sub-traders so the unified open-positions card always shows
                // fresh P&L%, not stale entry-price=current snapshots. Each
                // updateLivePrice is a fast no-op if the trader doesn't hold
                // this mint, so calling all 4 unconditionally is safe.
                com.lifecyclebot.v3.scoring.ShitCoinTraderAI.updateLivePrice(ts.mint, pair.candle.priceUsd)
                com.lifecyclebot.v3.scoring.MoonshotTraderAI.updateLivePrice(ts.mint, pair.candle.priceUsd)
                com.lifecyclebot.v3.scoring.BlueChipTraderAI.updateLivePrice(ts.mint, pair.candle.priceUsd)
                com.lifecyclebot.v3.scoring.QualityTraderAI.updateLivePrice(ts.mint, pair.candle.priceUsd)

                // V5.8: Compute price momentum вҖ” ShitCoinExpress pre-filter needs >= 3.0
                // ts.momentum was NEVER assigned anywhere, blocking all Express entries
                // V5.9.116: Require only 3 candles (was 5) so fresh launches get a
                // momentum read sooner вҖ” Express was silent on most tokens because
                // it hadn't collected 5 candles yet.
                val histSnap = ts.history
                val histSize = histSnap.size
                val refPrice = when {
                    histSize >= 5 -> histSnap.elementAtOrNull(histSize - 5)?.priceUsd ?: 0.0
                    histSize >= 3 -> histSnap.elementAtOrNull(histSize - 3)?.priceUsd ?: 0.0
                    histSize >= 2 -> histSnap.firstOrNull()?.priceUsd ?: 0.0
                    else -> 0.0
                }
                ts.momentum = if (refPrice > 0) (pair.candle.priceUsd - refPrice) / refPrice * 100.0 else null
            }
            
            synchronized(ts.history) {
                ts.history.addLast(pair.candle)
                if (ts.history.size > 300) ts.history.removeFirst()
            }
            // Update peak holder count and growth rate
            val latestHolders = pair.candle.holderCount
            if (latestHolders > ts.peakHolderCount) ts.peakHolderCount = latestHolders
            // V5.9.1453 вҖ” flip resolved=true the FIRST time we receive a
            // candle's holder count from Birdeye/Helius, even if it's 0
            // (which legitimately means zero holders after data resolved).
            // Distinguishes "data pending" from "confirmed zero holders"
            // so the FATAL rug gate doesn't kill fresh launches whose
            // holder API hasn't responded yet.
            if (!ts.holderDataResolved && pair.candle.ts > 0L) {
                ts.holderDataResolved = true
            }
            if (ts.history.size >= 12) {
                val recentH = ts.history.takeLast(3).map { it.holderCount }.filter { it > 0 }
                val earlierH = ts.history.takeLast(12).take(6).map { it.holderCount }.filter { it > 0 }
                if (recentH.isNotEmpty() && earlierH.isNotEmpty()) {
                    val rAvg = recentH.average(); val eAvg = earlierH.average()
                    ts.holderGrowthRate = if (eAvg > 0) (rAvg - eAvg) / eAvg * 100.0 else 0.0
                }
            }
        }

        val ts = status.tokens[mint] ?: return
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // PAPER MODE LEARNING: Update shadow tracking for blocked trades
        // Track what would have happened if we traded FDG-blocked opportunities
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        if (cfg.paperMode && ts.ref > 0) {
            ShadowLearningEngine.updateBlockedTradePrices(mint, ts.ref)
        }
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // Skip permanently banned tokens immediately (REAL MODE ONLY)
        // In paper mode, we want to keep trading banned tokens for learning
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        if (!cfg.paperMode && BannedTokens.isBanned(mint)) {
            // V5.9.413 вҖ” sticky held-position guard. Even banned mints must
            // stay in status.tokens if we hold an open position, otherwise
            // we can never price-check or close the bag.
            if (GlobalTradeRegistry.hasOpenPosition(mint)) {
                ErrorLogger.debug("BotService", "рҹӣЎпёҸ Banned token ${ts.symbol} kept вҖ” held position")
                return
            }
            // V5.9.624 вҖ” protected intake rule: do not remove banned mints
            // from status.tokens / scanner-visible state. Retain as shadow-only;
            // entry remains blocked by BannedTokens while scheduler fairness and
            // shadow deprioritization prevent it from becoming a loop choke.
            try {
                com.lifecyclebot.engine.MemePipelineTracer.blocked(
                    mint = ts.mint,
                    symbol = ts.symbol,
                    reason = "BANNED_TOKEN_SHADOW",
                    detail = "Banned token retained in protected intake; execution blocked",
                )
            } catch (_: Throwable) {}
            ErrorLogger.debug("BotService", "Banned token ${ts.symbol} shadow-retained in protected intake")
            return
        }
        
        // в”Җв”Җ Rug Detection - Learn from sudden liquidity/price drops в”Җв”Җ
        if (ts.history.size >= 3) {
            val recentCandles = ts.history.takeLast(3)
            val olderCandles = ts.history.takeLast(6).take(3)
            
            val recentLiq = pair.liquidity
            val olderLiq = olderCandles.firstOrNull()?.let { 
                // Estimate older liquidity from mcap if available
                ts.history.takeLast(6).firstOrNull()?.marketCap?.let { it * 0.1 } ?: recentLiq 
            } ?: recentLiq
            
            val recentPrice = recentCandles.lastOrNull()?.priceUsd ?: 0.0
            val olderPrice = olderCandles.firstOrNull()?.priceUsd ?: recentPrice
            
            // V5.0.3893 вҖ” CONFIRMED DATA ONLY for intake rug blacklists.
            // Screenshots showed repeated BLACKLIST_SHADOW "Rug detected: price -96%"
            // rows across fresh meme symbols. Source bug: V5.9.204 allowed price-only
            // collapse to become a true TokenBlacklist reason, and olderLiq was only
            // mcapГ—0.1 estimated вҖ” not a historical liquidity proof. Crypto prices can
            // print -90% from pool migration, bad decimal basis, stale BC synthetic вҶ’ DEX
            // basis switch, or indexer glitch. That is NOT enough to hard-blacklist.
            // True rug learning/blacklist now requires real liquidity-collapse evidence
            // from TokenSafetyChecker.checkLiquidityConflict plus a large price collapse.
            // Price-only collapse becomes telemetry + safety-refresh request only.
            if (olderPrice > 0 && recentPrice > 0) {
                val priceDropPct = ((olderPrice - recentPrice) / olderPrice) * 100
                val (liqConflict, liqConflictReason) = try {
                    safetyChecker.checkLiquidityConflict(mint, recentLiq)
                } catch (_: Throwable) { false to "" }
                val liqDropPct = Regex("""dropped\s+(\d+)%""", RegexOption.IGNORE_CASE)
                    .find(liqConflictReason)?.groupValues?.getOrNull(1)?.toDoubleOrNull() ?: 0.0

                val confirmedDualRug = priceDropPct >= 50.0 && liqConflict
                val unconfirmedPriceCollapse = priceDropPct >= 80.0 && !liqConflict
                if (confirmedDualRug) {
                    val ageHours = (System.currentTimeMillis() - (ts.addedToWatchlistAt)) / 3_600_000.0
                    val volumeSpike = recentCandles.sumOf { it.vol } > olderCandles.sumOf { it.vol } * 2

                    TradingMemory.learnFromRug(
                        mint = mint,
                        symbol = ts.symbol,
                        creatorWallet = null,  // Would need API to get this
                        liquidityDropPct = liqDropPct,
                        priceDropPct = priceDropPct,
                        volumeSpikeBeforeRug = volumeSpike,
                        holderDumpDetected = ts.holderGrowthRate < -20,
                        timeFromLaunchHours = ageHours,
                    )
                    addLog("рҹӨ– AI RUG LEARNED: ${ts.symbol} | confirmed price -${priceDropPct.toInt()}% liqProof=$liqConflictReason | Pattern saved", mint)
                    TokenBlacklist.block(mint, "CONFIRMED_RUG_COLLAPSE: price -${priceDropPct.toInt()}% liqProof=${liqConflictReason.take(96)} pool=${pair.pairAddress.take(12)}")
                } else if (unconfirmedPriceCollapse) {
                    try { SafetyRefreshQueue.request(mint) } catch (_: Throwable) {}
                    try { PipelineHealthCollector.labelInc("RUG_PRICE_COLLAPSE_UNCONFIRMED") } catch (_: Throwable) {}
                    try {
                        ForensicLogger.lifecycle(
                            "RUG_PRICE_COLLAPSE_UNCONFIRMED",
                            "mint=${mint.take(10)} symbol=${ts.symbol} priceDrop=${priceDropPct.toInt()}% older=$olderPrice recent=$recentPrice liq=${recentLiq.toInt()} source=${ts.lastPriceSource} pool=${pair.pairAddress.take(12)} action=no_blacklist_refresh_safety",
                        )
                    } catch (_: Throwable) {}
                }
            }
        }
        
        // в”Җв”Җ Safety check (cached 10 min) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        // V5.9.776 вҖ” EMERGENT MEME-ONLY: CRITICAL FDG-SAFETY RACE FIX.
        //
        // Operator forensics: FDG allow=0 block=65, top reason
        // SAFETY_NOT_READY_MISSING=58. Root cause: this block previously
        // launched safetyChecker.check() asynchronously via scope.launch
        // (correct optimisation for refreshes) but did the SAME for the
        // very first check (lastSafetyCheck == 0L). The same cycle then
        // continued to FDG, which read ts.lastSafetyCheck == 0L and
        // blocked with SAFETY_NOT_READY_MISSING. The async job's
        // exceptions were also being swallowed silently (empty catch on
        // Exception) so when safety actually threw (RugCheck 502,
        // network timeout, etc.) the timestamp NEVER got set and FDG
        // blocked forever.
        //
        // Fix:
        //  1) FIRST-EVER check (lastSafetyCheck == 0L) runs SYNCHRONOUSLY
        //     so FDG immediately downstream sees a non-zero timestamp.
        //     SafetyChecker has its own in-flight dedupe + 6s wait cap,
        //     so concurrent intake doesn't burn quota.
        //  2) On ANY exception we set lastSafetyCheck = now and write a
        //     HARD_BLOCK SafetyReport with reason SAFETY_RUN_FAILED.
        //     FDG hard-blocks this cycle (correct) and the stale-refresh
        //     path retries 10 min later. The exception is now logged
        //     loudly via ErrorLogger and ForensicLogger.
        //  3) STALE refresh stays async (existing behaviour) вҖ” fast loop.
        //  4) Adds SAFETY_WRITE forensic line on every successful write
        //     so operator can trace canonical key flow end-to-end.
        val safetyAge = System.currentTimeMillis() - ts.lastSafetyCheck
        val canonicalMint = com.lifecyclebot.data.CanonicalMint.normalize(mint)
        val needsFirstCheck = ts.lastSafetyCheck == 0L
        // V5.0.3894 вҖ” explicit safety hydration requests must complete BEFORE
        // FDG/lane handoff. The old SafetyRefreshQueue path used scope.launch and
        // continued immediately, so current-cycle FDG still saw missing/old safety
        // and live candidates looped through SAFETY_NOT_READY_MISSING. Age-only
        // refreshes remain async below; explicit queue/defer refresh is sync.
        val explicitSafetyRefresh = !needsFirstCheck && (
            com.lifecyclebot.engine.SafetyRefreshQueue.consume(canonicalMint) ||
                com.lifecyclebot.engine.SafetyRefreshQueue.consume(mint)
        )
        if (explicitSafetyRefresh) {
            try { ForensicLogger.lifecycle("SAFETY_REFRESH_SYNC_REQUEST", "key=${canonicalMint.take(10)} symbol=${ts.symbol} ageSec=${safetyAge / 1000}") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("SAFETY_REFRESH_SYNC_REQUEST") } catch (_: Throwable) {}
        }

        // Resolve liquidity inputs once вҖ” used by both sync and async paths.
        fun runSafetyCheck(): SafetyReport? {
            return try {
                val pairCreatedAt = pair.pairCreatedAtMs.takeIf { it > 0L } ?: pair.candle.ts
                // V5.9.605 вҖ” LIVE MEME THROTTLE ROOT CAUSE liquidity fallback.
                val regEntry = try { GlobalTradeRegistry.getEntry(canonicalMint) } catch (_: Throwable) { null }
                val isPumpBondingCurve = (pair.liquidity <= 0.0) &&
                    (regEntry?.source?.contains("PUMP", ignoreCase = true) == true)
                val registryLiqEstimate = (regEntry?.initialMcap ?: 0.0).let { mcap ->
                    if (mcap > 0.0) {
                        if (isPumpBondingCurve) mcap * 0.85 else mcap * 0.10
                    } else 0.0
                }
                val resolvedLiquidityUsd = listOf(
                    pair.liquidity,
                    ts.lastLiquidityUsd,
                    registryLiqEstimate,
                ).filter { it.isFinite() && it > 0.0 }.maxOrNull() ?: pair.liquidity
                if (pair.liquidity <= 0.0 && resolvedLiquidityUsd > 0.0) {
                    ErrorLogger.info("BotService", "рҹ’§ Safety liquidity fallback: ${ts.symbol} pair=$${pair.liquidity.toInt()} ts=$${ts.lastLiquidityUsd.toInt()} regEst=$${registryLiqEstimate.toInt()} вҶ’ using $${resolvedLiquidityUsd.toInt()}")
                }
                val r = safetyChecker.check(
                    mint            = canonicalMint,
                    symbol          = ts.symbol,
                    name            = ts.name,
                    pairCreatedAtMs = pairCreatedAt,
                    currentLiquidityUsd = resolvedLiquidityUsd,
                    score = ts.entryScore.toInt().coerceIn(0, 100),
                )
                synchronized(ts) {
                    ts.safety       = r
                    ts.lastSafetyCheck = System.currentTimeMillis()
                }
                try {
                    ForensicLogger.lifecycle(
                        "SAFETY_WRITE",
                        "key=${canonicalMint.take(10)} symbol=${ts.symbol} tier=${r.tier.name} hardBlocks=${r.hardBlockReasons.size}",
                    )
                } catch (_: Throwable) {}
                r
            } catch (e: Exception) {
                // V5.9.776 вҖ” never swallow safety failures.
                ErrorLogger.warn(
                    "BotService",
                    "рҹҡЁ SAFETY_CHECK_THREW [${ts.symbol}] mint=${canonicalMint.take(10)} ${e.javaClass.simpleName}: ${e.message?.take(120)}",
                )
                try {
                    ForensicLogger.lifecycle(
                        "SAFETY_RUN_FAILED",
                        "key=${canonicalMint.take(10)} symbol=${ts.symbol} err=${e.javaClass.simpleName}: ${e.message?.take(80)}",
                    )
                } catch (_: Throwable) {}
                // V5.9.1561 вҖ” safety failure / partial metadata is UNKNOWN,
                // not confirmed fatal. Stamp CAUTION so FDG can apply penalty
                // and preflight can reject under the correct route/cost reason.
                val failReport = SafetyReport(
                    tier = SafetyTier.CAUTION,
                    softPenalties = listOf("SAFETY_RUN_FAILED_PARTIAL_DATA: ${e.message?.take(60) ?: e.javaClass.simpleName}" to 18),
                    entryScorePenalty = 18,
                    rugcheckStatus = "PENDING_REVIEW",
                    checkedAt = System.currentTimeMillis(),
                )
                synchronized(ts) {
                    ts.safety       = failReport
                    ts.lastSafetyCheck = System.currentTimeMillis()
                }
                null
            }
        }

        if (needsFirstCheck || explicitSafetyRefresh) {
            // SYNCHRONOUS first-ever / explicit-defer safety check so the very next
            // pipeline phase (FDG) sees a populated ts.lastSafetyCheck. SafetyChecker's
            // per-mint in-flight dedupe keeps concurrent callers cheap (6s wait cap).
            // This is the current-structure equivalent of the 3868 live path: do not
            // dispatch a live candidate until the safety proof write has landed.
            val report = runSafetyCheck()
            if (report != null) {
                when (report.tier) {
                    SafetyTier.HARD_BLOCK -> {
                        val reason = report.hardBlockReasons.firstOrNull() ?: "Safety check"
                        addLog("SAFETY BLOCK [${ts.symbol}]: $reason", mint)
                        sendTradeNotif("Token Blocked", "${ts.symbol}: ${report.summary}",
                            NotificationHistory.NotifEntry.NotifType.SAFETY_BLOCK)
                        val isTransientLiquidityBlock = reason.startsWith("Liquidity ", ignoreCase = true) && pair.liquidity <= 0.0
                        if (!isTransientLiquidityBlock) {
                            TokenBlacklist.block(mint, "Safety: $reason")
                            ScannerHardRejectStore.mark(mint, ts.symbol, "Safety: $reason", "SAFETY_ASYNC")
                            try { GlobalTradeRegistry.registerRejection(mint, ts.symbol, "Safety: $reason", "SAFETY_ASYNC_HARD") } catch (_: Throwable) {}
                        }
                        if (reason.contains("rug", ignoreCase = true) ||
                            reason.contains("honeypot", ignoreCase = true) ||
                            reason.contains("scam", ignoreCase = true)) {
                            BannedTokens.ban(mint, "Safety: $reason")
                            addLog("рҹҡ« PERMANENTLY BANNED: ${ts.symbol} - $reason", mint)
                        }
                        soundManager.playSafetyBlock()
                    }
                    SafetyTier.CAUTION -> {
                        addLog("SAFETY CAUTION [${ts.symbol}]: ${report.summary}", mint)
                    }
                    else -> {}
                }
            }
        } else if (safetyAge > SAFETY_REFRESH_TRIGGER_MS) {
            // Age-only stale refresh stays async. Explicit finality/pretrade safety
            // hydration is handled synchronously above so FDG cannot race the write.
            // V5.9.1495 вҖ” STALE-REFRESH DEAD-ZONE FIX (source).
            // ROOT CAUSE (5.0.3501): FDG hard-blocks LIVE entries with
            // SAFETY_NOT_READY_STALE once safetyAge > LiveBuyAdmissionGate
            // .SAFETY_STALE_MS (120s), but this refresher only re-ran the
            // safety check when safetyAge > 10min. That left a 2minвҖ“10min
            // DEAD ZONE: the report was "stale" to FDG (blocking otherwise
            // valid live buys, e.g. BrГ¶tchen safety=SAFE rug=58 still blocked)
            // yet nothing regenerated it until 10min. For 10 live testers this
            // silently kills real entries. Fix: trigger the async refresh at
            // (SAFETY_STALE_MS - 30s margin) so a fresh report lands BEFORE
            // FDG's staleness cutoff. Still async (hot loop never blocks); no
            // veto/threshold weakening вҖ” we just stop starving the refresher.
            scope.launch {
                val report = runSafetyCheck() ?: return@launch
                when (report.tier) {
                    SafetyTier.HARD_BLOCK -> {
                        val reason = report.hardBlockReasons.firstOrNull() ?: "Safety check"
                        addLog("SAFETY BLOCK [${ts.symbol}]: $reason", mint)
                        sendTradeNotif("Token Blocked", "${ts.symbol}: ${report.summary}",
                            NotificationHistory.NotifEntry.NotifType.SAFETY_BLOCK)
                        val isTransientLiquidityBlock = reason.startsWith("Liquidity ", ignoreCase = true) && pair.liquidity <= 0.0
                        if (!isTransientLiquidityBlock) {
                            TokenBlacklist.block(mint, "Safety: $reason")
                            ScannerHardRejectStore.mark(mint, ts.symbol, "Safety: $reason", "SAFETY_ASYNC")
                            try { GlobalTradeRegistry.registerRejection(mint, ts.symbol, "Safety: $reason", "SAFETY_ASYNC_HARD") } catch (_: Throwable) {}
                        }
                        if (reason.contains("rug", ignoreCase = true) ||
                            reason.contains("honeypot", ignoreCase = true) ||
                            reason.contains("scam", ignoreCase = true)) {
                            BannedTokens.ban(mint, "Safety: $reason")
                            addLog("рҹҡ« PERMANENTLY BANNED: ${ts.symbol} - $reason", mint)
                        }
                        soundManager.playSafetyBlock()
                    }
                    SafetyTier.CAUTION -> {
                        addLog("SAFETY CAUTION [${ts.symbol}]: ${report.summary}", mint)
                    }
                    else -> {}
                }
            }
        }

    // Note: lastSuccessfulPollMs update is handled in botLoop

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.407 вҖ” IDLE вҶ’ SCANNING transition.
    // The TokenState's default phase is literally "idle". Without this nudge,
    // any token that gets blocked by an early gate (HardRugPreFilter,
    // DistributionFadeAvoider, etc) never escapes "IDLE" in the UI even
    // though we are actively examining it every cycle. Promoting to
    // "scanning" the moment we touch the token gives the user honest live
    // progress in the watchlist column.
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if (ts.phase == "idle" && !ts.position.isOpen) {
        ts.phase = "scanning"
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.449 вҖ” REMOVED V5.9.417 HARD_SL_BACKSTOP (-25% memes / -30% others).
    // The backstop was killing winners that wicked past -25% before they
    // could recover вҖ” exactly the meme runners that produced build-1941's
    // 60% WR + 500% trades. Build-1941 era trusted each sub-trader's own
    // HARD_FLOOR (ShitCoin -20, Quality SL ladder, Moonshot -20) and let
    // wicks survive. With ShitCoinTraderAI.HARD_FLOOR_STOP_PCT now back
    // at -20 (V5.9.449 revert) and the universal back-fund still in place
    // (TreasuryManager $500 floor + MemeWREmergencyBrake), the backstop
    // is redundant choke pressure. See V5.9.449 deep-dive write-up.
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // STEP 0: CORE EVALUATIONS (needed by subsequent steps)
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    val curveState = BondingCurveTracker.evaluate(ts)
    val whaleState = WhaleDetector.evaluate(mint, ts)

    // V5.9.418 вҖ” REFRESH SYMBOLIC CONTEXT PER MEME CYCLE.
    // SymbolicContext.refresh() is internally throttled (2s) so calling it
    // here every cycle is cheap; this guarantees that the 24-channel
    // symbolic nervous system has *this* token's symbol/mint stamped on
    // its latest snapshot before V3 / FDG / sub-traders read it. Without
    // this, the per-token signals (CrossRegime, LeadLag, Fragility,
    // PortfolioHeat, вҖҰ) were only being refreshed once per outer botLoop
    // cycle from the global symbol вҖ” meme entries on hot launches got the
    // BTC/SOL signal map instead of their own.
    try { com.lifecyclebot.engine.SymbolicContext.refresh(ts.symbol, ts.mint) } catch (_: Throwable) {}
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // STEP 1: HARD RUG PRE-FILTER
    // Kill obvious garbage BEFORE consuming strategy/FDG cycles
    // V5.2 FIX: Pass paperMode to allow learning from all tokens
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if (!ts.position.isOpen) {
        val preFilterResult = try {
            HardRugPreFilter.filter(ts, cfg.paperMode)
        } catch (e: Exception) {
            ErrorLogger.debug("BotService", "PreFilter error: ${e.message}")
            HardRugPreFilter.PreFilterResult(true, null, HardRugPreFilter.FilterSeverity.PASS)
        }
        
        if (!preFilterResult.pass) {
            HardRugPreFilter.logFailure(ts, preFilterResult)
            // V5.9.407 вҖ” surface why we bailed so the watchlist stops showing IDLE.
            ts.phase = when {
                preFilterResult.reason?.contains("LIQUID", true) == true -> "thin_liq"
                preFilterResult.reason?.contains("CONCEN", true) == true -> "rug_holders"
                preFilterResult.reason?.contains("AUTH",  true) == true  -> "rug_auth"
                else                                                      -> "rug_filtered"
            }
            return  // Skip to next token (exit this coroutine)
        }
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // STEP 2: DISTRIBUTION FADE AVOIDER
    // Check if token is in distribution/dead-bounce state
    // Note: edgePhase comes from ScoreResult later, so we pass null here
    // and rely on price/volume pattern detection instead
    // V5.2 FIX: Pass paperMode to allow learning from distribution trades
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    val distributionCheck = try {
        DistributionFadeAvoider.evaluate(ts, null, cfg.paperMode)
    } catch (e: Exception) {
        ErrorLogger.debug("BotService", "DistFade error: ${e.message}")
        DistributionFadeAvoider.FadeResult(false, null, 1.0, 0L)
    }
    
    if (distributionCheck.shouldBlock && !ts.position.isOpen) {
        ErrorLogger.info("BotService", "рҹ”» ${ts.symbol} DISTRIBUTION_FADE: ${distributionCheck.reason}")
        ts.phase = "distributing"   // V5.9.407 вҖ” surface gate reason in UI
        // V5.9.495z50 вҖ” operator log 17:43 evidence:
        // The watchlist gets dominated by drained/rugged tokens (HEG, Harambe,
        // Hitler etc.) that keep firing DISTRIBUTION_FADE every cycle. These
        // zombies starve fresh high-liq candidates (HANTY $3242, GIGARAT $21733)
        // out of the per-cycle processing budget. When a token is draining
        // ($0 current liquidity) AND not held, evict it from watchlist + status
        // immediately so fresh candidates get a fair shot.
        val drainedZombie = ts.lastLiquidityUsd <= 0.0 &&
            distributionCheck.reason?.contains("DRAIN", ignoreCase = true) == true
        if (drainedZombie) {
            // V5.9.624 вҖ” protected intake rule: do NOT evict drained zombies from
            // GlobalTradeRegistry/status.tokens. Tag them as shadow-only and let
            // the fair scheduler deprioritize them. This preserves the scanner /
            // watchlist as an intake universe while still preventing a drained
            // token from becoming an entry candidate.
            try {
                com.lifecyclebot.engine.MemePipelineTracer.blocked(
                    mint = ts.mint, symbol = ts.symbol,
                    reason = "DRAINED_ZOMBIE_SHADOW",
                    detail = "liq=\$0 + DISTRIBUTION_FADE вҖ” shadow-only, retained in protected intake",
                )
            } catch (_: Throwable) {}
            try {
                LiveTradeLogStore.log(
                    tradeKey = "INTAKE_${ts.mint.take(16)}",
                    mint = ts.mint,
                    symbol = ts.symbol,
                    side = "INFO",
                    phase = LiveTradeLogStore.Phase.INTAKE_RISK_PENALTY,
                    message = "рҹӣЎ drained zombie risk-shadow retained in protected intake",
                    traderTag = "INTAKE",
                )
            } catch (_: Throwable) {}
        }
        return  // Skip to next token (exit this coroutine)
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // STEP 3: LIQUIDITY BUCKET CLASSIFICATION
    // Determines which mode family is appropriate
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    val liquidityBucket = try {
        LiquidityBucketRouter.classify(ts)
    } catch (e: Exception) {
        ErrorLogger.debug("BotService", "LiqBucket error: ${e.message}")
        null
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // STEP 4: REENTRY RECOVERY CHECK
    // If token previously failed, use stricter recovery rules
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    val isRecoveryCandidate = ReentryRecoveryMode.isRecoveryCandidate(ts.mint)
    val recoveryEval = if (isRecoveryCandidate && !ts.position.isOpen) {
        try {
            val eval = ReentryRecoveryMode.evaluateRecovery(ts)
            ReentryRecoveryMode.logEvaluation(ts, eval)
            eval
        } catch (e: Exception) {
            ErrorLogger.debug("BotService", "ReentryRecovery error: ${e.message}")
            null
        }
    } else null
    
    // Auto-mode evaluation - must come before strategy.evaluate
    val trendRank  = try { null } catch (_: Exception) { null } // from CoinGecko cache
    val modeConf   = if (cfg.autoMode) {
        autoMode.evaluate(ts, whaleState.whaleScore, trendRank, curveState.stage)
    } else null
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // STEP 5: MODE ROUTER - Classify what KIND of trade this is
    // 
    // Pipeline: prefilter вҶ’ distribution check вҶ’ liq bucket вҶ’ mode classifier вҶ’ FDG
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    val modeClassification = try {
        ModeRouter.classify(ts)
    } catch (e: Exception) {
        ErrorLogger.debug("BotService", "ModeRouter error: ${e.message}")
        ModeRouter.Classification(
            tradeType = ModeRouter.TradeType.UNKNOWN,
            confidence = 0.0,
            signals = emptyList(),
            subSignals = emptyMap(),
        )
    }
    
    // V5.9.1414 вҖ” FLUID CHARACTER RE-ROUTE. Merge the classifier's lane
    // affinity onto this mint every tick. At birth this seeds the right lane;
    // as character emerges (thin token graduates into a runner, accumulation
    // pattern firms up) the newly-appropriate lane is added and can claim the
    // book on the next election. Gated on a confident, non-UNKNOWN verdict so
    // noise doesn't thrash routing. Additive only вҖ” existing lanes are kept.
    try {
        if (modeClassification.tradeType != ModeRouter.TradeType.UNKNOWN &&
            modeClassification.confidence >= 50.0) {
            val baseCharLanes = laneAffinityForTradeType(modeClassification.tradeType)
            val styleDecision = AgenticStyleRouter.decide(ts, modeClassification)
            // V5.0.4125 вҖ” Persist style TP/hold multipliers on TokenState so ALL
            // downstream buy paths (paperBuy, liveBuy, treasuryBuy, blueChipBuy,
            // shitCoinBuy, dipHunterBuy, v3Buy) can apply them at Position creation.
            // Previously only MOONSHOT at line ~18180 used the style decision.
            ts.styleTpMult = styleDecision.tunedTpMult
            ts.styleHoldMult = styleDecision.tunedHoldMult
            val charLanes = AgenticStyleRouter.lanesFor(ts, modeClassification, baseCharLanes)
            val charTools = AgenticStyleRouter.toolsFor(ts, modeClassification, emptySet())
            if (charLanes.isNotEmpty() || charTools.isNotEmpty()) {
                val newLanes = charLanes - (GlobalTradeRegistry.getLaneAffinity(ts.mint))
                val newTools = charTools - (GlobalTradeRegistry.getToolAffinity(ts.mint))
                if (newLanes.isNotEmpty() || newTools.isNotEmpty()) {
                    ts.laneAffinity.addAll(charLanes)
                    ts.toolAffinity.addAll(charTools)
                    GlobalTradeRegistry.mergeAffinity(ts.mint, charLanes, charTools)
                    try {
                        ForensicLogger.lifecycle(
                            "AGENTIC_STYLE_ROUTE",
                            "symbol=${ts.symbol} mint=${ts.mint.take(10)} style=${styleDecision.style.label} " +
                            "type=${modeClassification.tradeType} tactic=${styleDecision.tactic} conf=${modeClassification.confidence.toInt()} " +
                            "+lanes=${newLanes.joinToString("+")} +tools=${newTools.joinToString("+")} reason=${styleDecision.reason.take(140)}"
                        )
                    } catch (_: Throwable) {}
                }
            }
        }
    } catch (_: Throwable) {}

    // Apply distribution penalty to mode classification confidence
    val adjustedModeConfidence = modeClassification.confidence * distributionCheck.scoreMultiplier
    
    // Apply liquidity bucket size multiplier
    val liqSizeMultiplier = liquidityBucket?.maxSizeMultiplier ?: 1.0
    
    // Apply recovery mode restrictions if applicable
    val finalSizeMultiplier = if (recoveryEval?.canReenter == true) {
        liqSizeMultiplier * recoveryEval.sizeMultiplier
    } else {
        liqSizeMultiplier
    }
    
    // Run specialized scanners for additional signals
    val scanResult = try {
        ModeSpecificScanners.scanAll(ts)
    } catch (e: Exception) {
        ErrorLogger.debug("BotService", "ModeScanner error: ${e.message}")
        null
    }
    
    // Log significant classifications
    if (modeClassification.tradeType != ModeRouter.TradeType.UNKNOWN && 
        modeClassification.confidence > 50 && !ts.position.isOpen) {
        ModeRouter.logClassification(ts, modeClassification)
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // PRIORITY 2: Use unified evaluateWithDecision for complete analysis
    // Pass isPaperMode to relax Edge veto in paper mode for better learning
    // Pass brain for adaptive threshold learning
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // MOMENTUM PREDICTOR AI: Record price/volume data for pattern detection
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    try {
        if (ts.history.size >= 2) {
            val lastCandle = ts.history.lastOrNull()
            if (lastCandle != null) {
                MomentumPredictorAI.recordPricePoint(
                    mint = mint,
                    symbol = ts.symbol,
                    price = lastCandle.priceUsd,
                    volume = lastCandle.vol,
                    buyPressure = (lastCandle.buyRatio * 100),
                    txCount = lastCandle.buysH1 + lastCandle.sellsH1,
                )
            }
        }
    } catch (e: Exception) {
        ErrorLogger.debug("BotService", "MomentumPredictorAI record error: ${e.message}")
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.978 вҖ” TIER 1 FEEDER-CONSUMER ASYMMETRY FIX
    // Three V3 scoring layers (OrderFlowImbalanceAI, SmartMoneyDivergenceAI,
    // VolatilityRegimeAI) had dormant analyze() feeders вҖ” their score()
    // methods were aggregating neutral defaults forever, diluting real
    // layers. Doctrine #31: scoring layers without feeders are dead weight.
    // Feed them all from the candle history at the same tick frequency
    // as MomentumPredictorAI.
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    try {
        val hist = ts.history
        if (hist.size >= 5) {
            // Take last 20 candles вҖ” enough for ATR(14) + flow window
            val window = hist.takeLast(20)

            // OrderFlowImbalanceAI: needs buy/sell volume + price series
            try {
                val buyVols  = window.map { it.vol * it.buyRatio }
                val sellVols = window.map { it.vol * (1.0 - it.buyRatio) }
                val prices   = window.map { it.priceUsd }
                com.lifecyclebot.v3.scoring.OrderFlowImbalanceAI.analyze(
                    mint = mint, symbol = ts.symbol,
                    buyVolumes = buyVols, sellVolumes = sellVols, prices = prices,
                )
            } catch (_: Throwable) {}

            // SmartMoneyDivergenceAI: needs price series + whale recommendation
            try {
                val prices = window.map { it.priceUsd }
                com.lifecyclebot.v3.scoring.SmartMoneyDivergenceAI.analyze(
                    mint = mint, symbol = ts.symbol,
                    recentPrices = prices,
                    whaleRecommendation = null,  // analyze() looks it up if null
                    topHolderPctChange = 0.0,
                    holderCountChange = 0,
                )
            } catch (_: Throwable) {}

            // VolatilityRegimeAI: needs OHLC arrays for ATR
            try {
                val highs  = window.map { if (it.highUsd > 0) it.highUsd else it.priceUsd }
                val lows   = window.map { if (it.lowUsd  > 0) it.lowUsd  else it.priceUsd }
                val closes = window.map { it.priceUsd }
                com.lifecyclebot.v3.scoring.VolatilityRegimeAI.analyze(
                    mint = mint, symbol = ts.symbol,
                    recentHighs = highs, recentLows = lows, recentCloses = closes,
                )
            } catch (_: Throwable) {}
        }
    } catch (e: Exception) {
        ErrorLogger.debug("BotService", "V3-scorer feeder error: ${e.message}")
    }
    
    val modeConfForEval = if (cfg.autoMode) modeConf else null
    // V5.9.58: Gentle self-heal if the scanner has choked itself off.
    try { executor.brain?.maybeEaseDrought() } catch (_: Exception) {}
    val (result, decision) = strategy.evaluateWithDecision(ts, modeConfForEval, cfg.paperMode, executor.brain)

        synchronized(ts) {
            ts.phase      = result.phase
            ts.signal     = result.signal
            ts.entryScore = result.entryScore
            ts.exitScore  = result.exitScore
            ts.meta       = result.meta
        }
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V3 CLEAN RUNTIME: Strategy output is now INPUT to V3, not a decision
        // 
        // Old flow: Strategy вҶ’ "BUY SIGNAL" вҶ’ CANDIDATE вҶ’ FDG вҶ’ V3 (nested)
        // New flow: Strategy вҶ’ V3 input вҶ’ V3 SCORING вҶ’ V3 DECISION вҶ’ Execute
        // 
        // Strategy still calculates entry/exit scores, phases, quality - but
        // these become V3 CandidateSnapshot extras, not decision authority.
        // V3 is the ONLY thing that outputs EXECUTE/WATCH/REJECT.
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        
        // NOTE: Legacy logs like "BUY SIGNAL", "shouldTrade", "CANDIDATE" 
        // are now suppressed. V3 will output clean decision logs.

        // Sentiment refresh (every sentimentPollMins)
    val sentAge = System.currentTimeMillis() - ts.lastSentimentRefresh
    if (cfg.sentimentEnabled && sentAge > cfg.sentimentPollMins * 60_000L) {
        scope.launch {
            try {
                val fresh = sentimentEngine.refresh(mint, ts.symbol, ts.lastPrice)
                synchronized(ts) {
                    ts.sentiment = fresh
                    ts.lastSentimentRefresh = System.currentTimeMillis()
                }
                if (fresh.blocked) {
                    addLog("SENTIMENT BLOCK: ${fresh.blockReason}", mint)
                    sendTradeNotif("Blocked", "${ts.symbol}: ${fresh.blockReason}", NotificationHistory.NotifEntry.NotifType.SAFETY_BLOCK)
                }
            } catch (_: Exception) {}
        }
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // SMART CHART SCANNER вҖ” Multi-timeframe pattern detection
    // Runs asynchronously to avoid blocking main evaluation loop
    // Feeds insights to SuperBrainEnhancements for learning
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if (ts.history.size >= 10) {
        scope.launch {
            try {
                // V5.9.495z14 вҖ” every 10th scan (per-token), run a FULL
                // multi-timeframe scan instead of the 5-min quickScan. Long-
                // horizon patterns (Cup & Handle, Head & Shoulders, Wedges,
                // Dead Cat Bounce, etc.) need 1h+ candles which quickScan
                // never reaches. Sample 1-in-10 to cap CPU cost.
                val tick = smartChartScanCounter.incrementAndGet()
                val results = if (tick % 10 == 0L) SmartChartScanner.scan(ts)
                              else listOfNotNull(SmartChartScanner.quickScan(ts))
                val scanResult = results.maxByOrNull { it.confidence }
                if (scanResult != null && scanResult.confidence >= 60) {
                    // V5.9.495z14 вҖ” push pattern enum names into cache so the
                    // entry decision can read them via getPatternNames() and
                    // apply PatternAutoTuner.getPatternMultiplier(name).
                    val patternNames = results.flatMap { r ->
                        r.candlePatterns.map { it.name } + r.chartPatterns.map { it.name }
                    }.distinct()
                    SmartChartCache.update(
                        mint = ts.mint,
                        bias = scanResult.overallBias,
                        confidence = scanResult.confidence,
                        patternNames = patternNames,
                    )
                    val patternStr = buildString {
                        scanResult.candlePatterns.forEach { append(it.emoji) }
                        scanResult.chartPatterns.forEach { append(it.emoji) }
                    }
                    if (patternStr.isNotEmpty()) {
                        ErrorLogger.debug("SmartChart", 
                            "${ts.symbol}: $patternStr ${scanResult.overallBias} (${scanResult.confidence.toInt()}%)")
                    }
                }
            } catch (e: Exception) {
                ErrorLogger.debug("BotService", "SmartChart scan error: ${e.message}")
            }
        }
    }

    // Blacklist check вҖ” immediate skip if blocked. Workset filtering normally keeps
    // flat hard-blacklisted rows out before they burn lane-eval slots; this branch is
    // the per-mint safety net and held-position exit surface.
    if (TokenBlacklist.isBlocked(mint)) {
        if (ts.position.isOpen) {
            // Force exit if we somehow hold a blacklisted token
            val effectiveBalance = status.getEffectiveBalance(cfg.paperMode)
            executor.maybeAct(ts, "EXIT", 0.0, effectiveBalance, wallet,
                lastSuccessfulPollMs, status.openPositionCount, status.totalExposureSol)
        } else {
            try { ForensicLogger.lifecycle("TOKEN_BLACKLIST_FLAT_SKIPPED_PRELANE", "mint=${mint.take(10)} symbol=${ts.symbol} paper=${cfg.paperMode} source=${ts.source.take(80)}") } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("TOKEN_BLACKLIST_FLAT_SKIPPED_PRELANE") } catch (_: Throwable) {}
        }
        return
    }

    // In PAUSED mode: no new entries (existing positions still managed)
    if (modeConf?.mode == AutoModeEngine.BotMode.PAUSED && !ts.position.isOpen) {
        try {
            PipelineHealthCollector.labelInc("ENTRY_SUPPRESSOR_AUTOMODE_PAUSED_4163")
            ForensicLogger.lifecycle("ENTRY_SUPPRESSOR_AUTOMODE_PAUSED_4163", "mint=${mint.take(10)} symbol=${ts.symbol} source=${ts.source.take(80)}")
        } catch (_: Throwable) {}
        return
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.1270 вҖ” REVIVE RegimeTransitionAI (dead-intelligence fix).
    // AUDIT FINDING: analyzeTransition() вҖ” the ONLY method that populates
    // transitionCache вҖ” had ZERO callers anywhere in the codebase. So
    // getActiveTransitions() filtered a permanently-empty map and always
    // returned []. Consequence: SymbolicExitReasoner rule #18 "Transition
    // Pressure" (weight 0.04) + the AGI snapshot's RegimeTransitionPressure
    // read dead air and NEVER fired. An entire exit-reasoning signal вҖ”
    // meant to de-risk on rug-forming / graduation / breakout regime shifts
    // вҖ” ran inert. Producer existed, consumer existed, wire was missing.
    // Feed it once per cycle for OPEN positions (where transition pressure
    // matters for exits). analyzeTransition has its own CACHE_TTL_MS guard
    // so per-cycle calls are cheap. Fail-open. holderCount/volume24h are not
    // on the runtime TokenState; the detection keys on regime/liq/vol/
    // momentum deltas which ARE real here.
    if (ts.position.isOpen) {
        try {
            com.lifecyclebot.v3.scoring.RegimeTransitionAI.analyzeTransition(
                mint = ts.mint,
                symbol = ts.symbol,
                currentRegime = modeConf?.mode?.name ?: "NEUTRAL",
                liquidity = ts.lastLiquidityUsd,
                volatility = ts.volatility ?: 0.0,
                momentum = ts.momentum ?: 0.0,
                holderCount = 0,
                volume24h = 0.0,
            )
        } catch (_: Exception) {}
    }

    // Trade on ALL watchlist tokens simultaneously
    val cbState = securityGuard.getCircuitBreakerState()
    val effectiveBalance = status.getEffectiveBalance(cfg.paperMode)
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // TRADE IDENTITY: Get or create canonical identity for this token
    // This ensures mint/symbol are always consistent across all systems
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    val identity = TradeIdentityManager.getOrCreate(ts.mint, ts.symbol, ts.source)
    val cyclePrimaryLane = canonicalCycleLaneFor(ts, modeClassification)
    try {
        ForensicLogger.lifecycle(
            "CYCLE_PRIMARY_LANE",
            "mint=${ts.mint.take(10)} symbol=${ts.symbol} primary=$cyclePrimaryLane type=${modeClassification.tradeType} conf=${modeClassification.confidence.toInt()}"
        )
    } catch (_: Throwable) {}

    // V5.9.1094 вҖ” CIRCUIT BREAKER EARLY BUY SHORT-CIRCUIT.
    // The breaker was previously discovered inside FDG, after all lane evals
    // had already run. That produced storms: LANE_EVAL/FDG/EXEC_OPEN_REQUEST/
    // PAPER_LEARNING_PROBE_NOT_EXECUTED/LANE_BUY_NOT_OPENED_RELEASED while the
    // snapshot already showed CIRCUIT_BREAKER. Exits and universal/rug safety
    // above this point still run; new BUY/V3/lane/FDG/open work below is paused.
    if (!ts.position.isOpen) {
        try {
            val toxicPause = com.lifecyclebot.engine.ToxicModeCircuitBreaker.currentEntryPause()
            if (toxicPause.active && !cfg.paperMode) {
                if (com.lifecyclebot.engine.ToxicModeCircuitBreaker.emitExecutionStateBlockedIfDue(identity.symbol, "processTokenCycle.preLane")) {
                    return
                }
            } else if (toxicPause.active && cfg.paperMode) {
                // V5.0.3907 вҖ” PAPER must keep learning/refilling during circuit pauses.
                // SecurityGuard and ExecutableOpenGate already bypass this pause for PAPER,
                // but this pre-lane short-circuit returned before V3/LANE_EVAL/FDG, producing
                // the exact UI symptom: Signal=BUY + Paused + open book draining with no refill.
                try { ForensicLogger.lifecycle("PAPER_PRELANE_CIRCUIT_PAUSE_BYPASSED", "mint=${identity.mint.take(10)} symbol=${identity.symbol} reason=${toxicPause.reason}") } catch (_: Throwable) {}
                try { PipelineHealthCollector.labelInc("PAPER_PRELANE_CIRCUIT_PAUSE_BYPASSED") } catch (_: Throwable) {}
            }
        } catch (_: Throwable) {}
    }

    if (!ts.position.isOpen) {
        if (RuntimeConfigOverlay.isTradingPaused() || RuntimeConfigOverlay.isPreAuthDisabled()) {
            try { ForensicLogger.lifecycle("PREAUTH_BLOCK_RUNTIME_OVERLAY", "symbol=${identity.symbol} mint=${identity.mint.take(10)}") } catch (_: Throwable) {}
            return
        }
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V3 CLEAN RUNTIME: V3 is the PRIMARY and ONLY decision authority
    // 
    // Flow:
    //   1. Basic eligibility (dedupe, fatal suppression)
    //   2. V3 processes token using Strategy output as input
    //   3. V3 outputs: EXECUTE/WATCH/REJECT/BLOCK with clean logs
    //   4. Only EXECUTE triggers trade
    //
    // Legacy concepts (shouldTrade, BUY SIGNAL, CANDIDATE) are internal
    // notes only - they do NOT control execution anymore.
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    
    // DEDUPE: Skip if we recently evaluated this token
    val (canProposeEarly, dedupeReason) = TradeLifecycle.canPropose(identity.mint)
    if (!canProposeEarly && !ts.position.isOpen) {
        // V5.0: Log why tokens are being skipped (for debugging)
        ErrorLogger.debug("BotService", "вҸӯпёҸ SKIP: ${identity.symbol} | $dedupeReason")
        return
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.690 вҖ” SYMBOL FAMILY DEDUP GUARD
    // Blocks entry when a same-name-family token is already open.
    // Pump.fun deployers carpet-launch 5-20 near-identical tokens
    // (Maya / MAYA / MAYAS / maya) all at the same micro-price вҖ”
    // the bot was entering all of them simultaneously, creating a
    // correlated loss cluster that shows as a wall of -2.9% positions.
    //
    // Rule: if ANY open position shares a case-insensitive normalised
    // root (first 4+ chars stripped of special chars) with this token,
    // skip it UNLESS we have no open position at all for this mint.
    //
    // V5.9.923 вҖ” EXTEND DEDUP TO UNION OF ALL LANE STORES.
    // Operator V5.9.922 screenshots: two open Luisa positions (one on
    // meme card mintA @ $0.00000264 entered 02:11, one on Treasury
    // Scalps card mintB @ $0.00000236 entered 02:12). Same risk with
    // FFD, Tiko. Root cause: the V5.9.690 loop scanned only
    // status.tokens.values for ts.position.isOpen. CashGenerationAI /
    // BlueChip / Moonshot / ShitCoin / Quality / Manipulated /
    // ProjectSniper all keep their own position maps; those lanes were
    // invisible to the family-dedup, so an already-held Luisa via the
    // Treasury private store did not block a second meme-lane Luisa
    // entry (or vice-versa). UnifiedPositionRegistry flattens every
    // lane store into a single read so we catch all variants.
    //
    // Same-mint check is also strengthened: a mint we hold via any
    // private lane store must not get a second open via another lane,
    // even if the symbol root differs.
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if (!ts.position.isOpen) {
        // V5.9.923 вҖ” same-mint guard across every lane store.
        try {
            if (UnifiedPositionRegistry.isMintHeldAnywhere(identity.mint, excludeLane = null)) {
                ErrorLogger.debug("BotService",
                    "вҸӯпёҸ CROSS_LANE_MINT_DEDUP: ${identity.symbol} | ${identity.mint.take(8)} already held by another lane вҶ’ skip")
                try {
                    ForensicLogger.lifecycle(
                        "CROSS_LANE_MINT_DEDUP",
                        "mint=${identity.mint.take(10)} symbol=${identity.symbol}",
                    )
                } catch (_: Throwable) {}
                return
            }
        } catch (_: Throwable) {}

        // V5.9.923 вҖ” family dedup now scans the union of all lane stores.
        try {
            if (UnifiedPositionRegistry.isFamilyHeldAnywhere(identity.symbol, identity.mint)) {
                val thisRoot = identity.symbol.uppercase().replace(Regex("[^A-Z0-9]"), "").take(4)
                ErrorLogger.debug("BotService",
                    "вҸӯпёҸ SYMBOL_FAMILY_DEDUP: ${identity.symbol} | root=$thisRoot | same-family already open in some lane вҶ’ skip")
                try {
                    ForensicLogger.lifecycle(
                        "SYMBOL_FAMILY_DEDUP",
                        "mint=${identity.mint.take(10)} symbol=${identity.symbol} root=$thisRoot",
                    )
                } catch (_: Throwable) {}
                return
            }
        } catch (_: Throwable) {}
    }

    // FATAL SUPPRESSION: Only rugged/honeypot/unsellable blocks
    val isFatalSuppression = DistributionFadeAvoider.isFatalSuppression(identity.mint)
    if (isFatalSuppression && !ts.position.isOpen) {
        val reason = DistributionFadeAvoider.checkRawStrategySuppression(identity.mint)
        ErrorLogger.info("BotService", "[FATAL] ${identity.symbol} | BLOCK | $reason")
        return
    }
    
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V5.9.248: UNIVERSAL ENTRY GATES вҖ” apply to ALL layers, no exceptions
    //   1. Re-entry cooldown  вҖ” don't rebuy the same token we just sold
    //   2. Volume gate        вҖ” don't buy dead tokens with no activity
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if (!ts.position.isOpen) {
        // V5.9.704 вҖ” graduated air control: guards activate progressively
        // per the 500/1000/3000/5000-trade schedule.
        val guardLvl = FreeRangeMode.guardLevel()
        val wideOpen = guardLvl == 0  // kept for vol-gate branch below

        // 1. RE-ENTRY COOLDOWN вҖ” active at guardLevel >= 2 (1000+ trades)
        val closedAgoMs = System.currentTimeMillis() - (BotService.recentlyClosedMs[ts.mint] ?: 0L)
        if (guardLvl >= 2 && closedAgoMs < BotService.RE_ENTRY_COOLDOWN_MS) {
            ErrorLogger.debug("BotService", "вҸі [COOLDOWN] ${identity.symbol} | SKIP | closed ${closedAgoMs/1000}s ago (min ${BotService.RE_ENTRY_COOLDOWN_MS/1000}s)")
            return
        }

        // V5.9.353: 1b. LOSS-STREAK BLOCK вҖ” refuse re-entry on a mint whose
        // last 3 closes were all losses (block elapses after 1 hour).
        // MemeLossStreakGuard activates at guardLevel >= 1 internally, but the
        // BotService check here also guards via guardLvl so the log is consistent.
        val lossBlockUntil = MemeLossStreakGuard.blockedUntilMs(ts.mint)
        if (guardLvl >= 1 && lossBlockUntil > 0L) {
            val remainingMin = (lossBlockUntil - System.currentTimeMillis()) / 60_000L
            // V5.9.1005 вҖ” PERFORMANCE_DOCTRINE: loss streak is NOT an original
            // hard veto. It can inform scoring, but it must not short-circuit
            // lane candidates before FDG. The snapshot showed LANE_EVAL=49,
            // FDG=0, V3_SKIPPED=12 вҖ” this return was one of the pre-FDG choke
            // points. Keep visibility, allow the candidate downstream.
            ErrorLogger.debug("BotService", "рҹҹЎ [LOSS_STREAK_SOFT] ${identity.symbol} | ${remainingMin}min left вҖ” FDG still evaluates")
            try {
                ForensicLogger.gate(
                    ForensicLogger.PHASE.V3, ts.symbol,
                    allow = true,
                    reason = "V3_SOFT_SHAPED loss_streak | ${remainingMin}min left | src=${ts.source}"
                )
            } catch (_: Throwable) {}
        }

        // 2. VOLUME GATE вҖ” no volume = dead token, don't buy
        val lastVolumeH1 = ts.history.lastOrNull()?.volumeH1 ?: 0.0
        val learningPct  = try { com.lifecyclebot.v3.scoring.FluidLearningAI.getLearningProgress() } catch (_: Exception) { 0.0 }
        // V5.9.704 вҖ” volume floor graduated with guard level:
        //   Level 0 (0-500 trades):   $100  вҖ” almost anything (exploration)
        //   Level 1 (500-1000):       $500  вҖ” soft filter starts
        //   Level 2 (1000-3000):     $1000  вҖ” growing selectivity
        //   Level 3+ (3000+):        $2000  вҖ” experienced bot, high bar
        // V5.9.954 вҖ” THROUGHPUT FIX. The $2000 floor at guardLvl 3+ was killing
        // 17% of V3 candidates (operator dump: 64 V3_SKIPPED of 379 intakes).
        // PERFORMANCE_DOCTRINE band requires 500-1000 trades/day to climb the
        // WR curve; the bot doesn't reach that throughput with a $2000 vol1h
        // hard veto on every fresh launch. Mature-band floor stays sane at
        // $750 (still 7.5x level-0). This is a tighten-NOT-loosen for pure
        // mature operation but doctrine #86 (help, don't hinder) trumps elite
        // selectivity until the bot consistently sustains the volume band.
        val minVolumeH1  = when {
            guardLvl == 0       -> 100.0
            guardLvl == 1       -> 300.0
            guardLvl == 2       -> 500.0
            else                -> 750.0
        }
        if (lastVolumeH1 < minVolumeH1) {
            // V5.9.672 вҖ” restore LIVE-mode VOL_GATE bypass. V5.9.606 only
            // granted the unknown-volume-but-tradable pass in paper mode,
            // which silently dropped every fresh PumpPortal/Dex hydration
            // in live mode (vol1h=0 but liq=$2.3k is the normal state for
            // a newly-listed meme). Operator confirmed live buys worked
            // end-to-end 4 days ago вҖ” this was the regression. Drop the
            // paperMode-only guard; downstream V3 + scoring still decide
            // whether the token is buy-worthy.
            // unknownVolumeButTradable: bypass vol gate for fresh listings (vol=0 but liq/mcap ok).
            // Keep this bypass for all guard levels вҖ” a token with no vol history but
            // solid liquidity is a legitimate fresh launch, not a dead token.
            // V5.9.954 вҖ” relax bypass thresholds. Fresh Pump.fun launches average
            // $500-$1500 liq and $3k-$15k mcap. The old $2k/$10k thresholds dropped
            // the early-pump phase where 10x runners are caught. Per doctrine #86,
            // shrink the veto cone; downstream V3 + FDG soft-shapers still decide
            // if the token is worth real size. A $600-liq fresh meme is a learning
            // sample either way (W or L).
            val unknownVolumeButTradable = lastVolumeH1 <= 0.0 &&
                (ts.lastLiquidityUsd >= 500.0 || ts.lastMcap >= 3_000.0)
            if (!unknownVolumeButTradable) {
                // V5.9.1005 вҖ” PERFORMANCE_DOCTRINE: volume floor is a soft
                // quality signal, not an execution veto. Hard-returning here
                // starved FDG entirely (snapshot: SAFETY=28, LANE_EVAL=49,
                // FDG=0). Let FDG/lane scorers size or reject downstream.
                ErrorLogger.debug("BotService", "рҹҹЎ [VOL_GATE_SOFT] ${identity.symbol} | \$${lastVolumeH1.toInt()} h1vol < \$${minVolumeH1.toInt()} вҖ” FDG still evaluates")
                try {
                    ForensicLogger.gate(
                        ForensicLogger.PHASE.V3, ts.symbol,
                        allow = true,
                        reason = "V3_SOFT_SHAPED vol_gate | h1vol=\$${lastVolumeH1.toInt()} < \$${minVolumeH1.toInt()} | liq=\$${ts.lastLiquidityUsd.toInt()}"
                    )
                } catch (_: Throwable) {}
            } else {
                ErrorLogger.info("BotService", "рҹ”“ [VOL_GATE_BYPASS] ${identity.symbol} | free-range unknown h1vol but liq=\$${ts.lastLiquidityUsd.toInt()} mcap=\$${ts.lastMcap.toInt()} paper=${cfg.paperMode}")
            }
        }
    }

    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // V3 ENGINE: Process token through unified scoring
    // Strategy output (phase, entry/exit scores, quality) feeds into V3
    // V3 is the ONLY thing that decides EXECUTE/WATCH/REJECT
    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if (ts.position.isOpen && ts.position.isPaperPosition) {
        val paperCloseState = try { PaperPositionCloseAuthority.stateOf("PAPER", ts.mint) } catch (_: Throwable) { null }
        if (paperCloseState == PaperPositionCloseAuthority.State.CLOSED) {
            try { ts.position = ts.position.copy(qtyToken = 0.0, pendingVerify = false) } catch (_: Throwable) {}
            try { PositionPersistence.removePosition(ts.mint) } catch (_: Throwable) {}
            try { PipelineHealthCollector.labelInc("PAPER_CLOSED_ACTIVE_ROW_DROPPED") } catch (_: Throwable) {}
            try { ForensicLogger.lifecycle("PAPER_CLOSED_ACTIVE_ROW_DROPPED", "mint=${ts.mint.take(10)} symbol=${ts.symbol} src=${ts.source}") } catch (_: Throwable) {}
            return
        }
        if (paperCloseState == PaperPositionCloseAuthority.State.CLOSE_REQUESTED || paperCloseState == PaperPositionCloseAuthority.State.CLOSING) {
            try { PaperPositionCloseAuthority.preSellGuard("PAPER", ts.mint, ts.symbol, "MAIN_LOOP_ALREADY_PENDING") } catch (_: Throwable) {}
            return
        }
        val openPaperPositions = try { synchronized(status.tokens) { status.tokens.values.count { it.position.isOpen && it.position.isPaperPosition } } } catch (_: Throwable) { 1 }
        if (!PaperExitSweepBudget.allow(ts.mint, openPaperPositions)) return
    }

    val _v3PosOpen      = ts.position.isOpen
    val _v3CfgEnabled   = cfg.v3EngineEnabled
    val _v3MgrReady     = try { com.lifecyclebot.v3.V3EngineManager.isReady() } catch (_: Throwable) { false }

    // V5.9.668 вҖ” drop-off visibility BEFORE the V3 gate. Operator
    // forensics dump showed only 13/269 SAFETY-allowed candidates
    // reaching V3. Without this audit, we couldn't tell why most
    // got skipped. Pure additive log; the actual V3 path below is
    // unchanged.
    if (_v3PosOpen || !_v3CfgEnabled || !_v3MgrReady) {
        try {
            // V5.9.683 вҖ” split position_open exits from true V3 blocks.
            // Previously ALL three conditions were V3_SKIPPED, making the
            // operator think ~2995 tokens were blocked when those were actually
            // open-position exit-management passes (correct, expected behavior).
            // Splitting to EXIT_MANAGED keeps the gate logic unchanged вҖ” additive display only.
            val reason = buildString {
                if (_v3PosOpen) append("position_open ")
                if (!_v3CfgEnabled) append("v3_disabled ")
                if (!_v3MgrReady) append("v3_not_ready ")
            }.trim()
            if (_v3PosOpen) {
                // Normal exit-management pass вҖ” label it so operator can see exits vs real blocks
                try {
                    ForensicLogger.gate(
                        ForensicLogger.PHASE.EXIT_GATE,
                        ts.symbol,
                        allow = true,
                        reason = "EXIT_MANAGED src=${ts.source}"
                    )
                } catch (_: Throwable) {}
            } else {
                ForensicLogger.gate(
                    ForensicLogger.PHASE.V3,
                    ts.symbol,
                    allow = false,
                    reason = "V3_SKIPPED $reason | src=${ts.source} liq=$${ts.lastLiquidityUsd.toInt()}"
                )
            }
        } catch (_: Throwable) {}
    }

    if (!_v3PosOpen && _v3CfgEnabled && _v3MgrReady) {
        // V5.9.651 вҖ” forensic V3 entry. Operator wants to see EVERY V3
        // evaluation: which mints reach V3, what score/conf they have,
        // what V3 verdict was. Pair this with V3_DECIDE log emitted
        // after V3Engine returns.
        ForensicLogger.phase(
            ForensicLogger.PHASE.V3,
            ts.symbol,
            "stage=ENTRY src=${ts.source} liq=$${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore.toInt()} mcap=$${ts.lastMcap.toInt()}"
        )
        // V5.9.495z50 вҖ” confirm V3 engine reached for this candidate so the
        // operator can verify the watchlistвҶ’V3 handoff fires.
        try {
            com.lifecyclebot.engine.MemePipelineTracer.stage(
                "V3_REACHED", ts.mint, ts.symbol,
                "src=${ts.source} liq=${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore.toInt()}",
            )
        } catch (_: Throwable) {}        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V3.3: CHECK FOR RECOVERY OPPORTUNITY FIRST
        // If this token was stopped out but has bounced, consider re-entry
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        val isRecoveryCandidate = try {
            executor.checkRecoveryOpportunity(ts)
        } catch (_: Exception) { false }
        
        if (isRecoveryCandidate) {
            ErrorLogger.info("BotService", "рҹ”„ RECOVERY ENTRY: ${identity.symbol} | Bounced from stop - attempting recovery trade")
            addLog("рҹ”„ RECOVERY: ${identity.symbol} bounced - attempting re-entry", ts.mint)
            
            // Execute recovery trade with smaller size and tighter stops
            val recoverySize = effectiveBalance * 0.02  // 2% position max for recovery
            
            try {
                executor.v3Buy(
                    ts = ts,
                    sizeSol = recoverySize.coerceAtMost(0.05),  // Max 0.05 SOL for recovery
                    walletSol = effectiveBalance,
                    v3Score = 50,  // Moderate score for recovery
                    v3Band = "RECOVERY",
                    v3Confidence = 60.0,
                    wallet = wallet,
                    lastSuccessfulPollMs = lastSuccessfulPollMs,
                    openPositionCount = status.openPositionCount,
                    totalExposureSol = status.totalExposureSol
                )
                
                addLog("вҡЎ RECOVERY EXECUTED: ${identity.symbol} | ${recoverySize.fmt(4)} SOL", ts.mint)
            } catch (e: Exception) {
                ErrorLogger.debug("BotService", "Recovery trade error: ${e.message}")
            }
            
            // Skip normal V3 processing for this token
            return
        }
        
        // Calculate token age in minutes
        val tokenAgeMinutes = (System.currentTimeMillis() - ts.addedToWatchlistAt) / 60000.0
        
        // Log discovery (entry point to V3 pipeline)
        ErrorLogger.debug("BotService", "[DISCOVERY] ${identity.symbol} | src=${ts.source} liq=${ts.lastLiquidityUsd.toInt()} age=${tokenAgeMinutes.toInt()}m")
        
        // Check AI degradation state
        val isAIDegraded = try {
            GeminiCopilot.isAIDegraded()
        } catch (e: Exception) {
            false
        }
        
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.9.937 вҖ” BIRDEYE STARTER-TIER PREFETCH (fire-and-forget).
        //
        // Operator upgraded to Starter on 2026-05-19 unlocking token_security
        // + trade-data. Both providers cache aggressively (sec=30min, trade=
        // 15min) so the actual network cost is bounded. Prefetching HERE
        // (just before V3 processToken) means the FDG soft-shapes below
        // will see fresh cached data on the NEXT pass for any mint that
        // makes it through V3 selection.
        //
        // Fire-and-forget on the service scope вҖ” does NOT block V3 scoring
        // or FDG. First time a mint hits this code, the cache is empty and
        // FDG silently neutral-shapes; by the next intake tick (~7s later)
        // both providers have data cached вҶ’ FDG shapes correctly.
        //
        // Cost analysis: ~50 admitted mints + 15-min TTL вҶ’ ~200 calls/hour
        // total across both endpoints Г— 25 CU avg = 5K CU/hour. Starter
        // budget is 5M CU/month = ~6.9K CU/hour. Fits with headroom.
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        // V5.9.945 вҖ” FREE-SOURCE-FIRST PREFETCH + GLOBAL CU BUDGET.
        //
        // BACKGROUND
        //   V5.9.937-942 lit up 6 Birdeye prefetch endpoints PER token, on EVERY
        //   SCAN_CB. After scanner expansion (6+ new sources, NARRATIVE_SCAN
        //   etc), this cost ballooned to ~5.4M CU/day, eating the entire
        //   5M/month Starter quota in 10 hours.
        //
        // STRATEGY: COMBINE FREE SOURCES, ESCALATE TO BIRDEYE ONLY WHEN NEEDED
        //
        //   FREE SEED (zero Birdeye cost вҖ” DexScreener-cached 45s):
        //     вҖў Creation age (pair.pairCreatedAtMs)     вҖ” used to fire deploy-age FDG shape
        //     вҖў Socials/websites (pair.socials/.websites) вҖ” used to fire social-depth FDG shape
        //
        //   BIRDEYE PREMIUM (only the signals DexScreener can't supply):
        //     вҖў Security (honeypot/freezeAuth/top10Pct)  вҖ” REAL VALUE, keep
        //     вҖў Trade-data (buy/sell flow imbalance)     вҖ” REAL VALUE, keep
        //     вҖў Price-stats (volatility regime)          вҖ” REAL VALUE, keep
        //     вҖў Whale feeder (wallet activity)           вҖ” REAL VALUE, keep
        //
        //   PREMIUM PREFETCH IS GATED BY:
        //     1. TRADABILITY вҖ” liq вүҘ \$2K AND mcap вүҘ \$5K (skip dust)
        //     2. GLOBAL CU BUDGET вҖ” BirdeyeBudgetGate (default 150K CU/day)
        //
        // EXPECTED IMPACT
        //   Before: 6 Birdeye calls Г— ~1500 unique mints/h = 9000 calls/h
        //   After:  4 Birdeye calls Г— ~200 tradable mints/h = 800 calls/h
        //                                                    вҶ“ 11Г— reduction
        //   At 25 CU/call avg: 20K CU/h = 480K CU/day = ~14.4M CU/month
        //   (still over budget вҖ” BirdeyeBudgetGate brings it under cap).
        //
        // DOCTRINE
        //   #87.1 'Dropped signal = dropped AGI sample' вҖ” we don't drop ANY
        //     signal. DexScreener pair fields were ALREADY being parsed for
        //     other paths; we're just reusing them to seed Birdeye caches.
        //   #87.12 'Free data on wire = dropped if not parsed' вҖ” same idea
        //     applied: free signals on wire = wasted if we still pay
        //     premium for equivalents.
        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
        try {
            val beKey = cfg.birdeyeApiKey
            val liqUsd = ts.lastLiquidityUsd
            val mcapUsd = ts.lastMcap

            // STEP 1: FREE SEED вҖ” populate Creation+Meta caches from DexScreener.
            // DexScreener pair lookup is 45s-cached and already used heavily; warm
            // hit-rate is high. Even a fresh fetch is "free" (no quota cost).
            scope.launch {
                try {
                    val needsCreation = com.lifecyclebot.engine.BirdeyeCreationInfoProvider.peekCached(ts.mint) == null
                    val needsMeta     = com.lifecyclebot.engine.BirdeyeMetaDataProvider.peekCached(ts.mint) == null
                    if (needsCreation || needsMeta) {
                        val pair = withContext(kotlinx.coroutines.Dispatchers.IO) {
                            com.lifecyclebot.network.DexscreenerApi().getBestPair(ts.mint)
                        }
                        if (pair != null) {
                            if (needsCreation && pair.pairCreatedAtMs > 0L) {
                                com.lifecyclebot.engine.BirdeyeCreationInfoProvider
                                    .seedFromFreeSource(ts.mint, pair.pairCreatedAtMs)
                            }
                            if (needsMeta) {
                                com.lifecyclebot.engine.BirdeyeMetaDataProvider
                                    .seedFromFreeSource(
                                        mint = ts.mint,
                                        symbol = identity.symbol,
                                        socialTypes = pair.socials,
                                        websites = pair.websites,
                                    )
                            }
                        }
                    }
                } catch (_: Throwable) { /* fail-open вҖ” seed is advisory only */ }
            }

            // STEP 2: BIRDEYE PREMIUM вҖ” gated by tradability + budget.
            val tradable = liqUsd >= 2_000.0 && mcapUsd >= 5_000.0
            val budgetOk = com.lifecyclebot.engine.BirdeyeBudgetGate.canAfford(4)
            if (beKey.isNotBlank() && tradable && budgetOk) {
                // V5.0.4299 вҖ” provider-budget accounting belongs at the actual
                // network-call/provider layer, not here. The old code called
                // recordCalls(1) after every maybePrefetch(), even when the
                // provider returned from cache, in-flight dedupe, TTL, or budget
                // skip; SecurityProvider also records internally. Runtime report
                // 5.0.4297 burned 6000 Birdeye calls / 150K CU in ~10 minutes.
                // Remove phantom/double accounting so the daily cap reflects real
                // premium calls and preserves Birdeye for finalists/exits.
                scope.launch {
                    try { com.lifecyclebot.engine.BirdeyeSecurityProvider.getTrust(ts.mint, beKey) }
                    catch (_: Throwable) { /* fail-open */ }
                }
                scope.launch {
                    try { com.lifecyclebot.engine.BirdeyeTradeDataProvider.maybePrefetch(ts.mint, beKey) }
                    catch (_: Throwable) { /* fail-open */ }
                }
                scope.launch {
                    try { com.lifecyclebot.engine.BirdeyePriceStatsProvider.maybePrefetch(ts.mint, beKey) }
                    catch (_: Throwable) { /* fail-open */ }
                }
                scope.launch {
                    try {
                        com.lifecyclebot.engine.BirdeyeWhaleFeeder.maybeFeed(
                            mint = ts.mint,
                            symbol = identity.symbol,
                            apiKey = beKey,
                            currentPriceUsd = ts.lastPrice,
                        )
                    } catch (_: Throwable) { /* fail-open */ }
                }
            } else if (beKey.isNotBlank() && !budgetOk) {
                com.lifecyclebot.engine.BirdeyeBudgetGate.logThrottleIfDue()
            }
            // Note: BirdeyeCreationInfo + BirdeyeMetaData PREMIUM prefetch is
            // DROPPED entirely (free seed above covers the FDG consumer needs).
            // If a token reaches FDG and has a high-confidence buy signal, the
            // operator can manually trigger maybePrefetch() to get the full
            // Birdeye-grade data, but the bot's autonomous loop no longer
            // burns CU on it.
        } catch (_: Throwable) { /* fail-open вҖ” prefetch is purely advisory */ }

        try {
            val v3Decision = com.lifecyclebot.v3.V3EngineManager.processToken(
                ts = ts,
                walletSol = effectiveBalance,
                totalExposureSol = status.totalExposureSol,
                openPositions = status.openPositionCount,
                recentWinRate = botBrain?.getRecentWinRate() ?: 50.0,
                recentTradeCount = botBrain?.getTradeCount() ?: 0,
                marketRegime = modeConf?.mode?.name ?: "NEUTRAL",
                isAIDegraded = isAIDegraded  // V3 SELECTIVITY: Pass AI degradation
            )

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.349 вҖ” MEME UNIFIED SCORER BRIDGE (universal visibility)
            //
            // The bridge sees EVERY meme token that reaches the V3 engine,
            // not just V3-rejected ones. We compute its verdict once here
            // and override any non-execute V3 outcome in paper mode when
            // the bridge says shouldEnter. Live mode always defers to V3.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.618 вҖ” Bridge computation now runs in BOTH paper and live (was paper-only).
            // The override at line ~9550 is still paper-gated, so live behaviour is unchanged
            // EXCEPT live now gets the verdict as an advisory the meme buy paths can read.
            // This finally lets the proven 79% WR architecture contribute to live decisions
            // without bypassing V3 вҖ” V3 still controls. Pure additive nudge.
            val memeBridgeVerdict: com.lifecyclebot.v3.MemeUnifiedScorerBridge.MemeVerdict? =
                if (!ts.position.isOpen) {
                    try { com.lifecyclebot.v3.MemeUnifiedScorerBridge.scoreForEntry(ts) }
                    catch (e: Exception) {
                        ErrorLogger.debug("BotService", "рҹҢү Bridge scoring error for ${ts.symbol}: ${e.message}")
                        null
                    }
                } else null
            memeBridgeVerdict?.let { mv ->
                ErrorLogger.debug("BotService",
                    "рҹҢү Bridge${if (cfg.paperMode) "" else "[LIVE-ADVISORY]"}: ${identity.symbol} | tech=${mv.techScore} v3=${mv.v3Score} blend=${mv.blendedScore} mult=${"%.2f".format(mv.trustMultiplier)} enter=${mv.shouldEnter}${if (mv.rejectReason != null) " rej=${mv.rejectReason}" else ""}"
                )
            }
            // V5.9.618 вҖ” Stash bridge verdict on TokenState so meme evaluators downstream
            // can read it as a small confidence bonus. Cleared on next pass / position close.
            ts.bridgeAdvisoryAgrees = (memeBridgeVerdict?.shouldEnter == true)
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V4.0 FIX: Register V3 decision with FinalExecutionPermit
            // ONLY register HARD BLOCKS (safety issues, fatal problems)
            // Soft rejections (low score, timing) should NOT block Treasury/ShitCoin
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            when (val result = v3Decision) {
                is com.lifecyclebot.v3.V3Decision.BlockFatal -> {
                    // V5.9.1568 вҖ” model-only EXTREME_RUG_RISK is NOT a terminal
                    // blocker in PAPER/bootstrap. The code below already had a
                    // later v3HardReject carveout saying this, but this earlier
                    // branch registered FinalExecutionPermit rejection + returned
                    // before sub-traders/FDG could run. Confirmed rugcheck score=0
                    // still emits EXTREME_RUG_CRITICAL_score=0 and remains fatal.
                    val paperModelRugFatal = cfg.paperMode && result.reason.contains("EXTREME_RUG_RISK", ignoreCase = true)
                    val rcPendingLiveFatal = !cfg.paperMode &&
                        ts.safety.rugcheckScore == 1 &&
                        result.reason.contains("RC_PENDING_LIVE", ignoreCase = true)
                    if (paperModelRugFatal || rcPendingLiveFatal) {
                        try {
                            val label = if (rcPendingLiveFatal) "V3_LIVE_RC_PENDING_FATAL_SOFTENED" else "V3_PAPER_MODEL_RUG_FATAL_SOFTENED"
                            ForensicLogger.lifecycle(
                                label,
                                "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${result.reason} rc=${ts.safety.rugcheckScore}"
                            )
                            com.lifecyclebot.engine.PipelineHealthCollector.labelInc(label)
                        } catch (_: Throwable) {}
                    } else {
                        ExecutableOpenGate.recordV3(ts.mint, ts.symbol, "BLOCK_FATAL", result.reason, "BLOCK_FATAL", ts.safety.rugcheckScore)
                        // HARD BLOCK: Safety issue - block ALL layers
                        FinalExecutionPermit.registerRejection(
                            mint = ts.mint,
                            symbol = ts.symbol,
                            reason = result.reason,
                            rejectedBy = "V3_BLOCK_FATAL",
                            v3Score = 0,
                            v3Confidence = 0
                        )
                        // V5.9.1121 вҖ” hard V3 fatal is terminal for new entries.
                        // 3086 showed EXTREME_RUG_RISK_* continuing through every
                        // lane, creating 4,858 fatal open blocks + 1,433 supervisor
                        // worker timeouts. Exits/managed open positions already ran
                        // above this point; for flat tokens, stop before Treasury/
                        // ShitCoin/Moonshot/FDG fanout.
                        if (!ts.position.isOpen) {
                            try { ForensicLogger.lifecycle("V3_FATAL_EARLY_RETURN", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${result.reason}") } catch (_: Throwable) {}
                            // V5.9.1323 вҖ” V3 Verdict Reconciliation (P0-4 surgical).
                            try {
                                com.lifecyclebot.engine.runtime.V3VerdictContract.recordEntry()
                                com.lifecyclebot.engine.runtime.V3VerdictContract.recordVerdict(
                                    com.lifecyclebot.engine.runtime.V3VerdictContract.Verdict.BLOCK,
                                    "FATAL_${result.reason}"
                                )
                            } catch (_: Throwable) {}
                            ErrorLogger.debug("BotService", "рҹ§Ҝ V3_FATAL_EARLY_RETURN: ${ts.symbol} | ${result.reason}")
                            return
                        }
                    }
                }
                is com.lifecyclebot.v3.V3Decision.Blocked -> {
                    ExecutableOpenGate.recordV3(ts.mint, ts.symbol, "BLOCKED", result.reason, "BLOCK_FATAL", ts.safety.rugcheckScore)
                    // HARD BLOCK: Safety/exposure issue - block ALL layers
                    FinalExecutionPermit.registerRejection(
                        mint = ts.mint,
                        symbol = ts.symbol,
                        reason = result.reason,
                        rejectedBy = "V3_BLOCK",
                        v3Score = 0,
                        v3Confidence = 0
                    )
                    if (!ts.position.isOpen) {
                        try { ForensicLogger.lifecycle("V3_BLOCKED_EARLY_RETURN", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${result.reason}") } catch (_: Throwable) {}
                        // V5.9.1323 вҖ” V3 Verdict Reconciliation (P0-4 surgical).
                        try {
                            com.lifecyclebot.engine.runtime.V3VerdictContract.recordEntry()
                            com.lifecyclebot.engine.runtime.V3VerdictContract.recordVerdict(
                                com.lifecyclebot.engine.runtime.V3VerdictContract.Verdict.BLOCK,
                                "BLOCKED_${result.reason}"
                            )
                        } catch (_: Throwable) {}
                        ErrorLogger.debug("BotService", "рҹ§Ҝ V3_BLOCKED_EARLY_RETURN: ${ts.symbol} | ${result.reason}")
                        return
                    }
                }
                is com.lifecyclebot.v3.V3Decision.Execute -> {
                    ExecutableOpenGate.clearExecutableApproval(ts.mint, ts.symbol, "EXECUTE")
                    // V3 approved - register approval to clear any previous rejection
                    FinalExecutionPermit.registerApproval(
                        mint = ts.mint,
                        symbol = ts.symbol,
                        approvedBy = "V3",
                        v3Score = result.score,
                        v3Confidence = result.confidence.toInt()
                    )
                    // V5.9.1483 вҖ” STALE-VERDICT FINALITY LEAK FIX. A V3 EXECUTE is
                    // itself the buy authority, but it only registered an approval and
                    // NEVER refreshed ExecutableOpenGate's cached preFdgVerdict. So the
                    // STANDARD/V3 doBuy() ran finality against a STALE preFdgVerdict left
                    // by a PRIOR tick's lane FDG record (often NO_BUY/WATCH), and the
                    // string precheck dropped it as EXEC_OPEN_DROPPED_PRE_FDG_NOT_BUY вҖ”
                    // killing the MAIN execute path in the live log (CAINYABEL/MUMU:
                    // EXECUTE_AGGRESSIVE -> NO_BUY -> no_open_committed_blocked_finality).
                    // Refresh the verdict to BUY for the STANDARD lane so finality reads
                    // V3's OWN decision, not a stale one. Boolean fdgCan + hardNo + the
                    // -15% floor remain the real safety rails; this only stops a V3-
                    // approved buy from being vetoed by a stale cached string.
                    try {
                        ExecutableOpenGate.recordFdg(
                            ts.mint, ts.symbol, "STANDARD",
                            canExecute = true,
                            reason = "V3_EXECUTE",
                            signal = "BUY",
                            rugScore = ts.safety.rugcheckScore,
                            safetyTier = ts.safety.tier.name,
                            liquidityUsd = ts.lastLiquidityUsd,
                            hardNoReasons = ts.safety.hardBlockReasons,
                            entryScore = ts.entryScore.toInt(),
                            tokenMapRouteStatus = TokenMapAuthority.ensureDiscoveryTokenMap(ts, ts.source).routeStatus,
                            tokenMapHydrationComplete = ts.tokenMap.hydrationComplete,
                            tokenMapExpectedOut = ts.tokenMap.expectedOutAmount,
                            tokenMapProviderAttempts = ts.tokenMap.providerAttempts,
                        )
                    } catch (_: Throwable) { /* fail-open per FDG doctrine */ }
                    // V5.9.1323 вҖ” V3 Verdict Reconciliation (P0-4 surgical).
                    try {
                        com.lifecyclebot.engine.runtime.V3VerdictContract.recordEntry()
                        com.lifecyclebot.engine.runtime.V3VerdictContract.recordVerdict(
                            com.lifecyclebot.engine.runtime.V3VerdictContract.Verdict.ALLOW
                        )
                    } catch (_: Throwable) {}
                }
                // V4.0 FIX: These are SOFT decisions - DON'T block other layers!
                // - Rejected: V3 doesn't want it, but Treasury/ShitCoin might
                // - ShadowOnly: Tracking only, other layers can trade
                // - Watch: Monitoring, other layers can trade
                is com.lifecyclebot.v3.V3Decision.Watch -> {
                    ExecutableOpenGate.recordV3(ts.mint, ts.symbol, "WATCH", "DECISION_WATCH", "WATCH", ts.safety.rugcheckScore)
                    // V5.9.1323 вҖ” V3 Verdict Reconciliation (P0-4 surgical).
                    try {
                        com.lifecyclebot.engine.runtime.V3VerdictContract.recordEntry()
                        com.lifecyclebot.engine.runtime.V3VerdictContract.recordVerdict(
                            com.lifecyclebot.engine.runtime.V3VerdictContract.Verdict.SKIP, "WATCH"
                        )
                    } catch (_: Throwable) {}
                }
                is com.lifecyclebot.v3.V3Decision.Rejected -> {
                    ExecutableOpenGate.recordV3(ts.mint, ts.symbol, "REJECTED", result.reason, "REJECT", ts.safety.rugcheckScore)
                    // V5.9.1323 вҖ” V3 Verdict Reconciliation (P0-4 surgical).
                    try {
                        com.lifecyclebot.engine.runtime.V3VerdictContract.recordEntry()
                        com.lifecyclebot.engine.runtime.V3VerdictContract.recordVerdict(
                            com.lifecyclebot.engine.runtime.V3VerdictContract.Verdict.BLOCK,
                            "REJECTED_${result.reason}"
                        )
                    } catch (_: Throwable) {}
                    // V5.0.3703 вҖ” TERMINAL REJECTION DOCTRINE RESTORED.
                    // 3700 dump showed REJECTED_FATAL_V3/SCORE_TOO_LOW=98 while
                    // FDG/EXEC still allowed buys (LAZY: v3Decision=REJECTED,
                    // fdgCan=true, EXEC_GATE_ALLOW). A V3 terminal reject must
                    // stop execution signalling at the gate level. This is not a
                    // score-floor tune; it enforces the existing terminal label.
                    val terminalRejected = result.reason.contains("TRUE_ZERO_LIQUIDITY", ignoreCase = true) ||
                        result.reason.contains("SOURCE_IDENTITY_BAD", ignoreCase = true) ||
                        result.reason.contains("NO_EXECUTABLE_ROUTE", ignoreCase = true) ||
                        result.reason.contains("NO_SELL_ROUTE", ignoreCase = true) ||
                        result.reason.contains("CONFIRMED_RUG", ignoreCase = true) ||
                        result.reason.contains("RUGCHECK_100", ignoreCase = true)
                    if (terminalRejected && !ts.position.isOpen) {
                        // V5.9.1225 вҖ” terminal factual rejects must leave the hot
                        // supervisor pool. 3192 showed 409 terminal early returns
                        // plus 132 supervisor worker timeouts while ZERO_LIQUIDITY
                        // mints kept re-entering WATCHLIST_RR. This does not prune
                        // the protected scanner pool; it quarantines factual poison
                        // already proven terminal by V3 eligibility.
                        if (result.reason.contains("TRUE_ZERO_LIQUIDITY", ignoreCase = true)) {
                            try { com.lifecyclebot.engine.QuarantineStore.quarantine(ts.mint, ts.symbol, "V3_TRUE_ZERO_LIQUIDITY_TERMINAL") } catch (_: Throwable) {}
                            try { com.lifecyclebot.engine.GlobalTradeRegistry.removeFromWatchlist(ts.mint, "V3_TRUE_ZERO_LIQUIDITY_TERMINAL") } catch (_: Throwable) {}
                        }
                        try { ForensicLogger.lifecycle("V3_REJECTED_TERMINAL_EARLY_RETURN", "mint=${ts.mint.take(10)} symbol=${ts.symbol} reason=${result.reason}") } catch (_: Throwable) {}
                        ErrorLogger.debug("BotService", "рҹ§Ҝ V3_REJECTED_TERMINAL_EARLY_RETURN: ${ts.symbol} | ${result.reason}")
                        return
                    }
                }
                is com.lifecyclebot.v3.V3Decision.ShadowOnly -> {
                    ExecutableOpenGate.recordV3(ts.mint, ts.symbol, "SHADOW_ONLY", result.reason, "WATCH", ts.safety.rugcheckScore)
                }
                else -> { 
                    // No FinalExecutionPermit action for non-final errors/not-ready.
                }
            }
            try {
                val v3CoreDecision4489 = when (v3Decision) {
                    is com.lifecyclebot.v3.V3Decision.Execute -> "EXECUTE"
                    is com.lifecyclebot.v3.V3Decision.Rejected -> "REJECTED"
                    is com.lifecyclebot.v3.V3Decision.Blocked -> "BLOCKED"
                    is com.lifecyclebot.v3.V3Decision.ShadowOnly -> "SHADOW_ONLY"
                    else -> "OTHER"
                }
                ForensicLogger.phase(
                    ForensicLogger.PHASE.LANE_EVAL,
                    ts.symbol,
                    "lane=V3_CORE shadow=V3_CORE_VISIBILITY_4489 decision=$v3CoreDecision4489 no_extra_fdg=true mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore}"
                )
                ForensicLogger.phase(
                    ForensicLogger.PHASE.LANE_EVAL,
                    ts.symbol,
                    "lane=STANDARD shadow=CORE_STANDARD_VISIBILITY_4489 decision=$v3CoreDecision4489 no_extra_fdg=true mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore}"
                )
                PipelineHealthCollector.labelInc("V3_CORE_VISIBILITY_4489_$v3CoreDecision4489")
                PipelineHealthCollector.labelInc("CORE_STANDARD_VISIBILITY_4489")
            } catch (_: Throwable) {}
            
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V3.3 FIX: Run Treasury Mode IMMEDIATELY after V3 decision
            // BEFORE any return statements, so Treasury can evaluate ALL tokens!
            // 
            // Treasury Mode runs CONCURRENTLY with V3 - it's a "2nd shadow mode"
            // that scalps tokens V3 might reject for normal trading.
            // It has its own filters (tight stops, lower thresholds).
            // 
            // V4.0 FIX: But Treasury CANNOT override V3 rejections!
            // If V3 REJECTED/BLOCKED a token, Treasury must respect that decision.
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // V5.9.93: ONE-BOOK-PER-TOKEN lockout. When V3 is about to
            // EXECUTE the CORE book on this same tick, skip Treasury
            // entirely вҖ” the audit showed Treasury and V3 opening the
            // same mint on the same tick (double-buy, conflicting TP/SL
            // ladders). Treasury will re-evaluate on later ticks once
            // the CORE position is open/closed.
            val v3WillExecuteCore = v3Decision is com.lifecyclebot.v3.V3Decision.Execute
            if (v3WillExecuteCore) {
                ErrorLogger.info(
                    "BotService",
                    "рҹ’° [TREASURY] ${ts.symbol} | SKIP | V3_EXECUTE_SAME_TICK вҖ” one book per token"
                )
            }

            val treasuryLaneAllowedThisCycle4483 = !ts.position.isOpen && shouldRunBuyLaneForCycle(ts, "TREASURY", cyclePrimaryLane)
            val cashgenLaneAllowedThisCycle4483 = !ts.position.isOpen && shouldRunBuyLaneForCycle(ts, "CASHGEN", cyclePrimaryLane)
            if (cashgenLaneAllowedThisCycle4483 && com.lifecyclebot.v3.scoring.CashGenerationAI.isEnabled()) {
                try {
                    ForensicLogger.phase(
                        ForensicLogger.PHASE.LANE_EVAL,
                        ts.symbol,
                        "lane=CASHGEN paper=${cfg.paperMode} mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore} alias=TREASURY_CASHGEN_SHARED_EXEC no_fdg=true v3Skip=$v3WillExecuteCore"
                    )
                    PipelineHealthCollector.labelInc("CASHGEN_ALIAS_LANE_EVAL_4483")
                } catch (_: Throwable) {}
            }
            if (!v3WillExecuteCore && treasuryLaneAllowedThisCycle4483 && com.lifecyclebot.v3.scoring.CashGenerationAI.isEnabled()) {
                // V5.9.920 вҖ” TREASURY LANE_EVAL emit.
                try {
                    ForensicLogger.phase(
                        ForensicLogger.PHASE.LANE_EVAL,
                        ts.symbol,
                        "lane=TREASURY paper=${cfg.paperMode} mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} score=${ts.entryScore} v3Skip=$v3WillExecuteCore"
                    )
                } catch (_: Throwable) {}
                try {
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    // V4.0 FIX: CHECK FINAL EXECUTION PERMIT
                    // If V3 rejected this token, Treasury CANNOT buy it
                    // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                    val permitResult = FinalExecutionPermit.canExecute(
                        mint = ts.mint,
                        symbol = ts.symbol,
                        requestingLayer = "TREASURY",
                        hasOpenPosition = ts.position.isOpen
                    )
                    
                    if (!permitResult.allowed) {
                        ErrorLogger.debug("BotService", "рҹ’° [TREASURY] ${ts.symbol} | BLOCKED | ${permitResult.reason}")
                        // Skip treasury evaluation for this token
                    } else {
                        // Extract V3 scores from decision (any type)
                        val (v3Score, v3Confidence) = when (val result = v3Decision) {
                            is com.lifecyclebot.v3.V3Decision.Execute -> result.score to result.confidence.toInt()
                            is com.lifecyclebot.v3.V3Decision.Watch -> result.score to result.confidence
                            is com.lifecyclebot.v3.V3Decision.Rejected -> 20 to 30  // Low defaults for rejected
                            else -> 15 to 25  // Very low for blocked/fatal
                        }
                        
                        // Cache scores for later use
                        ts.lastV3Score = v3Score
                        ts.lastV3Confidence = v3Confidence
                        
                        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                        // V4.1 COLD-START FIX: Check for bootstrap forced entry
                        // This breaks the deadlock: no trades вҶ’ no learning вҶ’ no trades
                        // 
                        // NOTE: Use momentum/buy-pressure based score, NOT v3Score!
                        // v3Score is low (20-30) for rejected tokens, but Treasury trades
                        // tokens V3 doesn't like. Use a composite of raw signals instead.
                        // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                        val tokenAge = if (ts.addedToWatchlistAt > 0) {
                            (System.currentTimeMillis() - ts.addedToWatchlistAt) / 60_000.0
                        } else 30.0
                        
                        // Calculate raw signal score for bootstrap (not v3Score)
                        val rawSignalScore = calculateBootstrapScore(
                            buyPressurePct = ts.lastBuyPressurePct,
                            liquidityUsd = ts.lastLiquidityUsd,
                            momentum = ts.momentum ?: 0.0,
                            volatility = ts.volatility ?: 0.0,
                        )
                        
                        val forceBootstrapEntry = com.lifecyclebot.v3.scoring.FluidLearningAI.shouldForceBootstrapEntry(
                            score = rawSignalScore,
                            liquidityUsd = ts.lastLiquidityUsd,
                            tokenAgeMinutes = tokenAge,
                            buyPressurePct = ts.lastBuyPressurePct,
                            isPaper = com.lifecyclebot.engine.RuntimeModeAuthority.isPaper()  // V5.9.1563 вҖ” runtime authority, not stale cfg
                        )
                        
                        val treasurySignal = com.lifecyclebot.v3.scoring.CashGenerationAI.evaluate(
                            mint = ts.mint,
                            symbol = ts.symbol,
                            currentPrice = ts.ref,
                            liquidityUsd = ts.lastLiquidityUsd,
                            // V5.0.3986 вҖ” live profitability/safety fix. Missing
                            // holder data is NOT safe. In live it must hydrate/defer
                            // at PreTradeHardGate; scorer receives a neutral/failure
                            // value so Treasury/CashGen does not over-score unknown
                            // high-holder tokens as cashflow candidates.
                            topHolderPct = ts.topHolderPct ?: if (com.lifecyclebot.engine.RuntimeModeAuthority.isLive()) 50.0 else 20.0,
                            buyPressurePct = ts.lastBuyPressurePct,
                            v3Score = v3Score,
                            v3Confidence = v3Confidence,
                            momentum = ts.momentum ?: 0.0,
                            volatility = ts.volatility ?: 0.0,
                            discoverySource = ts.source,
                            priceSource = ts.lastPriceSource,
                            priceDex = ts.lastPriceDex,
                            tokenAgeMinutes = tokenAge,
                        )
                        val treasuryBridge6022 = if (!treasurySignal.shouldEnter) toolkitGoodLaneBridge6022(ts, "TREASURY", treasurySignal.reason) else null
                        val treasurySignal6022 = if (treasuryBridge6022 != null) treasurySignal.copy(
                            shouldEnter = true,
                            positionSizeSol = treasuryBridge6022.sizeSol,
                            takeProfitPct = treasuryBridge6022.tpPct,
                            stopLossPct = treasuryBridge6022.slPct,
                            confidence = maxOf(treasurySignal.confidence, treasuryBridge6022.score),
                            reason = treasuryBridge6022.reason,
                            entryScore = maxOf(treasurySignal.entryScore, treasuryBridge6022.score),
                        ) else treasurySignal

                        // V5.0.5999 вҖ” WIRED: TreasuryScannerFeed producer.
                        // Publish this token to the dedicated Treasury/CashGen
                        // watchlist if it meets established-token criteria
                        // (mcap вүҘ $1M, liq вүҘ $50K). Feed size capped @ 100
                        // with oldest-eviction. Rejected tokens still flow
                        // through meme lanes вҖ” this is a producer for a
                        // curated CashGen surface, NOT a veto.
                        // vol24h isn't carried on TokenState directly, so we
                        // pass the min floor to satisfy the criteria check;
                        // mcap+liq are the honest gates here.
                        //
                        // V5.0.6002 вҖ” WIRED: TreasuryScannerFeed CONSUMER.
                        // Established tokens (mcap вүҘ $1M, liq вүҘ $50K) get an
                        // affinity boost toward CASHGEN/TREASURY/QUALITY so
                        // the compounder lanes win the primary election on
                        // real free-money-engine candidates. Operator directive:
                        // "focus on quality, cashgen/treasury were ramped up
                        // and active." This does NOT veto meme lanes for the
                        // same token вҖ” the affinity is additive and the
                        // scanner keeps feeding memes; it just ensures the
                        // established tokens have a fast path to the lanes
                        // that were designed for them.
                        //
                        // V5.0.6004 вҖ” SOURCE-BASED AFFINITY BOOST.
                        // Operator dump 17:22 showed CASHGEN/TREASURY/BLUECHIP
                        // starved despite bluechip-watchlist intake because
                        // pumpfun API is degraded вҖ” mcap/liq don't populate
                        // in time for the metric-based boost above. Boost by
                        // SOURCE first, then by metrics as fallback. Bluechip
                        // watchlist tokens go straight to the compounders even
                        // when their liq hasn't hydrated yet.
                        try {
                            val srcU = ts.source.uppercase()
                            val bluechipSource = srcU.contains("BLUECHIP_WATCHLIST") ||
                                srcU.contains("COINGECKO_TRENDING") ||
                                srcU.contains("DEX_TRENDING") ||
                                srcU.contains("DEX_BOOSTED")
                            val establishedMetrics = ts.lastMcap >= TreasuryScannerFeed.MIN_TREASURY_MCAP &&
                                ts.lastLiquidityUsd >= TreasuryScannerFeed.MIN_TREASURY_LIQUIDITY
                            if (bluechipSource || establishedMetrics) {
                                if (establishedMetrics) {
                                    TreasuryScannerFeed.publishCandidate(
                                        TreasuryScannerFeed.TreasuryCandidate(
                                            mint = ts.mint,
                                            symbol = ts.symbol,
                                            mcap = ts.lastMcap,
                                            liquidityUsd = ts.lastLiquidityUsd,
                                            vol24hUsd = TreasuryScannerFeed.MIN_TREASURY_24H_VOL,
                                            source = ts.source.ifBlank { "processTokenCycle" },
                                        ),
                                    )
                                }
                                // Affinity boost so canonicalCycleLaneFor / AgenticStyleRouter
                                // elect CASHGEN/TREASURY/QUALITY as primary for this token.
                                val boostedBefore = ts.laneAffinity.size
                                ts.laneAffinity.add("CASHGEN")
                                ts.laneAffinity.add("TREASURY")
                                ts.laneAffinity.add("QUALITY")
                                if (ts.lastMcap >= 500_000.0 || bluechipSource) ts.laneAffinity.add("BLUECHIP")
                                if (ts.laneAffinity.size != boostedBefore) {
                                    try {
                                        ForensicLogger.lifecycle(
                                            "TREASURY_FEED_AFFINITY_BOOST_6004",
                                            "symbol=${ts.symbol} mint=${ts.mint.take(10)} src=${ts.source} mcap=${ts.lastMcap.toInt()} liq=${ts.lastLiquidityUsd.toInt()} boostBy=${if (bluechipSource) "source" else "metrics"} affinityAdded=CASHGEN+TREASURY+QUALITY${if (ts.lastMcap >= 500_000.0 || bluechipSource) "+BLUECHIP" else ""}",
                                        )
                                        PipelineHealthCollector.labelInc("TREASURY_FEED_AFFINITY_BOOST_6004_${if (bluechipSource) "SOURCE" else "METRICS"}")
                                    } catch (_: Throwable) {}
                                }
                            }
                        } catch (_: Throwable) { /* producer must never break the cycle */ }
                        
                        // V4.1: Enter if Treasury says yes OR bootstrap override triggered
                        // V5.2.13: Block bootstrap override when V3 hard-rejects OR dump signals active
                        // V5.9: All terminal V3 decisions block Treasury вҖ” Rejected, BlockFatal, AND Blocked.
                        // V5.9.690: In paper/bootstrap mode, BlockFatal from EXTREME_RUG_RISK is too
                        // aggressive вҖ” it blocks all 5 sub-traders even on tokens that SafetyChecker
                        // passed (RC_PENDING + paper bypass). Only genuine structural fatals (liquidity
                        // collapse, pair invalid, unsellable, confirmed rug score=0) should hard-block.
                        // EXTREME_RUG_RISK in paper mode: let sub-traders make their own decision.
                        val v3IsPaperMode = cfg.paperMode
                        val v3BlockFatalReason = (v3Decision as? com.lifecyclebot.v3.V3Decision.BlockFatal)?.reason ?: ""
                        val v3BlockFatalIsRug = v3BlockFatalReason.contains("EXTREME_RUG", ignoreCase = true)
                        val v3HardReject = v3Decision is com.lifecyclebot.v3.V3Decision.Rejected
                            || (v3Decision is com.lifecyclebot.v3.V3Decision.BlockFatal && !(v3IsPaperMode && v3BlockFatalIsRug))
                            || v3Decision is com.lifecyclebot.v3.V3Decision.Blocked
                        val hasDumpSignal = try { AICrossTalk.isCoordinatedDump(ts.mint, ts.symbol) } catch (_: Exception) { false }
                        // V5.9.156 вҖ” CrossTalk dump veto is volume-killing on
                        // fresh pump.fun launches that ALWAYS fire LiquidityAI
                        // COLLAPSE in the first 4-5 minutes (user log 04-23:
                        // PORINGMAN collapse -7% over 4min on a token 3 min
                        // old). During bootstrap (<40% learning) we let those
                        // tokens through вҖ” the scorer already has the signal
                        // as a component, and the bot needs volume to learn
                        // what's a real dump vs launch noise. Above 40%
                        // learning the original hard veto re-engages.
                        val dumpBootstrapBypass = try {
                            com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() && com.lifecyclebot.v3.scoring.FluidLearningAI.getLearningProgress() < 0.40
                        } catch (_: Exception) { false }
                        val dumpBlocks = hasDumpSignal && !dumpBootstrapBypass
                        // V5.9: Terminal V3 rejects are globally binding вҖ” Treasury cannot override them.
                        // Previously v3HardReject only gated forceBootstrapEntry, not treasurySignal6022.shouldEnter.
                        // TOO_OLD / INELIGIBLE / ZERO_LIQUIDITY rejections from V3|ELIGIBILITY must block all layers.
                        var shouldEnter = !v3HardReject && !dumpBlocks && (treasurySignal6022.shouldEnter || (com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() && forceBootstrapEntry))
                        var treasuryBlockedReason: String? = null

                        // V5.9.1091 вҖ” Treasury is only ONE lane. Its private skip
                        // conditions must not return from processTokenCycle(), because
                        // that starves Quality/BlueChip/Moonshot/ShitCoin/Manip/Sniper/Dip.
                        // Convert Treasury-only vetoes into local shouldEnter=false.

                        // V5.9: Post-close cooldown вҖ” prevent immediate re-entry after a close
                        val closedAgoMs = System.currentTimeMillis() - (BotService.recentlyClosedMs[ts.mint] ?: 0L)
                        if (!(com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() && FreeRangeMode.isWideOpen()) && closedAgoMs < BotService.RE_ENTRY_COOLDOWN_MS) {
                            treasuryBlockedReason = "COOLDOWN_${closedAgoMs/1000}s"
                            ErrorLogger.debug("BotService", "рҹ’° [TREASURY] ${ts.symbol} | COOLDOWN | closed ${closedAgoMs/1000}s ago (min ${BotService.RE_ENTRY_COOLDOWN_MS/1000}s) вҖ” yielding to other lanes")
                            shouldEnter = false
                        }
                        
                        // V5.0.4021 вҖ” bootstrap score gate is paper-only. Live adapts
                        // from trade 1 via live feedback and deterministic proof.
                        if (shouldEnter && com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() && !FreeRangeMode.isWideOpen() &&
                            com.lifecyclebot.v3.scoring.FluidLearningAI.shouldBlockBootstrapTrade(treasurySignal6022.confidence)) {
                            treasuryBlockedReason = "PAPER_BOOTSTRAP_BLOCKED_score_${treasurySignal6022.confidence}"
                            ErrorLogger.debug("BotService", "рҹ’° [TREASURY] ${ts.symbol} | PAPER_BOOTSTRAP_BLOCKED | score=${treasurySignal6022.confidence} | ${com.lifecyclebot.v3.scoring.FluidLearningAI.getBootstrapStatus()} вҖ” yielding to other lanes")
                            shouldEnter = false
                        }

                        // V5.9.92: SmartChart veto for Treasury (same fix as
                        // Executor entry in V5.9.91). Treasury had its own
                        // scoring path that bypassed chart-bias checks вҖ” if
                        // the scanner reads >=80% bearish in the last 2 min
                        // we skip regardless of Treasury score.
                        // V5.9.156 вҖ” but during bootstrap (<40% learning)
                        // let these through: SmartChart's "bearish 80%" on a
                        // 2-min chart is noise on tokens that haven't had time
                        // to print a real pattern. Blocking them here denied
                        // the scorer the volume it needs to learn. Above 40%
                        // learning the original veto re-engages.
                        // V5.9.495z3 вҖ” operator: paper showing SMARTCHART_BLOCK
                        // bearish=100% on every Treasury candidate, killing
                        // sweep volume. Paper mode is for LEARNING; force the
                        // bypass on regardless of learning progress so paper
                        // gets the volume to evaluate "is the bearish veto
                        // actually correct?". Live mode keeps the veto at >=40%
                        // learning as before вҖ” real money still respects it.
                        val smartChartBypass = try {
                            cfg.paperMode ||
                            com.lifecyclebot.v3.scoring.FluidLearningAI.getLearningProgress() < 0.40
                        } catch (_: Exception) { cfg.paperMode }
                        val tsBearish = try {
                            com.lifecyclebot.engine.SmartChartCache.getBearishConfidence(ts.mint)
                        } catch (_: Exception) { null }
                        if (shouldEnter && !smartChartBypass && tsBearish != null && tsBearish >= 80.0) {
                            treasuryBlockedReason = "SMARTCHART_BEARISH_${tsBearish.toInt()}"
                            ErrorLogger.info(
                                "BotService",
                                "рҹ’° [TREASURY] ${ts.symbol} | SMARTCHART_BLOCK | bearish=${tsBearish.toInt()}% вҖ” yielding to other lanes"
                            )
                            shouldEnter = false
                        }

                        if (!shouldEnter && treasuryBlockedReason != null) {
                            try {
                                ForensicLogger.lifecycle(
                                    "TREASURY_YIELDED_TO_OTHER_LANES",
                                    "symbol=${ts.symbol} mint=${ts.mint.take(10)} reason=$treasuryBlockedReason"
                                )
                            } catch (_: Throwable) {}
                        }

                        if (shouldEnter) {
                            // V5.0.4021 вҖ” bootstrap size multiplier is paper-only; live
                            // sizing stays fluid/adaptive from SmartSizer + lane/market proof.
                            val bootstrapMultiplier = if (com.lifecyclebot.engine.RuntimeModeAuthority.isPaper()) com.lifecyclebot.v3.scoring.FluidLearningAI.getBootstrapSizeMultiplier() else 1.0
                            // V5.9.1246 вҖ” SOFT-SHAPE matured TREASURY death buckets.
                            // V5.9.1068 downgraded the danger-zone HARD BLOCK to
                            // telemetry-only and claimed "SmartSizer/SL tightening
                            // already handling size + risk reduction downstream" вҖ”
                            // but that wire never existed: the danger flag was only
                            // LOGGED, and adjustedSize entered at full size. Result
                            // (snapshot 5.0.3213): TREASURY bled to -1.85 SOL / n=25,
                            // driven by TREASURY|S61+ (losses=20, wins=4, mean -21%),
                            // a MATURED bucket (LosingPatternMemory.isDangerous needs
                            // losses>=8 AND sample>=20 AND lossRate>=0.75 вҖ” real
                            // statistical weight, not a bootstrap false-positive).
                            // Doctrine = soft-shape, not veto: keep the trade (volume +
                            // learning preserved, no starvation, FDG still the only
                            // hard gate) but shrink matured-danger entries to a third
                            // so each bleeder costs ~1/3 while the outcome is still
                            // recorded. Bootstrap-band danger never qualifies (sample<20).
                            // Computed here (depends only on rawSignalScore +
                            // treasurySignal6022.confidence, both in scope); the later
                            // telemetry block reuses these same vals.
                            val _trsScore = rawSignalScore.coerceAtLeast(treasurySignal6022.confidence).coerceIn(0, 100)
                            val _trsIsDanger = try {
                                com.lifecyclebot.engine.LosingPatternMemory.isDangerZone("TREASURY", _trsScore)
                            } catch (_: Throwable) { false }
                            // V5.9.1247 вҖ” tiered danger sizing. Flat Г—0.35 (1246)
                            // did not stop the bleed: TREASURY|S61+ kept firing 40+
                            // entries and grew to -3.08 SOL / n=49 (snapshot 3214).
                            // Use the loss-count-scaled multiplier so deeper, more
                            // proven death buckets shrink harder (>=30 losses вҶ’ Г—0.10),
                            // while still letting every bucket record outcomes (no veto,
                            // no starvation). Bootstrap candidates (sample<20) get Г—1.0.
                            val dangerSizeMult = try {
                                com.lifecyclebot.engine.LosingPatternMemory.recommendedSizeMult("TREASURY", _trsScore)
                            } catch (_: Throwable) { if (_trsIsDanger) 0.35 else 1.0 }
                            // V5.9.1256 вҖ” TREASURY was the ONE lane missing the
                            // score-expectancy soft-gate the other 6 lanes have
                            // (BLUECHIP/CASHGEN/SHITCOIN/MOONSHOT/MANIPULATED/QUALITY
                            // all call ScoreExpectancyTracker.shouldReject; TREASURY
                            // never did вҶ’ TREASURY|S61+ bled to -1.44 SOL unpruned).
                            // Doctrine = soft-shape not veto: when this score bucket
                            // is net-losing over its rolling window (n>=15, mean<-8%),
                            // stack an extra Г—0.25 shrink on top of the danger mult.
                            // The trade still fires (volume + learning preserved, FDG
                            // still the only hard gate) but a proven-negative score
                            // bucket enters at a fraction of size.
                            val _trsExpectancyReject = try {
                                com.lifecyclebot.engine.ScoreExpectancyTracker.shouldReject("TREASURY", _trsScore)
                            } catch (_: Throwable) { false }
                            val _trsExpectancyMult = if (_trsExpectancyReject) 0.25 else 1.0
                            // V5.9.1257 вҖ” calibration-aware shrink (net-negative band).
                            val _trsCalMult = try {
                                com.lifecyclebot.engine.ScoreExpectancyTracker.calibrationSizeMult("TREASURY", _trsScore)
                            } catch (_: Throwable) { 1.0 }
                            if (_trsExpectancyReject) {
                                ErrorLogger.info("BotService",
                                    "рҹҸ·пёҸ [TREASURY] ${ts.symbol} | EXPECTANCY_SOFTSHAPE (sizeГ—0.25, not blocked) | score=$_trsScore | Ој=${"%+.1f".format(com.lifecyclebot.engine.ScoreExpectancyTracker.bucketMean("TREASURY", _trsScore) ?: 0.0)}% n=${com.lifecyclebot.engine.ScoreExpectancyTracker.bucketSamples("TREASURY", _trsScore)}")
                            }
                            // V5.9.1556 вҖ” tuning only: Treasury overall is net-positive,
                            // but console shows TREASURY|S0-10 as the dominant danger
                            // bucket (42L/6W mean -11.4%). Preserve learning/volume, but
                            // let toxic buckets become true dust probes instead of being
                            // floored back to 0.01 SOL after multipliers.
                            val treasuryToxicBucket = _trsIsDanger || _trsExpectancyReject || _trsCalMult < 1.0
                            val treasuryMinSize = if (treasuryToxicBucket) 0.002 else 0.01
                            // V5.0.5999 вҖ” WIRED: TreasuryBrain scalp-setup verdict.
                            // Purpose-built scoring layer for CashGen 3-5% scalps
                            // (5m+15m momentum Г— buy pressure Г— liq depth Г— whipsaw
                            // penalty). Fluid: verdict.sizeMultiplier ranges 0.15
                            // (SKIP вҶ’ tiny learning probe) to 1.35 (PREMIUM_SCALP).
                            // Doctrine-clean вҖ” never a veto, always folded into
                            // sizing as an EDGE, never a block. Operator directive:
                            // Treasury needs its own brain, not a repurposed meme
                            // trader.
                            val brainVerdict = try {
                                TreasuryBrain.evaluate(ts)
                            } catch (_: Throwable) {
                                TreasuryBrain.ScalpVerdict(50.0, "PROBE_SCALP", 1.0, listOf("brain_fail_open"))
                            }
                            if (brainVerdict.category != "STANDARD_SCALP") {
                                try {
                                    ForensicLogger.lifecycle(
                                        "TREASURY_BRAIN_VERDICT_5999",
                                        "sym=${ts.symbol} score=${brainVerdict.score.toInt()} cat=${brainVerdict.category} sizeГ—=${"%.2f".format(brainVerdict.sizeMultiplier)} reasons=${brainVerdict.reasons.joinToString(",")}",
                                    )
                                    PipelineHealthCollector.labelInc("TREASURY_BRAIN_VERDICT_5999_${brainVerdict.category}")
                                } catch (_: Throwable) {}
                            }
                            val adjustedSize = (treasurySignal6022.positionSizeSol * bootstrapMultiplier * dangerSizeMult * _trsExpectancyMult * _trsCalMult * brainVerdict.sizeMultiplier).coerceAtLeast(treasuryMinSize)
                            
                            // V5.2.8 FIX: If bootstrap override forced entry, use default TP/SL values
                            // When Treasury rejects, it returns 0% TP which causes immediate exits!
                            val effectiveTpPct = if (treasurySignal6022.takeProfitPct <= 0.0) 4.0 else treasurySignal6022.takeProfitPct
                            val effectiveSlPct = if (treasurySignal6022.stopLossPct >= 0.0) -4.0 else treasurySignal6022.stopLossPct
                            
                            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                            // V5.0: TRADE AUTHORIZER - MUST pass before ANY execution
                            // This is the SINGLE source of truth for execution permission
                            // Prevents post-execution gating drift (inokumi bug)
                            // 
                            // V5.2 FIX: Use Treasury's own score/confidence, NOT V3's!
                            // V3 rejects treasury candidates with low scores (20-30)
                            // Treasury has its own scoring criteria - use those instead
                            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
                            val treasuryScore = _trsScore  // V5.9.1246 вҖ” reuse the hoisted danger-score

                            // V5.9.1068 вҖ” DANGER ZONE IS TELEMETRY, NOT A BLOCK.
                            // V5.9.1246 hoisted _trsScore/_trsIsDanger above the size
                            // calc so matured danger buckets are soft-shaped (Г—0.35
                            // size) instead of entering full-size. Trade still proceeds
                            // вҖ” operator mandate: "never pause or disable; everything
                            // gets a chance to learn then self-adjust." Size reduction
                            // (not a veto) is the self-adjust.
                            if (_trsIsDanger) {
                                ErrorLogger.info("BotService",
                                    "рҹҸ·пёҸ [TREASURY] ${ts.symbol} | DANGER_ZONE_SOFTSHAPE (sizeГ—${dangerSizeMult}, not blocked) | score=$_trsScore | LosingPatternMemory flagged (TREASURY|S${(_trsScore/10)*10}-${(_trsScore/10)*10+10})")
                            }
                            // V5.9.1068 вҖ” no else wrapper; execution proceeds.
                            run {

                            // V5.9.688 вҖ” FDG gate for Treasury path
                            val treasuryFdg = try {
                                FinalDecisionGate.evaluate(
                                    ts = ts,
                                    candidate = laneQualifiedBuyDecision(decision, "TREASURY", confidenceFloor = treasurySignal6022.confidence.toDouble(), liquidityUsd = ts.lastLiquidityUsd, mintForProbe = ts.mint),
                                    laneScore = treasurySignal6022.confidence.toDouble(),
                                    config = cfg,
                                    proposedSizeSol = adjustedSize,
                                    brain = executor.brain,
                                    tradingModeTag = try { ModeSpecificGates.fromTradingMode("TREASURY") } catch (_: Exception) { null },
                                )
                            } catch (fdgEx: Exception) {
                                ErrorLogger.warn("BotService", "рҹҸҰ [TREASURY] FDG error: ${fdgEx.message} вҖ” proceeding fail-open")
                                null
                            }
                            // V5.9.689 вҖ” bump FDG forensic counter for TREASURY path
            try {
                ForensicLogger.phase(ForensicLogger.PHASE.FDG, ts.symbol,
                    "path=TREASURY can=${treasuryFdg?.canExecute() ?: true} reason=${treasuryFdg?.blockReason ?: "n/a"}")
                ForensicLogger.gate(ForensicLogger.PHASE.FDG, ts.symbol,
                    allow = treasuryFdg?.canExecute() ?: true,
                    reason = treasuryFdg?.blockReason ?: "ok")
            } catch (_: Throwable) {}
            ExecutableOpenGate.recordFdg(ts.mint, ts.symbol, "TREASURY", treasuryFdg?.canExecute() ?: true, treasuryFdg?.blockReason, signal = "BUY", rugScore = ts.safety.rugcheckScore, safetyTier = ts.safety.tier.name, liquidityUsd = ts.lastLiquidityUsd, hardNoReasons = ts.safety.hardBlockReasons, entryScore = ts.entryScore.toInt(), tokenMapRouteStatus = TokenMapAuthority.ensureDiscoveryTokenMap(ts, ts.source).routeStatus, tokenMapHydrationComplete = ts.tokenMap.hydrationComplete, tokenMapExpectedOut = ts.tokenMap.expectedOutAmount, tokenMapProviderAttempts = ts.tokenMap.providerAttempts)
            // V5.9.691 вҖ” FDG modulates, does not hard-kill, Treasury signals
                            val trsFdgStructural = treasuryFdg != null && !treasuryFdg.canExecute() &&
                                treasuryFdg.blockReason?.let { it.contains("LIQUIDITY") || it.contains("ML_RUG_PROBABILITY") || it.contains("COPY_TRADE") || it.contains("EMERGENCY_STOP") } == true
                            val trsFdgProbe = treasuryFdg != null && !treasuryFdg.canExecute() && !trsFdgStructural
                            if (trsFdgStructural) {
                                ErrorLogger.info("BotService", "рҹҡ« FDG STRUCTURAL BLOCK on TREASURY: ${ts.symbol} | ${treasuryFdg?.blockReason ?: "fdg_block"}")
                                RejectionTelemetry.record("TREASURY_FDG", treasuryFdg?.blockReason ?: "fdg_block")
                            } else {
                            if (trsFdgProbe) {
                                ErrorLogger.info("BotService", "вҡ пёҸ FDG SIZE-REDUCE on TREASURY: ${ts.symbol} | ${treasuryFdg?.blockReason ?: "fdg_caution"} | probe trade")
                                RejectionTelemetry.record("TREASURY_FDG_PROBE", treasuryFdg?.blockReason ?: "fdg_caution")
                            }


                            val authResult = TradeAuthorizer.authorize(
                                mint = ts.mint,
                                symbol = ts.symbol,
                                score = treasuryScore,  // V5.2: Use Treasury's score
                                confidence = treasurySignal6022.confidence.toDouble(),  // V5.2: Use Treasury's confidence
                                quality = if (treasurySignal6022.confidence >= 70) "B" else "C",  // V5.2: Derive quality from confidence
                                isPaperMode = cfg.paperMode,
                                requestedBook = TradeAuthorizer.ExecutionBook.TREASURY,
                                rugcheckScore = ts.safety.rugcheckScore.takeIf { it >= 0 } ?: 100,
                                liquidity = ts.lastLiquidityUsd,
                                isBanned = BannedTokens.isBanned(ts.mint),
                            )
                            
                            if (!authResult.isExecutable()) {
                                // NOT AUTHORIZED - log and skip
                                if (authResult.isShadowOnly()) {
                                    ErrorLogger.info("BotService", "рҹ’° [TREASURY] ${ts.symbol} | SHADOW_ONLY | ${authResult.reason}")
                                    // Track for learning but do NOT create position
                                } else {
                                    ErrorLogger.debug("BotService", "рҹ’° [TREASURY] ${ts.symbol} | REJECTED | ${authResult.reason}")
                                    RejectionTelemetry.record("TREASURY", authResult.reason)
                                }
                                // Skip execution - do NOT proceed to buy
                            } else {
                                // AUTHORIZED - proceed with execution
                                // V5.9.1191 вҖ” reuse the canonical EXEC_OPEN_ALLOWED
                                // key emitted by TradeAuthorizer/ExecutableOpenGate.
                                // Passing a parallel authResult.attemptId into FEP/executor
                                // can self-report DUPLICATE_EXECUTION_KEY on the same approved
                                // lane handoff. Fallback keeps old behavior if telemetry is absent.
                                val treasuryAttemptId = ExecutableOpenGate.recentAllowedAttemptId(ts.mint, "TREASURY") ?: authResult.attemptId
                            
                                // Try to acquire execution permit
                                val canExecute = FinalExecutionPermit.tryAcquireExecution(
                                    mint = ts.mint,
                                    symbol = ts.symbol,
                                    layer = "TREASURY",
                                    sizeSol = adjustedSize,
                                    attemptId = treasuryAttemptId,
                                    finalityPrechecked = true,
                                    paperMode = cfg.paperMode,
                                    rugScore = ts.safety.rugcheckScore,
                                    liquidityUsd = ts.lastLiquidityUsd,
                                    safetyTier = ts.safety.tier.name,
                                    lastSafetyCheckMs = ts.lastSafetyCheck
                                )
                                
                                if (canExecute) {
                                val bootstrapTag = if (com.lifecyclebot.engine.RuntimeModeAuthority.isPaper() && forceBootstrapEntry) " [PAPER_BOOTSTRAP OVERRIDE]" else ""
                                
                                // V5.2 FIX: Capture Treasury's OWN entry price BEFORE paperBuy applies slippage!
                                // Treasury is a separate trading layer - it tracks its own entry independent of the position
                                val treasuryEntryPrice = ts.lastPrice.takeIf { it > 0 } 
                                    ?: ts.history.lastOrNull()?.priceUsd 
                                    ?: ts.ref
                                
                                ErrorLogger.info("BotService", "рҹ’° [TREASURY] ${ts.symbol} | ENTER$bootstrapTag | " +
                                    "size=${adjustedSize.fmt(3)} SOL (${(bootstrapMultiplier*100).toInt()}%) | " +
                                    "TP=${treasurySignal6022.takeProfitPct}% | " +
                                    "treasuryEntry=$treasuryEntryPrice | " +
                                    "mode=${treasurySignal6022.mode}")
                                
                                // V5.7.8: In LIVE mode, verify actual wallet can fund the trade
                                val canFundLive = if (!cfg.paperMode) {
                                    val realWalletBal = status.walletSol
                                    if (realWalletBal < adjustedSize) {
                                        ErrorLogger.warn("BotService", "рҹ’° [TREASURY] ${ts.symbol} | LIVE_SKIP | " +
                                            "wallet=${realWalletBal.fmt(3)}в—Һ < size=${adjustedSize.fmt(3)}в—Һ")
                                        addLog("рҹ’° TREASURY SKIP: ${ts.symbol} | Insufficient wallet (${realWalletBal.fmt(3)}в—Һ < ${adjustedSize.fmt(3)}в—Һ)")
                                        FinalExecutionPermit.releaseExecution(ts.mint)
                                        false
                                    } else true
                                } else true
                                
                                if (!canFundLive) {
                                    // Skip treasury entry вҖ” wallet can't fund
                                } else {
                                
                                // Execute treasury buy (this calls paperBuy which applies slippage to ts.position)
                                // V5.2.8 FIX: Use effectiveTpPct/effectiveSlPct to prevent 0% TP instant-exits!
                                val treasuryOpened = executor.treasuryBuy(
                                    ts = ts,
                                    sizeSol = adjustedSize,
                                    walletSol = effectiveBalance,
                                    takeProfitPct = effectiveTpPct,   // V5.2.8: Use effective (non-zero) TP
                                    stopLossPct = effectiveSlPct,     // V5.2.8: Use effective SL
                                    wallet = wallet,
                                    isPaper = com.lifecyclebot.engine.RuntimeModeAuthority.isPaper(),  // V5.9.1563 вҖ” runtime authority, not stale cfg
                                    finalityPrechecked = true,
